def approval_handoff_record(
    archive_root: Path | str,
    *,
    handoff_id: str | None,
    operation_kind: str,
    target_ref: str | None,
    requested_action: str | None,
    status: str,
    requested_by: str | None = None,
    reviewed_by: str | None = None,
    related_command: list[str] | None = None,
    related_release: list[str] | None = None,
    supersedes: str | None = None,
    resolved_in: str | None = None,
    dry_run: bool = False,
    approve: bool = False,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    blockers: list[str] = []
    warnings: list[str] = []
    if dry_run == approve:
        blockers.append("approval-handoff-record requires exactly one of --dry-run or --approve.")

    safe_id = safe_approval_handoff_id(handoff_id)
    if safe_id is None:
        blockers.append("handoff_id must be a safe id using letters, numbers, dot, underscore, or hyphen.")

    normalized_kind = (operation_kind or "").strip()
    if normalized_kind not in APPROVAL_HANDOFF_OPERATION_KINDS:
        blockers.append("operation_kind must be one of: " + ", ".join(APPROVAL_HANDOFF_OPERATION_KINDS) + ".")

    normalized_status = (status or "").strip().lower()
    if normalized_status not in APPROVAL_HANDOFF_STATUSES:
        blockers.append("status must be one of: " + ", ".join(APPROVAL_HANDOFF_STATUSES) + ".")

    safe_target_ref = safe_approval_handoff_scalar(target_ref, max_length=240)
    if safe_target_ref is None:
        blockers.append("target_ref must be a safe non-secret ref, not a URL, email, token, or local path.")

    safe_requested_action = safe_approval_handoff_scalar(requested_action, max_length=240)
    if safe_requested_action is None:
        blockers.append("requested_action must be a safe non-secret single-line label.")

    requester = safe_project_intake_actor_id(requested_by) if requested_by else None
    if requested_by and requester is None:
        blockers.append("requested_by must be a safe non-secret actor id.")

    reviewer = safe_project_intake_actor_id(reviewed_by) if reviewed_by else None
    if approve and reviewer is None:
        blockers.append("--approve requires a safe --reviewed-by actor id.")
    if reviewed_by and reviewer is None:
        blockers.append("reviewed_by must be a safe non-secret actor id.")

    commands: list[str] = []
    for item in related_command or []:
        safe_command = safe_approval_handoff_scalar(item, max_length=120)
        if safe_command is None:
            blockers.append("related_command values must be safe non-secret labels.")
        elif safe_command not in commands:
            commands.append(safe_command)

    releases: list[str] = []
    for item in related_release or []:
        safe_release = safe_approval_handoff_scalar(item, max_length=80)
        if safe_release is None:
            blockers.append("related_release values must be safe non-secret labels.")
        elif safe_release not in releases:
            releases.append(safe_release)

    safe_supersedes = safe_approval_handoff_id(supersedes) if supersedes else None
    if supersedes and safe_supersedes is None:
        blockers.append("supersedes must be a safe handoff id.")
    if normalized_status == "superseded" and not safe_supersedes:
        blockers.append("superseded status requires --supersedes.")

    safe_resolved_in = safe_approval_handoff_scalar(resolved_in, max_length=80) if resolved_in else None
    if resolved_in and safe_resolved_in is None:
        blockers.append("resolved_in must be a safe non-secret release or receipt label.")
    if normalized_status == "resolved" and not safe_resolved_in:
        blockers.append("resolved status requires --resolved-in.")

    now = datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace("+00:00", "Z")
    record_relative = approval_handoff_record_relative_path(safe_id or "invalid-handoff-id")
    receipt_relative = approval_handoff_receipt_relative_path(safe_id or "invalid-handoff-id", now)
    target_path = root / record_relative
    receipt_path = root / receipt_relative
    if target_path.exists() and approve:
        warnings.append("Existing approval handoff record will be replaced with the approved metadata update.")

    record = {
        "schema": APPROVAL_HANDOFF_SCHEMA,
        "handoff_id": safe_id,
        "operation_kind": normalized_kind if normalized_kind in APPROVAL_HANDOFF_OPERATION_KINDS else None,
        "target_ref": safe_target_ref,
        "requested_action": safe_requested_action,
        "status": normalized_status if normalized_status in APPROVAL_HANDOFF_STATUSES else None,
        "requested_by": requester,
        "reviewed_by": reviewer if approve else None,
        "related_commands": commands,
        "related_releases": releases,
        "supersedes": safe_supersedes,
        "resolved_in": safe_resolved_in,
        "updated_at": now,
        "operation_executed_by_this_record": False,
        "private_material_read_by_this_record": False,
        "external_provider_called_by_this_record": False,
    }
    receipt = {
        "schema": APPROVAL_HANDOFF_RECEIPT_SCHEMA,
        "dry_run": dry_run,
        "approved": approve,
        "handoff_id": safe_id,
        "record_path": record_relative,
        "operation_kind": normalized_kind if normalized_kind in APPROVAL_HANDOFF_OPERATION_KINDS else None,
        "status": normalized_status if normalized_status in APPROVAL_HANDOFF_STATUSES else None,
        "reviewed_by": reviewer if approve else None,
        "record_sha256": sha256_text(dump_yaml(record))
        if safe_id
        and safe_target_ref
        and safe_requested_action
        and normalized_kind in APPROVAL_HANDOFF_OPERATION_KINDS
        and normalized_status in APPROVAL_HANDOFF_STATUSES
        else None,
        "created_at": now,
        "closed_actions": {
            "operation_executed": False,
            "private_material_read": False,
            "provider_called": False,
            "secrets_read": False,
        },
    }

    if approve and not blockers:
        target_path.parent.mkdir(parents=True, exist_ok=True)
        receipt_path.parent.mkdir(parents=True, exist_ok=True)
        write_text_atomic(target_path, dump_yaml(json_safe(record)))
        write_text_atomic(receipt_path, json.dumps(json_safe(receipt), indent=2, ensure_ascii=False) + "\n")

    state = "blocked" if blockers else ("written" if approve else "preview")
    return {
        "ok": not blockers,
        "state": state,
        "dry_run": dry_run or not approve,
        "approved": approve and not blockers,
        "lifecycle_action": "approval_handoff_record",
        "archive_id": read_archive_id(root),
        "summary": {
            "handoff_id": safe_id,
            "operation_kind": normalized_kind if normalized_kind in APPROVAL_HANDOFF_OPERATION_KINDS else None,
            "status": normalized_status if normalized_status in APPROVAL_HANDOFF_STATUSES else None,
            "record_path": record_relative if safe_id else None,
            "receipt_path": receipt_relative if approve and not blockers else None,
            "target_ref_present": bool(safe_target_ref),
            "requested_action_present": bool(safe_requested_action),
            "related_command_count": len(commands),
            "related_release_count": len(releases),
            "operation_executed": False,
        },
        "data": {
            "record_schema": APPROVAL_HANDOFF_SCHEMA,
            "receipt_schema": APPROVAL_HANDOFF_RECEIPT_SCHEMA,
            "status_lifecycle": list(APPROVAL_HANDOFF_STATUSES),
            "operation_kinds": list(APPROVAL_HANDOFF_OPERATION_KINDS),
            "handoff_only": True,
        },
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
        "would_change": [] if approve and not blockers else ([record_relative, receipt_relative] if not blockers else []),
        "files_written": [record_relative, receipt_relative] if approve and not blockers else [],
        "privacy_guards": {
            "target_ref_value_echoed": False,
            "requested_action_value_echoed": False,
            "private_material_read": False,
            "provider_called": False,
            "network_checked": False,
            "local_absolute_paths_echoed": False,
            "tokens_or_secrets_echoed": False,
            "operation_executed": False,
            "writes": approve and not blockers,
        },
    }


def approval_handoff_audit(
    archive_root: Path | str,
    *,
    handoff_record: str | None,
    expected_operation_kind: str | None = None,
    expected_status: str = "approved_once",
    dry_run: bool = True,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    blockers: list[str] = []
    warnings: list[str] = []
    if not dry_run:
        blockers.append("approval-handoff-audit is read-only and requires --dry-run.")

    record_relative: str | None = None
    record: dict[str, Any] | None = None
    raw_record = str(handoff_record or "").strip()
    if not raw_record:
        blockers.append("handoff_record is required.")
    else:
        try:
            record_path = resolve_archive_relative_path(root, raw_record)
            record_relative = archive_relative_path(record_path, root)
        except ArchivePathError:
            blockers.append("handoff_record must be an archive-relative path inside the archive root.")
            record_path = None
        if record_relative and (
            not record_relative.startswith(f"{APPROVAL_HANDOFF_DIR}/") or not record_relative.endswith(".yml")
        ):
            blockers.append(f"handoff_record must point under {APPROVAL_HANDOFF_DIR}/ and end with .yml.")
        if record_path is not None and not record_path.is_file():
            blockers.append("approval handoff record is missing.")
        if record_path is not None and record_path.is_file() and not blockers:
            loaded = load_yaml(record_path.read_text(encoding="utf-8"))
            if not isinstance(loaded, dict):
                blockers.append("approval handoff record must be a YAML object.")
            else:
                record = json_safe(loaded)

    normalized_expected_status = (expected_status or "").strip().lower()
    if normalized_expected_status not in APPROVAL_HANDOFF_STATUSES:
        blockers.append("expected_status must be one of: " + ", ".join(APPROVAL_HANDOFF_STATUSES) + ".")
    normalized_expected_kind = (expected_operation_kind or "").strip() or None
    if normalized_expected_kind and normalized_expected_kind not in APPROVAL_HANDOFF_OPERATION_KINDS:
        blockers.append("expected_operation_kind must be one of: " + ", ".join(APPROVAL_HANDOFF_OPERATION_KINDS) + ".")

    handoff_id = None
    status = None
    operation_kind = None
    reviewed_by_present = False
    target_ref_present = False
    requested_action_present = False
    if record is not None:
        if record.get("schema") != APPROVAL_HANDOFF_SCHEMA:
            blockers.append(f"approval handoff record schema must be {APPROVAL_HANDOFF_SCHEMA}.")
        handoff_id = record.get("handoff_id") if isinstance(record.get("handoff_id"), str) else None
        status = str(record.get("status") or "")
        operation_kind = str(record.get("operation_kind") or "")
        reviewed_by_present = bool(record.get("reviewed_by"))
        target_ref_present = bool(record.get("target_ref"))
        requested_action_present = bool(record.get("requested_action"))
        if status != normalized_expected_status:
            blockers.append("approval handoff status does not match expected_status.")
        if normalized_expected_kind and operation_kind != normalized_expected_kind:
            blockers.append("approval handoff operation_kind does not match expected_operation_kind.")
        if status == "approved_once" and not reviewed_by_present:
            blockers.append("approved_once handoff requires reviewed_by.")
        if record.get("operation_executed_by_this_record") is not False:
            blockers.append("approval handoff record must not report operation execution.")
        if record.get("private_material_read_by_this_record") is not False:
            blockers.append("approval handoff record must not report private material reads.")
        if record.get("external_provider_called_by_this_record") is not False:
            blockers.append("approval handoff record must not report provider calls.")

    future_operation_authorized = not blockers and status == "approved_once"
    if status == "needs_review":
        warnings.append("The handoff still needs human review before any future operation proceeds.")
    if status == "denied":
        warnings.append("The handoff was denied; the future operation must not proceed.")
    if status == "superseded":
        warnings.append("The handoff was superseded; audit the replacement handoff before proceeding.")
    if status == "resolved":
        warnings.append("The handoff is resolved; use the closing receipt or release as the authority.")

    return {
        "ok": not blockers,
        "state": "authorized" if future_operation_authorized else ("blocked" if blockers else "not_authorized"),
        "dry_run": True,
        "lifecycle_action": "approval_handoff_audit",
        "archive_id": read_archive_id(root),
        "summary": {
            "handoff_id": handoff_id,
            "record_path": record_relative,
            "status": status or None,
            "operation_kind": operation_kind or None,
            "expected_status": normalized_expected_status if normalized_expected_status in APPROVAL_HANDOFF_STATUSES else None,
            "expected_operation_kind": normalized_expected_kind,
            "target_ref_present": target_ref_present,
            "requested_action_present": requested_action_present,
            "reviewed_by_present": reviewed_by_present,
            "future_operation_authorized": future_operation_authorized,
        },
        "data": {
            "record_schema": APPROVAL_HANDOFF_SCHEMA,
            "status_lifecycle": list(APPROVAL_HANDOFF_STATUSES),
            "operation_kinds": list(APPROVAL_HANDOFF_OPERATION_KINDS),
            "audit_only": True,
        },
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
        "would_change": [],
        "privacy_guards": {
            "handoff_record_body_read": bool(record is not None),
            "target_ref_value_echoed": False,
            "requested_action_value_echoed": False,
            "private_material_read": False,
            "provider_called": False,
            "network_checked": False,
            "local_absolute_paths_echoed": False,
            "tokens_or_secrets_echoed": False,
            "operation_executed": False,
            "writes": False,
        },
    }


def operation_status_taxonomy(archive_root: Path | str, *, dry_run: bool = True) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    blockers: list[str] = []
    if not dry_run:
        blockers.append("operation-status-taxonomy is read-only and requires --dry-run.")

    statuses = [
        {
            "status_class": "succeeded",
            "ok": True,
            "terminal": True,
            "meaning": "the requested read-only or verification operation completed fully",
            "ai_operator_rule": "it may be summarized as complete if warnings are empty or explicitly explained",
        },
        {
            "status_class": "preview",
            "ok": True,
            "terminal": False,
            "meaning": "a dry-run preview or plan completed without writing",
            "ai_operator_rule": "do not claim the planned write or external action happened",
        },
        {
            "status_class": "written",
            "ok": True,
            "terminal": True,
            "meaning": "an approval-gated local write completed and receipts should name what changed",
            "ai_operator_rule": "summarize files_written or receipt_path before saying the write is done",
        },
        {
            "status_class": "no_change",
            "ok": True,
            "terminal": True,
            "meaning": "the operation was valid but idempotent and nothing needed to change",
            "ai_operator_rule": "say no change was needed rather than implying a new write happened",
        },
        {
            "status_class": "partial",
            "ok": False,
            "terminal": False,
            "meaning": "some items completed but at least one requested item did not",
            "ai_operator_rule": "never report this as success; list incomplete counts and next safe actions",
        },
        {
            "status_class": "truncated",
            "ok": False,
            "terminal": False,
            "meaning": "the command intentionally omitted results because of limits, caps, or paging",
            "ai_operator_rule": "never report this as complete coverage; ask for a narrower scope or continue paging",
        },
        {
            "status_class": "blocked",
            "ok": False,
            "terminal": False,
            "meaning": "preconditions or safety gates stopped the operation before it could run",
            "ai_operator_rule": "surface blockers first and do not retry with broader permissions automatically",
        },
        {
            "status_class": "failed",
            "ok": False,
            "terminal": True,
            "meaning": "the command failed unexpectedly or an operation error occurred",
            "ai_operator_rule": "report the failure and preserve evidence instead of claiming a policy blocker",
        },
    ]
    return {
        "ok": not blockers,
        "state": "ready" if not blockers else "blocked",
        "dry_run": True,
        "lifecycle_action": "operation_status_taxonomy",
        "archive_id": read_archive_id(root),
        "summary": {
            "schema": OPERATION_STATUS_TAXONOMY_SCHEMA,
            "status_class_count": len(statuses),
            "failure_class_count": len(OPERATION_STATUS_FAILURE_CLASSES),
            "partial_and_truncated_are_success": False,
            "writes": False,
        },
        "data": {
            "schema": OPERATION_STATUS_TAXONOMY_SCHEMA,
            "required_envelope_fields": [
                "ok",
                "state",
                "summary",
                "data",
                "blockers",
                "warnings",
                "privacy_guards",
            ],
            "status_classes": statuses,
            "failure_classes": list(OPERATION_STATUS_FAILURE_CLASSES),
            "recommended_state_mapping": {
                "complete_and_verified": "succeeded",
                "dry_run_only": "preview",
                "approval_gated_write_done": "written",
                "idempotent": "no_change",
                "item_level_gaps": "partial",
                "limit_or_page_cap_hit": "truncated",
                "precondition_missing": "blocked",
                "unexpected_exception": "failed",
            },
            "agent_operator_checks": [
                "If ok is false, lead with blockers, incomplete counts, or truncation before any success wording.",
                "If a summary contains truncated=true, limit_hit=true, omitted_count>0, or incomplete_count>0, classify as truncated or partial even when some items were returned.",
                "If dry_run=true, do not say files were written or external actions were performed.",
                "If privacy_guards say values were not echoed, do not invent those values in the user-facing answer.",
            ],
        },
        "blockers": blockers,
        "warnings": [],
        "would_change": [],
        "privacy_guards": {
            "archive_body_text_read": False,
            "zettel_body_text_echoed": False,
            "source_values_echoed": False,
            "provider_called": False,
            "network_checked": False,
            "local_absolute_paths_echoed": False,
            "tokens_or_secrets_echoed": False,
            "writes": False,
        },
    }


def input_provenance_taxonomy(archive_root: Path | str, *, dry_run: bool = True) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    blockers: list[str] = []
    if not dry_run:
        blockers.append("input-provenance-taxonomy is read-only and requires --dry-run.")

    provenance_classes = [
        {
            "provenance_class": "tool_discovered",
            "verified_by_tool": True,
            "owner": "tool",
            "meaning": "the command discovered the input from archive metadata, an index, or a local manifest",
            "ai_operator_rule": "the AI may say the tool found the input, while still respecting privacy guards",
        },
        {
            "provenance_class": "receipt_verified",
            "verified_by_tool": True,
            "owner": "prior_receipt",
            "meaning": "the input came from a receipt that the command parsed and matched to the current archive",
            "ai_operator_rule": "cite the receipt path or hash when the command output exposes a safe reference",
        },
        {
            "provenance_class": "human_selected",
            "verified_by_tool": False,
            "owner": "human",
            "meaning": "a human selected the input, but the command may not have independently verified the target",
            "ai_operator_rule": "say the human selected it; do not claim the tool discovered it unless a receipt confirms it",
        },
        {
            "provenance_class": "caller_supplied",
            "verified_by_tool": False,
            "owner": "caller",
            "meaning": "the invoking AI, script, or shell supplied the input argument",
            "ai_operator_rule": "treat it as brittle until the command validates it against archive state or a receipt",
        },
        {
            "provenance_class": "ai_generated",
            "verified_by_tool": False,
            "owner": "ai",
            "meaning": "an AI generated the input label, path, identifier, or mapping",
            "ai_operator_rule": "never treat it as source truth without a validation command or human correction event",
        },
        {
            "provenance_class": "fixture_supplied",
            "verified_by_tool": False,
            "owner": "test_fixture",
            "meaning": "the input came from a local fixture or sanitized sample",
            "ai_operator_rule": "do not generalize fixture success to live provider or full archive coverage",
        },
        {
            "provenance_class": "environment_inferred",
            "verified_by_tool": False,
            "owner": "runtime_environment",
            "meaning": "the input was inferred from cwd, environment variables, path conventions, or local defaults",
            "ai_operator_rule": "re-check explicit archive roots, accounts, and release state before writing or publishing",
        },
        {
            "provenance_class": "unknown",
            "verified_by_tool": False,
            "owner": "unknown",
            "meaning": "the command cannot tell where the input came from",
            "ai_operator_rule": "do not claim provenance; ask for or generate a receipt-backed validation step",
        },
    ]

    return {
        "ok": not blockers,
        "state": "ready" if not blockers else "blocked",
        "dry_run": True,
        "lifecycle_action": "input_provenance_taxonomy",
        "archive_id": read_archive_id(root),
        "summary": {
            "schema": INPUT_PROVENANCE_TAXONOMY_SCHEMA,
            "provenance_class_count": len(provenance_classes),
            "unverified_class_count": len(INPUT_PROVENANCE_UNVERIFIED_CLASSES),
            "caller_supplied_is_verified": False,
            "writes": False,
        },
        "data": {
            "schema": INPUT_PROVENANCE_TAXONOMY_SCHEMA,
            "provenance_classes": provenance_classes,
            "unverified_classes": list(INPUT_PROVENANCE_UNVERIFIED_CLASSES),
            "recommended_fields_for_future_commands": [
                "input_provenance",
                "input_provenance_class",
                "input_verified_by_tool",
                "source_receipt_path",
                "source_receipt_sha256",
                "caller_supplied_fields",
            ],
            "agent_operator_checks": [
                "If an input is caller_supplied, say it was supplied to the command, not discovered by the command.",
                "If an input is ai_generated, require validation before minting, linking, fetching, or publishing.",
                "If an input is fixture_supplied, do not claim live provider coverage.",
                "If provenance is unknown, add a validation or receipt step before treating it as canonical.",
            ],
        },
        "blockers": blockers,
        "warnings": [],
        "would_change": [],
        "privacy_guards": {
            "archive_body_text_read": False,
            "zettel_body_text_echoed": False,
            "input_values_echoed": False,
            "source_values_echoed": False,
            "provider_called": False,
            "network_checked": False,
            "local_absolute_paths_echoed": False,
            "tokens_or_secrets_echoed": False,
            "writes": False,
        },
    }


def secret_signal_taxonomy(archive_root: Path | str, *, dry_run: bool = True) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    blockers: list[str] = []
    if not dry_run:
        blockers.append("secret-signal-taxonomy is read-only and requires --dry-run.")

    signal_classes = [
        {
            "signal_class": "concept_word",
            "blocking": False,
            "meaning": "a documentation or schema word such as secret, token, credential, password, or key",
            "ai_operator_rule": "do not treat a concept word as a leaked value by itself",
        },
        {
            "signal_class": "safe_reference",
            "blocking": False,
            "meaning": "a non-secret label that points to a vault, OS store, approval receipt, or future adapter",
            "ai_operator_rule": "safe refs may be shown when the command explicitly marks them safe",
        },
        {
            "signal_class": "credential_reference",
            "blocking": False,
            "meaning": "a structured reference such as secret:ref, credential id, or vault entry label without the value",
            "ai_operator_rule": "do not resolve or echo the actual secret value; keep it as an indirection",
        },
        {
            "signal_class": "secret_value_pattern",
            "blocking": True,
            "meaning": "a value-shaped token, API key, password, private key block, session cookie, or high-entropy bearer string",
            "ai_operator_rule": "block echoing, record only non-reversible fingerprints or safe receipt metadata when needed",
        },
        {
            "signal_class": "private_locator",
            "blocking": True,
            "meaning": "a local absolute path, provider locator, private file URL, or object location that exposes where private material lives",
            "ai_operator_rule": "do not echo; replace with durable WOM refs, manifests, object ids, or redacted summaries",
        },
        {
            "signal_class": "account_identifier",
            "blocking": True,
            "meaning": "an email address, account id, org id, tenant id, or provider profile that can identify a private account",
            "ai_operator_rule": "do not expose in public outputs unless an explicit public-safe policy says it is allowed",
        },
        {
            "signal_class": "unknown_sensitive_context",
            "blocking": True,
            "meaning": "text appears near auth, provider, mailbox, credential, or private-material context but is not classified safely",
            "ai_operator_rule": "fail closed and ask for a safer ref or approval receipt instead of guessing",
        },
    ]

    return {
        "ok": not blockers,
        "state": "ready" if not blockers else "blocked",
        "dry_run": True,
        "lifecycle_action": "secret_signal_taxonomy",
        "archive_id": read_archive_id(root),
        "summary": {
            "schema": SECRET_SIGNAL_TAXONOMY_SCHEMA,
            "signal_class_count": len(signal_classes),
            "blocking_class_count": len(SECRET_SIGNAL_BLOCKING_CLASSES),
            "concept_words_are_secret_values": False,
            "writes": False,
        },
        "data": {
            "schema": SECRET_SIGNAL_TAXONOMY_SCHEMA,
            "signal_classes": signal_classes,
            "blocking_classes": list(SECRET_SIGNAL_BLOCKING_CLASSES),
            "recommended_fields_for_future_commands": [
                "secret_signal_class",
                "secret_value_echoed",
                "safe_reference_echoed",
                "private_locator_echoed",
                "account_identifier_echoed",
            ],
            "agent_operator_checks": [
                "Do not flag concept words alone as leaked secret values.",
                "Block value-shaped tokens, private locators, and account identifiers in public outputs.",
                "Prefer safe refs, object ids, receipt paths, or non-reversible fingerprints over secret values.",
                "When context is ambiguous and sensitive, fail closed and request a safer reference.",
            ],
        },
        "blockers": blockers,
        "warnings": [],
        "would_change": [],
        "privacy_guards": {
            "archive_body_text_read": False,
            "sample_values_read": False,
            "sample_values_echoed": False,
            "provider_called": False,
            "network_checked": False,
            "local_absolute_paths_echoed": False,
            "tokens_or_secrets_echoed": False,
            "writes": False,
        },
    }


def ai_response_contract(archive_root: Path | str, *, dry_run: bool = True) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    blockers: list[str] = []
    if not dry_run:
        blockers.append("ai-response-contract is read-only and requires --dry-run.")

    response_sections = [
        {
            "section": "operation_outcome",
            "required": True,
            "operator_rule": "classify the result before saying work is complete",
            "safe_status_classes": ["succeeded", "preview", "written", "no_change"],
            "not_success_status_classes": ["partial", "truncated", "blocked", "failed"],
        },
        {
            "section": "evidence_basis",
            "required": True,
            "operator_rule": "name whether evidence came from command output, a receipt, a release, a tag, or a caller-supplied input",
            "source_truth_rule": "do not describe caller-supplied or AI-generated values as tool-discovered source truth",
        },
        {
            "section": "privacy_boundary",
            "required": True,
            "operator_rule": "do not echo secret-like values, private locators, account identifiers, local absolute paths, tokens, or secret values",
            "safe_alternatives": ["safe refs", "archive-relative refs", "object ids", "receipt paths", "non-reversible fingerprints"],
        },
        {
            "section": "approval_boundary",
            "required": True,
            "operator_rule": "only claim writes, live fetches, uploads, external actions, or privileged execution after explicit approval and receipt evidence",
        },
        {
            "section": "remaining_work",
            "required": True,
            "operator_rule": "surface blockers, warnings, incomplete coverage, and next safe action instead of burying them in a summary",
        },
        {
            "section": "conversation_status_board",
            "required": False,
            "operator_rule": "a compact conversational status board is allowed; a web UI is not required",
            "web_ui_required": False,
        },
    ]

    return {
        "ok": not blockers,
        "state": "ready" if not blockers else "blocked",
        "dry_run": True,
        "lifecycle_action": "ai_response_contract",
        "archive_id": read_archive_id(root),
        "summary": {
            "schema": AI_RESPONSE_CONTRACT_SCHEMA,
            "required_section_count": sum(1 for item in response_sections if item.get("required")),
            "optional_section_count": sum(1 for item in response_sections if not item.get("required")),
            "conversation_status_board_allowed": True,
            "web_ui_required": False,
            "writes": False,
        },
        "data": {
            "schema": AI_RESPONSE_CONTRACT_SCHEMA,
            "taxonomy_dependencies": [
                "operation-status-taxonomy",
                "input-provenance-taxonomy",
                "secret-signal-taxonomy",
                "approval-handoff-audit",
                "status-board",
            ],
            "minimum_result_fields_to_check": [
                "ok",
                "state",
                "summary",
                "blockers",
                "warnings",
                "privacy_guards",
                "would_change",
                "files_written",
                "receipt_path",
            ],
            "response_sections": response_sections,
            "must_not_claim": [
                "partial, truncated, blocked, or failed results are complete",
                "caller-supplied input was discovered or verified by the tool",
                "a dry-run preview performed a write or live external action",
                "a future adapter boundary has already executed",
                "secret concept words are leaked secret values by themselves",
            ],
            "recommended_answer_order": [
                "outcome",
                "evidence",
                "privacy/approval boundary",
                "remaining blockers or next safe action",
            ],
        },
        "blockers": blockers,
        "warnings": [],
        "would_change": [],
        "privacy_guards": {
            "archive_body_text_read": False,
            "zettel_body_text_echoed": False,
            "source_values_echoed": False,
            "sample_values_read": False,
            "sample_values_echoed": False,
            "provider_called": False,
            "network_checked": False,
            "local_absolute_paths_echoed": False,
            "tokens_or_secrets_echoed": False,
            "writes": False,
        },
    }


def zettel_summary(path: Path, archive_root: Path, expected_status: str) -> dict[str, Any]:
    frontmatter, _body = split_zettel_text(path.read_text(encoding="utf-8"))
    frontmatter = json_safe(frontmatter)
    if frontmatter.get("status") == "redacted":
        # Privacy: a redacted zettel still appears in listings (so its existence is known), but its
        # content-bearing fields (title/kind/facets/visibility) are suppressed.
        return {
            "path": archive_relative_path(path, archive_root),
            "id": frontmatter.get("id"),
            "title": None,
            "status": "redacted",
            "kind": None,
            "created_at": frontmatter.get("created_at"),
            "updated_at": frontmatter.get("updated_at"),
            "facets": {},
            "visibility": {},
            "redacted": True,
        }
    return {
        "path": archive_relative_path(path, archive_root),
        "id": frontmatter.get("id"),
        "title": frontmatter.get("title"),
        "status": frontmatter.get("status", expected_status),
        "kind": frontmatter.get("kind"),
        "created_at": frontmatter.get("created_at"),
        "updated_at": frontmatter.get("updated_at"),
        "facets": frontmatter.get("facets", {}),
        "visibility": frontmatter.get("visibility", {}),
    }


def compact_zettel_overview_text(value: str, *, max_chars: int = ZETTEL_OVERVIEW_GIST_CHAR_LIMIT) -> str:
    text = re.sub(r"\s+", " ", value).strip()
    if len(text) <= max_chars:
        return text
    return text[: max_chars - 3].rstrip() + "..."


def safe_zettel_overview_string(value: Any, warnings: list[str], field_path: str) -> str | None:
    if value is None:
        return None
    text = compact_zettel_overview_text(str(value))
    if not text:
        return None
    if header_string_is_private_or_unsafe(text) or source_intake_has_provider_url(text) or source_intake_secret_like(text):
        warnings.append(f"Redacted private or unsafe first-read value in {field_path}.")
        return None
    return text


def markdown_body_overview_candidates(body: str) -> list[str]:
    candidates: list[str] = []
    in_fence = False
    current: list[str] = []
    for raw_line in normalize_text_for_block_hash(body).splitlines():
        stripped = raw_line.strip()
        if stripped.startswith("```") or stripped.startswith("~~~"):
            in_fence = not in_fence
            continue
        if in_fence:
            continue
        if not stripped:
            if current:
                candidates.append(" ".join(current))
                current = []
            continue
        if stripped.startswith("#"):
            continue
        if stripped.startswith(("|", ">", "![", "<")):
            continue
        cleaned = re.sub(r"^\s*[-*+]\s+", "", stripped)
        cleaned = re.sub(r"^\s*\d+[.)]\s+", "", cleaned)
        cleaned = re.sub(r"`([^`]+)`", r"\1", cleaned)
        cleaned = re.sub(r"\[([^\]]+)\]\([^)]+\)", r"\1", cleaned)
        if cleaned:
            current.append(cleaned)
    if current:
        candidates.append(" ".join(current))
    return candidates


def zettel_gist(frontmatter: dict[str, Any], body: str, warnings: list[str]) -> tuple[str | None, str]:
    for field in ZETTEL_OVERVIEW_FRONTMATTER_FIELDS:
        value = frontmatter.get(field)
        if isinstance(value, str):
            gist = safe_zettel_overview_string(value, warnings, f"$.frontmatter.{field}")
            if gist:
                return gist, f"frontmatter.{field}"
    for paragraph in markdown_body_overview_candidates(body):
        gist = safe_zettel_overview_string(paragraph, warnings, "$.body")
        if gist:
            return gist, "body.first_safe_paragraph"
    return None, "unavailable"


def safe_overview_facets(frontmatter: dict[str, Any], warnings: list[str]) -> dict[str, Any]:
    facets = frontmatter.get("facets")
    if not isinstance(facets, dict):
        return {}
    sanitized = sanitize_block_header_value(facets, warnings, "$.first_read.facets")
    return sanitized if isinstance(sanitized, dict) else {}


def safe_overview_edge_preview(edge: dict[str, Any], warnings: list[str], index: int) -> dict[str, Any]:
    edge_type = safe_zettel_overview_string(edge.get("type"), warnings, f"$.first_read.edges_preview[{index}].type")
    target = safe_zettel_overview_string(edge.get("target") or edge.get("zettel_id") or edge.get("target_id"), warnings, f"$.first_read.edges_preview[{index}].target")
    if target is None and any(edge.get(key) for key in ("target", "zettel_id", "target_id")):
        target = "<redacted-reference>"
    target_kind = None
    if isinstance(target, str):
        if target.startswith("zet_"):
            target_kind = "zettel"
        elif target.startswith("objet:sha256:") or target.startswith("sha256:"):
            target_kind = "objet"
    return drop_none_values({"type": edge_type, "target": target, "target_kind": target_kind})


def zettel_first_read_summary(frontmatter: dict[str, Any], body: str, *, redacted: bool = False) -> tuple[dict[str, Any], list[str]]:
    warnings: list[str] = []
    zettel_id = frontmatter.get("id")
    status = frontmatter.get("status")
    if redacted:
        return (
            {
                "zettel_id": zettel_id,
                "title": None,
                "status": "redacted",
                "kind": None,
                "gist": None,
                "gist_source": "redacted",
                "gist_char_limit": ZETTEL_OVERVIEW_GIST_CHAR_LIMIT,
                "facets": {},
                "tie_summary": {
                    "edge_count": 0,
                    "edge_types": [],
                    "referenced_zets_count": 0,
                    "referenced_objets_count": 0,
                    "referenced_receipts_count": 0,
                },
                "edges_preview": [],
                "redacted": True,
                "body_omitted": True,
            },
            warnings,
        )

    title = safe_zettel_overview_string(frontmatter.get("title"), warnings, "$.frontmatter.title")
    kind = safe_zettel_overview_string(frontmatter.get("kind"), warnings, "$.frontmatter.kind")
    gist, gist_source = zettel_gist(frontmatter, body, warnings)
    edges = frontmatter.get("edges") if isinstance(frontmatter.get("edges"), list) else []
    edge_dicts = [edge for edge in edges if isinstance(edge, dict)]
    edge_types = sorted(
        {
            str(edge.get("type")).strip()
            for edge in edge_dicts
            if edge.get("type") and not header_string_is_private_or_unsafe(str(edge.get("type")))
        }
    )
    referenced_zets = collect_referenced_zets(frontmatter)
    referenced_objets = collect_referenced_objets(frontmatter)
    referenced_receipts = collect_referenced_receipts(frontmatter)
    return (
        {
            "zettel_id": zettel_id,
            "title": title,
            "status": status,
            "kind": kind,
            "gist": gist,
            "gist_source": gist_source,
            "gist_char_limit": ZETTEL_OVERVIEW_GIST_CHAR_LIMIT,
            "facets": safe_overview_facets(frontmatter, warnings),
            "tie_summary": {
                "edge_count": len(edge_dicts),
                "edge_types": edge_types,
                "referenced_zets_count": len(referenced_zets),
                "referenced_objets_count": len(referenced_objets),
                "referenced_receipts_count": len(referenced_receipts),
            },
            "edges_preview": [safe_overview_edge_preview(edge, warnings, index) for index, edge in enumerate(edge_dicts[:10])],
            "redacted": False,
            "body_omitted": True,
        },
        warnings,
    )


def zettel_overview_frontmatter(frontmatter: dict[str, Any]) -> dict[str, Any]:
    return {
        "id": frontmatter.get("id"),
        "title": frontmatter.get("title"),
        "status": frontmatter.get("status"),
        "kind": frontmatter.get("kind"),
        "created_at": frontmatter.get("created_at"),
        "updated_at": frontmatter.get("updated_at"),
        "facets": frontmatter.get("facets") if isinstance(frontmatter.get("facets"), dict) else {},
        "visibility": frontmatter.get("visibility") if isinstance(frontmatter.get("visibility"), dict) else {},
    }


def read_zettel(
    archive_root: Path | str,
    *,
    zettel_id: str | None = None,
    relative_path: str | None = None,
    section: str = "body",
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    if not zettel_id and not relative_path:
        raise ArchiveServiceError("Provide zettel_id or path.")
    if section not in ZETTEL_READ_SECTIONS:
        raise ArchiveServiceError("section must be one of: overview, body, details, all")

    path = resolve_zettel_path(root, zettel_id=zettel_id, relative_path=relative_path)
    frontmatter, body = split_zettel_text(path.read_text(encoding="utf-8"))
    frontmatter = json_safe(frontmatter)
    if frontmatter.get("status") == "redacted":
        # Privacy: a redacted zettel's body and frontmatter are suppressed on read; only its id and
        # redacted status are returned so callers can see it exists without exposing the content.
        overview, overview_warnings = zettel_first_read_summary(frontmatter, "", redacted=True)
        return {
            "path": archive_relative_path(path, root),
            "frontmatter": {"id": frontmatter.get("id"), "status": "redacted"},
            "body": "",
            "section": section,
            "overview": overview,
            "redacted": True,
            "warnings": overview_warnings,
        }
    overview, overview_warnings = zettel_first_read_summary(frontmatter, body)
    include_body = section in {"body", "all"}
    include_full_frontmatter = section in {"body", "details", "all"}
    return {
        "path": archive_relative_path(path, root),
        "frontmatter": frontmatter if include_full_frontmatter else zettel_overview_frontmatter(frontmatter),
        "body": body if include_body else "",
        "section": section,
        "overview": overview,
        "body_omitted": not include_body,
        "details_omitted": not include_full_frontmatter,
        "redacted": False,
        "warnings": unique_preserve_order(overview_warnings),
    }


def objet_ref_occurrences_in_text(text: str, *, source: str, field: str | None = None) -> list[dict[str, Any]]:
    occurrences: list[dict[str, Any]] = []
    for line_number, line in enumerate(text.splitlines(), start=1):
        for match in OBJET_REF_TOKEN_RE.finditer(line):
            digest = match.group("digest").lower()
            occurrences.append(
                {
                    "source": source,
                    "line": line_number,
                    "field": field,
                    "token_kind": "objet_ref" if match.group("prefix") else "object_id",
                    "object_id": f"sha256:{digest}",
                }
            )
    return occurrences


def safe_objet_ref_field_segment(value: Any) -> str:
    text = str(value).strip()
    if not text:
        return "field"
    if contains_forbidden_location_reference(text) or source_intake_has_provider_url(text) or source_intake_secret_like(text):
        return "redacted_field"
    sanitized = re.sub(r"[^A-Za-z0-9_-]+", "_", text).strip("_")
    return sanitized[:80] if sanitized else "field"


def objet_ref_occurrences_in_value(value: Any, *, field: str) -> list[dict[str, Any]]:
    if isinstance(value, dict):
        occurrences: list[dict[str, Any]] = []
        for key, child in value.items():
            key_text = safe_objet_ref_field_segment(key)
            child_field = f"{field}.{key_text}" if field else key_text
            occurrences.extend(objet_ref_occurrences_in_value(child, field=child_field))
        return occurrences
    if isinstance(value, list):
        occurrences = []
        for index, child in enumerate(value):
            child_field = f"{field}[{index}]"
            occurrences.extend(objet_ref_occurrences_in_value(child, field=child_field))
        return occurrences
    if isinstance(value, str):
        return objet_ref_occurrences_in_text(value, source="frontmatter", field=field)
    return []


def zettel_objet_links(
    archive_root: Path | str,
    *,
    zettel_id: str | None = None,
    relative_path: str | None = None,
    dry_run: bool = True,
    max_refs: int = 100,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []
    if not dry_run:
        blockers.append("zettel-objet-links is read-only; pass --dry-run.")
    if not zettel_id and not relative_path:
        blockers.append("Provide zettel_id or path.")
        return {
            "ok": False,
            "dry_run": True,
            "lifecycle_action": "zettel_objet_links",
            "archive_id": archive_id,
            "zettel": {"path": None, "redacted": False},
            "count": 0,
            "links": [],
            "truncated": False,
            "privacy_guards": {
                "body_text_echoed": False,
                "frontmatter_values_echoed": False,
                "absolute_local_paths_echoed": False,
                "provider_urls_echoed": False,
                "provider_api_called": False,
                "presigned_url_created": False,
                "download_performed": False,
                "object_file_bytes_read": False,
                "object_file_hash_verified_now": False,
                "writes": False,
            },
            "would_change": [],
            "next_safe_actions": ["Fix blockers before rendering objet links."],
            "blockers": unique_preserve_order(blockers),
            "warnings": unique_preserve_order(warnings),
        }

    path = resolve_zettel_path(root, zettel_id=zettel_id, relative_path=relative_path)
    text = path.read_text(encoding="utf-8")
    frontmatter, body = split_zettel_text(text)
    safe_frontmatter = json_safe(frontmatter)
    zettel_summary_value = {
        "path": archive_relative_path(path, root),
        "redacted": safe_frontmatter.get("status") == "redacted",
    }
    if safe_frontmatter.get("status") == "redacted":
        blockers.append("zettel_is_redacted")
        return {
            "ok": False,
            "dry_run": True,
            "lifecycle_action": "zettel_objet_links",
            "archive_id": archive_id,
            "zettel": zettel_summary_value,
            "count": 0,
            "links": [],
            "truncated": False,
            "privacy_guards": {
                "body_text_echoed": False,
                "frontmatter_values_echoed": False,
                "absolute_local_paths_echoed": False,
                "provider_urls_echoed": False,
                "provider_api_called": False,
                "presigned_url_created": False,
                "download_performed": False,
                "object_file_bytes_read": False,
                "object_file_hash_verified_now": False,
                "writes": False,
            },
            "would_change": [],
            "next_safe_actions": ["Redacted zettels do not expose objet link previews."],
            "blockers": unique_preserve_order(blockers),
            "warnings": unique_preserve_order(warnings),
        }

    max_refs = max(1, min(int(max_refs), 500))
    occurrences: list[dict[str, Any]] = []
    occurrences.extend(objet_ref_occurrences_in_value(safe_frontmatter, field="frontmatter"))
    occurrences.extend(objet_ref_occurrences_in_text(body, source="body"))

    grouped: dict[str, list[dict[str, Any]]] = {}
    order: list[str] = []
    for occurrence in occurrences:
        object_id_value = str(occurrence.get("object_id") or "")
        if object_id_value not in grouped:
            grouped[object_id_value] = []
            order.append(object_id_value)
        grouped[object_id_value].append(occurrence)

    truncated = len(order) > max_refs
    links: list[dict[str, Any]] = []
    for object_id_value in order[:max_refs]:
        object_occurrences = grouped[object_id_value]
        resolution = resolve_objet_ref(root, object_id=object_id_value, dry_run=True)
        link_candidates: list[dict[str, Any]] = []
        for candidate in resolution.get("local_candidates", []):
            if not isinstance(candidate, dict):
                continue
            link_candidates.append(
                {
                    "kind": "archive_relative_path",
                    "label": "local archive candidate",
                    "archive_relative_path": candidate.get("archive_relative_path"),
                    "exists": bool(candidate.get("exists")),
                    "availability": candidate.get("availability"),
                    "clickable_in_local_client": bool(candidate.get("exists")),
                    "href_kind": "archive_relative",
                }
            )
        for candidate in resolution.get("external_candidates", []):
            if not isinstance(candidate, dict):
                continue
            link_candidates.append(
                {
                    "kind": "external_store_label",
                    "label": "manual external store label",
                    "provider": candidate.get("provider"),
                    "store_kind": candidate.get("store_kind"),
                    "store_ref": candidate.get("store_ref"),
                    "availability": candidate.get("availability"),
                    "clickable_in_local_client": False,
                    "href_kind": "label_only",
                }
            )
        links.append(
            {
                "object_id": object_id_value,
                "occurrence_count": len(object_occurrences),
                "occurrences": [
                    {
                        "source": occurrence.get("source"),
                        "line": occurrence.get("line"),
                        "field": occurrence.get("field"),
                        "token_kind": occurrence.get("token_kind"),
                    }
                    for occurrence in object_occurrences[:10]
                ],
                "occurrences_truncated": len(object_occurrences) > 10,
                "resolution_state": resolution.get("resolution_state"),
                "resolution_ok": bool(resolution.get("ok")),
                "manifest_record_count": resolution.get("manifest_record_count"),
                "local_openable": bool(resolution.get("local_openable")),
                "external_declared": bool(resolution.get("external_declared")),
                "link_candidates": link_candidates,
                "resolver_blockers": resolution.get("blockers", []),
                "resolver_warnings": resolution.get("warnings", []),
                "command_hints": [
                    f"archive resolve-objet-ref <archive-root> --object-id {object_id_value} --dry-run"
                ],
            }
        )

    if truncated:
        warnings.append("objet_ref_link_preview_truncated")

    next_safe_actions: list[str] = []
    if links:
        next_safe_actions.append("Render local archive-relative candidates as local-client links when they exist.")
        next_safe_actions.append("Keep external store labels non-clickable until an explicit provider URL policy exists.")
    else:
        next_safe_actions.append("No objet refs were found in this zettel.")
    if blockers:
        next_safe_actions.append("Fix blockers before rendering objet links.")

    return {
        "ok": not blockers,
        "dry_run": True,
        "lifecycle_action": "zettel_objet_links",
        "archive_id": archive_id,
        "zettel": zettel_summary_value,
        "count": len(links),
        "links": links,
        "truncated": truncated,
        "privacy_guards": {
            "body_text_echoed": False,
            "frontmatter_values_echoed": False,
            "absolute_local_paths_echoed": False,
            "provider_urls_echoed": False,
            "provider_api_called": False,
            "presigned_url_created": False,
            "download_performed": False,
            "object_file_bytes_read": False,
            "object_file_hash_verified_now": False,
            "writes": False,
        },
        "would_change": [],
        "next_safe_actions": next_safe_actions,
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }


def normalize_notion_provider_locator(value: str) -> str:
    text = str(value or "").strip()
    text = text.rstrip(".,;")
    if text.endswith("&quot;"):
        text = text[:-6]
    if text.endswith("&gt;"):
        text = text[:-4]
    return text.lower()


def notion_provider_locator_fingerprint(locator: str) -> str:
    return "sha256:" + hashlib.sha256(normalize_notion_provider_locator(locator).encode("utf-8")).hexdigest()


def notion_provider_locator_occurrences_in_text(
    text: str,
    *,
    source: str,
    field: str | None = None,
) -> list[dict[str, Any]]:
    occurrences: list[dict[str, Any]] = []
    for line_number, line in enumerate(text.splitlines(), start=1):
        for match in NOTION_PROVIDER_LOCATOR_RE.finditer(line):
            normalized = normalize_notion_provider_locator(match.group(0))
            if not normalized:
                continue
            lower_line = line.lower()
            if "<mention-page" in lower_line:
                context_kind = "notion_mention_page_marker"
            elif "embed" in lower_line or "<file" in lower_line:
                context_kind = "notion_embed_or_file_marker"
            else:
                context_kind = "notion_provider_locator"
            occurrences.append(
                drop_none_values(
                    {
                        "source": source,
                        "line": line_number,
                        "field": field,
                        "locator_kind": context_kind,
                        "locator_fingerprint": notion_provider_locator_fingerprint(normalized),
                        "_normalized_locator": normalized,
                    }
                )
            )
    return occurrences


def notion_provider_locator_occurrences_in_value(value: Any, *, field: str) -> list[dict[str, Any]]:
    if isinstance(value, dict):
        occurrences: list[dict[str, Any]] = []
        for key, child in value.items():
            key_text = safe_objet_ref_field_segment(key)
            child_field = f"{field}.{key_text}" if field else key_text
            occurrences.extend(notion_provider_locator_occurrences_in_value(child, field=child_field))
        return occurrences
    if isinstance(value, list):
        occurrences = []
        for index, child in enumerate(value):
            child_field = f"{field}[{index}]"
            occurrences.extend(notion_provider_locator_occurrences_in_value(child, field=child_field))
        return occurrences
    if isinstance(value, str):
        return notion_provider_locator_occurrences_in_text(value, source="frontmatter", field=field)
    return []


def safe_manifest_label(value: Any, *, fallback: str | None = None) -> str | None:
    if value is None:
        return fallback
    text = str(value).strip()
    if not text:
        return fallback
    if contains_forbidden_location_reference(text) or source_intake_has_provider_url(text) or source_intake_secret_like(text):
        return fallback
    return text


def manifest_record_has_notion_store_label(record: dict[str, Any]) -> bool:
    labels: list[str] = []
    provenance = record.get("provenance") if isinstance(record.get("provenance"), dict) else {}
    for value in (
        record.get("store_kind"),
        record.get("store_ref"),
        record.get("logical_key"),
        provenance.get("source"),
        provenance.get("store_kind"),
        provenance.get("store_ref"),
    ):
        if isinstance(value, str):
            labels.append(value.lower())
    locations = record.get("locations") if isinstance(record.get("locations"), list) else []
    for location in locations:
        if not isinstance(location, dict):
            continue
        for key in ("provider", "store_kind", "store_ref"):
            value = location.get(key)
            if isinstance(value, str):
                labels.append(value.lower())
    return any("notion" in label for label in labels)


def notion_manifest_store_labels(record: dict[str, Any]) -> list[dict[str, Any]]:
    labels: list[dict[str, Any]] = []
    locations = record.get("locations") if isinstance(record.get("locations"), list) else []
    for location in locations:
        if not isinstance(location, dict):
            continue
        labels.append(
            drop_none_values(
                {
                    "provider": safe_manifest_label(location.get("provider"), fallback="redacted_provider"),
                    "store_kind": safe_manifest_label(location.get("store_kind"), fallback="redacted_store_kind"),
                    "store_ref": safe_manifest_label(location.get("store_ref"), fallback="redacted_store_ref"),
                    "availability": safe_manifest_label(location.get("availability"), fallback="unknown"),
                    "content_addressed": bool(location.get("content_addressed")),
                    "byte_verification_by_wom_kit": bool(location.get("byte_verification_by_wom_kit")),
                }
            )
        )
    return labels


def notion_locator_manifest_match_fields(
    value: Any,
    *,
    normalized_locator: str,
    locator_fingerprint: str,
    field: str = "$",
) -> list[dict[str, str]]:
    matches: list[dict[str, str]] = []
    fingerprint_hex = locator_fingerprint.removeprefix("sha256:")
    if isinstance(value, dict):
        for key, child in value.items():
            key_text = safe_objet_ref_field_segment(key)
            child_field = f"{field}.{key_text}" if field != "$" else f"$.{key_text}"
            matches.extend(
                notion_locator_manifest_match_fields(
                    child,
                    normalized_locator=normalized_locator,
                    locator_fingerprint=locator_fingerprint,
                    field=child_field,
                )
            )
        return matches
    if isinstance(value, list):
        for index, child in enumerate(value):
            matches.extend(
                notion_locator_manifest_match_fields(
                    child,
                    normalized_locator=normalized_locator,
                    locator_fingerprint=locator_fingerprint,
                    field=f"{field}[{index}]",
                )
            )
        return matches
    if isinstance(value, str):
        text = value.strip()
        normalized_text = normalize_notion_provider_locator(text)
        if normalized_locator and normalized_locator in normalized_text:
            matches.append({"field": field, "match_kind": "exact_locator_redacted"})
        elif text.lower() in {locator_fingerprint, fingerprint_hex}:
            matches.append({"field": field, "match_kind": "locator_fingerprint"})
    return matches


def group_notion_provider_locator_occurrences(
    occurrences: list[dict[str, Any]],
) -> tuple[dict[str, list[dict[str, Any]]], dict[str, str], list[str]]:
    grouped: dict[str, list[dict[str, Any]]] = {}
    normalized_by_fingerprint: dict[str, str] = {}
    order: list[str] = []
    for occurrence in occurrences:
        fingerprint = str(occurrence.get("locator_fingerprint") or "")
        if not fingerprint:
            continue
        if fingerprint not in grouped:
            grouped[fingerprint] = []
            order.append(fingerprint)
        grouped[fingerprint].append(occurrence)
        normalized = str(occurrence.get("_normalized_locator") or "")
        if normalized:
            normalized_by_fingerprint.setdefault(fingerprint, normalized)
    return grouped, normalized_by_fingerprint, order


def notion_locator_candidate_entries(
    root: Path,
    manifest_records: list[dict[str, Any]],
    *,
    normalized_locator: str,
    locator_fingerprint: str,
    max_candidates: int,
) -> list[dict[str, Any]]:
    candidates: list[dict[str, Any]] = []
    for record in manifest_records:
        if not isinstance(record, dict):
            continue
        match_fields = notion_locator_manifest_match_fields(
            record,
            normalized_locator=normalized_locator,
            locator_fingerprint=locator_fingerprint,
        )
        if not match_fields:
            continue
        object_id_value = str(record.get("object_id") or "")
        candidate_blockers: list[str] = []
        normalized_object_id = normalize_object_id(object_id_value, candidate_blockers)
        resolution = resolve_objet_ref(root, object_id=normalized_object_id, dry_run=True) if normalized_object_id else {}
        candidates.append(
            {
                "object_id": normalized_object_id or None,
                "match_fields": match_fields[:10],
                "match_fields_truncated": len(match_fields) > 10,
                "store_labels": notion_manifest_store_labels(record),
                "resolution_state": resolution.get("resolution_state"),
                "manifest_record_count": resolution.get("manifest_record_count"),
                "local_openable": bool(resolution.get("local_openable")),
                "external_declared": bool(resolution.get("external_declared")),
                "suggested_objet_ref": f"objet:{normalized_object_id}" if normalized_object_id else None,
                "candidate_blockers": unique_preserve_order(candidate_blockers),
            }
        )
        if len(candidates) >= max_candidates:
            break
    return candidates


def notion_objet_link_plan(
    archive_root: Path | str,
    *,
    zettel_id: str | None = None,
    relative_path: str | None = None,
    dry_run: bool = True,
    max_locators: int = 100,
    max_candidates: int = 20,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []
    if not dry_run:
        blockers.append("notion-objet-link-plan is read-only; pass --dry-run.")
    if not zettel_id and not relative_path:
        blockers.append("Provide zettel_id or path.")
        return {
            "ok": False,
            "dry_run": True,
            "lifecycle_action": "notion_objet_link_plan",
            "archive_id": archive_id,
            "zettel": {"path": None, "redacted": False},
            "locator_count": 0,
            "locators": [],
            "manifest_summary": {"manifest_path": "objects/manifests/files.jsonl", "record_count": 0, "notion_labeled_record_count": 0},
            "truncated": False,
            "privacy_guards": {
                "provider_urls_echoed": False,
                "zettel_body_text_echoed": False,
                "frontmatter_values_echoed": False,
                "absolute_local_paths_echoed": False,
                "provider_api_called": False,
                "presigned_url_created": False,
                "download_performed": False,
                "object_file_bytes_read": False,
                "writes": False,
            },
            "would_change": [],
            "next_safe_actions": ["Fix blockers before planning Notion locator to objet links."],
            "blockers": unique_preserve_order(blockers),
            "warnings": unique_preserve_order(warnings),
        }

    path = resolve_zettel_path(root, zettel_id=zettel_id, relative_path=relative_path)
    text = path.read_text(encoding="utf-8")
    frontmatter, body = split_zettel_text(text)
    safe_frontmatter = json_safe(frontmatter)
    zettel_summary_value = {
        "path": archive_relative_path(path, root),
        "redacted": safe_frontmatter.get("status") == "redacted",
    }
    if isinstance(safe_frontmatter.get("id"), str):
        zettel_summary_value["id"] = safe_frontmatter.get("id")
    if safe_frontmatter.get("status") == "redacted":
        blockers.append("zettel_is_redacted")
        return {
            "ok": False,
            "dry_run": True,
            "lifecycle_action": "notion_objet_link_plan",
            "archive_id": archive_id,
            "zettel": zettel_summary_value,
            "locator_count": 0,
            "locators": [],
            "manifest_summary": {"manifest_path": "objects/manifests/files.jsonl", "record_count": 0, "notion_labeled_record_count": 0},
            "truncated": False,
            "privacy_guards": {
                "provider_urls_echoed": False,
                "zettel_body_text_echoed": False,
                "frontmatter_values_echoed": False,
                "absolute_local_paths_echoed": False,
                "provider_api_called": False,
                "presigned_url_created": False,
                "download_performed": False,
                "object_file_bytes_read": False,
                "writes": False,
            },
            "would_change": [],
            "next_safe_actions": ["Redacted zettels do not expose Notion locator plans."],
            "blockers": unique_preserve_order(blockers),
            "warnings": unique_preserve_order(warnings),
        }

    max_locators = max(1, min(int(max_locators), 500))
    max_candidates = max(1, min(int(max_candidates), 100))
    occurrences: list[dict[str, Any]] = []
    occurrences.extend(notion_provider_locator_occurrences_in_value(safe_frontmatter, field="frontmatter"))
    occurrences.extend(notion_provider_locator_occurrences_in_text(body, source="body"))

    grouped, normalized_by_fingerprint, order = group_notion_provider_locator_occurrences(occurrences)

    manifest_records = load_manifest_records(root)
    notion_labeled_record_count = sum(1 for record in manifest_records if manifest_record_has_notion_store_label(record))
    truncated = len(order) > max_locators
    locators: list[dict[str, Any]] = []
    for fingerprint in order[:max_locators]:
        locator_occurrences = grouped[fingerprint]
        normalized_locator = normalized_by_fingerprint.get(fingerprint, "")
        candidates = notion_locator_candidate_entries(
            root,
            manifest_records,
            normalized_locator=normalized_locator,
            locator_fingerprint=fingerprint,
            max_candidates=max_candidates,
        )
        candidate_count = len(candidates)
        if candidate_count:
            state = "matched_manifest_object"
        elif notion_labeled_record_count:
            state = "notion_manifest_present_without_locator_binding"
        else:
            state = "no_notion_manifest_candidates"
        locators.append(
            {
                "locator_fingerprint": fingerprint,
                "occurrence_count": len(locator_occurrences),
                "occurrences": [
                    {
                        "source": occurrence.get("source"),
                        "line": occurrence.get("line"),
                        "field": occurrence.get("field"),
                        "locator_kind": occurrence.get("locator_kind"),
                    }
                    for occurrence in locator_occurrences[:10]
                ],
                "occurrences_truncated": len(locator_occurrences) > 10,
                "candidate_state": state,
                "candidate_count": candidate_count,
                "candidates": candidates,
                "candidates_truncated": candidate_count >= max_candidates,
            }
        )

    if truncated:
        warnings.append("notion_locator_plan_truncated")

    next_safe_actions: list[str] = []
    if locators and any(locator.get("candidate_count", 0) for locator in locators):
        next_safe_actions.append("Review each matched object_id before replacing provider locators with objet:sha256 refs or writing a reviewed embed edge.")
        next_safe_actions.append("Run zettel-objet-links again after reviewed refs exist in the zettel body or frontmatter.")
    elif locators and notion_labeled_record_count:
        next_safe_actions.append("Add a reviewed non-secret locator binding or manifest fingerprint before converting Notion provider locators to objet refs.")
    elif locators:
        next_safe_actions.append("Register the relevant Notion source-export objets in objects/manifests/files.jsonl before link conversion.")
    else:
        next_safe_actions.append("No Notion provider locators were found in this zettel.")
    if blockers:
        next_safe_actions.append("Fix blockers before planning Notion locator to objet links.")

    return {
        "ok": not blockers,
        "dry_run": True,
        "lifecycle_action": "notion_objet_link_plan",
        "archive_id": archive_id,
        "zettel": zettel_summary_value,
        "locator_count": len(locators),
        "locators": locators,
        "manifest_summary": {
            "manifest_path": "objects/manifests/files.jsonl",
            "record_count": len(manifest_records),
            "notion_labeled_record_count": notion_labeled_record_count,
        },
        "truncated": truncated,
        "privacy_guards": {
            "provider_urls_echoed": False,
            "zettel_body_text_echoed": False,
            "frontmatter_values_echoed": False,
            "absolute_local_paths_echoed": False,
            "provider_api_called": False,
            "presigned_url_created": False,
            "download_performed": False,
            "object_file_bytes_read": False,
            "writes": False,
        },
        "would_change": [],
        "next_safe_actions": unique_preserve_order(next_safe_actions),
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }


def notion_objet_link_index(
    archive_root: Path | str,
    *,
    dry_run: bool = True,
    max_zettels: int = 50,
    max_locators_per_zettel: int = 20,
    max_candidates: int = 5,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []
    if not dry_run:
        blockers.append("notion-objet-link-index is read-only; pass --dry-run.")

    manifest_records = load_manifest_records(root)
    notion_labeled_record_count = sum(1 for record in manifest_records if manifest_record_has_notion_store_label(record))
    zettel_paths = iter_zettel_paths(root)
    max_zettels = max(1, min(int(max_zettels), 500))
    max_locators_per_zettel = max(1, min(int(max_locators_per_zettel), 100))
    max_candidates = max(1, min(int(max_candidates), 50))

    scanned_non_redacted = 0
    redacted_zettel_count = 0
    zettels_with_locator_count = 0
    locator_occurrence_count = 0
    zettel_locator_row_count = 0
    matched_zettel_locator_row_count = 0
    distinct_locators: set[str] = set()
    matched_distinct_locators: set[str] = set()
    zettel_entries: list[dict[str, Any]] = []
    zettel_entries_truncated = False

    if blockers:
        zettel_paths = []

    for path in zettel_paths:
        text = path.read_text(encoding="utf-8")
        frontmatter, body = split_zettel_text(text)
        safe_frontmatter = json_safe(frontmatter)
        if safe_frontmatter.get("status") == "redacted":
            redacted_zettel_count += 1
            continue
        scanned_non_redacted += 1

        occurrences: list[dict[str, Any]] = []
        occurrences.extend(notion_provider_locator_occurrences_in_value(safe_frontmatter, field="frontmatter"))
        occurrences.extend(notion_provider_locator_occurrences_in_text(body, source="body"))
        grouped, normalized_by_fingerprint, order = group_notion_provider_locator_occurrences(occurrences)
        if not order:
            continue

        zettels_with_locator_count += 1
        locator_occurrence_count += len(occurrences)
        zettel_locator_row_count += len(order)
        distinct_locators.update(order)
        locators: list[dict[str, Any]] = []
        matched_locator_count_for_zettel = 0

        for fingerprint in order[:max_locators_per_zettel]:
            locator_occurrences = grouped[fingerprint]
            candidates = notion_locator_candidate_entries(
                root,
                manifest_records,
                normalized_locator=normalized_by_fingerprint.get(fingerprint, ""),
                locator_fingerprint=fingerprint,
                max_candidates=max_candidates,
            )
            candidate_count = len(candidates)
            if candidate_count:
                state = "matched_manifest_object"
                matched_locator_count_for_zettel += 1
                matched_zettel_locator_row_count += 1
                matched_distinct_locators.add(fingerprint)
            elif notion_labeled_record_count:
                state = "notion_manifest_present_without_locator_binding"
            else:
                state = "no_notion_manifest_candidates"
            locators.append(
                {
                    "locator_fingerprint": fingerprint,
                    "occurrence_count": len(locator_occurrences),
                    "candidate_state": state,
                    "candidate_count": candidate_count,
                    "candidates": candidates,
                    "candidates_truncated": candidate_count >= max_candidates,
                }
            )

        if len(order) > max_locators_per_zettel:
            warnings.append("notion_locator_index_zettel_locator_list_truncated")
        entry = drop_none_values(
            {
                "path": archive_relative_path(path, root),
                "id": safe_frontmatter.get("id") if isinstance(safe_frontmatter.get("id"), str) else None,
                "locator_count": len(order),
                "locator_occurrence_count": len(occurrences),
                "matched_locator_count": matched_locator_count_for_zettel,
                "unmatched_locator_count": max(0, len(order) - matched_locator_count_for_zettel),
                "locators": locators,
                "locators_truncated": len(order) > max_locators_per_zettel,
            }
        )
        if len(zettel_entries) < max_zettels:
            zettel_entries.append(entry)
        else:
            zettel_entries_truncated = True

    if zettel_entries_truncated:
        warnings.append("notion_locator_index_zettel_list_truncated")

    unmatched_zettel_locator_row_count = max(0, zettel_locator_row_count - matched_zettel_locator_row_count)
    next_safe_actions: list[str] = []
    if blockers:
        next_safe_actions.append("Fix blockers before indexing Notion locator to objet link candidates.")
    elif matched_zettel_locator_row_count:
        next_safe_actions.append("Run notion-objet-link-plan for a matched zettel before any reviewed locator rewrite or embed edge write.")
        next_safe_actions.append("Keep conversion approval-gated: this index is only a map of where candidates exist.")
    elif zettels_with_locator_count and notion_labeled_record_count:
        next_safe_actions.append("Add reviewed non-secret locator fingerprints to manifest records before attempting locator conversion.")
    elif zettels_with_locator_count:
        next_safe_actions.append("Register the relevant Notion source-export objets before planning locator conversion.")
    else:
        next_safe_actions.append("No Notion provider locators were found in non-redacted zettels.")

    return {
        "ok": not blockers,
        "dry_run": True,
        "lifecycle_action": "notion_objet_link_index",
        "archive_id": archive_id,
        "summary": {
            "total_zettel_count": len(iter_zettel_paths(root)),
            "scanned_non_redacted_zettel_count": scanned_non_redacted,
            "redacted_zettel_count": redacted_zettel_count,
            "zettels_with_locator_count": zettels_with_locator_count,
            "locator_occurrence_count": locator_occurrence_count,
            "zettel_locator_row_count": zettel_locator_row_count,
            "distinct_locator_count": len(distinct_locators),
            "distinct_locators_with_manifest_candidate_count": len(matched_distinct_locators),
            "zettel_locator_rows_with_manifest_candidate_count": matched_zettel_locator_row_count,
            "zettel_locator_rows_without_manifest_candidate_count": unmatched_zettel_locator_row_count,
        },
        "manifest_summary": {
            "manifest_path": "objects/manifests/files.jsonl",
            "record_count": len(manifest_records),
            "notion_labeled_record_count": notion_labeled_record_count,
        },
        "zettels": zettel_entries,
        "truncated": zettel_entries_truncated,
        "privacy_guards": {
            "provider_urls_echoed": False,
            "zettel_body_text_echoed": False,
            "frontmatter_values_echoed": False,
            "absolute_local_paths_echoed": False,
            "provider_api_called": False,
            "presigned_url_created": False,
            "download_performed": False,
            "object_file_bytes_read": False,
            "writes": False,
        },
        "would_change": [],
        "next_safe_actions": unique_preserve_order(next_safe_actions),
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }


NOTION_SOURCE_MAP_ZETTEL_KEYS = {
    "zettel_id",
    "zet_id",
    "from_zettel",
    "source_zettel",
    "source_zet",
    "imported_zettel_id",
}
NOTION_SOURCE_MAP_ZETTEL_PATH_KEYS = {
    "zettel_path",
    "zet_path",
    "from_path",
    "target_path",
    "imported_zettel_path",
}
NOTION_SOURCE_MAP_PAGE_REF_KEYS = {
    "page_id",
    "notion_page_id",
    "provider_page_id",
    "provider_object_id",
    "external_id",
    "external_ref",
    "page_ref",
    "source_page_ref",
    "source_item_id",
    "item_id",
    "block_id",
}
NOTION_SOURCE_MAP_LOCATOR_REF_KEYS = {
    "url",
    "source_url",
    "provider_url",
    "external_url",
    "locator",
    "provider_locator",
    "notion_url",
}
NOTION_SOURCE_MAP_FILE_REF_KEYS = {
    "relative_path",
    "source_path",
    "download_path",
    "export_path",
    "file",
    "file_path",
    "path",
    "key",
    "name",
    "logical_key",
    "store_key",
}
NOTION_SOURCE_MAP_OBJECT_KEYS = {
    "object_id",
    "approved_object_id",
    "source_object_id",
    "target_object_id",
    "objet_ref",
    "sha256",
}


def notion_source_map_normalized_key(key: Any) -> str:
    return str(key or "").strip().lower().replace("-", "_")


def notion_source_map_value_fingerprint(value: Any) -> str | None:
    text = str(value or "").strip()
    if not text or "\x00" in text:
        return None
    if source_intake_secret_like(text):
        return None
    normalized = normalize_notion_provider_locator(text)
    if not normalized:
        return None
    return "sha256:" + hashlib.sha256(normalized.encode("utf-8")).hexdigest()


def notion_source_map_add_hashes(target: dict[str, list[str]], family: str, value: Any) -> None:
    if isinstance(value, dict):
        for child in value.values():
            notion_source_map_add_hashes(target, family, child)
        return
    if isinstance(value, list):
        for child in value:
            notion_source_map_add_hashes(target, family, child)
        return
    fingerprint = notion_source_map_value_fingerprint(value)
    if fingerprint:
        target.setdefault(family, []).append(fingerprint)


def notion_source_map_ref_family_for_key(key: Any) -> str | None:
    normalized = notion_source_map_normalized_key(key)
    if normalized in NOTION_SOURCE_MAP_PAGE_REF_KEYS or normalized.endswith("_page_id"):
        return "page_refs"
    if normalized in NOTION_SOURCE_MAP_LOCATOR_REF_KEYS or normalized.endswith("_url"):
        return "locator_refs"
    if normalized in NOTION_SOURCE_MAP_FILE_REF_KEYS:
        return "file_refs"
    return None


def notion_source_map_hashes_from_value(value: Any) -> dict[str, list[str]]:
    hashes: dict[str, list[str]] = {"page_refs": [], "file_refs": [], "locator_refs": []}

    def walk(item: Any) -> None:
        if isinstance(item, dict):
            for key, child in item.items():
                family = notion_source_map_ref_family_for_key(key)
                if family:
                    notion_source_map_add_hashes(hashes, family, child)
                if isinstance(child, (dict, list)):
                    walk(child)
            return
        if isinstance(item, list):
            for child in item:
                walk(child)

    walk(value)
    return {key: unique_preserve_order(values) for key, values in hashes.items()}


def notion_source_map_add_object_values(value: Any, add_object_id: Any) -> None:
    if isinstance(value, dict):
        for child in value.values():
            notion_source_map_add_object_values(child, add_object_id)
        return
    if isinstance(value, list):
        for child in value:
            notion_source_map_add_object_values(child, add_object_id)
        return
    add_object_id(value)


def notion_source_map_object_ids_from_value(value: Any) -> list[str]:
    object_ids: list[str] = []

    def add_object_id(raw: Any) -> None:
        text = str(raw or "").strip().lower()
        if not text:
            return
        blockers: list[str] = []
        if text.startswith("objet:sha256:"):
            normalized = object_id_from_objet_ref(text, blockers)
        else:
            normalized = normalize_object_id(text, blockers)
        if normalized and not blockers:
            object_ids.append(normalized)

    def walk(item: Any) -> None:
        if isinstance(item, dict):
            for key, child in item.items():
                if notion_source_map_normalized_key(key) in NOTION_SOURCE_MAP_OBJECT_KEYS:
                    notion_source_map_add_object_values(child, add_object_id)
                if isinstance(child, (dict, list)):
                    walk(child)
            return
        if isinstance(item, list):
            for child in item:
                walk(child)

    walk(value)
    return unique_preserve_order(object_ids)


def notion_source_map_safe_zettel_id(value: Any) -> str | None:
    text = str(value or "").strip()
    if not text or not re.match(r"^[A-Za-z0-9][A-Za-z0-9_.:-]{0,199}$", text):
        return None
    if contains_forbidden_location_reference(text) or source_intake_has_provider_url(text) or source_intake_secret_like(text):
        return None
    return text


def notion_source_map_safe_zettel_path(root: Path, value: Any) -> str | None:
    text = str(value or "").strip()
    if not text or Path(text).expanduser().is_absolute():
        return None
    try:
        candidate = resolve_archive_relative_path(root, text)
        relative = archive_relative_path(candidate, root)
    except (ArchivePathError, OSError, ValueError):
        return None
    if not relative.startswith(VALID_ZETTEL_FOLDERS) or candidate.suffix.lower() != ".md":
        return None
    return relative


def notion_source_map_zettel_ref_from_record(root: Path, record: dict[str, Any]) -> tuple[str | None, str | None]:
    zettel_id: str | None = None
    zettel_path: str | None = None
    for key, value in record.items():
        normalized = notion_source_map_normalized_key(key)
        if zettel_id is None and normalized in NOTION_SOURCE_MAP_ZETTEL_KEYS:
            zettel_id = notion_source_map_safe_zettel_id(value)
        if zettel_path is None and normalized in NOTION_SOURCE_MAP_ZETTEL_PATH_KEYS:
            zettel_path = notion_source_map_safe_zettel_path(root, value)
        if isinstance(value, dict):
            nested_id, nested_path = notion_source_map_zettel_ref_from_record(root, value)
            zettel_id = zettel_id or nested_id
            zettel_path = zettel_path or nested_path
    return zettel_id, zettel_path


def read_zettel_frontmatter_only(path: Path) -> dict[str, Any]:
    try:
        with path.open("r", encoding="utf-8") as handle:
            first = handle.readline()
            if first.strip() != "---":
                return {}
            lines: list[str] = []
            for line in handle:
                if line.strip() == "---":
                    break
                lines.append(line)
    except OSError:
        return {}
    try:
        data = load_yaml("".join(lines))
    except Exception:
        return {}
    return json_safe(data) if isinstance(data, dict) else {}


def notion_source_map_archive_json_records(
    root: Path,
    relative_path: str,
    *,
    role: str,
    max_rows: int,
    blockers: list[str],
    warnings: list[str],
) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    summary = {"path": None, "role": role, "record_count": 0, "truncated": False, "status": "not_read"}
    try:
        normalized = normalize_archive_relative_path(relative_path)
    except ArchivePathError:
        blockers.append(f"{role} path must be archive-relative and safe.")
        summary["status"] = "unsafe_path"
        return [], summary
    summary["path"] = normalized
    try:
        path = resolve_archive_relative_path(root, normalized)
    except ArchivePathError:
        blockers.append(f"{role} path must stay inside the archive root.")
        summary["status"] = "unsafe_path"
        return [], summary
    if not path.is_file():
        blockers.append(f"{role} file is missing: {normalized}")
        summary["status"] = "missing"
        return [], summary
    suffix = path.suffix.lower()
    if suffix not in {".json", ".jsonl", ".yaml", ".yml"}:
        blockers.append(f"{role} file must be JSON, JSONL, YAML, or YML: {normalized}")
        summary["status"] = "unsupported_extension"
        return [], summary

    records: list[dict[str, Any]] = []
    try:
        text = path.read_text(encoding="utf-8")
    except OSError:
        blockers.append(f"{role} file could not be read: {normalized}")
        summary["status"] = "unreadable"
        return [], summary

    if suffix == ".jsonl":
        for raw_line in text.splitlines():
            if len(records) >= max_rows:
                summary["truncated"] = True
                break
            line = raw_line.strip()
            if not line:
                continue
            try:
                data = json.loads(line)
            except json.JSONDecodeError:
                warnings.append(f"{role} JSONL contains an invalid row: {normalized}")
                continue
            if isinstance(data, dict):
                records.append(json_safe(data))
        summary["status"] = "read"
    else:
        try:
            data = json.loads(text) if suffix == ".json" else load_yaml(text)
        except Exception:
            blockers.append(f"{role} file must be JSON, JSONL, YAML, or YML: {normalized}")
            summary["status"] = "invalid_json"
            return [], summary
        rows = data.get("items") if isinstance(data, dict) and isinstance(data.get("items"), list) else data
        if isinstance(rows, dict):
            rows = [rows]
        if not isinstance(rows, list):
            blockers.append(f"{role} file must contain an object or items list: {normalized}")
            summary["status"] = "invalid_shape"
            return [], summary
        for row in rows[:max_rows]:
            if isinstance(row, dict):
                records.append(json_safe(row))
        summary["truncated"] = len(rows) > max_rows
        summary["status"] = "read"

    summary["record_count"] = len(records)
    return records, summary


def notion_source_map_default_paths(root: Path) -> list[str]:
    maps_root = root / SOURCE_MAPS_DIR
    if not maps_root.is_dir():
        return []
    return [archive_relative_path(path, root) for path in safe_archive_glob(maps_root, "*.jsonl", root)]


def notion_source_map_add_zettel_entry(
    entries: dict[str, dict[str, Any]],
    *,
    zettel_id: str | None,
    zettel_path: str | None,
    hashes: dict[str, list[str]],
    existing_object_ids: list[str] | None = None,
    source: str,
) -> None:
    if not zettel_id and not zettel_path:
        return
    key = zettel_id or zettel_path or source
    entry = entries.setdefault(
        key,
        {
            "id": zettel_id,
            "path": zettel_path,
            "page_refs": [],
            "file_refs": [],
            "locator_refs": [],
            "sources": [],
            "existing_object_ids": [],
        },
    )
    entry["id"] = entry.get("id") or zettel_id
    entry["path"] = entry.get("path") or zettel_path
    for family in ("page_refs", "file_refs", "locator_refs"):
        entry[family] = unique_preserve_order([*entry.get(family, []), *hashes.get(family, [])])
    entry["sources"] = unique_preserve_order([*entry.get("sources", []), source])
    entry["existing_object_ids"] = unique_preserve_order(
        [*entry.get("existing_object_ids", []), *(existing_object_ids or [])]
    )


def notion_source_map_existing_object_refs(frontmatter: dict[str, Any]) -> list[str]:
    refs: list[str] = []
    for item in collect_referenced_objets(frontmatter):
        if not isinstance(item, dict):
            continue
        value = str(item.get("value") or "").strip().lower()
        blockers: list[str] = []
        if value.startswith("objet:sha256:"):
            normalized = object_id_from_objet_ref(value, blockers)
        else:
            normalized = normalize_object_id(value, blockers)
        if normalized and not blockers:
            refs.append(normalized)
    edges = frontmatter.get("edges") if isinstance(frontmatter.get("edges"), list) else []
    for edge in edges:
        if not isinstance(edge, dict):
            continue
        target = str(edge.get("target") or edge.get("ref") or "").strip().lower()
        blockers = []
        normalized = normalize_object_id(target, blockers)
        if normalized and not blockers:
            refs.append(normalized)
    return unique_preserve_order(refs)


def manifest_records_by_normalized_object_id(manifest_records: list[dict[str, Any]]) -> dict[str, list[dict[str, Any]]]:
    records_by_object_id: dict[str, list[dict[str, Any]]] = {}
    for record in manifest_records:
        blockers: list[str] = []
        object_id = normalize_object_id(str(record.get("object_id") or ""), blockers)
        if object_id and not blockers:
            records_by_object_id.setdefault(object_id, []).append(record)
    return records_by_object_id


def notion_source_map_resolution_from_manifest_index(
    root: Path,
    object_id: str,
    manifest_records_by_object_id: dict[str, list[dict[str, Any]]],
) -> dict[str, Any]:
    blockers: list[str] = []
    normalized_object_id = normalize_object_id(str(object_id or ""), blockers)
    records = manifest_records_by_object_id.get(normalized_object_id, []) if normalized_object_id else []
    if normalized_object_id and not records:
        blockers.append("object_id_not_found_in_manifest")

    digest = normalized_object_id.removeprefix("sha256:") if normalized_object_id else ""
    local_openable = False
    external_declared = False

    def mark_local_candidate(relative_path: str) -> None:
        nonlocal local_openable
        try:
            normalized = normalize_archive_relative_path(relative_path)
        except ArchivePathError:
            return
        candidate = root.joinpath(*PurePosixPath(normalized).parts)
        if candidate.is_file():
            local_openable = True

    if records and digest:
        mark_local_candidate(f"objects/sha256/{digest[:2]}/{digest}")

    for record in records:
        logical_key = record.get("logical_key")
        if isinstance(logical_key, str) and logical_key.startswith("objects/sha256/"):
            mark_local_candidate(logical_key)
        locations = record.get("locations")
        if not isinstance(locations, list):
            continue
        for location in locations:
            if not isinstance(location, dict):
                continue
            provider = str(location.get("provider") or "").strip()
            path_value = location.get("path")
            if provider == "local" and isinstance(path_value, str):
                mark_local_candidate(path_value)
            else:
                external_declared = True

    if blockers:
        resolution_state = "blocked"
    elif local_openable:
        resolution_state = "local_available"
    elif external_declared:
        resolution_state = "external_declared"
    elif records:
        resolution_state = "manifest_only"
    else:
        resolution_state = "not_found"

    return {
        "resolution_state": resolution_state,
        "manifest_record_count": len(records),
        "local_openable": local_openable,
        "external_declared": external_declared,
        "blockers": blockers,
    }


def notion_source_map_object_entry(
    root: Path,
    object_id: str,
    *,
    hashes: dict[str, list[str]],
    source: str,
    manifest_records_by_object_id: dict[str, list[dict[str, Any]]] | None = None,
) -> dict[str, Any]:
    if manifest_records_by_object_id is None:
        resolution = resolve_objet_ref(root, object_id=object_id, dry_run=True)
    else:
        resolution = notion_source_map_resolution_from_manifest_index(root, object_id, manifest_records_by_object_id)
    return {
        "object_id": object_id,
        "page_refs": hashes.get("page_refs", []),
        "file_refs": hashes.get("file_refs", []),
        "locator_refs": hashes.get("locator_refs", []),
        "sources": [source],
        "resolution_state": resolution.get("resolution_state"),
        "manifest_record_count": resolution.get("manifest_record_count"),
        "local_openable": bool(resolution.get("local_openable")),
        "external_declared": bool(resolution.get("external_declared")),
        "resolver_blockers": resolution.get("blockers", []),
    }


def notion_source_map_candidate_id(zettel_entry: dict[str, Any], object_id: str, join_basis: list[dict[str, Any]]) -> str:
    payload = {
        "zettel": zettel_entry.get("id") or zettel_entry.get("path"),
        "object_id": object_id,
        "join_basis": join_basis,
    }
    digest = hashlib.sha256(json.dumps(payload, sort_keys=True, separators=(",", ":")).encode("utf-8")).hexdigest()
    return f"notion-source-map-link:{digest[:20]}"


def notion_source_map_candidate(
    zettel_entry: dict[str, Any],
    object_entry: dict[str, Any],
    *,
    join_basis: list[dict[str, Any]],
    confidence: str,
) -> dict[str, Any]:
    object_id = str(object_entry.get("object_id") or "")
    already_referenced = object_id in set(zettel_entry.get("existing_object_ids") or [])
    if already_referenced:
        write_status = "already_referenced"
    elif object_entry.get("resolver_blockers"):
        write_status = "blocked_until_manifest_review"
    else:
        write_status = "not_written"
    return {
        "candidate_id": notion_source_map_candidate_id(zettel_entry, object_id, join_basis),
        "from_zettel": drop_none_values({"id": zettel_entry.get("id"), "path": zettel_entry.get("path")}),
        "target_object_id": object_id,
        "suggested_objet_ref": f"objet:{object_id}",
        "target_mode": "embed_edge",
        "edge_type": "embed",
        "confidence": confidence,
        "join_basis": join_basis,
        "resolution_state": object_entry.get("resolution_state"),
        "manifest_record_count": object_entry.get("manifest_record_count"),
        "local_openable": bool(object_entry.get("local_openable")),
        "external_declared": bool(object_entry.get("external_declared")),
        "write_status": write_status,
        "human_review_required": True,
        "review_note": "Review the source-map or ledger evidence before writing an embed edge.",
    }


def notion_objet_source_map_link_plan(
    archive_root: Path | str,
    *,
    source_maps: list[str] | None = None,
    ledgers: list[str] | None = None,
    dry_run: bool = True,
    max_rows: int = 10000,
    max_candidates: int = 200,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []
    if not dry_run:
        blockers.append("notion-objet-source-map-link-plan is read-only; pass --dry-run.")

    max_rows = max(1, min(int(max_rows), 100000))
    max_candidates = max(1, min(int(max_candidates), 1000))
    source_map_paths = [str(item).strip() for item in source_maps or [] if str(item).strip()]
    if not source_map_paths:
        source_map_paths = notion_source_map_default_paths(root)
    ledger_paths = [str(item).strip() for item in ledgers or [] if str(item).strip()]

    source_records: list[tuple[dict[str, Any], str]] = []
    ledger_records: list[tuple[dict[str, Any], str]] = []
    input_summaries: list[dict[str, Any]] = []
    rows_remaining = max_rows
    for relative in source_map_paths:
        records, summary = notion_source_map_archive_json_records(
            root,
            relative,
            role="source_map",
            max_rows=rows_remaining,
            blockers=blockers,
            warnings=warnings,
        )
        input_summaries.append(summary)
        source_records.extend((record, str(summary.get("path") or "source-map")) for record in records)
        rows_remaining = max(0, rows_remaining - len(records))
        if rows_remaining <= 0:
            warnings.append("notion_source_map_link_plan_row_limit_reached")
            break
    for relative in ledger_paths:
        records, summary = notion_source_map_archive_json_records(
            root,
            relative,
            role="ledger",
            max_rows=max_rows,
            blockers=blockers,
            warnings=warnings,
        )
        input_summaries.append(summary)
        ledger_records.extend((record, str(summary.get("path") or "ledger")) for record in records)

    if not source_map_paths:
        warnings.append("No source-maps/*.jsonl files were found; pass --source-map with an archive-relative file.")

    zettel_entries: dict[str, dict[str, Any]] = {}
    redacted_zettel_count = 0
    for path in iter_zettel_paths(root):
        frontmatter = read_zettel_frontmatter_only(path)
        if frontmatter.get("status") == "redacted":
            redacted_zettel_count += 1
            continue
        zettel_id = notion_source_map_safe_zettel_id(frontmatter.get("id"))
        zettel_path = archive_relative_path(path, root)
        hashes = notion_source_map_hashes_from_value(frontmatter)
        notion_source_map_add_zettel_entry(
            zettel_entries,
            zettel_id=zettel_id,
            zettel_path=zettel_path,
            hashes=hashes,
            existing_object_ids=notion_source_map_existing_object_refs(frontmatter),
            source="zettel_frontmatter",
        )

    for record, record_source in source_records:
        zettel_id, zettel_path = notion_source_map_zettel_ref_from_record(root, record)
        if zettel_id or zettel_path:
            notion_source_map_add_zettel_entry(
                zettel_entries,
                zettel_id=zettel_id,
                zettel_path=zettel_path,
                hashes=notion_source_map_hashes_from_value(record),
                source=f"source_map:{record_source}",
            )

    manifest_records = load_manifest_records(root)
    manifest_records_by_object_id = manifest_records_by_normalized_object_id(manifest_records)

    object_entries: list[dict[str, Any]] = []
    page_to_files: dict[str, set[str]] = {}
    records_with_page_ref = 0
    records_with_file_ref = 0
    records_with_object_ref = 0
    for record, record_source in [*source_records, *ledger_records]:
        hashes = notion_source_map_hashes_from_value(record)
        page_refs = hashes.get("page_refs", [])
        file_refs = hashes.get("file_refs", [])
        object_ids = notion_source_map_object_ids_from_value(record)
        if page_refs:
            records_with_page_ref += 1
        if file_refs:
            records_with_file_ref += 1
        if object_ids:
            records_with_object_ref += 1
        for page_ref in page_refs:
            page_to_files.setdefault(page_ref, set()).update(file_refs)
        for object_id in object_ids:
            object_entries.append(
                notion_source_map_object_entry(
                    root,
                    object_id,
                    hashes=hashes,
                    source=f"metadata:{record_source}",
                    manifest_records_by_object_id=manifest_records_by_object_id,
                )
            )

    for record in manifest_records:
        object_id_value = str(record.get("object_id") or "")
        record_blockers: list[str] = []
        object_id = normalize_object_id(object_id_value, record_blockers)
        if not object_id:
            continue
        object_entries.append(
            notion_source_map_object_entry(
                root,
                object_id,
                hashes=notion_source_map_hashes_from_value(record),
                source="objects/manifests/files.jsonl",
                manifest_records_by_object_id=manifest_records_by_object_id,
            )
        )

    object_by_page: dict[str, list[dict[str, Any]]] = {}
    object_by_file: dict[str, list[dict[str, Any]]] = {}
    seen_object_entry_keys: set[tuple[str, str, str]] = set()
    for entry in object_entries:
        object_id = str(entry.get("object_id") or "")
        for page_ref in entry.get("page_refs", []):
            key = (object_id, "page", page_ref)
            if key not in seen_object_entry_keys:
                object_by_page.setdefault(page_ref, []).append(entry)
                seen_object_entry_keys.add(key)
        for file_ref in entry.get("file_refs", []):
            key = (object_id, "file", file_ref)
            if key not in seen_object_entry_keys:
                object_by_file.setdefault(file_ref, []).append(entry)
                seen_object_entry_keys.add(key)

    candidates: list[dict[str, Any]] = []
    seen_candidates: set[str] = set()

    def add_candidate(entry: dict[str, Any], object_entry: dict[str, Any], join_basis: list[dict[str, Any]], confidence: str) -> None:
        if len(candidates) >= max_candidates:
            return
        candidate = notion_source_map_candidate(entry, object_entry, join_basis=join_basis, confidence=confidence)
        key = candidate["candidate_id"]
        if key in seen_candidates:
            return
        seen_candidates.add(key)
        candidates.append(candidate)

    for zettel_entry in zettel_entries.values():
        for page_ref in zettel_entry.get("page_refs", []):
            for object_entry in object_by_page.get(page_ref, []):
                add_candidate(
                    zettel_entry,
                    object_entry,
                    [{"kind": "page_ref", "ref_fingerprint": page_ref, "join_path": "zettel_source_ref_to_object_ref"}],
                    "high",
                )
            for file_ref in sorted(page_to_files.get(page_ref, set())):
                for object_entry in object_by_file.get(file_ref, []):
                    add_candidate(
                        zettel_entry,
                        object_entry,
                        [
                            {
                                "kind": "page_to_file_to_object",
                                "page_ref_fingerprint": page_ref,
                                "file_ref_fingerprint": file_ref,
                                "join_path": "source_map_page_to_file_then_ledger_file_to_sha256",
                            }
                        ],
                        "medium",
                    )
        for file_ref in zettel_entry.get("file_refs", []):
            for object_entry in object_by_file.get(file_ref, []):
                add_candidate(
                    zettel_entry,
                    object_entry,
                    [{"kind": "file_ref", "ref_fingerprint": file_ref, "join_path": "zettel_source_file_to_object_ref"}],
                    "medium",
                )
        for locator_ref in zettel_entry.get("locator_refs", []):
            for object_entry in object_by_page.get(locator_ref, []):
                add_candidate(
                    zettel_entry,
                    object_entry,
                    [{"kind": "locator_ref", "ref_fingerprint": locator_ref, "join_path": "redacted_locator_fingerprint_to_object_ref"}],
                    "medium",
                )

    truncated = len(candidates) >= max_candidates
    if truncated:
        warnings.append("notion_objet_source_map_link_candidates_truncated")

    next_safe_actions: list[str] = []
    if blockers:
        next_safe_actions.append("Fix blockers before planning source-map based material links.")
    elif candidates:
        next_safe_actions.append("Review candidate_id, from_zettel, target_object_id, and join_basis before writing any embed edge.")
        next_safe_actions.append("After review, write edges through the existing zettel-edge or zettel-edge-batch approval gates.")
        next_safe_actions.append("Keep provider locator body replacement separate; this planner does not rewrite zettel bodies.")
    elif not object_entries:
        next_safe_actions.append("Register or pass a download ledger with sha256/object_id metadata before planning material links.")
    elif not zettel_entries:
        next_safe_actions.append("Import or identify zettels with safe source_refs/external_import metadata before planning material links.")
    else:
        next_safe_actions.append("No source-map/ledger join matched a zettel to an objet; add a reviewed page/file/object bridge row.")
    if records_with_file_ref and not records_with_page_ref:
        warnings.append("source_map_or_ledger_rows_have_file_refs_but_no_page_refs")
    if records_with_page_ref and not records_with_object_ref and not ledger_records:
        warnings.append("source_maps_have_page_refs_but_no_object_hashes_pass_ledger_if_available")

    return {
        "ok": not blockers,
        "dry_run": True,
        "lifecycle_action": "notion_objet_source_map_link_plan",
        "archive_id": archive_id,
        "summary": {
            "source_map_file_count": len(source_map_paths),
            "ledger_file_count": len(ledger_paths),
            "source_map_record_count": len(source_records),
            "ledger_record_count": len(ledger_records),
            "manifest_record_count": len(manifest_records),
            "zettel_source_count": len(zettel_entries),
            "redacted_zettel_count": redacted_zettel_count,
            "object_ref_source_count": len(object_entries),
            "records_with_page_ref": records_with_page_ref,
            "records_with_file_ref": records_with_file_ref,
            "records_with_object_ref": records_with_object_ref,
            "candidate_count": len(candidates),
            "candidates_truncated": truncated,
        },
        "inputs": input_summaries,
        "candidates": candidates,
        "current_capability": {
            "body_locator_required": False,
            "source_map_ledger_join_available": True,
            "approved_write_performed_by_this_command": False,
            "import_time_object_ref_preservation_required": True,
            "provider_locator_body_rewrite_implemented": False,
        },
        "privacy_guards": {
            "provider_urls_echoed": False,
            "provider_locator_text_echoed": False,
            "page_titles_echoed": False,
            "zettel_body_text_read": False,
            "zettel_body_text_echoed": False,
            "frontmatter_values_echoed": False,
            "absolute_local_paths_echoed": False,
            "account_ids_echoed": False,
            "emails_echoed": False,
            "tokens_echoed": False,
            "secret_values_echoed": False,
            "provider_api_called": False,
            "object_file_bytes_read": False,
            "writes": False,
        },
        "would_change": [],
        "next_safe_actions": unique_preserve_order(next_safe_actions),
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }


NOTION_IMPORT_SOURCE_KEYS = {
    "source",
    "source_system",
    "provider",
    "provider_system",
    "external_system",
    "import_source",
}
NOTION_IMPORT_OMISSION_COUNT_KEYS = {
    "source_locator_omitted_count",
    "provider_locator_omitted_count",
    "locator_omitted_count",
    "omitted_locator_count",
}


def notion_import_source_text_is_notion(value: Any) -> bool:
    text = str(value or "").strip().lower().replace("-", "_")
    if not text:
        return False
    return text == "notion" or text.startswith("notion:") or text.endswith(":notion") or text.endswith("_notion")


def notion_import_frontmatter_is_notion(frontmatter: dict[str, Any]) -> bool:
    zettel_id = str(frontmatter.get("id") or "").strip().lower()
    if zettel_id.startswith("zet_notion_") or zettel_id.startswith("zet_import_notion_"):
        return True

    def walk(value: Any) -> bool:
        if isinstance(value, dict):
            for key, child in value.items():
                normalized = notion_source_map_normalized_key(key)
                if normalized in NOTION_IMPORT_SOURCE_KEYS and notion_import_source_text_is_notion(child):
                    return True
                if isinstance(child, (dict, list)) and walk(child):
                    return True
            return False
        if isinstance(value, list):
            return any(walk(child) for child in value)
        return False

    return walk(frontmatter)


def notion_import_locator_omitted_count(value: Any) -> int:
    total = 0

    def add_count(raw: Any) -> None:
        nonlocal total
        if isinstance(raw, bool):
            total += 1 if raw else 0
            return
        if isinstance(raw, int):
            total += max(0, raw)
            return
        text = str(raw or "").strip()
        if text.isdigit():
            total += int(text)

    def walk(item: Any) -> None:
        if isinstance(item, dict):
            for key, child in item.items():
                if notion_source_map_normalized_key(key) in NOTION_IMPORT_OMISSION_COUNT_KEYS:
                    add_count(child)
                if isinstance(child, (dict, list)):
                    walk(child)
            return
        if isinstance(item, list):
            for child in item:
                walk(child)

    walk(value)
    return total


def notion_import_candidate_keys(candidate: dict[str, Any]) -> list[str]:
    from_zettel = candidate.get("from_zettel") if isinstance(candidate.get("from_zettel"), dict) else {}
    keys = []
    zettel_id = str(from_zettel.get("id") or "").strip()
    path = str(from_zettel.get("path") or "").strip()
    if zettel_id:
        keys.append(f"id:{zettel_id}")
    if path:
        keys.append(f"path:{path}")
    return keys


def notion_objet_import_clue_audit(
    archive_root: Path | str,
    *,
    source_maps: list[str] | None = None,
    ledgers: list[str] | None = None,
    dry_run: bool = True,
    max_rows: int = 10000,
    max_zettels: int = 500,
    max_candidates: int = 1000,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []
    if not dry_run:
        blockers.append("notion-objet-import-clue-audit is read-only; pass --dry-run.")

    max_zettels = max(1, min(int(max_zettels), 5000))
    source_map_plan = notion_objet_source_map_link_plan(
        root,
        source_maps=source_maps,
        ledgers=ledgers,
        dry_run=True,
        max_rows=max_rows,
        max_candidates=max_candidates,
    )
    if source_map_plan.get("blockers"):
        blockers.extend(str(item) for item in source_map_plan.get("blockers") or [])
    warnings.extend(str(item) for item in source_map_plan.get("warnings") or [])

    candidate_ids_by_zettel: dict[str, set[str]] = {}
    for candidate in source_map_plan.get("candidates", []):
        if not isinstance(candidate, dict):
            continue
        candidate_id = str(candidate.get("candidate_id") or "")
        for key in notion_import_candidate_keys(candidate):
            candidate_ids_by_zettel.setdefault(key, set()).add(candidate_id)

    zettels: list[dict[str, Any]] = []
    redacted_zettel_count = 0
    scanned_non_redacted_count = 0
    truncated = False
    for path in iter_zettel_paths(root):
        if len(zettels) >= max_zettels:
            truncated = True
            warnings.append("notion_objet_import_clue_audit_zettel_limit_reached")
            break
        frontmatter = read_zettel_frontmatter_only(path)
        if frontmatter.get("status") == "redacted":
            redacted_zettel_count += 1
            continue
        scanned_non_redacted_count += 1
        if not notion_import_frontmatter_is_notion(frontmatter):
            continue
        zettel_id = notion_source_map_safe_zettel_id(frontmatter.get("id"))
        zettel_path = archive_relative_path(path, root)
        object_ref_count = len(notion_source_map_existing_object_refs(frontmatter))
        omitted_count = notion_import_locator_omitted_count(frontmatter)
        matching_candidate_ids = set()
        if zettel_id:
            matching_candidate_ids.update(candidate_ids_by_zettel.get(f"id:{zettel_id}", set()))
        matching_candidate_ids.update(candidate_ids_by_zettel.get(f"path:{zettel_path}", set()))
        candidate_count = len(matching_candidate_ids)

        if object_ref_count:
            material_clue_state = "preserved_object_ref_or_edge"
        elif candidate_count:
            material_clue_state = "source_map_join_available"
        elif omitted_count:
            material_clue_state = "missing_material_clue_after_locator_omission"
        else:
            material_clue_state = "no_omission_signal_or_body_locator_path_needed"

        zettels.append(
            {
                "zettel": drop_none_values({"id": zettel_id, "path": zettel_path}),
                "source_locator_omitted_count": omitted_count,
                "object_ref_or_edge_count": object_ref_count,
                "source_map_candidate_count": candidate_count,
                "material_clue_state": material_clue_state,
                "needs_import_time_preservation_fix": material_clue_state == "missing_material_clue_after_locator_omission",
                "body_locator_tools_may_be_required": material_clue_state == "no_omission_signal_or_body_locator_path_needed",
            }
        )

    counts_by_state: dict[str, int] = {}
    for item in zettels:
        state = str(item.get("material_clue_state") or "unknown")
        counts_by_state[state] = counts_by_state.get(state, 0) + 1

    missing_count = counts_by_state.get("missing_material_clue_after_locator_omission", 0)
    source_map_available_count = counts_by_state.get("source_map_join_available", 0)
    preserved_count = counts_by_state.get("preserved_object_ref_or_edge", 0)
    no_signal_count = counts_by_state.get("no_omission_signal_or_body_locator_path_needed", 0)

    next_safe_actions: list[str] = []
    if blockers:
        next_safe_actions.append("Fix blockers before trusting the import material-clue audit.")
    if missing_count:
        next_safe_actions.append("Future import adapters should preserve a safe object_id, embed candidate, or source-map/ledger join row before omitting provider locators.")
    if source_map_available_count:
        next_safe_actions.append("Review source-map candidates with notion-objet-source-map-link-plan before any approved embed edge write.")
    if no_signal_count:
        next_safe_actions.append("If body locators still exist, use notion-objet-link-index before assuming material clues are missing.")
    if preserved_count and not missing_count:
        next_safe_actions.append("Imported zettels with preserved object refs or embed edges already have a durable material clue.")

    return {
        "ok": not blockers,
        "dry_run": True,
        "lifecycle_action": "notion_objet_import_clue_audit",
        "archive_id": archive_id,
        "summary": {
            "scanned_non_redacted_zettel_count": scanned_non_redacted_count,
            "redacted_zettel_count": redacted_zettel_count,
            "notion_import_zettel_count": len(zettels),
            "preserved_object_ref_or_edge_count": preserved_count,
            "source_map_join_available_count": source_map_available_count,
            "missing_material_clue_after_locator_omission_count": missing_count,
            "no_omission_signal_or_body_locator_path_needed_count": no_signal_count,
            "zettels_truncated": truncated,
        },
        "source_map_plan_summary": source_map_plan.get("summary", {}),
        "zettels": zettels,
        "current_capability": {
            "audit_available": True,
            "body_locator_required": False,
            "import_time_object_ref_preservation_required": True,
            "approved_write_performed_by_this_command": False,
            "provider_locator_body_rewrite_implemented": False,
        },
        "privacy_guards": {
            "zettel_body_text_read": False,
            "zettel_body_text_echoed": False,
            "frontmatter_values_echoed": False,
            "provider_urls_echoed": False,
            "provider_locator_text_echoed": False,
            "page_titles_echoed": False,
            "absolute_local_paths_echoed": False,
            "account_ids_echoed": False,
            "emails_echoed": False,
            "tokens_echoed": False,
            "secret_values_echoed": False,
            "provider_api_called": False,
            "object_file_bytes_read": False,
            "writes": False,
        },
        "would_change": [],
        "next_safe_actions": unique_preserve_order(next_safe_actions),
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }


NOTION_OBJET_LINK_REWRITE_TARGET_MODES = {
    "objet_ref_rewrite",
    "embed_edge",
}


def normalize_notion_locator_fingerprint(value: str | None, blockers: list[str]) -> str:
    text = str(value or "").strip().lower()
    if SHA256_RE.match(text):
        text = f"sha256:{text}"
    if not OBJECT_ID_RE.match(text):
        blockers.append("locator_fingerprint must be formatted as sha256:<64 lowercase hex characters>.")
        return ""
    return text


