def zet_markdown_style_section() -> dict[str, Any]:
    return {
        "section_id": "zet_markdown_style",
        "title": "zet Markdown authoring style",
        "beginner_explanation": "WOM zets are Markdown-compatible today, so AI writers must avoid Markdown punctuation that accidentally changes rendering.",
        "range_tilde_rule": {
            "rule_id": "range_tilde_single_spaced",
            "plain_meaning": "When a tilde means from A to B, write one tilde with a space on both sides.",
            "required_form": "A ~ B",
            "good_examples": ["2026-06-01 ~ 2026-06-22", "v0.3.67 ~ v0.3.72", "source note A ~ source note B"],
            "avoid_examples": ["A~~B", "A ~~ B", "A~B"],
            "why": "Many Markdown renderers treat double tilde as strikethrough, so range notation must not look like a strikethrough marker.",
        },
        "authoring_contract": {
            "range_tilde_requires_single_tilde_with_spaces": True,
            "double_tilde_reserved_for_intentional_strikethrough": True,
            "literal_tilde_inside_code_may_use_code_span": True,
            "prefer_words_when_space_would_be_ambiguous": True,
        },
        "safe_script": "For ranges, write `A ~ B`. Do not write `A~~B` or `A ~~ B` unless you intentionally want Markdown strikethrough.",
    }


def zet_markdown_style_guide(
    archive_root: Path | str,
    *,
    topic: str = "all",
    dry_run: bool = True,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []
    if not dry_run:
        blockers.append("zet-markdown-style-guide is read-only and requires --dry-run.")
    resolved_topic = (topic or "all").strip().lower().replace("-", "_")
    if resolved_topic not in ZET_MARKDOWN_STYLE_GUIDE_TOPICS:
        blockers.append("topic must be one of: " + ", ".join(sorted(ZET_MARKDOWN_STYLE_GUIDE_TOPICS)) + ".")
        resolved_topic = "all"
    sections = [zet_markdown_style_section()] if resolved_topic in {"all", "range_tilde"} else []
    return {
        "ok": not blockers,
        "dry_run": True,
        "lifecycle_action": "zet_markdown_style_guide",
        "archive_id": archive_id,
        "topic": resolved_topic,
        "markdown_profile": {
            "current_authoring_format": "markdown_compatible_zet_body",
            "long_term_rendering_target": "wom_safe_html_profile",
            "range_tilde_policy": "single_tilde_with_spaces",
            "strikethrough_marker": "double_tilde_only_when_intentional",
        },
        "sections": sections,
        "closed_actions": {
            "files_written": False,
            "zettels_written": False,
            "mint_run": False,
            "provider_api_called": False,
        },
        "privacy_guards": {
            "zet_body_text_read": False,
            "source_values_echoed": False,
            "local_absolute_paths_echoed": False,
            "provider_urls_echoed": False,
            "tokens_echoed": False,
            "secret_values_echoed": False,
            "writes": False,
        },
        "current_capability": {
            "zet_markdown_style_guide_available": True,
            "range_tilde_strikethrough_guard_available": True,
            "wom_safe_html_profile_linked": True,
            "mcp_tool_available": False,
        },
        "would_change": [],
        "warnings": unique_preserve_order(warnings),
        "blockers": unique_preserve_order(blockers),
    }


def ai_response_concept_guide_locale(locale: str, blockers: list[str], warnings: list[str]) -> str:
    raw = str(locale or "ko-KR").strip()
    if not safe_source_intake_plan_scalar(raw):
        blockers.append("locale must be a safe non-secret scalar.")
        return "ko-KR"
    resolved = AI_RESPONSE_CONCEPT_GUIDE_LOCALE_ALIASES.get(raw.lower())
    if resolved:
        return resolved
    warnings.append("Unsupported locale; falling back to ko-KR.")
    return "ko-KR"


def ai_response_localized_phrase(entry: dict[str, Any], locale: str) -> str:
    phrases = entry.get("phrases") if isinstance(entry.get("phrases"), dict) else {}
    value = phrases.get(locale) or phrases.get("ko-KR") or phrases.get("en-US") or ""
    return str(value)


def ai_response_operational_terms_section(locale: str) -> dict[str, Any]:
    edge_terms = []
    for entry in AI_OPERATIONAL_EDGE_TYPE_TRANSLATIONS:
        edge_terms.append(
            {
                "term": entry["term"],
                "plain_meaning": entry["plain_meaning"],
                "selected_user_phrase": ai_response_localized_phrase(entry, locale),
                "phrases": copy.deepcopy(entry["phrases"]),
                "metaphor": entry["metaphor"],
                "confusion_guardrail": entry["confusion_guardrail"],
            }
        )
    connection_terms = []
    for entry in AI_OPERATIONAL_CONNECTION_KIND_TRANSLATIONS:
        connection_terms.append(
            {
                "term": entry["term"],
                "selected_user_phrase": ai_response_localized_phrase(entry, locale),
                "phrases": copy.deepcopy(entry["phrases"]),
                "recommended_wording": entry["recommended_wording"],
            }
        )
    lifecycle_terms = []
    for entry in AI_OPERATIONAL_LIFECYCLE_TRANSLATIONS:
        lifecycle_terms.append(
            {
                "term": entry["term"],
                "selected_user_phrase": ai_response_localized_phrase(entry, locale),
                "phrases": copy.deepcopy(entry["phrases"]),
            }
        )
    return {
        "section_id": "operational_terms",
        "title": "operational terminology translation layer",
        "locale": locale,
        "beginner_explanation": "WOM keeps stable internal terms for machines, but AI responses should translate them into plain user language before asking a human to decide.",
        "answer_order": [
            "Name the human-facing meaning first.",
            "Show the internal WOM term in backticks only after the plain meaning is clear.",
            "Separate source_mechanism from relationship_meaning.",
            "When the relation is weak or broad, ask the human to name it or drop it instead of inventing a stronger tie.",
        ],
        "edge_type_terms": edge_terms,
        "connection_kind_terms": connection_terms,
        "lifecycle_terms": lifecycle_terms,
        "semantic_source_mechanism_note": {
            "synced_block_reference": "Currently translates through semantic unless the human names a more specific meaning.",
            "internal_url_hyperlink": "Currently translates through semantic unless the human names a more specific meaning.",
            "notion_containment": "Use contains for structural child page/database nesting; do not coerce it into view_query, references, material, or inherited_by.",
            "decision": "Do not add new edge types only to preserve provider mechanisms; keep source_mechanism metadata separate.",
        },
        "bundling_guidance": [
            "For beginners, material and derived_from can be explained as source material before exposing direction details.",
            "For beginners, semantic and references can be explained as meaning/reference links before asking for a precise name.",
            "For beginners, contains can be explained as one page structurally holding a child page or database.",
            "Use supersedes for version chains where a newer zet replaces an older one.",
        ],
        "do_not_say": [
            "This semantic edge proves the pages are the same thing.",
            "A Notion internal URL needs its own durable WOM edge type by default.",
            "A synced block source mechanism is already a final relationship meaning.",
            "A child database should be forced into view_query or references when contains is missing.",
        ],
    }


