def credential_vault_onboarding_store_id_from_recommendation(recommendation: dict[str, Any]) -> str:
    store_id = str(recommendation.get("store_id") or "").strip().lower().replace("-", "_")
    store_class = str(recommendation.get("store_class") or "").strip().lower().replace("-", "_")
    if store_id in CREDENTIAL_VAULT_ONBOARDING_STORE_IDS and store_id != "recommended":
        return store_id
    if store_id == "bitwarden_secrets_manager_or_cloud_secret_manager" or store_class == "developer_secret_manager":
        return "developer_secret_manager"
    if store_class == "operating_system_credential_store":
        return "os_keyring"
    if store_class == "browser_platform_password_manager":
        return "browser_or_platform_password_manager"
    if store_class == "runtime_injection":
        return "environment_variable"
    return "keepassxc"


def credential_vault_default_action_for_scenario(scenario: str) -> str:
    if scenario == "institutional_mail":
        return "mail_source_read"
    if scenario == "browser_or_platform_password_manager":
        return "browser_login_fill"
    if scenario == "team_or_family_sharing":
        return "browser_login_fill"
    if scenario == "automation_or_dev_secrets":
        return "model_api_call"
    return "model_api_call"


def credential_vault_default_adapter_operation(action_kind: str) -> str:
    if action_kind == "browser_login_fill":
        return "browser_login_fill"
    if action_kind == "plaintext_secret_migration":
        return "plaintext_secret_migration"
    return "resolve_for_approved_action"


def credential_access_broker_plan(
    archive_root: Path | str,
    *,
    credential_id: str,
    action_kind: str,
    store_kind: str = "password_manager",
    credential_ref: str | None = None,
    credential_kind: str | None = None,
    provider: str | None = None,
    consumer: str | None = None,
    platform: str = "windows",
    dry_run: bool = True,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []

    if not dry_run:
        blockers.append("credential-access-broker-plan is read-only and requires --dry-run.")

    resolved_credential_id = (credential_id or "").strip()
    if not resolved_credential_id:
        blockers.append("credential_id is required.")
    elif not safe_source_intake_plan_scalar(resolved_credential_id):
        blockers.append("credential_id must be a safe non-secret label such as cred:openai-api.")
        resolved_credential_id = ""

    resolved_action = (action_kind or "").strip().lower().replace("-", "_")
    if resolved_action not in CREDENTIAL_ACCESS_BROKER_ACTIONS:
        blockers.append("action_kind must be one of: " + ", ".join(sorted(CREDENTIAL_ACCESS_BROKER_ACTIONS)) + ".")
        resolved_action = "model_api_call"

    resolved_store = (store_kind or "password_manager").strip().lower().replace("-", "_")
    if resolved_store not in CREDENTIAL_ACCESS_BROKER_STORE_KINDS:
        blockers.append("store_kind must be one of: " + ", ".join(sorted(CREDENTIAL_ACCESS_BROKER_STORE_KINDS)) + ".")
        resolved_store = "password_manager"

    resolved_platform = (platform or "windows").strip().lower().replace("-", "_")
    if resolved_platform not in CREDENTIAL_STORE_RECOMMENDATION_PLATFORMS:
        blockers.append("platform must be one of: " + ", ".join(sorted(CREDENTIAL_STORE_RECOMMENDATION_PLATFORMS)) + ".")
        resolved_platform = "cross_platform"

    resolved_consumer = (consumer or "wom_local_adapter").strip()
    if not safe_source_intake_plan_scalar(resolved_consumer):
        blockers.append("consumer must be a safe non-secret label.")
        resolved_consumer = "wom_local_adapter"

    action_profile = credential_access_action_profile(resolved_action)
    resolved_kind = (credential_kind or action_profile["recommended_credential_kind"]).strip().lower().replace("-", "_")
    if resolved_kind not in CREDENTIAL_REF_ALLOWED_KINDS:
        blockers.append("credential_kind must be one of: " + ", ".join(sorted(CREDENTIAL_REF_ALLOWED_KINDS)) + ".")
        resolved_kind = action_profile["recommended_credential_kind"]

    resolved_provider = (provider or default_credential_ref_provider(resolved_kind)).strip().lower().replace("-", "_")
    if resolved_provider not in CREDENTIAL_REF_ALLOWED_PROVIDERS:
        blockers.append("provider must be one of: " + ", ".join(sorted(CREDENTIAL_REF_ALLOWED_PROVIDERS)) + ".")
        resolved_provider = "generic_provider"

    resolved_ref = (credential_ref or "").strip()
    ref_store = None
    if resolved_ref:
        if safe_credential_ref(resolved_ref):
            ref_store = credential_ref_store(resolved_ref)
        else:
            blockers.append("credential_ref must be an env/keyring/secret/wallet reference, not a raw key, token, password, email, URL, or local path.")

    if resolved_store == "browser_platform_manager" and resolved_action not in {"browser_login_fill", "plaintext_secret_migration"}:
        warnings.append("Browser/platform password managers are best for login autofill and passkeys; API keys and CLI tokens usually need a password manager, OS keyring, or developer secret manager.")
    if resolved_action == "plaintext_secret_migration":
        warnings.append("Plaintext secret migration must start from a human-selected local file and must not print detected secrets into chat.")
    if resolved_store == "environment":
        warnings.append("Environment variables are a runtime injection surface, not a long-term human password notebook.")

    platform_keyring = {
        "windows": "Windows Credential Manager",
        "macos": "macOS Keychain",
        "linux": "Linux Secret Service compatible keyring",
        "cross_platform": "OS credential manager/keyring",
    }[resolved_platform]

    return {
        "ok": not blockers,
        "dry_run": True,
        "lifecycle_action": "credential_access_broker_plan",
        "archive_id": archive_id,
        "credential": {
            "credential_id": resolved_credential_id,
            "credential_kind": resolved_kind,
            "purpose": default_credential_ref_purpose(resolved_kind),
            "provider": resolved_provider,
            "ref_store": ref_store,
            "ref_prefix": f"{ref_store}:" if ref_store else None,
            "exact_ref_value_echoed": False,
        },
        "broker_request": {
            "action_kind": resolved_action,
            "consumer": resolved_consumer,
            "store_kind": resolved_store,
            "platform": resolved_platform,
            "secret_value_return_to_ai": False,
            "approval_required": True,
            "approval_receipt_required_before_use": True,
            "secret_value_placeholder": "<never-return-secret>",
        },
        "action_profile": action_profile,
        "approval_flow": [
            "AI requests a credential capability by credential_id, purpose, action_kind, provider, and consumer.",
            "WOM checks archive policy, source/tool scope, requested action, and whether a matching safe ref exists.",
            "Human approval is requested through a local UI or OS prompt; secrets are not pasted into chat.",
            "A future local adapter talks to the real vault, keyring, browser/platform surface, or secret manager.",
            "The adapter uses the secret only for the approved action and returns non-secret result metadata.",
            "WOM records a non-secret approval/use receipt; the secret value is never written to zets, logs, receipts, prompts, or public docs.",
        ],
        "adapter_boundary": {
            "broker_adapter_implemented": False,
            "secret_retrieval_implemented": False,
            "allowed_future_store_surfaces": credential_access_store_surfaces(resolved_store, platform_keyring),
            "disallowed_access_patterns": [
                "AI scraping browser databases directly",
                "AI reading plaintext desktop notes directly",
                "AI receiving passwords or API keys in chat",
                "Writing secrets into Git, zets, receipts, logs, prompts, source maps, screenshots, or public docs",
                "Silent background secret use without a policy gate and approval receipt",
            ],
        },
        "plaintext_migration_flow": credential_plaintext_migration_flow() if resolved_action == "plaintext_secret_migration" else None,
        "next_safe_actions": [
            "Keep using credential-store-recommendation to choose the real vault class.",
            "Use credential-ref-plan to validate refs and credential-ref-inventory to catalog refs.",
            "Design future adapter reads as local-only, policy-gated, human-approved, and non-echoing.",
            "Treat browser/platform password managers as login/passkey/autofill sources, not generic API-key stores.",
        ],
        "current_capability": {
            "broker_plan_available": True,
            "credential_ref_contract_available": True,
            "credential_store_recommendation_available": True,
            "broker_adapter_implemented": False,
            "secret_value_retrieval_implemented": False,
            "plaintext_secret_migration_implemented": False,
            "browser_password_store_read_implemented": False,
        },
        "closed_actions": {
            "secret_prompted_in_chat": False,
            "secret_value_read": False,
            "secret_value_written": False,
            "password_manager_opened": False,
            "browser_password_store_opened": False,
            "os_keyring_opened": False,
            "environment_read": False,
            "plaintext_file_read": False,
            "provider_api_called": False,
            "oauth_started": False,
            "files_written": False,
        },
        "privacy_guards": {
            "secret_values_echoed": False,
            "credential_ref_values_echoed": False,
            "email_addresses_echoed": False,
            "tokens_echoed": False,
            "local_absolute_paths_echoed": False,
            "provider_urls_echoed": False,
            "writes": False,
        },
        "would_change": [],
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }


def credential_access_approval_plan(
    archive_root: Path | str,
    *,
    credential_id: str,
    action_kind: str,
    decision: str = "needs_review",
    store_kind: str = "password_manager",
    credential_ref: str | None = None,
    credential_kind: str | None = None,
    provider: str | None = None,
    consumer: str | None = None,
    reviewed_by: str | None = None,
    platform: str = "windows",
    dry_run: bool = True,
    approve: bool = False,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []

    if dry_run is approve:
        blockers.append("Choose exactly one mode: --dry-run or --approve.")

    resolved_decision = (decision or "needs_review").strip().lower().replace("-", "_")
    if resolved_decision not in CREDENTIAL_ACCESS_APPROVAL_DECISIONS:
        blockers.append("decision must be one of: " + ", ".join(sorted(CREDENTIAL_ACCESS_APPROVAL_DECISIONS)) + ".")
        resolved_decision = "needs_review"
    if approve and resolved_decision == "needs_review":
        blockers.append("--approve requires decision approve_once or deny; needs_review is preview-only.")

    broker_preview = credential_access_broker_plan(
        root,
        credential_id=credential_id,
        credential_ref=credential_ref,
        credential_kind=credential_kind,
        provider=provider,
        action_kind=action_kind,
        store_kind=store_kind,
        consumer=consumer,
        platform=platform,
        dry_run=True,
    )
    blockers.extend(str(item) for item in broker_preview.get("blockers") or [])
    warnings.extend(str(item) for item in broker_preview.get("warnings") or [])

    resolved_reviewed_by = (reviewed_by or ("human:pending-review" if dry_run else "")).strip()
    if approve and not resolved_reviewed_by:
        blockers.append("reviewed_by is required when --approve writes a credential access approval receipt.")
        resolved_reviewed_by = "human:required"
    if not safe_source_intake_plan_scalar(resolved_reviewed_by):
        blockers.append("reviewed_by must be a safe non-secret reviewer label.")
        resolved_reviewed_by = "human:pending-review"

    credential = broker_preview.get("credential") if isinstance(broker_preview.get("credential"), dict) else {}
    broker_request = broker_preview.get("broker_request") if isinstance(broker_preview.get("broker_request"), dict) else {}
    action_profile = broker_preview.get("action_profile") if isinstance(broker_preview.get("action_profile"), dict) else {}
    case_id = credential_access_approval_case_id(
        archive_id=archive_id,
        credential_id=str(credential.get("credential_id") or ""),
        action_kind=str(broker_request.get("action_kind") or ""),
        store_kind=str(broker_request.get("store_kind") or ""),
        consumer=str(broker_request.get("consumer") or ""),
        decision=resolved_decision,
    )
    proposed_receipt_path = f"{CREDENTIAL_ACCESS_APPROVAL_RECEIPTS_DIR}/{case_id}.credential-access-approval.json"
    receipt_path = archive_internal_path(root, proposed_receipt_path)
    receipt_exists = receipt_path.is_file()
    if approve and receipt_exists:
        blockers.append(f"Credential access approval receipt already exists: {proposed_receipt_path}.")
    decision_effect = {
        "approve_once": "would_allow_one_approved_action_after_receipt_write",
        "deny": "would_deny_the_requested_action_after_receipt_write",
        "needs_review": "would_keep_the_request_pending_for_human_review",
    }[resolved_decision]
    reviewed_at = datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace("+00:00", "Z") if approve else None

    receipt_preview = {
        "receipt_id": case_id,
        "receipt_kind": "credential_access_approval",
        "schema_version": "wom-credential-access-approval/v0.1",
        "lifecycle_action": "credential_access_approval_record",
        "archive_id": archive_id,
        "receipt_path": proposed_receipt_path,
        "decision": resolved_decision,
        "decision_effect": decision_effect,
        "reviewed_by": resolved_reviewed_by,
        "reviewed_at": reviewed_at,
        "approval_status": "recorded" if approve and not blockers else "preview",
        "credential": credential,
        "broker_request": broker_request,
        "action_description": action_profile.get("description"),
        "approval_constraints": {
            "single_action_only": resolved_decision == "approve_once",
            "secret_value_return_to_ai": False,
            "approval_receipt_required_before_use": True,
            "replay_requires_new_approval": True,
            "background_use_allowed": False,
        },
        "secret_material": {
            "secret_value_included": False,
            "credential_ref_value_included": False,
            "username_included": False,
            "email_included": False,
            "token_included": False,
            "local_path_included": False,
        },
        "non_secret_result_metadata_allowed": list(action_profile.get("expected_result_metadata") or []),
        "never_return": list(action_profile.get("never_return") or []),
        "files_written": [proposed_receipt_path] if approve and not blockers else [],
    }

    if approve and not blockers:
        created_paths: list[Path] = []
        created_dirs = missing_parent_dirs_before_write(root, [receipt_path])
        try:
            receipt_path.parent.mkdir(parents=True, exist_ok=True)
            write_json_new_file(receipt_path, receipt_preview)
            created_paths.append(receipt_path)
        except OSError as exc:
            for path in reversed(created_paths):
                path.unlink(missing_ok=True)
            cleanup_empty_archive_dirs(root, created_dirs)
            raise ArchiveServiceError(f"Could not write credential access approval receipt: {exc}") from exc

    approval_receipt_written = approve and not blockers
    files_written = [proposed_receipt_path] if approval_receipt_written else []
    would_change = [proposed_receipt_path] if dry_run else []

    return {
        "ok": not blockers,
        "dry_run": bool(dry_run),
        "approved": approval_receipt_written,
        "lifecycle_action": "credential_access_approval_plan" if dry_run else "credential_access_approval_record",
        "archive_id": archive_id,
        "decision": resolved_decision,
        "decision_effect": decision_effect,
        "proposed_receipt_path": proposed_receipt_path,
        "receipt_path": proposed_receipt_path if approval_receipt_written else None,
        "receipt_exists": receipt_exists or approval_receipt_written,
        "receipt_preview": json_safe(receipt_preview),
        "broker_plan_summary": {
            "action_kind": broker_request.get("action_kind"),
            "store_kind": broker_request.get("store_kind"),
            "consumer": broker_request.get("consumer"),
            "credential_id": credential.get("credential_id"),
            "credential_kind": credential.get("credential_kind"),
            "ref_store": credential.get("ref_store"),
            "ref_prefix": credential.get("ref_prefix"),
            "exact_ref_value_echoed": False,
        },
        "next_safe_actions": [
            "Human reviews the receipt preview locally.",
            "Use --approve with decision approve_once or deny only after explicit local human review.",
            "A future broker may use approve_once only for one scoped action, then require a new receipt for replay.",
            "Secret values and exact credential refs must stay outside chat, zets, receipts, logs, prompts, and public docs.",
        ],
        "current_capability": {
            "approval_receipt_preview_available": True,
            "approval_receipt_write_implemented": True,
            "broker_adapter_implemented": False,
            "secret_value_retrieval_implemented": False,
        },
        "closed_actions": {
            "approval_receipt_written": approval_receipt_written,
            "secret_prompted_in_chat": False,
            "secret_value_read": False,
            "secret_value_written": False,
            "password_manager_opened": False,
            "browser_password_store_opened": False,
            "os_keyring_opened": False,
            "environment_read": False,
            "plaintext_file_read": False,
            "provider_api_called": False,
            "oauth_started": False,
            "files_written": bool(files_written),
        },
        "privacy_guards": {
            "secret_values_echoed": False,
            "credential_ref_values_echoed": False,
            "email_addresses_echoed": False,
            "tokens_echoed": False,
            "local_absolute_paths_echoed": False,
            "provider_urls_echoed": False,
            "writes": bool(files_written),
        },
        "would_change": would_change,
        "files_written": files_written,
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }


def credential_access_approval_case_id(
    *,
    archive_id: str,
    credential_id: str,
    action_kind: str,
    store_kind: str,
    consumer: str,
    decision: str,
) -> str:
    payload = {
        "archive_id": archive_id,
        "credential_id": credential_id,
        "action_kind": action_kind,
        "store_kind": store_kind,
        "consumer": consumer,
        "decision": decision,
    }
    digest = hashlib.sha256(json.dumps(payload, sort_keys=True, separators=(",", ":")).encode("utf-8")).hexdigest()[:20]
    return f"credential-access-{digest}"


def credential_access_approval_receipt_review(
    archive_root: Path,
    receipt_relative: str,
    *,
    expected_archive_id: str,
    expected_credential_id: str | None,
    expected_action_kind: str,
    expected_store_kind: str,
    expected_consumer: str,
    expected_decision: str,
) -> dict[str, Any]:
    blockers: list[str] = []
    warnings: list[str] = []
    normalized_receipt = ""
    try:
        normalized_receipt = normalize_archive_relative_path(receipt_relative)
    except ArchivePathError:
        blockers.append("approval_receipt must be an archive-relative credential access approval receipt path.")
    if normalized_receipt and (
        not normalized_receipt.startswith(f"{CREDENTIAL_ACCESS_APPROVAL_RECEIPTS_DIR}/")
        or not normalized_receipt.endswith(".credential-access-approval.json")
    ):
        blockers.append(f"approval_receipt must point under {CREDENTIAL_ACCESS_APPROVAL_RECEIPTS_DIR}/.")

    receipt_doc: dict[str, Any] = {}
    if normalized_receipt and not blockers:
        receipt_path = archive_internal_path(archive_root, normalized_receipt)
        if not receipt_path.is_file():
            blockers.append(f"approval_receipt was not found: {normalized_receipt}.")
        else:
            loaded = load_json_object_for_review(receipt_path, "credential access approval receipt", blockers)
            if isinstance(loaded, dict):
                receipt_doc = loaded

    serialized = json.dumps(json_safe(receipt_doc), ensure_ascii=False, sort_keys=True, default=str)
    if contains_forbidden_location_reference(serialized) or DRAFT_SECRET_VALUE_RE.search(serialized):
        blockers.append("approval_receipt contains private locator or secret-like material and cannot be used.")

    credential = receipt_doc.get("credential") if isinstance(receipt_doc.get("credential"), dict) else {}
    broker_request = receipt_doc.get("broker_request") if isinstance(receipt_doc.get("broker_request"), dict) else {}
    receipt_decision = str(receipt_doc.get("decision") or "")
    if receipt_doc:
        if receipt_doc.get("receipt_kind") != "credential_access_approval":
            blockers.append("approval_receipt receipt_kind must be credential_access_approval.")
        if receipt_doc.get("schema_version") != "wom-credential-access-approval/v0.1":
            blockers.append("approval_receipt schema_version must be wom-credential-access-approval/v0.1.")
        if receipt_doc.get("archive_id") != expected_archive_id:
            blockers.append("approval_receipt archive_id does not match this archive.")
        if receipt_decision != expected_decision:
            blockers.append("approval_receipt decision does not match the requested approval_decision.")
        if receipt_decision == "needs_review":
            blockers.append("approval_receipt must record approve_once or deny, not needs_review.")
        if expected_credential_id and credential.get("credential_id") != expected_credential_id:
            blockers.append("approval_receipt credential_id does not match the requested credential.")
        if broker_request.get("action_kind") != expected_action_kind:
            blockers.append("approval_receipt action_kind does not match the requested action.")
        if broker_request.get("store_kind") != expected_store_kind:
            blockers.append("approval_receipt store_kind does not match the requested store.")
        if broker_request.get("consumer") != expected_consumer:
            blockers.append("approval_receipt consumer does not match the requested consumer.")
        if not is_utc_z_timestamp(receipt_doc.get("reviewed_at")):
            warnings.append("approval_receipt reviewed_at is missing or not a UTC Z timestamp.")
        if not isinstance(receipt_doc.get("files_written"), list) or normalized_receipt not in receipt_doc.get("files_written", []):
            warnings.append("approval_receipt files_written does not include its archive-relative receipt path.")

    return {
        "ok": not blockers,
        "receipt_path": normalized_receipt or receipt_relative,
        "receipt_present": bool(receipt_doc),
        "receipt_id": receipt_doc.get("receipt_id"),
        "decision": receipt_decision or None,
        "reviewed_by": receipt_doc.get("reviewed_by") if isinstance(receipt_doc.get("reviewed_by"), str) else None,
        "reviewed_at": receipt_doc.get("reviewed_at") if isinstance(receipt_doc.get("reviewed_at"), str) else None,
        "credential_id": credential.get("credential_id"),
        "action_kind": broker_request.get("action_kind"),
        "store_kind": broker_request.get("store_kind"),
        "consumer": broker_request.get("consumer"),
        "secret_material": safe_summary_mapping(receipt_doc.get("secret_material")),
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }


def credential_policy_check(
    archive_root: Path | str,
    *,
    credential_id: str,
    action_kind: str,
    approval_decision: str = "needs_review",
    store_kind: str = "password_manager",
    adapter_kind: str | None = None,
    operation: str | None = None,
    credential_ref: str | None = None,
    credential_kind: str | None = None,
    provider: str | None = None,
    consumer: str | None = None,
    reviewed_by: str | None = None,
    platform: str = "windows",
    approval_receipt: str | None = None,
    dry_run: bool = True,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []
    denied_rules: list[str] = []
    satisfied_rules: list[str] = []

    if not dry_run:
        blockers.append("credential-policy-check is read-only and requires --dry-run.")

    resolved_action = (action_kind or "").strip().lower().replace("-", "_")
    if resolved_action not in CREDENTIAL_ACCESS_BROKER_ACTIONS:
        blockers.append("action_kind must be one of: " + ", ".join(sorted(CREDENTIAL_ACCESS_BROKER_ACTIONS)) + ".")
        resolved_action = "model_api_call"

    resolved_decision = (approval_decision or "needs_review").strip().lower().replace("-", "_")
    if resolved_decision not in CREDENTIAL_ACCESS_APPROVAL_DECISIONS:
        blockers.append("approval_decision must be one of: " + ", ".join(sorted(CREDENTIAL_ACCESS_APPROVAL_DECISIONS)) + ".")
        resolved_decision = "needs_review"

    resolved_store = (store_kind or "password_manager").strip().lower().replace("-", "_")
    if resolved_store not in CREDENTIAL_ACCESS_BROKER_STORE_KINDS:
        blockers.append("store_kind must be one of: " + ", ".join(sorted(CREDENTIAL_ACCESS_BROKER_STORE_KINDS)) + ".")
        resolved_store = "password_manager"

    resolved_platform = (platform or "windows").strip().lower().replace("-", "_")
    if resolved_platform not in CREDENTIAL_STORE_RECOMMENDATION_PLATFORMS:
        blockers.append("platform must be one of: " + ", ".join(sorted(CREDENTIAL_STORE_RECOMMENDATION_PLATFORMS)) + ".")
        resolved_platform = "cross_platform"

    resolved_adapter = (adapter_kind or credential_policy_default_adapter_kind(resolved_store, resolved_platform)).strip().lower().replace("-", "_")
    if resolved_adapter not in CREDENTIAL_ADAPTER_KINDS:
        blockers.append("adapter_kind must be one of: " + ", ".join(sorted(CREDENTIAL_ADAPTER_KINDS)) + ".")
        resolved_adapter = credential_policy_default_adapter_kind(resolved_store, resolved_platform)

    resolved_operation = (operation or credential_policy_default_operation(resolved_action)).strip().lower().replace("-", "_")
    if resolved_operation not in CREDENTIAL_ADAPTER_OPERATIONS:
        blockers.append("operation must be one of: " + ", ".join(sorted(CREDENTIAL_ADAPTER_OPERATIONS)) + ".")
        resolved_operation = credential_policy_default_operation(resolved_action)

    approval_preview = credential_access_approval_plan(
        root,
        credential_id=credential_id,
        credential_ref=credential_ref,
        credential_kind=credential_kind,
        provider=provider,
        action_kind=resolved_action,
        decision=resolved_decision,
        store_kind=resolved_store,
        consumer=consumer or credential_adapter_profile(resolved_adapter, resolved_platform)["default_consumer"],
        reviewed_by=reviewed_by or "human:pending-review",
        platform=resolved_platform,
        dry_run=True,
    )
    blockers.extend(str(item) for item in approval_preview.get("blockers") or [])
    warnings.extend(str(item) for item in approval_preview.get("warnings") or [])

    adapter_profile = credential_adapter_profile(resolved_adapter, resolved_platform)
    supported_operations = credential_adapter_supported_operations(resolved_adapter)
    if adapter_profile["store_kind"] != resolved_store:
        denied_rules.append(f"adapter_kind={resolved_adapter} maps to store_kind={adapter_profile['store_kind']}, not {resolved_store}.")
    else:
        satisfied_rules.append("adapter kind matches requested store kind.")

    if resolved_operation not in supported_operations:
        denied_rules.append(f"adapter_kind={resolved_adapter} does not support operation={resolved_operation}.")
    else:
        satisfied_rules.append("adapter supports requested operation.")

    allowed_operations = credential_policy_allowed_operations_for_action(resolved_action)
    if resolved_operation not in allowed_operations:
        denied_rules.append(
            f"action_kind={resolved_action} allows operation(s) {', '.join(sorted(allowed_operations))}, not {resolved_operation}."
        )
    else:
        satisfied_rules.append("operation matches requested action kind.")

    if resolved_store == "browser_platform_manager" and resolved_action not in {"browser_login_fill", "plaintext_secret_migration"}:
        denied_rules.append("browser/platform password managers are not valid for API, OCR, object-storage, CLI-token, or generic model secret retrieval.")

    if resolved_store == "environment" and resolved_operation in {"write_new_secret", "rotate_secret", "plaintext_secret_migration"}:
        denied_rules.append("environment variables are not a durable target for secret write, rotation, or plaintext migration.")

    if resolved_action == "plaintext_secret_migration" and resolved_operation == "plaintext_secret_migration":
        satisfied_rules.append("plaintext migration is scoped to human-selected local UI and per-entry confirmation.")

    receipt_preview = approval_preview.get("receipt_preview") if isinstance(approval_preview.get("receipt_preview"), dict) else {}
    broker_request = receipt_preview.get("broker_request") if isinstance(receipt_preview.get("broker_request"), dict) else {}
    credential = receipt_preview.get("credential") if isinstance(receipt_preview.get("credential"), dict) else {}
    expected_consumer = str(broker_request.get("consumer") or consumer or adapter_profile["default_consumer"])
    approval_receipt_summary = None
    approval_receipt_verified = False
    if approval_receipt:
        approval_receipt_summary = credential_access_approval_receipt_review(
            root,
            approval_receipt,
            expected_archive_id=archive_id,
            expected_credential_id=str(credential.get("credential_id") or ""),
            expected_action_kind=str(broker_request.get("action_kind") or resolved_action),
            expected_store_kind=str(broker_request.get("store_kind") or resolved_store),
            expected_consumer=expected_consumer,
            expected_decision=resolved_decision,
        )
        blockers.extend(str(item) for item in approval_receipt_summary.get("blockers") or [])
        warnings.extend(str(item) for item in approval_receipt_summary.get("warnings") or [])
        approval_receipt_verified = bool(approval_receipt_summary.get("ok"))

    if resolved_decision == "deny":
        policy_result = "denied_by_human_decision"
    elif blockers:
        policy_result = "blocked"
    elif denied_rules:
        policy_result = "denied_by_policy"
    elif resolved_decision == "needs_review":
        policy_result = "needs_human_review"
    else:
        policy_result = "ready_after_approval_receipt"

    live_execution_allowed_now = False
    would_allow_future_adapter_after_receipt = policy_result == "ready_after_approval_receipt"

    return {
        "ok": policy_result == "ready_after_approval_receipt",
        "dry_run": True,
        "lifecycle_action": "credential_policy_check",
        "archive_id": archive_id,
        "policy_result": policy_result,
        "policy_object_preview": {
            "policy_kind": "credential_access_policy",
            "schema_version": "wom-credential-policy/v0.1",
            "archive_id": archive_id,
            "rules": [
                "secret values must never be returned to AI/chat/logs/receipts",
                "exact credential refs must not be echoed in AI-visible output",
                "one action requires one scoped human approval receipt",
                "adapter kind must match the requested store kind",
                "adapter operation must match the requested action kind",
                "plaintext migration requires visible local UI and per-entry confirmation",
                "browser/platform stores are login/passkey surfaces, not general API-key vaults",
            ],
        },
        "request": {
            "credential_id": credential.get("credential_id"),
            "credential_kind": credential.get("credential_kind"),
            "provider": credential.get("provider"),
            "ref_store": credential.get("ref_store"),
            "ref_prefix": credential.get("ref_prefix"),
            "exact_ref_value_echoed": False,
            "action_kind": broker_request.get("action_kind") or resolved_action,
            "store_kind": broker_request.get("store_kind") or resolved_store,
            "adapter_kind": resolved_adapter,
            "operation": resolved_operation,
            "consumer": broker_request.get("consumer") or consumer or adapter_profile["default_consumer"],
            "platform": resolved_platform,
            "approval_decision": resolved_decision,
        },
        "policy_evaluation": {
            "satisfied_rules": unique_preserve_order(satisfied_rules),
            "denied_rules": unique_preserve_order(denied_rules),
            "approval_receipt_required_before_use": True,
            "approval_receipt_written": approval_receipt_verified,
            "approval_receipt_verified": approval_receipt_verified,
            "approval_receipt_preview_path": approval_preview.get("proposed_receipt_path"),
            "approval_receipt_path": approval_receipt_summary.get("receipt_path") if isinstance(approval_receipt_summary, dict) else None,
            "live_execution_allowed_now": live_execution_allowed_now,
            "would_allow_future_adapter_after_receipt": would_allow_future_adapter_after_receipt,
            "future_adapter_has_verified_receipt": approval_receipt_verified and would_allow_future_adapter_after_receipt,
            "secret_value_return_to_ai": False,
            "secret_value_echoed": False,
            "exact_ref_value_echoed": False,
        },
        "next_gate": {
            "if_ready": "verified approval receipt can be required by a future adapter; live adapter execution is still a separate command",
            "if_needs_review": "human must approve_once or deny through a local approval UI",
            "if_denied": "do not call a live adapter",
        },
        "current_capability": {
            "policy_check_available": True,
            "policy_object_preview_available": True,
            "approval_receipt_preview_available": True,
            "approval_receipt_write_implemented": True,
            "live_adapter_implemented": False,
            "secret_value_read_implemented": False,
            "secret_value_write_implemented": False,
        },
        "approval_receipt_summary": json_safe(approval_receipt_summary) if isinstance(approval_receipt_summary, dict) else None,
        "closed_actions": {
            "approval_receipt_written": False,
            "live_adapter_executed": False,
            "secret_prompted_in_chat": False,
            "secret_value_read": False,
            "secret_value_written": False,
            "password_manager_opened": False,
            "browser_password_store_opened": False,
            "os_keyring_opened": False,
            "environment_read": False,
            "plaintext_file_read": False,
            "provider_api_called": False,
            "oauth_started": False,
            "files_written": False,
        },
        "privacy_guards": {
            "secret_values_echoed": False,
            "credential_ref_values_echoed": False,
            "email_addresses_echoed": False,
            "tokens_echoed": False,
            "local_absolute_paths_echoed": False,
            "provider_urls_echoed": False,
            "writes": False,
        },
        "would_change": [],
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }


def credential_keepassxc_command_plan(
    archive_root: Path | str,
    *,
    credential_id: str,
    approval_receipt: str | None,
    entry_label: str,
    group_label: str | None = None,
    database_ref: str | None = None,
    action_kind: str = "plaintext_secret_migration",
    operation: str = "plaintext_secret_migration",
    credential_ref: str | None = None,
    credential_kind: str | None = None,
    provider: str | None = None,
    consumer: str | None = None,
    reviewed_by: str | None = None,
    platform: str = "windows",
    dry_run: bool = True,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []

    if not dry_run:
        blockers.append("credential-keepassxc-command-plan is read-only and requires --dry-run.")

    resolved_consumer = (consumer or credential_adapter_profile("keepassxc_cli", platform)["default_consumer"]).strip()
    if not safe_source_intake_plan_scalar(resolved_consumer):
        blockers.append("consumer must be a safe non-secret label.")
        resolved_consumer = "wom:adapter:keepassxc"

    resolved_action = (action_kind or "plaintext_secret_migration").strip().lower().replace("-", "_")
    if resolved_action not in CREDENTIAL_ACCESS_BROKER_ACTIONS:
        blockers.append("action_kind must be one of: " + ", ".join(sorted(CREDENTIAL_ACCESS_BROKER_ACTIONS)) + ".")
        resolved_action = "plaintext_secret_migration"

    resolved_operation = (operation or "plaintext_secret_migration").strip().lower().replace("-", "_")
    allowed_keepassxc_operations = {"plaintext_secret_migration", "write_new_secret"}
    if resolved_operation not in allowed_keepassxc_operations:
        blockers.append("operation must be plaintext_secret_migration or write_new_secret for credential-keepassxc-command-plan.")
        resolved_operation = "plaintext_secret_migration"

    resolved_platform = (platform or "windows").strip().lower().replace("-", "_")
    if resolved_platform not in CREDENTIAL_STORE_RECOMMENDATION_PLATFORMS:
        blockers.append("platform must be one of: " + ", ".join(sorted(CREDENTIAL_STORE_RECOMMENDATION_PLATFORMS)) + ".")
        resolved_platform = "windows"

    resolved_entry_label = safe_keepassxc_command_label(entry_label, "entry_label", blockers)
    resolved_group_label = safe_optional_keepassxc_command_label(group_label, "group_label", blockers)
    resolved_database_ref = safe_optional_keepassxc_command_label(
        database_ref or "keepassxc:human-selected-database",
        "database_ref",
        blockers,
    )
    if not approval_receipt:
        blockers.append("approval_receipt is required before planning a KeePassXC command.")

    policy_check = credential_policy_check(
        root,
        credential_id=credential_id,
        credential_ref=credential_ref,
        credential_kind=credential_kind,
        provider=provider,
        action_kind=resolved_action,
        approval_decision="approve_once",
        store_kind="password_manager",
        adapter_kind="keepassxc_cli",
        operation=resolved_operation,
        consumer=resolved_consumer,
        reviewed_by=reviewed_by or "human:pending-review",
        platform=resolved_platform,
        approval_receipt=approval_receipt,
        dry_run=True,
    )
    blockers.extend(str(item) for item in policy_check.get("blockers") or [])
    warnings.extend(str(item) for item in policy_check.get("warnings") or [])
    policy_evaluation = policy_check.get("policy_evaluation") if isinstance(policy_check.get("policy_evaluation"), dict) else {}
    approval_receipt_verified = bool(policy_evaluation.get("approval_receipt_verified"))
    if approval_receipt and not approval_receipt_verified:
        blockers.append("approval_receipt must verify before a KeePassXC command plan can be considered ready.")
    if policy_check.get("policy_result") != "ready_after_approval_receipt":
        blockers.append("credential policy must be ready_after_approval_receipt before a KeePassXC command plan can be considered ready.")

    entry_target_placeholder = "<safe-entry-label>"
    if resolved_entry_label:
        entry_target_placeholder = resolved_entry_label
        if resolved_group_label:
            entry_target_placeholder = f"{resolved_group_label}/{resolved_entry_label}"

    command_plan = {
        "adapter_kind": "keepassxc_cli",
        "subcommand": "add",
        "argv_preview": [
            "keepassxc-cli",
            "add",
            "--password-prompt",
            "<database.kdbx selected by human outside WOM>",
            entry_target_placeholder,
        ],
        "database_ref": resolved_database_ref,
        "database_path_included": False,
        "database_unlock_mode": "local_keepassxc_cli_prompt",
        "entry_label": resolved_entry_label or None,
        "group_label": resolved_group_label,
        "entry_target_label_included": bool(resolved_entry_label),
        "password_entry_mode": "local_cli_password_prompt",
        "secret_value_in_argv": False,
        "secret_value_in_stdin": False,
        "username_included": False,
        "url_included": False,
        "exact_credential_ref_echoed": False,
        "command_execution_implemented": False,
        "live_execution_allowed_now": False,
    }

    return {
        "ok": not blockers,
        "dry_run": True,
        "lifecycle_action": "credential_keepassxc_command_plan",
        "archive_id": archive_id,
        "adapter": {
            "adapter_kind": "keepassxc_cli",
            "store_kind": "password_manager",
            "operation": resolved_operation,
            "action_kind": resolved_action,
            "consumer": resolved_consumer,
            "platform": resolved_platform,
            "approval_receipt_required": True,
            "approval_receipt_verified": approval_receipt_verified,
            "live_execution_allowed_now": False,
        },
        "policy_check_summary": {
            "policy_result": policy_check.get("policy_result"),
            "ok": bool(policy_check.get("ok")),
            "approval_receipt_verified": approval_receipt_verified,
            "future_adapter_has_verified_receipt": bool(policy_evaluation.get("future_adapter_has_verified_receipt")),
            "live_execution_allowed_now": bool(policy_evaluation.get("live_execution_allowed_now")),
        },
        "command_plan": command_plan,
        "execution_boundary": {
            "official_keepassxc_cli_shape": "keepassxc-cli add [options] <database> <entry>",
            "uses_password_prompt": True,
            "database_selected_outside_wom": True,
            "database_path_recorded_in_wom": False,
            "secret_value_return_to_ai": False,
            "requires_local_human_terminal_or_adapter_ui": True,
            "requires_followup_audit_receipt_after_future_execution": True,
        },
        "next_safe_actions": [
            "Use credential-access-approval --approve to create one scoped receipt before this plan.",
            "Use this plan only as a local preflight; do not paste vault passwords, entry passwords, usernames, URLs, or API keys into chat.",
            "When a future live adapter exists, it must select the KeePassXC database outside WOM and use the local CLI prompt for secret entry.",
            "After any future execution, record a non-secret credential adapter audit receipt.",
        ],
        "current_capability": {
            "keepassxc_command_plan_available": True,
            "approval_receipt_verification_required": True,
            "policy_check_reused": True,
            "command_execution_implemented": False,
            "secret_value_write_implemented": False,
            "database_path_storage_implemented": False,
        },
        "closed_actions": {
            "live_adapter_executed": False,
            "keepassxc_opened": False,
            "password_manager_opened": False,
            "database_path_read": False,
            "database_password_read": False,
            "secret_prompted_in_chat": False,
            "secret_value_read": False,
            "secret_value_written": False,
            "secret_value_piped_to_stdin": False,
            "plaintext_file_read": False,
            "provider_api_called": False,
            "oauth_started": False,
            "files_written": False,
        },
        "privacy_guards": {
            "secret_values_echoed": False,
            "credential_ref_values_echoed": False,
            "database_paths_echoed": False,
            "email_addresses_echoed": False,
            "tokens_echoed": False,
            "local_absolute_paths_echoed": False,
            "provider_urls_echoed": False,
            "writes": False,
        },
        "would_change": [],
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }


def credential_keepassxc_write(
    archive_root: Path | str,
    *,
    credential_id: str,
    approval_receipt: str | None,
    entry_label: str,
    database_path: str | Path | None = None,
    group_label: str | None = None,
    database_ref: str | None = None,
    action_kind: str = "plaintext_secret_migration",
    operation: str = "plaintext_secret_migration",
    credential_ref: str | None = None,
    credential_kind: str | None = None,
    provider: str | None = None,
    consumer: str | None = None,
    reviewed_by: str | None = None,
    platform: str = "windows",
    dry_run: bool = True,
    approve: bool = False,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []

    if dry_run is approve:
        blockers.append("Choose exactly one mode: --dry-run or --approve.")

    command_plan = credential_keepassxc_command_plan(
        root,
        credential_id=credential_id,
        credential_ref=credential_ref,
        credential_kind=credential_kind,
        provider=provider,
        action_kind=action_kind,
        operation=operation,
        approval_receipt=approval_receipt,
        entry_label=entry_label,
        group_label=group_label,
        database_ref=database_ref,
        consumer=consumer,
        reviewed_by=reviewed_by,
        platform=platform,
        dry_run=True,
    )
    blockers.extend(str(item) for item in command_plan.get("blockers") or [])
    warnings.extend(str(item) for item in command_plan.get("warnings") or [])

    adapter = command_plan.get("adapter") if isinstance(command_plan.get("adapter"), dict) else {}
    command_plan_payload = command_plan.get("command_plan") if isinstance(command_plan.get("command_plan"), dict) else {}
    policy_summary = command_plan.get("policy_check_summary") if isinstance(command_plan.get("policy_check_summary"), dict) else {}
    resolved_operation = str(adapter.get("operation") or operation or "plaintext_secret_migration")
    resolved_action = str(adapter.get("action_kind") or action_kind or "plaintext_secret_migration")
    resolved_consumer = str(adapter.get("consumer") or consumer or "wom:adapter:keepassxc")
    resolved_platform = str(adapter.get("platform") or platform or "windows")
    resolved_entry_label = command_plan_payload.get("entry_label") if isinstance(command_plan_payload.get("entry_label"), str) else ""
    resolved_group_label = command_plan_payload.get("group_label") if isinstance(command_plan_payload.get("group_label"), str) else None
    resolved_database_ref = command_plan_payload.get("database_ref") if isinstance(command_plan_payload.get("database_ref"), str) else None
    entry_target = keepassxc_entry_target_label(resolved_entry_label, resolved_group_label)

    normalized_approval_receipt = None
    if approval_receipt:
        try:
            normalized_approval_receipt = normalize_archive_relative_path(approval_receipt)
        except ArchivePathError:
            normalized_approval_receipt = None

    execution_case_id = credential_keepassxc_write_case_id(
        archive_id=archive_id,
        credential_id=credential_id,
        action_kind=resolved_action,
        operation=resolved_operation,
        consumer=resolved_consumer,
        approval_receipt=normalized_approval_receipt or "invalid-or-missing-approval-receipt",
        entry_label=resolved_entry_label,
        group_label=resolved_group_label,
    )
    proposed_receipt_path = f"{CREDENTIAL_KEEPASSXC_WRITE_RECEIPTS_DIR}/{execution_case_id}.credential-keepassxc-write.json"
    receipt_path = archive_internal_path(root, proposed_receipt_path)
    receipt_exists = receipt_path.is_file()
    if receipt_exists:
        blockers.append("approval_receipt already has a KeePassXC write execution receipt; create a new approval receipt before replay.")

    selected_database_path: Path | None = None
    if approve:
        selected_database_path = safe_keepassxc_database_path_for_write(database_path, root, blockers)
        if shutil.which("keepassxc-cli") is None:
            blockers.append("keepassxc-cli was not found on PATH.")
    elif database_path is not None:
        safe_keepassxc_database_path_for_write(database_path, root, blockers, required=False)

    reviewed_by_value = (reviewed_by or ("human:pending-review" if dry_run else "")).strip()
    if approve and not reviewed_by_value:
        blockers.append("reviewed_by is required when --approve executes a KeePassXC write.")
        reviewed_by_value = "human:required"
    if reviewed_by_value and not safe_source_intake_plan_scalar(reviewed_by_value):
        blockers.append("reviewed_by must be a safe non-secret reviewer label.")
        reviewed_by_value = "human:pending-review"

    receipt_preview = credential_keepassxc_write_receipt_payload(
        archive_id=archive_id,
        receipt_id=execution_case_id,
        receipt_path=proposed_receipt_path,
        approval_receipt=normalized_approval_receipt,
        credential_id=credential_id,
        credential_kind=credential_kind,
        provider=provider,
        action_kind=resolved_action,
        operation=resolved_operation,
        consumer=resolved_consumer,
        platform=resolved_platform,
        entry_label=resolved_entry_label,
        group_label=resolved_group_label,
        database_ref=resolved_database_ref,
        reviewed_by=reviewed_by_value or "human:pending-review",
        status="planned" if dry_run else "blocked",
        started_at=None,
        finished_at=None,
        return_code=None,
    )

    if blockers:
        return credential_keepassxc_write_result(
            ok=False,
            dry_run=dry_run,
            archive_id=archive_id,
            receipt_path=None,
            proposed_receipt_path=proposed_receipt_path,
            receipt_exists=receipt_exists,
            command_plan=command_plan,
            receipt_preview=receipt_preview,
            execution_status="blocked",
            return_code=None,
            files_written=[],
            would_change=[proposed_receipt_path, "KeePassXC database entry selected locally"] if dry_run else [],
            blockers=blockers,
            warnings=warnings,
        )

    if dry_run:
        return credential_keepassxc_write_result(
            ok=True,
            dry_run=True,
            archive_id=archive_id,
            receipt_path=None,
            proposed_receipt_path=proposed_receipt_path,
            receipt_exists=receipt_exists,
            command_plan=command_plan,
            receipt_preview=receipt_preview,
            execution_status="planned",
            return_code=None,
            files_written=[],
            would_change=[proposed_receipt_path, "KeePassXC database entry selected locally"],
            blockers=[],
            warnings=warnings,
        )

    assert selected_database_path is not None
    started_at = datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace("+00:00", "Z")
    started_receipt = credential_keepassxc_write_receipt_payload(
        archive_id=archive_id,
        receipt_id=execution_case_id,
        receipt_path=proposed_receipt_path,
        approval_receipt=normalized_approval_receipt,
        credential_id=credential_id,
        credential_kind=credential_kind,
        provider=provider,
        action_kind=resolved_action,
        operation=resolved_operation,
        consumer=resolved_consumer,
        platform=resolved_platform,
        entry_label=resolved_entry_label,
        group_label=resolved_group_label,
        database_ref=resolved_database_ref,
        reviewed_by=reviewed_by_value,
        status="started",
        started_at=started_at,
        finished_at=None,
        return_code=None,
    )

    created_dirs = missing_parent_dirs_before_write(root, [receipt_path])
    try:
        receipt_path.parent.mkdir(parents=True, exist_ok=True)
        write_json_new_file(receipt_path, started_receipt)
    except OSError as exc:
        cleanup_empty_archive_dirs(root, [receipt_path])
        cleanup_created_empty_dirs(root, created_dirs)
        raise ArchiveServiceError(f"Could not write KeePassXC execution receipt before adapter run: {exc}") from exc

    return_code: int | None = None
    execution_status = "failed"
    try:
        return_code = run_keepassxc_cli_add(
            [
                shutil.which("keepassxc-cli") or "keepassxc-cli",
                "add",
                "--password-prompt",
                str(selected_database_path),
                entry_target,
            ]
        )
        execution_status = "succeeded" if return_code == 0 else "failed"
        if return_code != 0:
            warnings.append("keepassxc-cli returned a non-zero exit code; raw output is not captured or echoed.")
    except OSError:
        warnings.append("keepassxc-cli could not be executed; raw exception details are not echoed.")
        execution_status = "failed"

    finished_at = datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace("+00:00", "Z")
    final_receipt = credential_keepassxc_write_receipt_payload(
        archive_id=archive_id,
        receipt_id=execution_case_id,
        receipt_path=proposed_receipt_path,
        approval_receipt=normalized_approval_receipt,
        credential_id=credential_id,
        credential_kind=credential_kind,
        provider=provider,
        action_kind=resolved_action,
        operation=resolved_operation,
        consumer=resolved_consumer,
        platform=resolved_platform,
        entry_label=resolved_entry_label,
        group_label=resolved_group_label,
        database_ref=resolved_database_ref,
        reviewed_by=reviewed_by_value,
        status=execution_status,
        started_at=started_at,
        finished_at=finished_at,
        return_code=return_code,
    )
    try:
        receipt_path.write_text(json.dumps(json_safe(final_receipt), indent=2, ensure_ascii=False, default=str) + "\n", encoding="utf-8")
    except OSError as exc:
        raise ArchiveServiceError("KeePassXC adapter ran, but its non-secret execution receipt could not be finalized.") from exc

    files_written = [proposed_receipt_path]
    return credential_keepassxc_write_result(
        ok=execution_status == "succeeded",
        dry_run=False,
        archive_id=archive_id,
        receipt_path=proposed_receipt_path,
        proposed_receipt_path=proposed_receipt_path,
        receipt_exists=True,
        command_plan=command_plan,
        receipt_preview=final_receipt,
        execution_status=execution_status,
        return_code=return_code,
        files_written=files_written,
        would_change=[],
        blockers=[],
        warnings=warnings,
    )


def credential_keepassxc_write_case_id(
    *,
    archive_id: str,
    credential_id: str,
    action_kind: str,
    operation: str,
    consumer: str,
    approval_receipt: str,
    entry_label: str,
    group_label: str | None,
) -> str:
    payload = {
        "archive_id": archive_id,
        "credential_id": credential_id,
        "action_kind": action_kind,
        "operation": operation,
        "consumer": consumer,
        "approval_receipt": approval_receipt,
        "entry_label": entry_label,
        "group_label": group_label,
    }
    digest = hashlib.sha256(json.dumps(payload, sort_keys=True, separators=(",", ":")).encode("utf-8")).hexdigest()[:20]
    return f"keepassxc-write-{digest}"


def keepassxc_entry_target_label(entry_label: str, group_label: str | None) -> str:
    if group_label:
        return f"{group_label}/{entry_label}"
    return entry_label


def safe_keepassxc_database_path_for_write(
    value: str | Path | None,
    archive_root: Path,
    blockers: list[str],
    *,
    required: bool = True,
) -> Path | None:
    if value is None or not str(value).strip():
        if required:
            blockers.append("database_path is required for --approve and must point to an existing local .kdbx file.")
        return None
    try:
        candidate = Path(value).expanduser().resolve()
    except (OSError, RuntimeError, ValueError):
        blockers.append("database_path could not be resolved safely.")
        return None
    if candidate.suffix.lower() != ".kdbx" or not candidate.is_file():
        blockers.append("database_path must point to an existing local .kdbx file selected by the human operator.")
        return None
    try:
        if is_path_within_root(candidate, archive_root.resolve()):
            blockers.append("database_path must be outside the WOM archive root so a vault file is not accidentally published.")
            return None
    except OSError:
        blockers.append("database_path could not be checked against the archive root safely.")
        return None
    return candidate


def run_keepassxc_cli_add(argv: list[str]) -> int:
    completed = subprocess.run(argv, check=False)
    return int(completed.returncode)


