def credential_adapter_manifest_plan(
    archive_root: Path | str,
    *,
    adapter_id: str,
    adapter_kind: str,
    operations: list[str] | None = None,
    store_kind: str | None = None,
    consumer: str | None = None,
    platform: str = "windows",
    dry_run: bool = True,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []

    if not dry_run:
        blockers.append("credential-adapter-manifest-plan is read-only and requires --dry-run.")

    resolved_adapter_id = (adapter_id or "").strip()
    if not safe_credential_adapter_id(resolved_adapter_id):
        blockers.append("adapter_id must be a safe path-segment label such as win-keyring or keepassxc-local.")
        resolved_adapter_id = "adapter"

    resolved_adapter = (adapter_kind or "").strip().lower().replace("-", "_")
    if resolved_adapter not in CREDENTIAL_ADAPTER_KINDS:
        blockers.append("adapter_kind must be one of: " + ", ".join(sorted(CREDENTIAL_ADAPTER_KINDS)) + ".")
        resolved_adapter = "keepassxc_cli"

    resolved_platform = (platform or "windows").strip().lower().replace("-", "_")
    if resolved_platform not in CREDENTIAL_STORE_RECOMMENDATION_PLATFORMS:
        blockers.append("platform must be one of: " + ", ".join(sorted(CREDENTIAL_STORE_RECOMMENDATION_PLATFORMS)) + ".")
        resolved_platform = "cross_platform"

    adapter_profile = credential_adapter_profile(resolved_adapter, resolved_platform)
    inferred_store = str(adapter_profile["store_kind"])
    resolved_store = (store_kind or inferred_store).strip().lower().replace("-", "_")
    if resolved_store not in CREDENTIAL_ACCESS_BROKER_STORE_KINDS:
        blockers.append("store_kind must be one of: " + ", ".join(sorted(CREDENTIAL_ACCESS_BROKER_STORE_KINDS)) + ".")
        resolved_store = inferred_store
    if resolved_store != inferred_store:
        warnings.append(f"adapter_kind={resolved_adapter} normally maps to store_kind={inferred_store}.")

    resolved_consumer = (consumer or adapter_profile["default_consumer"]).strip()
    if not safe_source_intake_plan_scalar(resolved_consumer):
        blockers.append("consumer must be a safe non-secret adapter label.")
        resolved_consumer = adapter_profile["default_consumer"]

    supported_operations = credential_adapter_supported_operations(resolved_adapter)
    requested_operations: list[str] = []
    for item in operations or supported_operations:
        normalized = str(item or "").strip().lower().replace("-", "_")
        if normalized not in CREDENTIAL_ADAPTER_OPERATIONS:
            blockers.append("operations must contain only: " + ", ".join(sorted(CREDENTIAL_ADAPTER_OPERATIONS)) + ".")
            continue
        requested_operations.append(normalized)
    requested_operations = unique_preserve_order(requested_operations)
    if not requested_operations:
        requested_operations = list(supported_operations)
    unsupported = [item for item in requested_operations if item not in supported_operations]
    for item in unsupported:
        warnings.append(f"adapter_kind={resolved_adapter} does not normally support operation={item}.")

    manifest_preview = {
        "schema": CREDENTIAL_ADAPTER_MANIFEST_SCHEMA,
        "manifest_kind": "credential_adapter_manifest",
        "manifest_version": "v0.1",
        "archive_id": archive_id,
        "adapter_id": resolved_adapter_id,
        "adapter_kind": resolved_adapter,
        "adapter_family": adapter_profile["adapter_family"],
        "store_kind": resolved_store,
        "platform": resolved_platform,
        "consumer": resolved_consumer,
        "expected_ref_prefixes": list(adapter_profile["expected_ref_prefixes"]),
        "supported_operations": requested_operations,
        "requires": {
            "policy_gate_before_use": True,
            "approval_receipt_before_use": True,
            "local_human_ui_for_secret_writes": True,
            "non_echo_contract": True,
            "audit_receipt_after_use": True,
        },
        "privacy_contract": {
            "secret_values_in_manifest": False,
            "exact_credential_refs_in_manifest": False,
            "local_absolute_paths_in_manifest": False,
            "provider_account_values_in_manifest": False,
            "provider_urls_in_manifest": False,
            "ai_visible_secret_output_allowed": False,
        },
        "closed_actions": {
            "adapter_manifest_written": False,
            "secret_value_read": False,
            "secret_value_written": False,
            "password_manager_opened": False,
            "browser_password_store_opened": False,
            "os_keyring_opened": False,
            "environment_read": False,
            "plaintext_file_read": False,
            "provider_api_called": False,
        },
    }

    schema_issues = validate_schema(manifest_preview, "credential-adapter-manifest.schema.json")
    if schema_issues:
        blockers.extend(f"{issue.data_path}: {issue.message}" for issue in schema_issues)

    proposed_manifest_path = f"{CREDENTIAL_ADAPTER_MANIFESTS_DIR}/{resolved_adapter_id}.credential-adapter.json"
    return {
        "ok": not blockers,
        "dry_run": True,
        "lifecycle_action": "credential_adapter_manifest_plan",
        "archive_id": archive_id,
        "proposed_manifest_path": proposed_manifest_path,
        "manifest_preview": json_safe(manifest_preview),
        "schema_validation": {
            "schema_name": "credential-adapter-manifest.schema.json",
            "ok": not schema_issues,
            "issue_count": len(schema_issues),
        },
        "next_safe_actions": [
            "Review the manifest preview locally.",
            "Only a future approval-gated writer may persist this manifest.",
            "Use credential-adapter-readiness-plan to evaluate a concrete operation before any live adapter exists.",
            "Keep real vault paths, account values, tokens, passwords, and exact credential refs out of adapter manifests.",
        ],
        "current_capability": {
            "adapter_manifest_preview_available": True,
            "adapter_manifest_schema_available": True,
            "adapter_manifest_write_implemented": False,
            "live_adapter_implemented": False,
            "secret_value_read_implemented": False,
            "secret_value_write_implemented": False,
        },
        "closed_actions": dict(manifest_preview["closed_actions"]),
        "privacy_guards": {
            "secret_values_echoed": False,
            "credential_ref_values_echoed": False,
            "email_addresses_echoed": False,
            "tokens_echoed": False,
            "local_absolute_paths_echoed": False,
            "provider_urls_echoed": False,
            "writes": False,
        },
        "would_change": [],
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }


def credential_adapter_audit_plan(
    archive_root: Path | str,
    *,
    adapter_id: str,
    adapter_kind: str,
    operation: str,
    credential_id: str,
    action_kind: str,
    result_status: str = "not_run",
    store_kind: str | None = None,
    credential_kind: str | None = None,
    provider: str | None = None,
    consumer: str | None = None,
    platform: str = "windows",
    dry_run: bool = True,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []

    if not dry_run:
        blockers.append("credential-adapter-audit-plan is read-only and requires --dry-run.")

    resolved_result_status = (result_status or "not_run").strip().lower().replace("-", "_")
    if resolved_result_status not in CREDENTIAL_ADAPTER_AUDIT_RESULT_STATUSES:
        blockers.append("result_status must be one of: " + ", ".join(sorted(CREDENTIAL_ADAPTER_AUDIT_RESULT_STATUSES)) + ".")
        resolved_result_status = "not_run"

    manifest_preview = credential_adapter_manifest_plan(
        root,
        adapter_id=adapter_id,
        adapter_kind=adapter_kind,
        operations=[operation],
        store_kind=store_kind,
        consumer=consumer,
        platform=platform,
        dry_run=True,
    )
    blockers.extend(str(item) for item in manifest_preview.get("blockers") or [])
    warnings.extend(str(item) for item in manifest_preview.get("warnings") or [])

    manifest = manifest_preview.get("manifest_preview") if isinstance(manifest_preview.get("manifest_preview"), dict) else {}
    readiness_preview = credential_adapter_readiness_plan(
        root,
        adapter_kind=str(manifest.get("adapter_kind") or adapter_kind),
        operation=operation,
        credential_id=credential_id,
        credential_ref=None,
        credential_kind=credential_kind,
        provider=provider,
        action_kind=action_kind,
        store_kind=str(manifest.get("store_kind") or store_kind or "password_manager"),
        consumer=str(manifest.get("consumer") or consumer or "wom:adapter"),
        platform=str(manifest.get("platform") or platform),
        dry_run=True,
    )
    blockers.extend(str(item) for item in readiness_preview.get("blockers") or [])
    warnings.extend(str(item) for item in readiness_preview.get("warnings") or [])

    adapter_id_for_receipt = str(manifest.get("adapter_id") or "adapter")
    operation_summary = readiness_preview.get("operation") if isinstance(readiness_preview.get("operation"), dict) else {}
    case_id = credential_adapter_audit_case_id(
        archive_id=archive_id,
        adapter_id=adapter_id_for_receipt,
        operation=str(operation_summary.get("operation") or operation),
        credential_id=str(operation_summary.get("credential_id") or credential_id),
        action_kind=str(operation_summary.get("action_kind") or action_kind),
        result_status=resolved_result_status,
    )
    proposed_receipt_path = f"{CREDENTIAL_ADAPTER_AUDIT_RECEIPTS_DIR}/{case_id}.credential-adapter-audit.json"
    receipt_preview = {
        "receipt_kind": "credential_adapter_audit",
        "schema_version": "wom-credential-adapter-audit/v0.1",
        "archive_id": archive_id,
        "result_status": resolved_result_status,
        "adapter": {
            "adapter_id": adapter_id_for_receipt,
            "adapter_kind": manifest.get("adapter_kind"),
            "adapter_family": manifest.get("adapter_family"),
            "store_kind": manifest.get("store_kind"),
            "platform": manifest.get("platform"),
            "consumer": manifest.get("consumer"),
        },
        "operation": operation_summary,
        "approval": {
            "approval_receipt_required_before_use": True,
            "approval_receipt_ref_included": False,
            "approval_receipt_writer_implemented": False,
        },
        "manifest": {
            "manifest_required_before_live_use": True,
            "manifest_ref_included": False,
            "manifest_writer_implemented": False,
        },
        "non_secret_result_metadata_allowed": [
            "result_status",
            "adapter_id",
            "adapter_kind",
            "operation",
            "action_kind",
            "credential_id",
            "provider",
            "cost_class",
            "source_object_ids",
            "derived_text_receipt_refs",
            "error_class",
        ],
        "secret_material": {
            "secret_value_included": False,
            "credential_ref_value_included": False,
            "username_included": False,
            "email_included": False,
            "token_included": False,
            "local_path_included": False,
            "provider_url_included": False,
        },
    }

    return {
        "ok": not blockers,
        "dry_run": True,
        "lifecycle_action": "credential_adapter_audit_plan",
        "archive_id": archive_id,
        "proposed_receipt_path": proposed_receipt_path,
        "receipt_preview": json_safe(receipt_preview),
        "manifest_plan_summary": {
            "proposed_manifest_path": manifest_preview.get("proposed_manifest_path"),
            "schema_validation_ok": (manifest_preview.get("schema_validation") or {}).get("ok") if isinstance(manifest_preview.get("schema_validation"), dict) else None,
            "adapter_id": manifest.get("adapter_id"),
            "adapter_kind": manifest.get("adapter_kind"),
            "store_kind": manifest.get("store_kind"),
        },
        "readiness_plan_summary": {
            "operation": operation_summary.get("operation"),
            "action_kind": operation_summary.get("action_kind"),
            "credential_id": operation_summary.get("credential_id"),
            "readiness_status": (readiness_preview.get("readiness") or {}).get("status") if isinstance(readiness_preview.get("readiness"), dict) else None,
        },
        "current_capability": {
            "adapter_audit_receipt_preview_available": True,
            "adapter_audit_receipt_write_implemented": False,
            "live_adapter_implemented": False,
            "secret_value_read_implemented": False,
            "secret_value_write_implemented": False,
            "approval_receipt_write_implemented": True,
            "adapter_manifest_write_implemented": False,
        },
        "closed_actions": {
            "audit_receipt_written": False,
            "adapter_manifest_written": False,
            "approval_receipt_written": False,
            "live_adapter_executed": False,
            "secret_prompted_in_chat": False,
            "secret_value_read": False,
            "secret_value_written": False,
            "password_manager_opened": False,
            "browser_password_store_opened": False,
            "os_keyring_opened": False,
            "environment_read": False,
            "plaintext_file_read": False,
            "provider_api_called": False,
            "oauth_started": False,
            "files_written": False,
        },
        "privacy_guards": {
            "secret_values_echoed": False,
            "credential_ref_values_echoed": False,
            "email_addresses_echoed": False,
            "tokens_echoed": False,
            "local_absolute_paths_echoed": False,
            "provider_urls_echoed": False,
            "writes": False,
        },
        "would_change": [],
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }


def credential_adapter_audit_case_id(
    *,
    archive_id: str,
    adapter_id: str,
    operation: str,
    credential_id: str,
    action_kind: str,
    result_status: str,
) -> str:
    payload = {
        "archive_id": archive_id,
        "adapter_id": adapter_id,
        "operation": operation,
        "credential_id": credential_id,
        "action_kind": action_kind,
        "result_status": result_status,
    }
    digest = hashlib.sha256(json.dumps(payload, sort_keys=True, separators=(",", ":")).encode("utf-8")).hexdigest()[:20]
    return f"credential-adapter-audit-{digest}"


def credential_access_action_profile(action_kind: str) -> dict[str, Any]:
    profiles: dict[str, dict[str, Any]] = {
        "mail_source_read": {
            "description": "Use a mail username/app-password/OAuth credential for an approved future mailbox operation.",
            "recommended_credential_kind": "mail_app_password",
            "expected_result_metadata": ["source_id", "mailbox_ref", "message_count", "derived_text_receipt_refs"],
            "never_return": ["email address", "password", "OAuth token", "message body unless separately captured as source evidence"],
        },
        "model_api_call": {
            "description": "Use a model provider API key for an approved future AI/OCR-supporting operation.",
            "recommended_credential_kind": "openai_api_key",
            "expected_result_metadata": ["provider", "model_or_service", "cost_class", "source_object_ids"],
            "never_return": ["API key", "request bearer token"],
        },
        "ocr_api_call": {
            "description": "Use an OCR provider API key for an approved future derived-text operation.",
            "recommended_credential_kind": "ocr_api_key",
            "expected_result_metadata": ["provider", "derivation_method", "source_object_ids", "confidence_summary"],
            "never_return": ["API key", "provider token"],
        },
        "object_storage_request": {
            "description": "Use an object-storage token for an approved future upload/download/presigned-url operation.",
            "recommended_credential_kind": "object_storage_token",
            "expected_result_metadata": ["store_kind", "store_ref", "object_id", "operation_receipt_ref"],
            "never_return": ["access key", "secret key", "private URL unless explicitly approved as an output artifact"],
        },
        "cli_token_auth": {
            "description": "Use a CLI/provider token for an approved local command or provider auth operation.",
            "recommended_credential_kind": "provider_api_key",
            "expected_result_metadata": ["provider", "command_label", "exit_status", "receipt_ref"],
            "never_return": ["token", "refresh token", "account email"],
        },
        "browser_login_fill": {
            "description": "Use a browser/platform password manager for an approved website login or passkey/autofill flow.",
            "recommended_credential_kind": "generic_secret",
            "expected_result_metadata": ["site_label", "approval_receipt_ref", "login_state"],
            "never_return": ["username", "password", "passkey private material", "browser profile path"],
        },
        "plaintext_secret_migration": {
            "description": "Plan a human-approved migration from an existing plaintext note into a real vault/keyring.",
            "recommended_credential_kind": "generic_secret",
            "expected_result_metadata": ["candidate_count", "confirmed_count", "target_store_kind", "inventory_ref_count"],
            "never_return": ["detected secret values", "source file absolute path", "raw note text"],
        },
    }
    return json_safe(profiles.get(action_kind) or profiles["model_api_call"])


def credential_access_store_surfaces(store_kind: str, platform_keyring: str) -> list[str]:
    if store_kind == "browser_platform_manager":
        return ["Chrome Password Manager", "Microsoft Password Manager", "Windows Hello/passkey surface", "Android/iOS/Samsung platform password surface"]
    if store_kind == "os_keyring":
        return [platform_keyring]
    if store_kind == "developer_secret_manager":
        return ["Bitwarden Secrets Manager", "cloud provider secret manager", "deployment secret store"]
    if store_kind == "environment":
        return ["process environment supplied outside the archive"]
    if store_kind == "future_wallet":
        return ["future WOM wallet/local custody surface"]
    return ["KeePassXC", "Bitwarden", "1Password", "other reviewed password manager"]


