def project_intake_next_review_prompts(missing_ids: list[str]) -> list[dict[str, Any]]:
    catalog = project_intake_status_prompt_catalog()
    prompts: list[dict[str, Any]] = []
    for checklist_id in missing_ids:
        item = catalog.get(checklist_id)
        if item is None:
            continue
        prompt = {
            "checklist_id": checklist_id,
            "question": item["question"],
            "answer_type": item["answer_type"],
            "required_before": item["required_before"],
            "decision_record_hint": {
                "checklist_id": checklist_id,
                "response_placeholder": "<human-reviewed response>",
                "notes_placeholder": "<optional review notes>",
            },
            "decision_values_included": False,
            "writes": False,
        }
        if "allowed_labels" in item:
            prompt["allowed_labels"] = item["allowed_labels"]
        prompts.append(prompt)
    return prompts


def project_intake_prompt_from_checklist_item(item: dict[str, Any]) -> dict[str, Any]:
    prompt = {
        "checklist_id": item["id"],
        "question": item["question"],
        "answer_type": item["answer_type"],
        "required_before": item["required_before"],
        "decision_record_hint": {
            "checklist_id": item["id"],
            "response_placeholder": "<human-reviewed response>",
            "notes_placeholder": "<optional review notes>",
        },
        "decision_values_included": False,
        "writes": False,
    }
    if "allowed_labels" in item:
        prompt["allowed_labels"] = item["allowed_labels"]
    return prompt


def project_intake_next_question(
    archive_root: Path | str,
    *,
    staged_folder: Path | str | None = None,
    receipt: str | None = None,
    dry_run: bool = True,
) -> dict[str, Any]:
    if not dry_run:
        raise ArchiveServiceError("project-intake-next-question is dry-run only.")
    if (staged_folder is None and not receipt) or (staged_folder is not None and receipt):
        raise ArchiveServiceError("Pass exactly one of staged_folder or receipt.")

    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []
    review_prompts: list[dict[str, Any]] = []
    source: dict[str, Any]
    state = "needs_review"
    session_id: str | None = None

    if staged_folder is not None:
        plan = project_intake_plan(root, staged_folder)
        warnings.extend(plan.get("warnings") or [])
        review_prompts = [
            project_intake_prompt_from_checklist_item(item)
            for item in plan["human_review_checklist"]
        ]
        source = {
            "kind": "staged_folder_plan",
            "follows_staging_convention": plan["follows_staging_convention"],
            "folder_summary": plan["folder_summary"],
            "staged_folder_path_included": False,
            "entry_names_included": False,
            "file_bodies_read": False,
        }
        state = "needs_first_review"
    else:
        assert receipt is not None
        status = project_intake_status(root, receipt, dry_run=True)
        blockers.extend(status.get("blockers") or [])
        warnings.extend(status.get("warnings") or [])
        review_prompts = status.get("next_review_prompts") or []
        session_id = status.get("session_id")
        source = {
            "kind": "decision_receipt_status",
            "receipt_path": status.get("receipt_path"),
            "readiness": status.get("readiness"),
            "checklist_coverage": status.get("checklist_coverage"),
            "decision_values_included": False,
        }
        if blockers:
            state = "blocked"
        elif review_prompts:
            state = "needs_more_review"
        else:
            state = "review_complete"

    selected_prompt = review_prompts[0] if review_prompts else None
    conversation_turn = None
    if selected_prompt is not None:
        conversation_turn = {
            "checklist_id": selected_prompt["checklist_id"],
            "ask_user": selected_prompt["question"],
            "answer_type": selected_prompt["answer_type"],
            "required_before": selected_prompt["required_before"],
            "decision_record_hint": selected_prompt["decision_record_hint"],
            "decision_values_included": False,
            "writes": False,
        }
        if "allowed_labels" in selected_prompt:
            conversation_turn["allowed_labels"] = selected_prompt["allowed_labels"]

    return {
        "ok": not blockers,
        "dry_run": True,
        "action": "archive_project_intake_next_question",
        "archive_id": archive_id,
        "state": state,
        "session_id": session_id,
        "source": source,
        "next_question": conversation_turn,
        "remaining_prompt_count": len(review_prompts),
        "remaining_checklist_ids": [prompt["checklist_id"] for prompt in review_prompts],
        "all_remaining_prompts": review_prompts,
        "privacy_guards": {
            "decision_values_included": False,
            "entry_names_included": False,
            "file_bodies_read": False,
            "content_hashes_calculated": False,
            "provider_calls": False,
            "writes": False,
        },
        "decision_file_guidance": {
            "schema": PROJECT_INTAKE_DECISION_SCHEMA,
            "single_answer_schema": PROJECT_INTAKE_ANSWER_SCHEMA,
            "session_id": session_id or "<safe-session-id>",
            "staged_folder_ref": "<optional human-reviewed non-secret reference>",
            "decision_values_included": False,
            "record_single_answer_with": "project-intake-record-answer --dry-run, then --approve after human review",
            "write_decisions_with": "project-intake-decisions --dry-run, then --approve after human review",
        },
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
        "next_safe_actions": project_intake_next_question_safe_actions(state),
        "would_change": [],
    }


def project_intake_next_question_safe_actions(state: str) -> list[str]:
    if state == "blocked":
        return [
            "Review the blocker before asking the next intake question.",
            "Do not run source-intake, capture, drafting, minting, or cleanup from a blocked receipt.",
        ]
    if state == "review_complete":
        return [
            "Run project-intake-status --dry-run before using the receipt as source-intake or capture context.",
            "Continue one item at a time with source-intake --project-intake-receipt.",
            "Keep capture, draft, mint, provider, and cleanup steps separately approved.",
        ]
    return [
        "Ask the user the next_question.ask_user text and record only the human-reviewed response.",
        "Update a project-intake decisions JSON file outside this command; this command writes nothing.",
        "Run project-intake-decisions --dry-run before approving any receipt.",
    ]


def project_intake_decision_template(
    archive_root: Path | str,
    *,
    staged_folder: Path | str | None = None,
    receipt: str | None = None,
    session_id: str | None = None,
    staged_folder_ref: str | None = None,
    dry_run: bool = True,
) -> dict[str, Any]:
    if not dry_run:
        raise ArchiveServiceError("project-intake-decision-template is dry-run only.")
    resolved_session_id = safe_project_intake_session_id(session_id) if session_id else None
    if session_id and resolved_session_id is None:
        raise ArchiveServiceError("session_id must be a safe project intake session id.")
    safe_staged_folder_ref = None
    if staged_folder_ref is not None:
        blockers: list[str] = []
        safe_staged_folder_ref = validate_project_intake_safe_value(
            staged_folder_ref,
            blockers,
            "$.staged_folder_ref",
        )
        if blockers:
            raise ArchiveServiceError("; ".join(blockers))

    next_question = project_intake_next_question(
        archive_root,
        staged_folder=staged_folder,
        receipt=receipt,
        dry_run=True,
    )
    selected = next_question.get("next_question") if isinstance(next_question.get("next_question"), dict) else None
    if selected is None:
        decision_record = None
        single_decision = None
        answer_record = None
    else:
        single_decision = {
            "checklist_id": selected["checklist_id"],
            "answer": None,
            "notes": None,
        }
        answer_record = {
            "schema": PROJECT_INTAKE_ANSWER_SCHEMA,
            "checklist_id": selected["checklist_id"],
            "answer": None,
            "notes": None,
        }
        decision_record = {
            "schema": PROJECT_INTAKE_DECISION_SCHEMA,
            "session_id": resolved_session_id or next_question.get("session_id") or "<safe-session-id>",
            "staged_folder_ref": safe_staged_folder_ref or "<optional human-reviewed non-secret reference>",
            "decisions": [single_decision],
        }

    source = next_question.get("source") if isinstance(next_question.get("source"), dict) else {}
    answered_ids: list[str] = []
    coverage = source.get("checklist_coverage") if isinstance(source.get("checklist_coverage"), dict) else {}
    if isinstance(coverage.get("answered_checklist_ids"), list):
        answered_ids = [str(item) for item in coverage["answered_checklist_ids"] if isinstance(item, str)]

    return {
        "ok": next_question["ok"],
        "dry_run": True,
        "action": "archive_project_intake_decision_template",
        "archive_id": next_question["archive_id"],
        "state": next_question["state"],
        "session_id": resolved_session_id or next_question.get("session_id"),
        "source": {
            "kind": source.get("kind"),
            "receipt_path": source.get("receipt_path"),
            "existing_answered_checklist_ids": answered_ids,
            "previous_decision_values_included": False,
        },
        "next_question": selected,
        "answer_record_template": answer_record,
        "decision_record_template": decision_record,
        "single_decision_template": single_decision,
        "template_policy": {
            "human_must_fill_answer": True,
            "answer_values_included": False,
            "previous_answer_values_included": False,
            "template_is_not_approval": True,
            "writes": False,
        },
        "privacy_guards": {
            "decision_values_included": False,
            "previous_decision_values_included": False,
            "entry_names_included": False,
            "file_bodies_read": False,
            "provider_calls": False,
            "writes": False,
        },
        "blockers": next_question.get("blockers") or [],
        "warnings": next_question.get("warnings") or [],
        "next_safe_actions": project_intake_decision_template_safe_actions(bool(receipt), selected is None),
        "would_change": [],
    }


def project_intake_decision_template_safe_actions(from_receipt: bool, complete: bool) -> list[str]:
    if complete:
        return [
            "No missing project-intake review question remains in this template context.",
            "Run project-intake-status --dry-run before continuing to source-intake or capture.",
        ]
    actions = [
        "Ask the user the next_question.ask_user text.",
        "Fill answer_record_template.answer only with the human-reviewed response.",
        "Run project-intake-record-answer --dry-run against the completed single-answer JSON before approval.",
    ]
    if from_receipt:
        actions.insert(
            2,
            "If continuing from an earlier receipt, pass that receipt to project-intake-record-answer; this template does not echo previous answer values.",
        )
    return actions


def project_intake_item_plan(
    archive_root: Path | str,
    *,
    receipt: str,
    local_path: Path | str,
    source_role: str = SOURCE_INTAKE_DEFAULT_ROLE,
    title: str | None = None,
    mime: str | None = None,
    dry_run: bool = True,
) -> dict[str, Any]:
    if not dry_run:
        raise ArchiveServiceError("project-intake-item-plan is dry-run only.")
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    status = project_intake_status(root, receipt, dry_run=True)
    source_plan = source_intake_plan(
        root,
        local_path=Path(local_path),
        source_role=source_role,
        title=title,
        mime=mime,
        redact_local_paths=True,
        project_intake_receipt=receipt,
    )
    blockers = unique_preserve_order(
        [
            *[str(item) for item in status.get("blockers", [])],
            *[str(item) for item in source_plan.get("blockers", [])],
        ]
    )
    warnings = unique_preserve_order(
        [
            *[str(item) for item in status.get("warnings", [])],
            *[str(item) for item in source_plan.get("warnings", [])],
        ]
    )
    command_parts = [
        "archive",
        "source-intake",
        "<archive-root>",
        "--dry-run",
        "--local-path",
        "<selected-local-path>",
        "--project-intake-receipt",
        str(status.get("receipt_path") or "<project-intake-receipt>"),
        "--redact-local-paths",
        "--format",
        "json",
    ]
    if source_role != SOURCE_INTAKE_DEFAULT_ROLE:
        command_parts.extend(["--source-role", source_role])
    if title:
        command_parts.extend(["--title", "<human-reviewed-title>"])
    if mime:
        command_parts.extend(["--mime", "<mime-type>"])
    source_record_parts = [
        "archive",
        "source-intake-record",
        "<archive-root>",
        "--source-intake-plan",
        "<source-intake-dry-run-json>",
        "--approve",
        "--reviewed-by",
        "<actor>",
        "--format",
        "json",
    ]
    selection_parts = [
        "archive",
        "objet-capture-selection",
        "<archive-root>",
        "--staged-path",
        "<archive-relative-staged-file>",
        "--source-intake-receipt",
        "<source-intake-record-path>",
        "--dry-run",
        "--format",
        "json",
    ]

    return {
        "ok": not blockers,
        "dry_run": True,
        "action": "archive_project_intake_item_plan",
        "archive_id": archive_id,
        "state": "blocked" if blockers else "ready_for_source_intake_dry_run",
        "receipt_path": status.get("receipt_path"),
        "project_intake_context": source_plan.get("project_intake_context"),
        "selected_item_plan": {
            "input_kind": source_plan.get("input_kind"),
            "source_kind": source_plan.get("source_kind"),
            "source_role": source_role,
            "objet_status": source_plan.get("objet_status"),
            "source_metadata": source_plan.get("source_metadata"),
            "source_refs_for_draft": source_plan.get("source_refs_for_draft"),
            "draft_provenance_suggestions": source_plan.get("draft_provenance_suggestions"),
            "content_access": source_plan.get("content_access"),
        },
        "source_intake_preview": source_plan,
        "command_guidance": {
            "source_intake_dry_run": " ".join(command_parts),
            "source_intake_record_approve": " ".join(source_record_parts),
            "objet_capture_selection_dry_run": " ".join(selection_parts),
            "save_source_intake_plan_before_capture": True,
            "capture_requires_persisted_source_intake_plan": True,
            "capture_requires_separate_selection_manifest": True,
            "selection_manifest_command_available": True,
            "selection_manifest_generated": False,
            "automatic_execution_authorized": False,
        },
        "privacy_guards": {
            "local_paths_redacted": True,
            "decision_values_included": False,
            "staged_entry_names_listed": False,
            "file_bodies_read": False,
            "content_hashes_calculated": False,
            "provider_calls": False,
            "writes": False,
        },
        "next_safe_actions": project_intake_item_plan_safe_actions(bool(blockers)),
        "would_change": [],
        "blockers": blockers,
        "warnings": warnings,
    }


def project_intake_item_plan_safe_actions(blocked: bool) -> list[str]:
    if blocked:
        return [
            "Fix the receipt or selected-file blocker before continuing.",
            "Do not run capture, drafting, minting, provider sync, or cleanup from a blocked item plan.",
        ]
    return [
        "Save the source-intake dry-run JSON as a receipt/source evidence file before capture.",
        "Use objet-capture-selection to prepare a separately reviewed selection manifest.",
        "Run objet-capture only after reviewing that selection manifest.",
        "Keep drafting, minting, provider sync, and cleanup as separate approval gates.",
    ]


def source_intake_record_path(plan_sha256: str) -> str:
    digest = plan_sha256.removeprefix("sha256:")
    return f"{SOURCE_SCAN_RECEIPTS_DIR}/source-intake-{digest[:16]}.source-intake-plan.json"


def source_intake_plan_has_unsafe_stored_string(value: Any) -> bool:
    if isinstance(value, str):
        return bool(
            contains_forbidden_location_reference(value)
            or source_intake_has_provider_url(value)
            or source_intake_secret_like(value)
        )
    if isinstance(value, list):
        return any(source_intake_plan_has_unsafe_stored_string(item) for item in value)
    if isinstance(value, dict):
        return any(source_intake_plan_has_unsafe_stored_string(item) for item in value.values())
    return False


def source_intake_record(
    archive_root: Path | str,
    plan_path: Path | str,
    *,
    dry_run: bool = False,
    approve: bool = False,
    reviewed_by: str | None = None,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []
    if dry_run is approve:
        blockers.append("Choose exactly one mode: --dry-run or --approve.")

    reviewer = safe_project_intake_actor_id(reviewed_by)
    if approve and reviewer is None:
        blockers.append("Source intake record approval requires --reviewed-by with a safe actor id.")
    if reviewed_by and reviewer is None:
        blockers.append("reviewed_by must be a safe non-secret actor id.")

    plan = load_json_object_for_review(Path(plan_path), "source intake plan", blockers)
    plan_sha256 = "sha256:" + ("0" * 64)
    receipt_relative = f"{SOURCE_SCAN_RECEIPTS_DIR}/source-intake-invalid.source-intake-plan.json"
    if plan is not None:
        if plan.get("archive_id") != archive_id:
            blockers.append("source_intake_plan.archive_id must match this archive.")
        validation_blockers: list[str] = []
        prepare_source_intake_plan_for_draft(plan, validation_blockers)
        blockers.extend(validation_blockers)
        if source_intake_plan_has_unsafe_stored_string(plan):
            blockers.append(
                "source_intake_plan must not contain local paths, provider URLs, tokens, or secrets; rerun source-intake with --redact-local-paths."
            )
        plan_sha256 = sha256_json_value(plan)
        receipt_relative = source_intake_record_path(plan_sha256)

    receipt_path = archive_internal_path(root, receipt_relative)
    if approve and receipt_path.exists():
        blockers.append("Source intake plan record already exists for this plan hash.")

    privacy_guards = {
        "source_plan_read": True,
        "local_paths_blocked": True,
        "decision_values_included": False,
        "file_bodies_read": False,
        "content_hashes_calculated": False,
        "provider_calls": False,
        "writes": approve and not blockers,
    }
    result: dict[str, Any] = {
        "ok": not blockers,
        "dry_run": dry_run,
        "action": "archive_source_intake_record",
        "archive_id": archive_id,
        "reviewed_by": reviewer,
        "source_intake_plan_sha256": plan_sha256,
        "proposed_plan_path": receipt_relative,
        "privacy_guards": privacy_guards,
        "would_change": [receipt_relative] if dry_run and not blockers else [],
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }
    if blockers or dry_run:
        return result

    assert plan is not None
    created_dirs = missing_parent_dirs_before_write(root, [receipt_path])
    created_paths: list[Path] = []
    try:
        receipt_path.parent.mkdir(parents=True, exist_ok=True)
        write_json_new_file(receipt_path, plan)
        created_paths.append(receipt_path)
    except Exception:
        for path in created_paths:
            try:
                path.unlink()
            except OSError:
                pass
        cleanup_created_empty_dirs(root, created_dirs)
        raise

    result.update(
        {
            "ok": True,
            "dry_run": False,
            "plan_path": receipt_relative,
            "files_written": [receipt_relative],
            "would_change": [],
            "privacy_guards": privacy_guards,
        }
    )
    return result


def safe_project_intake_actor_id(value: str | None) -> str | None:
    if value is None:
        return None
    normalized = value.strip()
    if not normalized:
        return None
    if PROJECT_INTAKE_ACTOR_ID_RE.match(normalized) and not header_string_is_private_or_unsafe(normalized):
        return normalized
    return None


def safe_project_intake_session_id(value: Any) -> str | None:
    if not isinstance(value, str):
        return None
    normalized = value.strip()
    if not normalized:
        return None
    if PROJECT_INTAKE_SESSION_ID_RE.match(normalized) and not header_string_is_private_or_unsafe(normalized):
        return normalized
    return None


def load_project_intake_decisions_payload(decisions_path: Path | str) -> dict[str, Any]:
    path = Path(decisions_path).expanduser().resolve()
    if not path.is_file():
        raise ArchiveServiceError("Project intake decisions file does not exist or is not a file.")
    try:
        data = json.loads(path.read_text(encoding="utf-8"))
    except json.JSONDecodeError as exc:
        raise ArchiveServiceError("Project intake decisions file must contain one JSON object.") from exc
    except OSError as exc:
        raise ArchiveServiceError("Project intake decisions file could not be read.") from exc
    if not isinstance(data, dict):
        raise ArchiveServiceError("Project intake decisions file must contain one JSON object.")
    return data


def validate_project_intake_safe_value(value: Any, blockers: list[str], field_path: str) -> Any:
    if isinstance(value, dict):
        normalized: dict[str, Any] = {}
        for key, child in value.items():
            key_text = str(key)
            if not key_text.strip():
                blockers.append(f"{field_path} contains an empty object key.")
                continue
            if len(key_text) > 200 or header_string_is_private_or_unsafe(key_text):
                blockers.append(f"{field_path} contains a private or unsafe object key.")
                continue
            normalized[key_text] = validate_project_intake_safe_value(child, blockers, f"{field_path}.<key>")
        return normalized
    if isinstance(value, list):
        return [
            validate_project_intake_safe_value(child, blockers, f"{field_path}[{index}]")
            for index, child in enumerate(value)
        ]
    if isinstance(value, str):
        if len(value) > PROJECT_INTAKE_MAX_STRING_LENGTH:
            blockers.append(f"{field_path} is too long for a project intake decision record.")
        if header_string_is_private_or_unsafe(value):
            blockers.append(f"{field_path} contains a private or unsafe reference.")
        return value
    if value is None or isinstance(value, (bool, int, float)):
        return value
    blockers.append(f"{field_path} must be a JSON-safe value.")
    return json_safe(value)


def normalize_project_intake_decisions_payload(
    payload: dict[str, Any],
    blockers: list[str],
    warnings: list[str],
) -> dict[str, Any]:
    schema = payload.get("schema")
    if schema != PROJECT_INTAKE_DECISION_SCHEMA:
        blockers.append(f"Project intake decisions schema must be {PROJECT_INTAKE_DECISION_SCHEMA}.")

    session_id = safe_project_intake_session_id(payload.get("session_id"))
    if session_id is None:
        blockers.append("Project intake decisions require a safe session_id.")
        session_id = "invalid-session"

    staged_folder_ref = payload.get("staged_folder_ref")
    if staged_folder_ref is not None:
        if not isinstance(staged_folder_ref, str):
            blockers.append("staged_folder_ref must be a string when provided.")
            staged_folder_ref = None
        else:
            staged_folder_ref = validate_project_intake_safe_value(
                staged_folder_ref,
                blockers,
                "$.staged_folder_ref",
            )

    decisions = payload.get("decisions")
    if not isinstance(decisions, list):
        blockers.append("Project intake decisions require a decisions list.")
        decisions = []
    elif not decisions:
        blockers.append("Project intake decisions list must contain at least one decision.")

    allowed_checklist_ids = project_intake_known_checklist_ids()
    allowed_keys = {"checklist_id", "answer", "notes"}
    normalized_decisions: list[dict[str, Any]] = []
    seen_checklist_ids: set[str] = set()
    for index, decision in enumerate(decisions):
        field_path = f"$.decisions[{index}]"
        if not isinstance(decision, dict):
            blockers.append(f"{field_path} must be an object.")
            continue
        unknown_keys = sorted(set(str(key) for key in decision) - allowed_keys)
        if unknown_keys:
            blockers.append(f"{field_path} contains unsupported field(s).")
        checklist_id = decision.get("checklist_id")
        if not isinstance(checklist_id, str) or checklist_id not in allowed_checklist_ids:
            blockers.append(f"{field_path}.checklist_id must match the project intake checklist.")
            checklist_id = "invalid"
        elif checklist_id in seen_checklist_ids:
            blockers.append(f"{field_path}.checklist_id duplicates an earlier decision.")
        else:
            seen_checklist_ids.add(checklist_id)

        if "answer" not in decision or decision.get("answer") is None:
            blockers.append(f"{field_path}.answer is required.")
            answer = None
        else:
            answer = validate_project_intake_safe_value(decision.get("answer"), blockers, f"{field_path}.answer")
            if isinstance(answer, str) and not answer.strip():
                blockers.append(f"{field_path}.answer must not be empty.")

        normalized: dict[str, Any] = {
            "checklist_id": checklist_id,
            "answer": answer,
        }
        if "notes" in decision and decision.get("notes") is not None:
            if not isinstance(decision.get("notes"), str):
                blockers.append(f"{field_path}.notes must be a string when provided.")
            else:
                normalized["notes"] = validate_project_intake_safe_value(
                    decision.get("notes"),
                    blockers,
                    f"{field_path}.notes",
                )
        normalized_decisions.append(normalized)

    if len(normalized_decisions) > 50:
        blockers.append("Project intake decisions list must contain 50 or fewer decisions.")

    if len(normalized_decisions) < len(project_intake_known_checklist_ids()):
        warnings.append("Project intake decisions do not answer every checklist item yet.")

    return {
        "schema": PROJECT_INTAKE_DECISION_SCHEMA,
        "session_id": session_id,
        "staged_folder_ref": staged_folder_ref,
        "decisions": normalized_decisions,
    }


def load_project_intake_answer_payload(answer_path: Path | str) -> dict[str, Any]:
    path = Path(answer_path).expanduser().resolve()
    if not path.is_file():
        raise ArchiveServiceError("Project intake answer file does not exist or is not a file.")
    try:
        data = json.loads(path.read_text(encoding="utf-8"))
    except json.JSONDecodeError as exc:
        raise ArchiveServiceError("Project intake answer file must contain one JSON object.") from exc
    except OSError as exc:
        raise ArchiveServiceError("Project intake answer file could not be read.") from exc
    if not isinstance(data, dict):
        raise ArchiveServiceError("Project intake answer file must contain one JSON object.")
    return data


def normalize_project_intake_answer_payload(payload: dict[str, Any], blockers: list[str]) -> dict[str, Any]:
    schema = payload.get("schema")
    if schema != PROJECT_INTAKE_ANSWER_SCHEMA:
        blockers.append(f"Project intake answer schema must be {PROJECT_INTAKE_ANSWER_SCHEMA}.")

    allowed_keys = {"schema", "checklist_id", "answer", "notes"}
    unknown_keys = sorted(set(str(key) for key in payload) - allowed_keys)
    if unknown_keys:
        blockers.append("Project intake answer contains unsupported field(s).")

    checklist_id = payload.get("checklist_id")
    if not isinstance(checklist_id, str) or checklist_id not in project_intake_known_checklist_ids():
        blockers.append("Project intake answer checklist_id must match the project intake checklist.")
        checklist_id = "invalid"

    if "answer" not in payload or payload.get("answer") is None:
        blockers.append("Project intake answer is required.")
        answer = None
    else:
        answer = validate_project_intake_safe_value(payload.get("answer"), blockers, "$.answer")
        if isinstance(answer, str) and not answer.strip():
            blockers.append("Project intake answer must not be empty.")

    normalized: dict[str, Any] = {
        "checklist_id": checklist_id,
        "answer": answer,
    }
    if "notes" in payload and payload.get("notes") is not None:
        if not isinstance(payload.get("notes"), str):
            blockers.append("Project intake answer notes must be a string when provided.")
        else:
            normalized["notes"] = validate_project_intake_safe_value(payload.get("notes"), blockers, "$.notes")
    return normalized


def project_intake_decisions_receipt_path(session_id: str, decision_sha256: str) -> str:
    session_slug = safe_slug(session_id)
    return f"{PROJECT_INTAKE_DECISION_RECEIPTS_DIR}/{session_slug}-{decision_sha256[:16]}.project-intake-decisions.json"


def project_intake_decisions(
    archive_root: Path | str,
    decisions_path: Path | str,
    *,
    dry_run: bool = False,
    approve: bool = False,
    reviewed_by: str | None = None,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []

    if dry_run is approve:
        blockers.append("Choose exactly one mode: --dry-run or --approve.")

    reviewer = safe_project_intake_actor_id(reviewed_by)
    if approve and reviewer is None:
        blockers.append("Project intake decision approval requires --reviewed-by with a safe actor id.")
    if reviewed_by and reviewer is None:
        blockers.append("reviewed_by must be a safe non-secret actor id.")

    payload = load_project_intake_decisions_payload(decisions_path)
    normalized_payload = normalize_project_intake_decisions_payload(payload, blockers, warnings)
    decision_sha256 = sha256_json_hex(normalized_payload)
    session_id = normalized_payload["session_id"]
    checklist_ids = [
        item["checklist_id"]
        for item in normalized_payload["decisions"]
        if isinstance(item.get("checklist_id"), str) and item.get("checklist_id") != "invalid"
    ]
    receipt_relative = project_intake_decisions_receipt_path(session_id, decision_sha256)
    receipt_path = archive_internal_path(root, receipt_relative)
    if approve and receipt_path.exists():
        blockers.append("Project intake decisions receipt already exists for this session and decision hash.")

    privacy_guards = {
        "decision_file_read": True,
        "decision_values_echoed": False,
        "unsafe_local_paths_blocked": True,
        "staged_folder_scanned": False,
        "staged_entry_names_included": False,
        "file_bodies_read": False,
        "provider_calls": False,
        "writes": approve and not blockers,
    }
    result: dict[str, Any] = {
        "ok": not blockers,
        "dry_run": dry_run,
        "action": "archive_project_intake_decisions",
        "archive_root": str(root),
        "archive_id": archive_id,
        "session_id": session_id,
        "reviewed_by": reviewer,
        "decision_sha256": decision_sha256,
        "answer_count": len(normalized_payload["decisions"]),
        "checklist_ids": checklist_ids,
        "privacy_guards": privacy_guards,
        "proposed_receipt_path": receipt_relative,
        "would_change": [receipt_relative] if dry_run else [],
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }
    if blockers or dry_run:
        return result

    assert reviewer is not None
    reviewed_at = datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace("+00:00", "Z")
    receipt = {
        "schema": PROJECT_INTAKE_DECISION_RECEIPT_SCHEMA,
        "receipt_id": f"receipt:project-intake-decisions:{safe_slug(session_id)}:{decision_sha256[:16]}",
        "receipt_kind": "project_intake_decisions",
        "receipt_path": receipt_relative,
        "action": "archive_project_intake_decisions",
        "dry_run": False,
        "timestamp": reviewed_at,
        "archive_id": archive_id,
        "session_id": session_id,
        "staged_folder_ref": normalized_payload.get("staged_folder_ref"),
        "reviewed_by": reviewer,
        "reviewed_at": reviewed_at,
        "decision_sha256": decision_sha256,
        "source_decision_schema": PROJECT_INTAKE_DECISION_SCHEMA,
        "answer_count": len(normalized_payload["decisions"]),
        "checklist_ids": checklist_ids,
        "decisions": normalized_payload["decisions"],
        "privacy_guards": privacy_guards,
        "closed_actions": {
            "source_intake_run": False,
            "objet_capture_run": False,
            "derived_text_capture_run": False,
            "draft_created": False,
            "zet_minted": False,
            "staged_cleanup_performed": False,
            "provider_api_called": False,
        },
        "files_written": [receipt_relative],
        "blockers": [],
        "warnings": unique_preserve_order(warnings),
    }

    created_dirs = missing_parent_dirs_before_write(root, [receipt_path])
    created_paths: list[Path] = []
    try:
        receipt_path.parent.mkdir(parents=True, exist_ok=True)
        write_json_new_file(receipt_path, receipt)
        created_paths.append(receipt_path)
    except Exception:
        for path in created_paths:
            try:
                path.unlink()
            except OSError:
                pass
        cleanup_created_empty_dirs(root, created_dirs)
        raise

    result.update(
        {
            "ok": True,
            "dry_run": False,
            "receipt_path": receipt_relative,
            "files_written": [receipt_relative],
            "would_change": [],
            "privacy_guards": privacy_guards,
        }
    )
    return result


def project_intake_record_answer_safe_actions(blocked: bool, complete_after_record: bool) -> list[str]:
    if blocked:
        return [
            "Fix the answer file, prior receipt, or approval mode before writing a new project-intake receipt.",
            "Do not run source-intake, capture, drafting, minting, provider sync, or cleanup from a blocked answer record.",
        ]
    if complete_after_record:
        return [
            "Run project-intake-status --dry-run on the new receipt before using it as source-intake or capture context.",
            "Continue one selected item at a time with project-intake-item-plan and source-intake --project-intake-receipt.",
            "Keep capture, drafting, minting, provider sync, and cleanup as separate approval gates.",
        ]
    return [
        "Approve this receipt only after the single answer file has been reviewed by the human owner.",
        "Run project-intake-status --dry-run on the new receipt to get the next missing question.",
        "Record the next answer with a new answer file; do not bulk-classify or auto-fill remaining checklist ids.",
    ]


def project_intake_record_answer(
    archive_root: Path | str,
    answer_path: Path | str,
    *,
    receipt: str | None = None,
    session_id: str | None = None,
    staged_folder_ref: str | None = None,
    dry_run: bool = False,
    approve: bool = False,
    reviewed_by: str | None = None,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []

    if dry_run is approve:
        blockers.append("Choose exactly one mode: --dry-run or --approve.")

    reviewer = safe_project_intake_actor_id(reviewed_by)
    if approve and reviewer is None:
        blockers.append("Project intake answer approval requires --reviewed-by with a safe actor id.")
    if reviewed_by and reviewer is None:
        blockers.append("reviewed_by must be a safe non-secret actor id.")

    if bool(receipt) == bool(session_id):
        blockers.append("Pass exactly one of --receipt or --session-id.")
    if receipt and staged_folder_ref is not None:
        blockers.append("staged_folder_ref can only be provided when starting from --session-id.")

    answer_payload = load_project_intake_answer_payload(answer_path)
    new_decision = normalize_project_intake_answer_payload(answer_payload, blockers)

    previous_receipt_path: str | None = None
    previous_decisions: list[dict[str, Any]] = []
    resolved_session_id = "invalid-session"
    resolved_staged_folder_ref: Any = None

    if receipt:
        status = project_intake_status(root, receipt, dry_run=True)
        blockers.extend(status.get("blockers") or [])
        previous_receipt_path = status.get("receipt_path") if isinstance(status.get("receipt_path"), str) else None
        if status.get("ok"):
            receipt_path = resolve_receipt_input_path(root, receipt)
            receipt_doc = load_json_object_for_review(receipt_path, "project intake decision receipt", blockers)
            if receipt_doc is not None:
                prior_payload = {
                    "schema": PROJECT_INTAKE_DECISION_SCHEMA,
                    "session_id": receipt_doc.get("session_id"),
                    "staged_folder_ref": receipt_doc.get("staged_folder_ref"),
                    "decisions": receipt_doc.get("decisions"),
                }
                prior_blockers: list[str] = []
                prior_warnings: list[str] = []
                prior_normalized = normalize_project_intake_decisions_payload(
                    prior_payload,
                    prior_blockers,
                    prior_warnings,
                )
                blockers.extend(prior_blockers)
                resolved_session_id = prior_normalized["session_id"]
                resolved_staged_folder_ref = prior_normalized.get("staged_folder_ref")
                previous_decisions = list(prior_normalized["decisions"])
        elif isinstance(status.get("session_id"), str):
            resolved_session_id = status["session_id"]
    elif session_id:
        safe_session_id = safe_project_intake_session_id(session_id)
        if safe_session_id is None:
            blockers.append("session_id must be a safe project intake session id.")
        else:
            resolved_session_id = safe_session_id
        if staged_folder_ref is not None:
            ref_blockers: list[str] = []
            safe_ref = validate_project_intake_safe_value(staged_folder_ref, ref_blockers, "$.staged_folder_ref")
            if ref_blockers:
                blockers.extend(ref_blockers)
            else:
                resolved_staged_folder_ref = safe_ref

    previous_ids = [
        item["checklist_id"]
        for item in previous_decisions
        if isinstance(item.get("checklist_id"), str) and item.get("checklist_id") != "invalid"
    ]
    remaining_ids = [checklist_id for checklist_id in project_intake_checklist_order() if checklist_id not in set(previous_ids)]
    expected_next_checklist_id = remaining_ids[0] if remaining_ids else None
    new_checklist_id = new_decision.get("checklist_id") if isinstance(new_decision.get("checklist_id"), str) else None
    if new_checklist_id and new_checklist_id != "invalid":
        if new_checklist_id in set(previous_ids):
            blockers.append("Project intake answer checklist_id is already recorded in the prior receipt.")
        elif expected_next_checklist_id is None:
            blockers.append("Project intake checklist is already complete for this session.")
        elif new_checklist_id != expected_next_checklist_id:
            blockers.append("Project intake answer checklist_id must match the next missing checklist id.")

    combined_source_payload = {
        "schema": PROJECT_INTAKE_DECISION_SCHEMA,
        "session_id": resolved_session_id,
        "staged_folder_ref": resolved_staged_folder_ref,
        "decisions": [*previous_decisions, new_decision],
    }
    combined_blockers: list[str] = []
    combined_warnings: list[str] = []
    combined_payload = normalize_project_intake_decisions_payload(
        combined_source_payload,
        combined_blockers,
        combined_warnings,
    )
    blockers.extend(combined_blockers)
    warnings.extend(combined_warnings)

    decision_sha256 = sha256_json_hex(combined_payload)
    receipt_relative = project_intake_decisions_receipt_path(combined_payload["session_id"], decision_sha256)
    receipt_path = archive_internal_path(root, receipt_relative)
    if approve and receipt_path.exists():
        blockers.append("Project intake decisions receipt already exists for this session and decision hash.")

    checklist_ids = [
        item["checklist_id"]
        for item in combined_payload["decisions"]
        if isinstance(item.get("checklist_id"), str) and item.get("checklist_id") != "invalid"
    ]
    complete_after_record = not [checklist_id for checklist_id in project_intake_checklist_order() if checklist_id not in set(checklist_ids)]
    privacy_guards = {
        "answer_file_read": True,
        "prior_receipt_read": bool(receipt),
        "answer_values_echoed": False,
        "previous_decision_values_echoed": False,
        "unsafe_local_paths_blocked": True,
        "staged_folder_scanned": False,
        "staged_entry_names_included": False,
        "file_bodies_read": False,
        "provider_calls": False,
        "writes": approve and not blockers,
    }
    closed_actions = {
        "source_intake_run": False,
        "objet_capture_run": False,
        "derived_text_capture_run": False,
        "draft_created": False,
        "zet_minted": False,
        "staged_cleanup_performed": False,
        "provider_api_called": False,
    }
    result: dict[str, Any] = {
        "ok": not blockers,
        "dry_run": dry_run,
        "action": "archive_project_intake_record_answer",
        "archive_root": str(root),
        "archive_id": archive_id,
        "session_id": combined_payload["session_id"],
        "previous_receipt_path": previous_receipt_path,
        "previous_answer_count": len(previous_decisions),
        "new_answer_checklist_id": new_checklist_id,
        "expected_next_checklist_id": expected_next_checklist_id,
        "answer_count": len(combined_payload["decisions"]),
        "checklist_ids": checklist_ids,
        "reviewed_by": reviewer,
        "decision_sha256": decision_sha256,
        "privacy_guards": privacy_guards,
        "closed_actions": closed_actions,
        "proposed_receipt_path": receipt_relative,
        "would_change": [receipt_relative] if dry_run and not blockers else [],
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
        "next_safe_actions": project_intake_record_answer_safe_actions(bool(blockers), complete_after_record),
    }
    if blockers or dry_run:
        return result

    assert reviewer is not None
    reviewed_at = datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace("+00:00", "Z")
    receipt_doc = {
        "schema": PROJECT_INTAKE_DECISION_RECEIPT_SCHEMA,
        "receipt_id": f"receipt:project-intake-decisions:{safe_slug(combined_payload['session_id'])}:{decision_sha256[:16]}",
        "receipt_kind": "project_intake_decisions",
        "receipt_path": receipt_relative,
        "action": "archive_project_intake_decisions",
        "dry_run": False,
        "timestamp": reviewed_at,
        "archive_id": archive_id,
        "session_id": combined_payload["session_id"],
        "staged_folder_ref": combined_payload.get("staged_folder_ref"),
        "reviewed_by": reviewer,
        "reviewed_at": reviewed_at,
        "decision_sha256": decision_sha256,
        "source_decision_schema": PROJECT_INTAKE_DECISION_SCHEMA,
        "source_answer_schema": PROJECT_INTAKE_ANSWER_SCHEMA,
        "answer_count": len(combined_payload["decisions"]),
        "checklist_ids": checklist_ids,
        "decisions": combined_payload["decisions"],
        "privacy_guards": privacy_guards,
        "closed_actions": closed_actions,
        "files_written": [receipt_relative],
        "blockers": [],
        "warnings": unique_preserve_order(warnings),
    }

    created_dirs = missing_parent_dirs_before_write(root, [receipt_path])
    created_paths: list[Path] = []
    try:
        receipt_path.parent.mkdir(parents=True, exist_ok=True)
        write_json_new_file(receipt_path, receipt_doc)
        created_paths.append(receipt_path)
    except Exception:
        for path in created_paths:
            try:
                path.unlink()
            except OSError:
                pass
        cleanup_created_empty_dirs(root, created_dirs)
        raise

    result.update(
        {
            "ok": True,
            "dry_run": False,
            "receipt_path": receipt_relative,
            "files_written": [receipt_relative],
            "would_change": [],
            "privacy_guards": privacy_guards,
        }
    )
    return result


def project_intake_decision_status_next_actions(blockers: list[str], missing_ids: list[str]) -> list[str]:
    if blockers:
        return ["fix the project intake decision receipt before using it as session context"]
    actions: list[str] = []
    if missing_ids:
        actions.append("review the missing checklist ids with the user before treating the intake session as complete")
    actions.extend(
        [
            "use the recorded decisions only as context for one-item-at-a-time source-intake dry-runs",
            "capture objets only after the specific original item or group is reviewed again for the current command",
            "keep create-draft, mint-zet, and staged cleanup as separate approval gates",
            "do not delete staged folders from this status report",
        ]
    )
    return actions


def project_intake_status(
    archive_root: Path | str,
    receipt: str,
    *,
    dry_run: bool = False,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []
    if not dry_run:
        blockers.append("Project intake status is read-only and requires --dry-run.")

    try:
        receipt_path = resolve_receipt_input_path(root, receipt)
    except ArchiveServiceError:
        raise

    if is_path_within_root(receipt_path, root):
        receipt_relative = archive_relative_path(receipt_path, root)
    else:
        receipt_relative = "<outside-archive>"
        blockers.append("Project intake decision receipt must be inside the archive root.")

    if receipt_relative != "<outside-archive>":
        if not receipt_relative.startswith(f"{PROJECT_INTAKE_DECISION_RECEIPTS_DIR}/"):
            blockers.append("Project intake decision receipt must be under receipts/project-intake/.")
        if not receipt_relative.endswith(".project-intake-decisions.json"):
            blockers.append("Project intake decision receipt filename must end with .project-intake-decisions.json.")

    receipt_doc = None
    if receipt_relative != "<outside-archive>":
        receipt_doc = load_json_object_for_review(receipt_path, "project intake decision receipt", blockers)

    session_id: str | None = None
    reviewed_by: str | None = None
    reviewed_at: str | None = None
    decision_sha256: str | None = None
    answered_ids: list[str] = []
    answer_count = 0
    if receipt_doc is not None:
        if receipt_doc.get("schema") != PROJECT_INTAKE_DECISION_RECEIPT_SCHEMA:
            blockers.append(f"Project intake decision receipt schema must be {PROJECT_INTAKE_DECISION_RECEIPT_SCHEMA}.")
        if receipt_doc.get("receipt_kind") != "project_intake_decisions":
            blockers.append("Project intake decision receipt_kind must be project_intake_decisions.")
        if receipt_doc.get("action") != "archive_project_intake_decisions":
            blockers.append("Project intake decision action must be archive_project_intake_decisions.")
        if receipt_doc.get("dry_run") is not False:
            blockers.append("Project intake decision receipt must be an approved non-dry-run receipt.")
        if receipt_doc.get("archive_id") != archive_id:
            blockers.append("Project intake decision receipt archive_id must match this archive.")
        if receipt_doc.get("receipt_path") and receipt_doc.get("receipt_path") != receipt_relative:
            blockers.append("Project intake decision receipt_path must match the reviewed file path.")

        session_id = safe_project_intake_session_id(receipt_doc.get("session_id"))
        if session_id is None:
            blockers.append("Project intake decision receipt session_id must be safe.")
        reviewed_by = safe_project_intake_actor_id(
            receipt_doc.get("reviewed_by") if isinstance(receipt_doc.get("reviewed_by"), str) else None
        )
        if reviewed_by is None:
            blockers.append("Project intake decision receipt reviewed_by must be a safe actor id.")
        reviewed_at_value = receipt_doc.get("reviewed_at")
        if isinstance(reviewed_at_value, str) and is_utc_z_timestamp(reviewed_at_value):
            reviewed_at = reviewed_at_value
        else:
            blockers.append("Project intake decision receipt reviewed_at must be a UTC Z timestamp.")
        decision_sha = receipt_doc.get("decision_sha256")
        if isinstance(decision_sha, str) and SHA256_RE.match(decision_sha):
            decision_sha256 = decision_sha
        else:
            blockers.append("Project intake decision receipt decision_sha256 must be a SHA-256 hex value.")

        replay_payload = {
            "schema": PROJECT_INTAKE_DECISION_SCHEMA,
            "session_id": receipt_doc.get("session_id"),
            "staged_folder_ref": receipt_doc.get("staged_folder_ref"),
            "decisions": receipt_doc.get("decisions"),
        }
        replay_blockers: list[str] = []
        replay_warnings: list[str] = []
        normalized_payload = normalize_project_intake_decisions_payload(
            replay_payload,
            replay_blockers,
            replay_warnings,
        )
        blockers.extend(replay_blockers)
        warnings.extend(replay_warnings)
        replay_sha256 = sha256_json_hex(normalized_payload)
        if decision_sha256 and replay_sha256 != decision_sha256:
            blockers.append("Project intake decision receipt decision_sha256 does not match the stored decisions.")
        answered_ids = [
            item["checklist_id"]
            for item in normalized_payload["decisions"]
            if isinstance(item.get("checklist_id"), str) and item.get("checklist_id") != "invalid"
        ]
        answer_count = len(normalized_payload["decisions"])
        if receipt_doc.get("answer_count") != answer_count:
            blockers.append("Project intake decision receipt answer_count must match the stored decisions.")
        receipt_checklist_ids = receipt_doc.get("checklist_ids")
        if isinstance(receipt_checklist_ids, list):
            safe_receipt_ids = [item for item in receipt_checklist_ids if isinstance(item, str)]
            if safe_receipt_ids != answered_ids:
                blockers.append("Project intake decision receipt checklist_ids must match the stored decisions.")
        else:
            blockers.append("Project intake decision receipt checklist_ids must be a list.")

    checklist_order = project_intake_checklist_order()
    missing_ids = [checklist_id for checklist_id in checklist_order if checklist_id not in set(answered_ids)]
    if blockers:
        readiness_status = "blocked"
    elif missing_ids:
        readiness_status = "partial_review_recorded"
    else:
        readiness_status = "complete_review_recorded"
    privacy_guards = {
        "receipt_file_read": True,
        "decision_values_echoed": False,
        "staged_folder_scanned": False,
        "file_bodies_read": False,
        "provider_calls": False,
        "writes": False,
    }
    return {
        "ok": not blockers,
        "dry_run": True,
        "action": "archive_project_intake_status",
        "archive_root": str(root),
        "archive_id": archive_id,
        "receipt_path": receipt_relative,
        "session_id": session_id,
        "reviewed_by": reviewed_by,
        "reviewed_at": reviewed_at,
        "decision_sha256": decision_sha256,
        "answer_count": answer_count,
        "checklist_coverage": {
            "answered_count": len(answered_ids),
            "required_count": len(checklist_order),
            "answered_checklist_ids": answered_ids,
            "missing_checklist_ids": missing_ids,
            "complete": not missing_ids,
        },
        "readiness": {
            "status": readiness_status,
            "ready_for_automatic_execution": False,
        },
        "privacy_guards": privacy_guards,
        "next_review_prompts": project_intake_next_review_prompts(missing_ids),
        "next_safe_actions": project_intake_decision_status_next_actions(blockers, missing_ids),
        "would_change": [],
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }


def restore_drill_dry_run(archive_root: Path | str, target: Path | str) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    target_path = Path(target).expanduser().resolve()
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []
    validate_restore_drill_target(root, target_path, blockers)
    copy_plan = restore_drill_copy_plan(root)
    receipt_preview = {
        "receipt_id": f"receipt:restore-drill:{safe_slug(archive_id)}:<execution-time>",
        "action": "restore_drill",
        "dry_run": True,
        "timestamp": "<execution-time>",
        "source_archive": archive_id,
        "source_archive_root": str(root),
        "target_root": str(target_path),
        "copy_plan": copy_plan,
        "validation": {
            "doctor_strict": "planned",
            "index": "planned",
            "search_smoke": "planned",
        },
        "result": {
            "status": "planned",
            "changed_paths": [],
        },
        "blockers": blockers,
        "warnings": warnings,
    }
    return {
        "ok": not blockers,
        "dry_run": True,
        "action": "restore_drill",
        "archive_id": archive_id,
        "archive_root": str(root),
        "target_root": str(target_path),
        "target_exists": target_path.exists(),
        "copy_plan": copy_plan,
        "receipt_preview": receipt_preview,
        "proposed_receipt_path": f"{RESTORE_DRILL_RECEIPTS_DIR}/<timestamp>.restore-drill.json",
        "would_change": [
            str(target_path),
            f"{RESTORE_DRILL_RECEIPTS_DIR}/<timestamp>.restore-drill.json",
        ],
        "blockers": blockers,
        "warnings": warnings,
    }


def validate_restore_drill_target(archive_root: Path, target: Path, blockers: list[str]) -> None:
    if target.exists() and not target.is_dir():
        blockers.append(f"Restore target must be a folder or absent: {target}.")
        return
    if target.exists() and any(target.iterdir()):
        blockers.append(f"Restore target must be empty or absent: {target}.")

    anchor = Path(target.anchor) if target.anchor else None
    if anchor is not None and target == anchor:
        blockers.append(f"Restore target must not be a filesystem or drive root: {target}.")

    kit_root = KIT_ROOT.resolve()
    if target == kit_root or target.is_relative_to(kit_root):
        blockers.append(f"Restore target must not be inside the WOM-kit repository: {target}.")

    if target == archive_root or target.is_relative_to(archive_root):
        blockers.append(f"Restore target must not be inside the source archive: {target}.")

    if archive_root.is_relative_to(target):
        blockers.append(f"Restore target must not contain the source archive: {target}.")

    system_reason = local_source_system_path_reason(target)
    if system_reason:
        blockers.append(f"Restore target must not be inside a system directory: {target} ({system_reason}).")


def restore_drill_copy_plan(archive_root: Path) -> dict[str, Any]:
    included_files = 0
    included_bytes = 0
    excluded_files = 0
    for path in sorted(archive_root.rglob("*")):
        if not path.is_file() or not is_path_within_root(path, archive_root):
            continue
        relative = archive_relative_path(path, archive_root)
        if restore_drill_should_exclude(relative):
            excluded_files += 1
            continue
        included_files += 1
        try:
            included_bytes += path.stat().st_size
        except OSError:
            pass
    return {
        "mode": "control_plane_copy",
        "metadata_only": True,
        "copies_external_originals": False,
        "included_files": included_files,
        "included_bytes": included_bytes,
        "excluded_files": excluded_files,
        "excluded_paths": RESTORE_DRILL_EXCLUDED_PATHS,
    }


def restore_drill_should_exclude(relative_path: str) -> bool:
    normalized = relative_path.replace("\\", "/").lstrip("/")
    for pattern in RESTORE_DRILL_EXCLUDED_PATHS:
        if pattern.endswith("/"):
            prefix = pattern.rstrip("/")
            if normalized == prefix or normalized.startswith(prefix + "/"):
                return True
            continue
        if fnmatch.fnmatch(normalized, pattern):
            return True
    return False


def copy_restore_drill_tree(archive_root: Path, target: Path) -> list[str]:
    changed_paths: list[str] = []
    target.mkdir(parents=True, exist_ok=True)
    for path in sorted(archive_root.rglob("*")):
        if not path.is_file() or not is_path_within_root(path, archive_root):
            continue
        relative = archive_relative_path(path, archive_root)
        if restore_drill_should_exclude(relative):
            continue
        destination = target / Path(relative)
        destination.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(path, destination)
        changed_paths.append(relative)
    return changed_paths


def latest_successful_restore_drill_receipt(archive_root: Path | str) -> dict[str, Any] | None:
    root = require_existing_archive_root(archive_root)
    receipts_root = archive_internal_path(root, RESTORE_DRILL_RECEIPTS_DIR)
    if not receipts_root.is_dir():
        return None
    latest: dict[str, Any] | None = None
    for path in sorted(receipts_root.glob("*.restore-drill.json")):
        if not is_path_within_root(path, root):
            continue
        try:
            data = json.loads(path.read_text(encoding="utf-8"))
        except (json.JSONDecodeError, OSError):
            continue
        if not isinstance(data, dict):
            continue
        result = data.get("result") if isinstance(data.get("result"), dict) else {}
        if data.get("dry_run") is False and result.get("status") == "passed":
            latest = {
                "receipt_path": archive_relative_path(path, root),
                "receipt_id": data.get("receipt_id"),
                "reviewed_by": data.get("reviewed_by"),
                "reviewed_at": data.get("reviewed_at"),
                "target_root": data.get("target_root"),
                "status": result.get("status"),
            }
    return latest


def preflight_check(
    archive_root: Path | str,
    *,
    diagnostics: list[dict[str, Any]] | None = None,
    peer_archive_root: Path | str | None = None,
    require_source_maps: bool = False,
    require_restore_drill: bool = False,
    strict: bool = False,
    docker_runtime: dict[str, Any] | None = None,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []
    findings: list[dict[str, Any]] = []

    def add_finding(severity: str, code: str, message: str, path: str | None = None) -> None:
        finding = {"severity": severity, "code": code, "message": message}
        if path:
            finding["path"] = path
        findings.append(finding)
        if severity == "BLOCKER":
            blockers.append(message)
        elif severity == "WARN":
            warnings.append(message)

    doctor_diagnostics = diagnostics or []
    doctor_errors = [item for item in doctor_diagnostics if item.get("severity") == "ERROR"]
    doctor_warnings = [item for item in doctor_diagnostics if item.get("severity") == "WARN"]
    if doctor_errors:
        add_finding("BLOCKER", "doctor_errors", f"archive doctor reported {len(doctor_errors)} error(s).")
    if doctor_warnings:
        add_finding("WARN", "doctor_warnings", f"archive doctor reported {len(doctor_warnings)} warning(s).")

    sources = list_sources(root)
    source_by_id = {source["source_id"]: source for source in sources["sources"]}
    for source in sources["sources"]:
        if source.get("enabled") and require_source_maps and not source.get("source_map_present"):
            add_finding(
                "BLOCKER",
                "source_map_missing",
                f"Required source map is missing for source: {source['source_id']}.",
                str(source.get("source_map_path") or ""),
            )

    local_profile_checks = []
    for source_id, entry in load_local_source_roots(root).items():
        path_value = entry.get("path") if isinstance(entry, dict) else None
        if not isinstance(path_value, str) or not path_value.strip():
            add_finding("BLOCKER", "local_source_root_missing", f"Local profile path is missing for source: {source_id}.")
            continue
        path = Path(path_value).expanduser().resolve()
        source_type = str(source_by_id.get(source_id, {}).get("source_type") or "")
        check = classify_local_source_root(path, archive_root=root, source_id=source_id, source_type=source_type)
        local_profile_checks.append(check)
        if check["severity"] == "BLOCKER":
            add_finding("BLOCKER", check["code"], check["message"], check.get("path"))
        elif check["severity"] == "WARN":
            add_finding("WARN", check["code"], check["message"], check.get("path"))
        if not path.exists():
            add_finding("WARN", "local_source_root_not_found", f"Local source root does not exist yet: {source_id}.", str(path))

    peer_summary = None
    if peer_archive_root is not None:
        peer = Path(peer_archive_root).expanduser().resolve()
        peer_summary = {"path": str(peer), "exists": peer.exists()}
        if paths_overlap(root, peer):
            add_finding("BLOCKER", "peer_archive_root_overlaps", "Peer archive root overlaps this archive root.", str(peer))
        if not peer.exists():
            add_finding("WARN", "peer_archive_missing", "Peer archive root does not exist yet; create it before team/personal separation testing.", str(peer))
        elif not peer.is_dir():
            add_finding("BLOCKER", "peer_archive_not_directory", "Peer archive root is not a directory.", str(peer))
        else:
            try:
                peer_id = read_archive_id(peer)
                peer_summary["archive_id"] = peer_id
                if peer_id == archive_id:
                    add_finding("BLOCKER", "peer_archive_id_duplicate", "Peer archive id must not match this archive id.", str(peer))
            except ArchiveServiceError as exc:
                add_finding("BLOCKER", "peer_archive_unreadable", f"Peer archive could not be read: {exc}", str(peer))

    provider_summary: dict[str, Any] | None = None
    try:
        provider_summary = provider_bindings_summary(root)
    except ArchiveServiceError as exc:
        add_finding("BLOCKER", "provider_bindings_unreadable", f"Provider bindings could not be read: {exc}")

    mounts = source_mount_plan(root)
    docker = docker_runtime or {"checked": False, "ok": None, "status": "not_checked"}
    if docker.get("checked") and not docker.get("ok"):
        add_finding("BLOCKER", "docker_runtime_unavailable", str(docker.get("message") or "Docker runtime is not available."))

    latest_restore = latest_successful_restore_drill_receipt(root)
    if require_restore_drill and latest_restore is None:
        add_finding(
            "BLOCKER",
            "restore_drill_required",
            "A successful restore drill receipt is required before real source pilot.",
            RESTORE_DRILL_RECEIPTS_DIR,
        )

    ok = not blockers and not (strict and warnings)
    return {
        "ok": ok,
        "action": "archive_preflight_check",
        "archive_root": str(root),
        "archive_id": archive_id,
        "strict": strict,
        "require_source_maps": require_source_maps,
        "require_restore_drill": require_restore_drill,
        "doctor": {
            "checked": bool(diagnostics is not None),
            "errors": len(doctor_errors),
            "warnings": len(doctor_warnings),
            "diagnostics": doctor_diagnostics,
        },
        "sources": {
            "source_count": sources["source_count"],
            "missing_source_maps": [
                source["source_id"]
                for source in sources["sources"]
                if source.get("enabled") and not source.get("source_map_present")
            ],
            "local_profile_checks": local_profile_checks,
            "mount_plan": mounts,
        },
        "providers": provider_summary,
        "peer_archive": peer_summary,
        "restore_drill": {
            "required": require_restore_drill,
            "latest_successful": latest_restore,
        },
        "docker_runtime": docker,
        "findings": findings,
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
        "next_safe_actions": preflight_next_actions(blockers, warnings),
    }


def classify_local_source_root(
    path: Path,
    *,
    archive_root: Path,
    source_id: str,
    source_type: str,
) -> dict[str, Any]:
    resolved = path.expanduser().resolve()
    severity = "OK"
    code = "local_source_root_ok"
    message = f"Local source root looks narrow enough for first pilot: {source_id}."

    def result(new_severity: str, new_code: str, new_message: str) -> dict[str, Any]:
        return {
            "source_id": source_id,
            "source_type": source_type,
            "path": str(resolved),
            "exists": resolved.exists(),
            "severity": new_severity,
            "code": new_code,
            "message": new_message,
        }

    anchor = Path(resolved.anchor) if resolved.anchor else None
    if anchor is not None and resolved == anchor:
        return result("BLOCKER", "local_source_root_too_broad", f"Local source root is a filesystem or drive root: {source_id}.")

    home = Path.home().resolve()
    if resolved == home:
        return result("BLOCKER", "local_source_root_home", f"Local source root is the whole home folder: {source_id}.")

    system_reason = local_source_system_path_reason(resolved)
    if system_reason:
        return result("BLOCKER", "local_source_root_system_path", f"Local source root points into a system directory: {source_id} ({system_reason}).")

    kit_root = KIT_ROOT.resolve()
    if resolved == kit_root or kit_root.is_relative_to(resolved):
        return result("BLOCKER", "local_source_root_contains_repo", f"Local source root contains the WOM-kit repository: {source_id}.")

    if resolved == archive_root or archive_root.is_relative_to(resolved):
        return result("BLOCKER", "local_source_root_contains_archive", f"Local source root contains the archive itself: {source_id}.")

    broad_home_children = [
        home / "Documents",
        home / "Desktop",
        home / "Downloads",
        home / "OneDrive",
        home / "Google Drive",
    ]
    if any(resolved == item.resolve() for item in broad_home_children if item.exists()):
        return result("WARN", "local_source_root_broad_user_folder", f"Local source root is a broad user folder; first pilot should prefer a narrower subfolder: {source_id}.")

    if resolved.is_relative_to(kit_root):
        return result("WARN", "local_source_root_inside_repo", f"Local source root is inside the WOM-kit repository checkout: {source_id}.")

    if resolved.is_relative_to(archive_root):
        return result("WARN", "local_source_root_inside_archive", f"Local source root is inside the archive; prefer archive: refs for internal folders: {source_id}.")

    return result(severity, code, message)


def local_source_system_path_reason(path: Path) -> str | None:
    windows_roots = [
        os.environ.get("SystemRoot"),
        os.environ.get("WINDIR"),
        os.environ.get("ProgramFiles"),
        os.environ.get("ProgramFiles(x86)"),
    ]
    for raw in windows_roots:
        if not raw:
            continue
        root = Path(raw).resolve()
        if path == root or path.is_relative_to(root):
            return str(root)

    posix_blocked = [Path(item) for item in ["/etc", "/usr", "/bin", "/sbin", "/var", "/opt", "/root"]]
    for root in posix_blocked:
        try:
            resolved = root.resolve()
        except OSError:
            resolved = root
        if path == resolved or path.is_relative_to(resolved):
            return str(resolved)
    return None


def preflight_next_actions(blockers: list[str], warnings: list[str]) -> list[str]:
    if blockers:
        return [
            "Fix blockers before touching real personal or team data.",
            "Run archive doctor --strict after fixing structural or secret-safety problems.",
            "Use add-source --dry-run before registering any real source.",
        ]
    if warnings:
        return [
            "Review warnings with the human owner/operator.",
            "Prefer one narrow source for the first scan.",
            "Run scan-source --dry-run and check item_count before approving a scan.",
        ]
    return [
        "Start with one narrow source registration dry-run.",
        "Run metadata-only scan-source --dry-run.",
        "Approve only after reviewing item_count, source root, and receipt preview.",
    ]


def profile_list(
    registry_path: Path | str,
    *,
    current_profile: str | None = None,
    strict: bool = False,
    redact_local_paths: bool = True,
) -> dict[str, Any]:
    registry_file, registry, blockers, warnings = load_profile_registry(registry_path)
    profiles = profile_registry_entries(registry, blockers, warnings)
    if strict and warnings:
        blockers.extend(warnings)
        warnings = []

    return {
        "ok": not blockers,
        "lifecycle_action": "profile_list",
        "registry_path": redacted_path_value(registry_file, redact_local_paths=redact_local_paths),
        "default_profile": registry.get("default_profile"),
        "current_profile": current_profile,
        "profiles": [profile_public_summary(profile, redact_local_paths=redact_local_paths) for profile in profiles],
        "warnings": unique_preserve_order(warnings),
        "blockers": unique_preserve_order(blockers),
        "redaction": {"local_paths_redacted": bool(redact_local_paths)},
    }


def profile_resolve(
    registry_path: Path | str,
    *,
    target: str,
    current_profile: str | None = None,
    strict: bool = False,
    redact_local_paths: bool = True,
) -> dict[str, Any]:
    registry_file, registry, blockers, warnings = load_profile_registry(registry_path)
    profiles = profile_registry_entries(registry, blockers, warnings)
    query = normalize_profile_lookup_text(target or "")
    if not query:
        blockers.append("target query is required.")

    matches = resolve_profile_matches(profiles, query) if query else []
    selected_profile = matches[0]["profile"] if len(matches) == 1 else None
    resolution_state = profile_resolution_state(matches, selected_profile)
    direct_write_available = False
    suggested_next_action = "suggest_delegate_flow"
    delegate_fallback_preview: dict[str, Any] | None = None
    target_archive_context_preview = None
    runtime_context_args_preview = None

    if len(matches) > 1:
        resolution_state = "ambiguous"
        suggested_next_action = "ask_user_to_choose_profile"
        warnings.append("Multiple profiles matched the target query; ask the user to choose one.")
    elif not matches:
        resolution_state = "not_found"
        suggested_next_action = "suggest_delegate_flow"
        warnings.append("No profile matched the target query; register the profile or use a delegate flow.")
        delegate_fallback_preview = {
            "available": True,
            "reason": "target_profile_not_found",
            "suggestion": "Ask the user to choose/register a profile, or prepare a delegate flow instead of direct archive writing.",
        }
    elif selected_profile is not None:
        token_state = profile_token_state(selected_profile)
        archive_root = profile_archive_root(selected_profile)
        if token_state == "missing":
            resolution_state = "token_missing"
            suggested_next_action = "register_profile_token"
            warnings.append("Matched profile has no usable token; direct write is not available.")
            delegate_fallback_preview = {
                "available": True,
                "reason": "profile_token_missing",
                "suggestion": "Register the profile token, or use a delegate flow if this AI should not write to the target archive.",
            }
        else:
            resolution_state = "resolved"
            suggested_next_action = "run_runtime_context"

        if not archive_root:
            direct_write_available = False
            warnings.append("Matched profile is missing archive_root; direct write is not available.")
        else:
            direct_write_available = token_state != "missing"

        target_archive_context_preview = profile_context_preview(selected_profile, redact_local_paths=redact_local_paths)
        runtime_context_args_preview = {
            "archive_root": redact_profile_archive_root(archive_root, redact_local_paths=redact_local_paths),
            "expected_archive_id": selected_profile.get("archive_id"),
            "expected_type": selected_profile.get("archive_type"),
            "format": "json",
        }

    if strict and warnings and resolution_state not in {"token_missing", "not_found"}:
        blockers.extend(warnings)
        warnings = []

    return {
        "ok": not blockers and resolution_state not in {"ambiguous", "not_found"},
        "lifecycle_action": "profile_resolve",
        "target_query": query,
        "current_profile": current_profile,
        "default_profile": registry.get("default_profile"),
        "matches": [profile_match_summary(match, redact_local_paths=redact_local_paths) for match in matches],
        "selected_profile": profile_public_summary(selected_profile, redact_local_paths=redact_local_paths)
        if selected_profile is not None and len(matches) == 1
        else None,
        "resolution_state": resolution_state,
        "direct_write_available": direct_write_available,
        "suggested_next_action": suggested_next_action,
        "target_archive_context_preview": target_archive_context_preview,
        "runtime_context_args_preview": runtime_context_args_preview,
        "delegate_fallback_preview": delegate_fallback_preview,
        "warnings": unique_preserve_order(warnings),
        "blockers": unique_preserve_order(blockers),
        "redaction": {"local_paths_redacted": bool(redact_local_paths)},
        "registry_path": redacted_path_value(registry_file, redact_local_paths=redact_local_paths),
    }


def profile_wallet_preview(
    archive_root: Path | str,
    *,
    profile: str,
    registry_path: Path | str | None = None,
    dry_run: bool = True,
    redact_local_paths: bool = True,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []

    if not dry_run:
        blockers.append("profile-wallet is a read-only dry-run preview; pass --dry-run.")

    registry_file = resolve_profile_wallet_registry_path(root, registry_path, blockers, warnings)
    registry: dict[str, Any] = {}
    profiles: list[dict[str, Any]] = []
    matches: list[dict[str, Any]] = []
    selected_profile: dict[str, Any] | None = None
    resolution_state = "not_found"

    query = normalize_profile_lookup_text(profile or "")
    if not query:
        blockers.append("profile is required.")

    if registry_file is not None:
        _registry_file, registry, registry_blockers, registry_warnings = load_profile_registry(registry_file)
        blockers.extend(registry_blockers)
        warnings.extend(registry_warnings)
        profiles = profile_registry_entries(registry, blockers, warnings)
        matches = resolve_profile_matches(profiles, query) if query else []
        selected_profile = matches[0]["profile"] if len(matches) == 1 else None
        resolution_state = profile_wallet_resolution_state(matches, selected_profile)
        if len(matches) > 1:
            blockers.append("Multiple profiles matched the requested profile; ask the user to choose one.")
        elif not matches and query:
            blockers.append("Requested WOM profile was not found in the registry.")

    if selected_profile is not None:
        validate_profile_wallet_metadata(selected_profile, blockers, warnings)
        selected_archive_id = selected_profile.get("archive_id")
        if isinstance(selected_archive_id, str) and selected_archive_id and selected_archive_id != archive_id:
            warnings.append(
                "Selected profile archive_id differs from the supplied archive_root; confirm the target archive before writes."
            )

    warnings.append(
        "WOM profile wallet metadata is wallet-ready identity context only; v0.2.33 does not generate keys or sign data."
    )

    return {
        "ok": not blockers,
        "dry_run": bool(dry_run),
        "lifecycle_action": "profile_wallet_preview",
        "archive_id": archive_id,
        "registry_path": redacted_path_value(registry_file, redact_local_paths=redact_local_paths) if registry_file else None,
        "target_query": query,
        "resolution_state": resolution_state,
        "profile": profile_public_summary(selected_profile, redact_local_paths=redact_local_paths)
        if selected_profile is not None
        else None,
        "matches": [profile_match_summary(match, redact_local_paths=redact_local_paths) for match in matches],
        "node_identity_preview": profile_node_identity_preview(selected_profile),
        "wallet_identity_preview": profile_wallet_identity_preview(selected_profile),
        "signing_readiness": profile_wallet_signing_readiness(selected_profile),
        "capability_surface_preview": profile_wallet_capability_surface_preview(),
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
        "would_change": [],
        "redaction": {"local_paths_redacted": bool(redact_local_paths)},
    }


def resolve_profile_wallet_registry_path(
    archive_root: Path,
    registry_path: Path | str | None,
    blockers: list[str],
    warnings: list[str],
) -> Path | None:
    if registry_path is not None:
        return Path(registry_path).expanduser().resolve()
    for candidate in PROFILE_WALLET_REGISTRY_CANDIDATES:
        path = archive_root / candidate
        if path.is_file():
            return path.resolve()
    blockers.append(
        "Profile registry was not found under the archive root. Pass --registry or create profiles/wom-profiles.yml."
    )
    warnings.append("Only fixed archive-local registry paths were checked; no whole-disk scan was performed.")
    return None


def profile_wallet_resolution_state(matches: list[dict[str, Any]], selected_profile: dict[str, Any] | None) -> str:
    if len(matches) > 1:
        return "ambiguous"
    if selected_profile is None:
        return "not_found"
    return "resolved"


def profile_node_identity_preview(profile: dict[str, Any] | None) -> dict[str, Any]:
    if profile is None:
        return {
            "available": False,
            "wallet_ready_identity_model": True,
            "note": "No resolved profile is available for node identity preview.",
        }
    node = profile.get("node") if isinstance(profile.get("node"), dict) else {}
    node_id = safe_profile_wallet_value(node.get("node_id")) or safe_profile_wallet_value(profile.get("node_id"))
    node_kind = safe_profile_wallet_value(node.get("node_kind")) or infer_profile_node_kind(node_id, profile.get("archive_type"))
    display_label = safe_profile_wallet_text(node.get("display_label")) or safe_profile_wallet_text(profile.get("label"))
    return drop_none_values(
        {
            "available": True,
            "node_id": node_id,
            "node_kind": node_kind,
            "display_label": display_label,
            "profile_id": profile.get("profile_id"),
            "archive_id": profile.get("archive_id"),
            "wallet_ready_identity_model": True,
            "model_note": "WOM profile selects the human-facing identity; WOM node is the subject/principal in the WOM network.",
        }
    )


def profile_wallet_identity_preview(profile: dict[str, Any] | None) -> dict[str, Any]:
    if profile is None:
        return {
            "available": False,
            "real_wallet": False,
            "real_signing_enabled": False,
            "note": "No resolved profile is available for wallet identity preview.",
        }
    wallet = profile.get("wallet") if isinstance(profile.get("wallet"), dict) else {}
    signing_status = safe_profile_wallet_value(wallet.get("signing_status")) or "not_configured"
    return drop_none_values(
        {
            "available": bool(wallet),
            "wallet_id": safe_profile_wallet_value(wallet.get("wallet_id")),
            "fingerprint": safe_profile_wallet_value(wallet.get("fingerprint")),
            "custody": safe_profile_wallet_value(wallet.get("custody")),
            "signing_status": signing_status,
            "signer_ref": safe_profile_wallet_value(wallet.get("signer_ref")),
            "real_wallet": False,
            "private_key_present": False,
            "seed_phrase_present": False,
            "real_signing_enabled": False,
            "model_note": "This is public wallet-ready metadata, not key material or a blockchain wallet.",
        }
    )


def profile_wallet_signing_readiness(profile: dict[str, Any] | None) -> dict[str, Any]:
    wallet = profile.get("wallet") if isinstance(profile, dict) and isinstance(profile.get("wallet"), dict) else {}
    status = safe_profile_wallet_value(wallet.get("signing_status")) or "not_configured"
    return {
        "status": status,
        "wallet_metadata_present": bool(wallet),
        "real_signing_available": False,
        "key_generation_available": False,
        "blockchain_api_called": False,
        "provider_api_called": False,
        "deferred_reason": "Private-key custody, signing UX, recovery, and threat modeling are future work.",
    }


def profile_wallet_capability_surface_preview() -> dict[str, Any]:
    return {
        "future_relevance": [
            "mint",
            "delegate",
            "attest",
            "anchor",
            "receipts",
            "block_headers",
            "ZET_sharing",
        ],
        "v0_2_25_available": [],
        "mutating_wallet_actions_available": False,
        "real_signing_available": False,
        "model_note": "A future WOM wallet layer can bind profile/node identity to capability proofs; v0.2.33 only previews readiness.",
    }


def validate_profile_wallet_metadata(profile: dict[str, Any], blockers: list[str], warnings: list[str]) -> None:
    profile_id = str(profile.get("profile_id") or "<unknown-profile>")
    node = profile.get("node")
    wallet = profile.get("wallet")
    if node is not None and not isinstance(node, dict):
        blockers.append(f"Profile {profile_id} node must be an object when present.")
        node = None
    if wallet is not None and not isinstance(wallet, dict):
        blockers.append(f"Profile {profile_id} wallet must be an object when present.")
        wallet = None

    if isinstance(node, dict):
        unknown_node_keys = sorted(str(key) for key in node.keys() if str(key) not in PROFILE_WALLET_NODE_KEYS)
        if unknown_node_keys:
            warnings.append(
                f"Profile {profile_id} node contains unsupported field(s) not shown in preview: "
                + ", ".join(unknown_node_keys)
                + "."
            )
        validate_profile_wallet_value_tree(node, blockers, f"profile {profile_id}.node")
        node_kind = node.get("node_kind")
        if isinstance(node_kind, str) and node_kind.strip() and node_kind.strip() not in PROFILE_WALLET_NODE_KINDS:
            blockers.append(
                f"Profile {profile_id} node.node_kind must be one of: "
                + ", ".join(sorted(PROFILE_WALLET_NODE_KINDS))
                + "."
            )

    if isinstance(wallet, dict):
        unknown_wallet_keys = sorted(str(key) for key in wallet.keys() if str(key) not in PROFILE_WALLET_WALLET_KEYS)
        if unknown_wallet_keys:
            blockers.append(
                f"Profile {profile_id} wallet contains unsupported field(s): "
                + ", ".join(unknown_wallet_keys)
                + ". Only public placeholder wallet metadata fields are allowed."
            )
        validate_profile_wallet_value_tree(wallet, blockers, f"profile {profile_id}.wallet")
        custody = wallet.get("custody")
        if isinstance(custody, str) and custody.strip() and custody.strip() not in PROFILE_WALLET_CUSTODY_MODES:
            blockers.append(
                f"Profile {profile_id} wallet.custody must be one of: "
                + ", ".join(sorted(PROFILE_WALLET_CUSTODY_MODES))
                + "."
            )
        signing_status = wallet.get("signing_status")
        if (
            isinstance(signing_status, str)
            and signing_status.strip()
            and signing_status.strip() not in PROFILE_WALLET_SIGNING_STATUSES
        ):
            blockers.append(
                f"Profile {profile_id} wallet.signing_status must be one of: "
                + ", ".join(sorted(PROFILE_WALLET_SIGNING_STATUSES))
                + "."
            )


def validate_profile_wallet_value_tree(value: Any, blockers: list[str], field_path: str) -> None:
    if isinstance(value, dict):
        for key, child in value.items():
            key_text = str(key)
            normalized_key = key_text.casefold().replace("-", "_")
            if normalized_key in PROFILE_WALLET_SECRET_KEYS:
                blockers.append(f"{field_path}.{key_text} is a secret-like field; store no key, token, seed, or credential values.")
            validate_profile_wallet_value_tree(child, blockers, f"{field_path}.{key_text}")
        return
    if isinstance(value, list):
        for index, child in enumerate(value):
            validate_profile_wallet_value_tree(child, blockers, f"{field_path}[{index}]")
        return
    if value is None:
        return
    text = str(value)
    if profile_wallet_value_is_private_or_secret(text):
        blockers.append(f"{field_path} contains private path, provider URL, wallet address, token-like, or secret-like data.")


def profile_wallet_value_is_private_or_secret(value: str) -> bool:
    text = value.strip()
    return bool(
        contains_forbidden_location_reference(text)
        or "://" in text
        or "@" in text
        or DRAFT_SECRET_VALUE_RE.search(text)
        or GITHUB_SECRET_LIKE_RE.search(text)
        or PROFILE_WALLET_ADDRESS_RE.search(text)
    )


def safe_profile_wallet_value(value: Any) -> str | None:
    if not isinstance(value, str):
        return None
    text = value.strip()
    if not text or profile_wallet_value_is_private_or_secret(text):
        return None
    return text


def safe_profile_wallet_text(value: Any) -> str | None:
    if not isinstance(value, str):
        return None
    text = unicodedata.normalize("NFC", value).strip()
    if not text or profile_wallet_value_is_private_or_secret(text):
        return None
    return text


def infer_profile_node_kind(node_id: str | None, archive_type: Any) -> str | None:
    if isinstance(node_id, str) and ":" in node_id:
        candidate = node_id.split(":", 2)[1] if node_id.startswith("node:") and node_id.count(":") >= 2 else node_id.split(":", 1)[0]
        if candidate in PROFILE_WALLET_NODE_KINDS:
            return candidate
    archive_type_text = archive_type if isinstance(archive_type, str) else None
    if archive_type_text == "personal":
        return "person"
    if archive_type_text == "company":
        return "organization"
    if archive_type_text in {"family", "project"}:
        return archive_type_text
    return None


def load_profile_registry(registry_path: Path | str) -> tuple[Path, dict[str, Any], list[str], list[str]]:
    registry_file = Path(registry_path).expanduser().resolve()
    blockers: list[str] = []
    warnings: list[str] = []
    if not registry_file.is_file():
        return registry_file, {}, ["Profile registry does not exist or is not a file."], warnings
    try:
        data = load_yaml(registry_file.read_text(encoding="utf-8"))
    except Exception as exc:
        return registry_file, {}, [f"Profile registry could not be read as YAML: {exc}"], warnings
    if not isinstance(data, dict):
        return registry_file, {}, ["Profile registry must be a YAML object."], warnings
    registry = json_safe(data)
    if registry.get("version") != PROFILE_REGISTRY_VERSION:
        blockers.append(f"Profile registry version must be {PROFILE_REGISTRY_VERSION}.")
    if not isinstance(registry.get("profiles"), list):
        blockers.append("Profile registry must contain a profiles list.")
    return registry_file, registry, blockers, warnings


def profile_registry_entries(registry: dict[str, Any], blockers: list[str], warnings: list[str]) -> list[dict[str, Any]]:
    raw_profiles = registry.get("profiles") if isinstance(registry.get("profiles"), list) else []
    profiles: list[dict[str, Any]] = []
    seen_profile_ids: set[str] = set()
    for index, item in enumerate(raw_profiles):
        if not isinstance(item, dict):
            warnings.append(f"Profile registry item {index} is not an object.")
            continue
        profile = json_safe(item)
        profile_id = profile.get("profile_id")
        if not isinstance(profile_id, str) or not profile_id.strip():
            warnings.append(f"Profile registry item {index} is missing profile_id.")
            continue
        if profile_id in seen_profile_ids:
            blockers.append(f"Profile registry contains duplicate profile_id: {profile_id}.")
        seen_profile_ids.add(profile_id)
        validate_profile_token_contract(profile, blockers)
        if profile.get("archive_type") and profile.get("archive_type") not in PROFILE_REGISTRY_ARCHIVE_TYPES:
            warnings.append(f"Profile {profile_id} has an unknown archive_type.")
        profiles.append(profile)
    return profiles


def validate_profile_token_contract(profile: dict[str, Any], blockers: list[str]) -> None:
    token = profile.get("token")
    if token is None:
        return
    profile_id = str(profile.get("profile_id") or "<unknown-profile>")
    if not isinstance(token, dict):
        blockers.append(f"Profile {profile_id} token must be an object with state/token_ref metadata only.")
        return
    token_keys = {str(key) for key in token.keys()}
    raw_keys = sorted(key for key in token_keys if key.casefold() in PROFILE_RAW_TOKEN_KEYS)
    if raw_keys:
        blockers.append(
            f"Profile {profile_id} token contains raw secret-like field(s): {', '.join(raw_keys)}. "
            "Use token_ref instead of storing token values."
        )
    unknown_keys = sorted(token_keys - PROFILE_ALLOWED_TOKEN_KEYS)
    if unknown_keys:
        blockers.append(
            f"Profile {profile_id} token contains unsupported field(s): {', '.join(unknown_keys)}. "
            "Only state and token_ref are allowed."
        )


def resolve_profile_matches(profiles: list[dict[str, Any]], query: str) -> list[dict[str, Any]]:
    ranked_matches: list[dict[str, Any]] = []
    for profile in profiles:
        match = profile_match(profile, query)
        if match is not None:
            ranked_matches.append(match)
    if not ranked_matches:
        return []
    best_rank = min(match["rank"] for match in ranked_matches)
    return [match for match in ranked_matches if match["rank"] == best_rank]


def profile_match(profile: dict[str, Any], query: str) -> dict[str, Any] | None:
    checks = [
        ("profile_id", profile.get("profile_id"), 0),
        ("label", profile.get("label"), 1),
    ]
    aliases = profile.get("aliases") if isinstance(profile.get("aliases"), list) else []
    for alias in aliases:
        checks.append(("alias", alias, 2))
    for field, value, rank in checks:
        if isinstance(value, str) and exact_profile_query_match(value, query):
            return {
                "profile": profile,
                "profile_id": profile.get("profile_id"),
                "match_type": field,
                "matched_value": value,
                "strength": "strong",
                "rank": rank,
            }
    return None


def exact_profile_query_match(value: str, query: str) -> bool:
    left = normalize_profile_lookup_text(value)
    right = normalize_profile_lookup_text(query)
    return left.casefold() == right.casefold()


def normalize_profile_lookup_text(value: str) -> str:
    return unicodedata.normalize("NFC", value).translate(PROFILE_IGNORABLE_QUERY_CHARS).strip()


def profile_resolution_state(matches: list[dict[str, Any]], selected_profile: dict[str, Any] | None) -> str:
    if len(matches) > 1:
        return "ambiguous"
    if not matches:
        return "not_found"
    if selected_profile is not None and profile_token_state(selected_profile) == "missing":
        return "token_missing"
    return "resolved"


def profile_public_summary(profile: dict[str, Any] | None, *, redact_local_paths: bool) -> dict[str, Any] | None:
    if profile is None:
        return None
    return {
        "profile_id": profile.get("profile_id"),
        "label": profile.get("label"),
        "aliases": profile_aliases(profile),
        "node_id": profile.get("node_id"),
        "archive_id": profile.get("archive_id"),
        "archive_type": profile.get("archive_type"),
        "operator_id": profile.get("operator_id"),
        "authority_mode": profile.get("authority_mode"),
        "token_state": profile_token_state(profile),
        "archive_root": redact_profile_archive_root(profile_archive_root(profile), redact_local_paths=redact_local_paths),
    }


def profile_match_summary(match: dict[str, Any], *, redact_local_paths: bool) -> dict[str, Any]:
    profile = match["profile"]
    return {
        "profile_id": profile.get("profile_id"),
        "label": profile.get("label"),
        "match_type": match.get("match_type"),
        "matched_value": match.get("matched_value"),
        "strength": match.get("strength"),
        "archive_id": profile.get("archive_id"),
        "archive_type": profile.get("archive_type"),
        "token_state": profile_token_state(profile),
        "authority_mode": profile.get("authority_mode"),
        "archive_root": redact_profile_archive_root(profile_archive_root(profile), redact_local_paths=redact_local_paths),
    }


def profile_context_preview(profile: dict[str, Any], *, redact_local_paths: bool) -> dict[str, Any]:
    return {
        "profile_id": profile.get("profile_id"),
        "archive_id": profile.get("archive_id"),
        "archive_type": profile.get("archive_type"),
        "node_id": profile.get("node_id"),
        "operator_id": profile.get("operator_id"),
        "authority_mode": profile.get("authority_mode"),
        "archive_root": redact_profile_archive_root(profile_archive_root(profile), redact_local_paths=redact_local_paths),
    }


def profile_aliases(profile: dict[str, Any]) -> list[str]:
    aliases = profile.get("aliases") if isinstance(profile.get("aliases"), list) else []
    return [alias for alias in aliases if isinstance(alias, str)]


def profile_archive_root(profile: dict[str, Any]) -> str | None:
    archive_root = profile.get("archive_root")
    if isinstance(archive_root, str) and archive_root.strip():
        return archive_root.strip()
    return None


def profile_token_state(profile: dict[str, Any]) -> str:
    token = profile.get("token") if isinstance(profile.get("token"), dict) else {}
    state = token.get("state")
    if isinstance(state, str) and state.strip():
        return state.strip()
    return "missing"


def redact_profile_archive_root(archive_root: str | None, *, redact_local_paths: bool) -> str | None:
    if not archive_root:
        return None
    return "<local-path-redacted>" if redact_local_paths else archive_root


def redacted_path_value(path: Path, *, redact_local_paths: bool) -> str:
    return "<local-path-redacted>" if redact_local_paths else str(path)


def normalize_version_label(value: str | None) -> str | None:
    if value is None:
        return None
    normalized = value.strip().lstrip("\ufeff").strip()
    if normalized.lower().startswith("v"):
        normalized = normalized[1:]
    return normalized or None


def version_sort_key(value: str | None) -> tuple[int, int, int, str] | None:
    normalized = normalize_version_label(value)
    if not normalized:
        return None
    match = re.match(r"^(\d+)\.(\d+)\.(\d+)(.*)$", normalized)
    if not match:
        return None
    return (int(match.group(1)), int(match.group(2)), int(match.group(3)), match.group(4))


def version_label_from_normalized(value: str | None) -> str | None:
    normalized = normalize_version_label(value)
    return f"v{normalized}" if normalized else None


def read_version_from_init_file(path: Path) -> str | None:
    try:
        text = path.read_text(encoding="utf-8")
    except OSError:
        return None
    match = re.search(r'(?m)^__version__\s*=\s*"([^"]+)"\s*$', text)
    return match.group(1) if match else None


def read_pyproject_version_at(path: Path) -> str | None:
    try:
        text = path.read_text(encoding="utf-8")
    except OSError:
        return None
    match = re.search(r'(?m)^version\s*=\s*"([^"]+)"\s*$', text)
    return match.group(1) if match else None


def read_wom_kit_pyproject_version() -> str | None:
    service_path = Path(__file__).resolve()
    pyproject_path = service_path.parents[2] / "pyproject.toml"
    try:
        text = pyproject_path.read_text(encoding="utf-8")
    except OSError:
        return None
    match = re.search(r'(?m)^version\s*=\s*"([^"]+)"\s*$', text)
    return match.group(1) if match else None


def wom_kit_version_pin_search_roots(root: Path) -> list[tuple[str, Path]]:
    roots = [("inspection_root", root)]
    if (root / "archive.yml").is_file() and root.parent != root:
        roots.append(("parent_of_archive", root.parent))
    return roots


def wom_kit_version_pin_location(root_label: str, candidate: str) -> str:
    if root_label == "inspection_root":
        return candidate
    return f"{root_label}/{candidate}"


def wom_kit_project_source_mirror_search_roots(root: Path) -> list[tuple[str, Path]]:
    return wom_kit_version_pin_search_roots(root)


def wom_kit_project_source_mirror_location(root_label: str) -> str:
    location = ".zettel-kasten/source"
    if root_label == "inspection_root":
        return location
    return f"{root_label}/{location}"


def git_output_lines(cwd: Path, args: list[str]) -> list[str]:
    try:
        completed = subprocess.run(
            ["git", "-C", str(cwd), *args],
            check=False,
            capture_output=True,
            text=True,
            timeout=5,
        )
    except (OSError, subprocess.SubprocessError):
        return []
    if completed.returncode != 0:
        return []
    return [line.strip() for line in completed.stdout.splitlines() if line.strip()]


def latest_semver_tag(labels: Iterable[str]) -> str | None:
    candidates: list[tuple[tuple[int, int, int, str], str]] = []
    for label in labels:
        key = version_sort_key(label)
        if key is not None:
            candidates.append((key, label.strip()))
    if not candidates:
        return None
    return max(candidates, key=lambda item: item[0])[1]


def wom_kit_project_source_mirror_info(
    inspection_root: Path | None,
    *,
    normalized_package: str | None,
    warnings: list[str],
) -> dict[str, Any]:
    summary: dict[str, Any] = {
        "checked": inspection_root is not None,
        "status": "not_checked",
        "path": None,
        "checked_locations": [],
        "source_version": None,
        "pyproject_version": None,
        "source_matches_pyproject_version": None,
        "source_matches_running_version": None,
        "installed_pin": None,
        "pin_matches_source_version": None,
        "head_tag": None,
        "latest_fetched_tag": None,
        "mirror_behind_latest_fetched_tag": None,
    }
    if inspection_root is None:
        return summary
    if not inspection_root.exists():
        summary["status"] = "inspection_root_missing"
        return summary

    mirror_path: Path | None = None
    for root_label, search_root in wom_kit_project_source_mirror_search_roots(inspection_root):
        logical_location = wom_kit_project_source_mirror_location(root_label)
        summary["checked_locations"].append(logical_location)
        candidate_path = search_root / ".zettel-kasten" / "source"
        if candidate_path.is_dir():
            mirror_path = candidate_path
            summary["status"] = "present"
            summary["path"] = logical_location
            break
    if mirror_path is None:
        summary["status"] = "missing"
        return summary

    source_version = (
        read_version_from_init_file(mirror_path / "wom-kit" / "src" / "wom_kit" / "__init__.py")
        or read_version_from_init_file(mirror_path / "wom_kit" / "__init__.py")
    )
    pyproject_version = read_pyproject_version_at(mirror_path / "wom-kit" / "pyproject.toml")
    pin_path = mirror_path / "installed-version.txt"
    installed_pin: str | None = None
    if pin_path.is_file():
        try:
            installed_pin = pin_path.read_text(encoding="utf-8").strip().lstrip("\ufeff").strip()
        except OSError:
            installed_pin = None
    summary["source_version"] = source_version
    summary["pyproject_version"] = pyproject_version
    summary["installed_pin"] = installed_pin

    normalized_source = normalize_version_label(source_version)
    normalized_pyproject = normalize_version_label(pyproject_version)
    normalized_pin = normalize_version_label(installed_pin)
    if normalized_source is None and normalized_pyproject is None:
        summary["status"] = "metadata_only"
        return summary

    if normalized_source is not None and normalized_pyproject is not None:
        summary["source_matches_pyproject_version"] = normalized_source == normalized_pyproject
        if summary["source_matches_pyproject_version"] is False:
            warnings.append("WOM-kit project source mirror package and pyproject.toml versions differ.")
    if normalized_source is not None and normalized_package is not None:
        summary["source_matches_running_version"] = normalized_source == normalized_package
        if summary["source_matches_running_version"] is False:
            warnings.append("WOM-kit project source mirror differs from the running CLI version.")
    if normalized_pin is not None and normalized_source is not None:
        summary["pin_matches_source_version"] = normalized_pin == normalized_source
        if summary["pin_matches_source_version"] is False:
            warnings.append("WOM-kit project source mirror installed-version pin differs from the source mirror version.")

    head_tags = git_output_lines(mirror_path, ["describe", "--tags", "--exact-match", "HEAD"])
    if head_tags:
        summary["head_tag"] = head_tags[0]
    summary["latest_fetched_tag"] = latest_semver_tag(git_output_lines(mirror_path, ["tag", "--list", "v*"]))
    latest_key = version_sort_key(str(summary["latest_fetched_tag"] or ""))
    source_key = version_sort_key(source_version)
    if latest_key is not None and source_key is not None:
        behind = source_key < latest_key
        summary["mirror_behind_latest_fetched_tag"] = behind
        if behind:
            warnings.append("WOM-kit project source mirror is behind its latest fetched tag.")

    return summary


def wom_kit_version_info(
    inspection_root: Path | str | None = None,
    *,
    redact_local_paths: bool = True,
) -> dict[str, Any]:
    service_path = Path(__file__).resolve()
    kit_root = service_path.parents[2]
    pyproject_version = read_wom_kit_pyproject_version()
    package_version = WOM_KIT_VERSION
    normalized_package = normalize_version_label(package_version)
    normalized_pyproject = normalize_version_label(pyproject_version)
    pyproject_matches = (
        normalized_pyproject == normalized_package
        if normalized_pyproject is not None
        else None
    )
    warnings: list[str] = []
    if pyproject_matches is False:
        warnings.append("WOM-kit package version and pyproject.toml version differ.")

    pin_summary: dict[str, Any] = {
        "checked": False,
        "status": "not_checked",
        "path": None,
        "pin_root": None,
        "installed_version": None,
        "matches_package_version": None,
        "checked_locations": [],
    }
    root: Path | None = None
    if inspection_root is not None:
        root = Path(inspection_root).expanduser().resolve()
        pin_summary["checked"] = True
        if not root.exists():
            pin_summary["status"] = "inspection_root_missing"
            warnings.append("Version inspection root does not exist.")
        else:
            for root_label, search_root in wom_kit_version_pin_search_roots(root):
                for candidate in WOM_KIT_VERSION_PIN_CANDIDATES:
                    logical_location = wom_kit_version_pin_location(root_label, candidate)
                    pin_summary["checked_locations"].append(logical_location)
                    candidate_path = search_root / candidate
                    if candidate_path.is_file():
                        try:
                            installed_version = candidate_path.read_text(encoding="utf-8").strip()
                        except OSError:
                            installed_version = None
                            pin_summary["status"] = "unreadable"
                            pin_summary["path"] = logical_location
                            pin_summary["pin_root"] = root_label
                            warnings.append("WOM-kit installed-version pin could not be read.")
                        else:
                            installed_version = installed_version.lstrip("\ufeff").strip()
                            pin_summary["status"] = "present"
                            pin_summary["path"] = logical_location
                            pin_summary["pin_root"] = root_label
                            pin_summary["installed_version"] = installed_version
                            pin_summary["matches_package_version"] = (
                                normalize_version_label(installed_version) == normalized_package
                            )
                            if pin_summary["matches_package_version"] is False:
                                warnings.append("WOM-kit installed-version pin differs from the running CLI version.")
                        break
                if pin_summary["status"] != "not_checked":
                    break
            else:
                pin_summary["status"] = "missing"

    source_mirror = wom_kit_project_source_mirror_info(
        root,
        normalized_package=normalized_package,
        warnings=warnings,
    )

    consistency_state = "source_checkout_match"
    if pyproject_matches is False:
        consistency_state = "source_checkout_mismatch"
    elif pyproject_matches is None:
        consistency_state = "package_version_only"
    if pin_summary["matches_package_version"] is False:
        consistency_state = "project_pin_mismatch"
    if source_mirror.get("source_matches_running_version") is False:
        consistency_state = "project_source_mirror_mismatch"
    if source_mirror.get("mirror_behind_latest_fetched_tag") is True:
        consistency_state = "project_source_mirror_behind_latest_fetched_tag"

    result: dict[str, Any] = {
        "ok": not warnings,
        "lifecycle_action": "wom_kit_version",
        "package": "wom_kit",
        "cli_entrypoint": "archive",
        "version": package_version,
        "version_label": f"v{package_version}",
        "source_of_truth": "wom_kit.__version__",
        "pyproject_version": pyproject_version,
        "pyproject_matches_package_version": pyproject_matches,
        "project_pin": pin_summary,
        "project_source_mirror": source_mirror,
        "consistency_state": consistency_state,
        "canonical_checks": {
            "human_readable": "archive --version",
            "structured": "archive version --format json",
            "runtime_context": "archive runtime-context <archive-root> --format json",
        },
        "paths": {
            "pyproject": "wom-kit/pyproject.toml" if pyproject_version is not None else None,
            "package_init": "wom-kit/src/wom_kit/__init__.py",
            "repo_root_shim": "wom_kit/__init__.py",
        },
        "redaction": {
            "local_paths_redacted": bool(redact_local_paths),
        },
        "closed_actions": {
            "files_written": False,
            "provider_api_called": False,
            "secrets_read": False,
        },
        "warnings": unique_preserve_order(warnings),
        "blockers": [],
    }
    if not redact_local_paths:
        local_paths: dict[str, str | None] = {
            "module": str(service_path),
            "kit_root": str(kit_root),
            "pyproject": str(kit_root / "pyproject.toml") if pyproject_version is not None else None,
        }
        if inspection_root is not None:
            local_paths["inspection_root"] = str(Path(inspection_root).expanduser().resolve())
        result["local_paths"] = local_paths
    return result


def operational_context(
    archive_root: Path | str,
    *,
    record_path: str | None = None,
    dry_run: bool = False,
    approve: bool = False,
    reviewed_by: str | None = None,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []
    target_relative = OPERATIONAL_CONTEXT_RELATIVE_PATH
    target_path = archive_internal_path(root, target_relative)
    reviewer = safe_foreign_quarantine_actor_id(reviewed_by)

    if dry_run is approve:
        blockers.append("Choose exactly one mode: --dry-run or --approve.")
    if approve and not record_path:
        blockers.append("operational-context approve requires --record.")
    if approve and not reviewer:
        blockers.append("operational-context approve requires a safe --reviewed-by actor id.")
    if reviewed_by and reviewer is None:
        blockers.append("reviewed_by must be a safe non-secret actor id.")

    if record_path:
        source_relative = operational_context_source_relative_path(root, record_path, blockers)
        source_text: str | None = None
        if source_relative:
            if source_relative == target_relative:
                blockers.append("--record must point to a staged candidate, not ops/operational-context.yml itself.")
            else:
                source_path = archive_internal_path(root, source_relative)
                if not source_path.is_file():
                    blockers.append("operational context candidate record is missing.")
                else:
                    source_text = source_path.read_text(encoding="utf-8")
        candidate_record = operational_context_parse_record_text(source_text, blockers, warnings) if source_text else None
        base_record_hash = sha256_json_value(candidate_record) if candidate_record else None
        proposed_receipt_path = operational_context_receipt_relative_path(base_record_hash) if base_record_hash else None
        if proposed_receipt_path and archive_internal_path(root, proposed_receipt_path).exists():
            blockers.append(f"Proposed operational context receipt already exists: {proposed_receipt_path}.")
        result: dict[str, Any] = {
            "ok": not blockers,
            "dry_run": bool(dry_run),
            "lifecycle_action": "operational_context",
            "archive_id": archive_id,
            "record_path": target_relative,
            "source_record_path": source_relative,
            "status": "blocked" if blockers else ("would_write" if dry_run else "ready_to_write"),
            "record": candidate_record,
            "session_start_injection": operational_context_session_start_injection(candidate_record)
            if candidate_record and not blockers
            else None,
            "proposed_receipt_path": proposed_receipt_path,
            "closed_actions": {
                "source_file_body_read": bool(source_text),
                "files_written": False,
                "provider_api_called": False,
                "secrets_read": False,
            },
            "blockers": unique_preserve_order(blockers),
            "warnings": unique_preserve_order(warnings),
        }
        if dry_run or blockers:
            return result

        assert approve
        assert candidate_record is not None
        assert proposed_receipt_path is not None
        assert reviewer is not None
        reviewed_at = datetime.now().astimezone().replace(microsecond=0).isoformat()
        written_record = {
            **candidate_record,
            "updated_at": reviewed_at,
            "reviewed_by": reviewer,
        }
        written_text = dump_yaml(written_record)
        written_hash = "sha256:" + hashlib.sha256(written_text.encode("utf-8")).hexdigest()
        previous_text = target_path.read_text(encoding="utf-8") if target_path.is_file() else None
        receipt_path = archive_internal_path(root, proposed_receipt_path)
        receipt = {
            "schema": "wom-kit/operational-context-receipt/v0.1",
            "lifecycle_action": "operational_context_write",
            "archive_id": archive_id,
            "record_path": target_relative,
            "source_record_path": source_relative,
            "receipt_path": proposed_receipt_path,
            "reviewed_by": reviewer,
            "reviewed_at": reviewed_at,
            "base_record_sha256": base_record_hash,
            "written_record_sha256": written_hash,
            "previous_record_sha256": "sha256:" + hashlib.sha256(previous_text.encode("utf-8")).hexdigest()
            if previous_text is not None
            else None,
            "session_start_injection": operational_context_session_start_injection(written_record),
            "closed_actions": {
                "provider_api_called": False,
                "secrets_read": False,
            },
            "files_written": [target_relative, proposed_receipt_path],
        }
        try:
            target_path.parent.mkdir(parents=True, exist_ok=True)
            receipt_path.parent.mkdir(parents=True, exist_ok=True)
            target_path.write_text(written_text, encoding="utf-8")
            write_json_new_file(receipt_path, receipt)
        except Exception:
            if previous_text is None:
                try:
                    target_path.unlink()
                except OSError:
                    pass
            else:
                target_path.write_text(previous_text, encoding="utf-8")
            raise

        result.update(
            {
                "ok": True,
                "dry_run": False,
                "status": "written",
                "record": written_record,
                "session_start_injection": operational_context_session_start_injection(written_record),
                "receipt_path": proposed_receipt_path,
                "closed_actions": {
                    "source_file_body_read": bool(source_text),
                    "files_written": True,
                    "provider_api_called": False,
                    "secrets_read": False,
                },
                "blockers": [],
            }
        )
        return result

    preview = runtime_context_operational_context(root)
    preview.update(
        {
            "dry_run": bool(dry_run),
            "archive_id": archive_id,
        }
    )
    if not preview["ok"]:
        blockers.extend(preview["blockers"])
    preview["blockers"] = unique_preserve_order(blockers)
    preview["warnings"] = unique_preserve_order([*warnings, *preview.get("warnings", [])])
    preview["ok"] = not preview["blockers"]
    return preview


def runtime_context_operational_context(root: Path) -> dict[str, Any]:
    target_path = archive_internal_path(root, OPERATIONAL_CONTEXT_RELATIVE_PATH)
    if not target_path.is_file():
        return {
            "ok": True,
            "lifecycle_action": "operational_context",
            "record_path": OPERATIONAL_CONTEXT_RELATIVE_PATH,
            "status": "missing_optional",
            "record": None,
            "session_start_injection": None,
            "recommended_commands": operational_context_recommended_commands(),
            "closed_actions": {
                "file_body_read": False,
                "files_written": False,
                "provider_api_called": False,
                "secrets_read": False,
            },
            "blockers": [],
            "warnings": [
                "No operational context record is present yet; AI runtimes should fall back to archive.yml, AGENTS.md, and current task context."
            ],
        }

    blockers: list[str] = []
    warnings: list[str] = []
    text = target_path.read_text(encoding="utf-8")
    record = operational_context_parse_record_text(text, blockers, warnings)
    return {
        "ok": not blockers,
        "lifecycle_action": "operational_context",
        "record_path": OPERATIONAL_CONTEXT_RELATIVE_PATH,
        "status": "present" if not blockers else "blocked",
        "record": record if not blockers else None,
        "session_start_injection": operational_context_session_start_injection(record) if record and not blockers else None,
        "recommended_commands": operational_context_recommended_commands(),
        "closed_actions": {
            "file_body_read": True,
            "files_written": False,
            "provider_api_called": False,
            "secrets_read": False,
        },
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }


def operational_context_source_relative_path(root: Path, record_path: str, blockers: list[str]) -> str | None:
    raw = record_path.strip()
    if not raw:
        blockers.append("record path must be a non-empty archive-relative path.")
        return None
    if Path(raw).is_absolute():
        blockers.append("record path must be archive-relative.")
        return None
    try:
        source_path = resolve_archive_relative_path(root, raw)
    except ArchivePathError:
        blockers.append("record path must stay inside the archive root.")
        return None
    return archive_relative_path(source_path, root)


def operational_context_parse_record_text(
    text: str | None,
    blockers: list[str],
    warnings: list[str],
) -> dict[str, Any] | None:
    if text is None:
        return None
    try:
        data = load_yaml(text)
    except Exception as exc:
        blockers.append(f"operational context record could not be parsed as YAML: {exc}")
        return None
    if not isinstance(data, dict):
        blockers.append("operational context record must be a YAML object.")
        return None
    return operational_context_normalize_record(data, blockers, warnings)


def operational_context_normalize_record(
    data: dict[str, Any],
    blockers: list[str],
    warnings: list[str],
) -> dict[str, Any] | None:
    schema = data.get("schema")
    if schema != OPERATIONAL_CONTEXT_SCHEMA:
        blockers.append(f"operational context schema must be {OPERATIONAL_CONTEXT_SCHEMA}.")

    mission = data.get("mission") if isinstance(data.get("mission"), dict) else {}
    state = data.get("state") if isinstance(data.get("state"), dict) else {}
    rehydration = data.get("rehydration") if isinstance(data.get("rehydration"), dict) else {}
    if not isinstance(data.get("mission"), dict):
        blockers.append("operational context mission must be a YAML object.")
    if not isinstance(data.get("state"), dict):
        blockers.append("operational context state must be a YAML object.")
    if data.get("rehydration") is not None and not isinstance(data.get("rehydration"), dict):
        blockers.append("operational context rehydration must be a YAML object.")

    mission_summary = operational_context_string(mission.get("summary"), blockers, "mission.summary", required=True)
    state_phase = operational_context_string(state.get("phase"), blockers, "state.phase", required=True, max_length=160)
    if blockers:
        return None

    assert mission_summary is not None
    assert state_phase is not None
    record: dict[str, Any] = {
        "schema": OPERATIONAL_CONTEXT_SCHEMA,
        "mission": {
            "summary": mission_summary,
            "scope": operational_context_string_list(mission.get("scope"), blockers, warnings, "mission.scope"),
            "non_goals": operational_context_string_list(mission.get("non_goals"), blockers, warnings, "mission.non_goals"),
        },
        "state": {
            "phase": state_phase,
            "completed": operational_context_string_list(state.get("completed"), blockers, warnings, "state.completed"),
            "in_progress": operational_context_string_list(state.get("in_progress"), blockers, warnings, "state.in_progress"),
            "next": operational_context_string_list(state.get("next"), blockers, warnings, "state.next"),
            "blocked": operational_context_string_list(state.get("blocked"), blockers, warnings, "state.blocked"),
        },
        "gotchas": operational_context_string_list(data.get("gotchas"), blockers, warnings, "gotchas"),
        "decisions": operational_context_string_list(data.get("decisions"), blockers, warnings, "decisions"),
        "rehydration": {
            "session_start": operational_context_string_list(
                rehydration.get("session_start"),
                blockers,
                warnings,
                "rehydration.session_start",
            ),
            "on_demand_commands": operational_context_string_list(
                rehydration.get("on_demand_commands"),
                blockers,
                warnings,
                "rehydration.on_demand_commands",
            ),
        },
    }
    if not record["rehydration"]["on_demand_commands"]:
        record["rehydration"]["on_demand_commands"] = [
            "archive runtime-context <archive-root> --format json",
            "archive operational-context <archive-root> --dry-run --format json",
        ]
    updated_at = operational_context_string(data.get("updated_at"), blockers, "updated_at", max_length=80)
    reviewed_by = data.get("reviewed_by")
    if isinstance(reviewed_by, str):
        safe_reviewer = safe_foreign_quarantine_actor_id(reviewed_by)
        if safe_reviewer:
            record["reviewed_by"] = safe_reviewer
        else:
            blockers.append("operational context reviewed_by must be a safe non-secret actor id.")
    elif reviewed_by is not None:
        blockers.append("operational context reviewed_by must be a string.")
    if updated_at:
        record["updated_at"] = updated_at
    if blockers:
        return None
    return record


def operational_context_string(
    value: Any,
    blockers: list[str],
    field_path: str,
    *,
    required: bool = False,
    max_length: int = OPERATIONAL_CONTEXT_MAX_TEXT_LENGTH,
) -> str | None:
    if value is None:
        if required:
            blockers.append(f"operational context {field_path} is required.")
        return None
    if not isinstance(value, str):
        blockers.append(f"operational context {field_path} must be a string.")
        return None
    text = " ".join(value.strip().split())
    if not text:
        if required:
            blockers.append(f"operational context {field_path} is required.")
        return None
    if len(text) > max_length:
        blockers.append(f"operational context {field_path} must be {max_length} characters or fewer.")
        return None
    if operational_context_text_is_unsafe(text):
        blockers.append(f"unsafe operational context value in {field_path}.")
        return None
    return text


def operational_context_string_list(
    value: Any,
    blockers: list[str],
    warnings: list[str],
    field_path: str,
) -> list[str]:
    if value is None:
        return []
    if not isinstance(value, list):
        blockers.append(f"operational context {field_path} must be a list of strings.")
        return []
    items: list[str] = []
    for index, item in enumerate(value):
        normalized = operational_context_string(item, blockers, f"{field_path}[{index}]")
        if normalized:
            items.append(normalized)
    if len(items) > OPERATIONAL_CONTEXT_MAX_LIST_ITEMS:
        warnings.append(
            f"operational context {field_path} has more than {OPERATIONAL_CONTEXT_MAX_LIST_ITEMS} items; extra items were omitted."
        )
        items = items[:OPERATIONAL_CONTEXT_MAX_LIST_ITEMS]
    return items


def operational_context_text_is_unsafe(text: str) -> bool:
    return (
        "@" in text
        or contains_forbidden_location_reference(text)
        or source_intake_has_provider_url(text)
        or source_intake_secret_like(text)
    )


def operational_context_session_start_injection(record: dict[str, Any] | None) -> dict[str, Any] | None:
    if not record:
        return None
    mission = record.get("mission") if isinstance(record.get("mission"), dict) else {}
    state = record.get("state") if isinstance(record.get("state"), dict) else {}
    rehydration = record.get("rehydration") if isinstance(record.get("rehydration"), dict) else {}
    return {
        "source": OPERATIONAL_CONTEXT_RELATIVE_PATH,
        "mission_summary": mission.get("summary"),
        "scope": mission.get("scope") if isinstance(mission.get("scope"), list) else [],
        "phase": state.get("phase"),
        "completed": state.get("completed") if isinstance(state.get("completed"), list) else [],
        "in_progress": state.get("in_progress") if isinstance(state.get("in_progress"), list) else [],
        "next": state.get("next") if isinstance(state.get("next"), list) else [],
        "blocked": state.get("blocked") if isinstance(state.get("blocked"), list) else [],
        "gotchas": record.get("gotchas") if isinstance(record.get("gotchas"), list) else [],
        "decisions": record.get("decisions") if isinstance(record.get("decisions"), list) else [],
        "session_start": rehydration.get("session_start") if isinstance(rehydration.get("session_start"), list) else [],
    }


def operational_context_recommended_commands() -> list[dict[str, str]]:
    return [
        {
            "command": "archive runtime-context <archive-root> --format json",
            "purpose": "rehydrate archive identity, entrypoints, version, and operational context in one read-only call",
        },
        {
            "command": "archive operational-context <archive-root> --dry-run --format json",
            "purpose": "read the current AI-facing mission, scope, state, gotchas, and decisions record",
        },
        {
            "command": "archive operational-context <archive-root> --record workbench/operational-context.next.yml --approve --reviewed-by <actor> --format json",
            "purpose": "write a reviewed operational context update and receipt after human approval",
        },
    ]


def operational_context_receipt_relative_path(record_hash: str) -> str:
    digest = record_hash.removeprefix("sha256:")
    return f"{OPERATIONAL_CONTEXT_RECEIPTS_DIR}/{digest[:16]}.operational-context.json"


def ai_usage_estimated_tokens(text: str) -> int:
    if not text:
        return 0
    return max(1, (len(text) + 3) // 4)


def ai_usage_safe_label(value: Any, blockers: list[str], field_path: str, *, required: bool = True) -> str | None:
    if value is None:
        if required:
            blockers.append(f"{field_path} is required.")
        return None
    text = " ".join(str(value).strip().split())
    if not text:
        if required:
            blockers.append(f"{field_path} is required.")
        return None
    if len(text) > AI_USAGE_MAX_LABEL_LENGTH:
        blockers.append(f"{field_path} must be {AI_USAGE_MAX_LABEL_LENGTH} characters or fewer.")
        return None
    if not safe_source_intake_plan_scalar(text):
        blockers.append(f"{field_path} must be a safe non-secret scalar.")
        return None
    return text


def ai_usage_non_negative_int(value: Any, blockers: list[str], field_path: str, *, required: bool = True) -> int | None:
    if value is None:
        if required:
            blockers.append(f"{field_path} is required.")
        return None
    try:
        number = int(value)
    except (TypeError, ValueError):
        blockers.append(f"{field_path} must be an integer.")
        return None
    if number < 0:
        blockers.append(f"{field_path} must be non-negative.")
        return None
    return number


def ai_usage_context_relative_path(root: Path, raw_path: str, blockers: list[str]) -> str | None:
    text = str(raw_path or "").strip()
    if not text:
        blockers.append("context include path must be non-empty.")
        return None
    if Path(text).is_absolute():
        blockers.append("context include path must be archive-relative.")
        return None
    try:
        path = resolve_archive_relative_path(root, text)
        relative = archive_relative_path(path, root)
    except (ArchivePathError, OSError, ValueError):
        blockers.append("context include path must stay inside the archive root.")
        return None
    normalized = relative.replace("\\", "/")
    if any(normalized.startswith(prefix) for prefix in AI_USAGE_BLOCKED_CONTEXT_PREFIXES):
        blockers.append(f"context include path is source/object byte storage and must not be read by ai-usage-plan: {normalized}.")
        return None
    if not path.is_file():
        blockers.append(f"context include path is missing or not a file: {normalized}.")
        return None
    return normalized


def ai_usage_plan(
    archive_root: Path | str,
    *,
    budget_tokens: int | None,
    include_paths: list[str] | None = None,
    task_id: str | None = None,
    purpose: str | None = None,
    dry_run: bool = False,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []
    task_label = ai_usage_safe_label(task_id, blockers, "task_id", required=False)
    purpose_label = ai_usage_safe_label(purpose, blockers, "purpose", required=False)
    budget = ai_usage_non_negative_int(budget_tokens, blockers, "budget_tokens")

    if not dry_run:
        blockers.append("ai-usage-plan is read-only and requires --dry-run.")
    if not include_paths:
        warnings.append("No context include paths were provided; the plan records a zero-token budget baseline only.")

    items: list[dict[str, Any]] = []
    for raw_path in include_paths or []:
        relative = ai_usage_context_relative_path(root, raw_path, blockers)
        if relative is None:
            continue
        path = archive_internal_path(root, relative)
        try:
            text = path.read_text(encoding="utf-8")
        except UnicodeDecodeError:
            blockers.append(f"context include path is not UTF-8 text: {relative}.")
            continue
        except OSError as exc:
            blockers.append(f"context include path could not be read: {relative} ({exc}).")
            continue
        stat = path.stat()
        estimated = ai_usage_estimated_tokens(text)
        items.append(
            {
                "path": relative,
                "sha256": "sha256:" + sha256_text(text),
                "bytes": stat.st_size,
                "chars": len(text),
                "estimated_tokens": estimated,
                "read_mode": "explicit_text_for_token_estimate",
                "content_echoed": False,
            }
        )

    total_estimated = sum(int(item["estimated_tokens"]) for item in items)
    remaining = (budget - total_estimated) if budget is not None else None
    if budget is not None and total_estimated > budget:
        warnings.append("Estimated context tokens exceed the requested budget.")

    return {
        "ok": not blockers,
        "dry_run": bool(dry_run),
        "lifecycle_action": "ai_usage_plan",
        "archive_id": archive_id,
        "task_id": task_label,
        "purpose": purpose_label,
        "budget_tokens": budget,
        "estimated_context_tokens": total_estimated,
        "remaining_budget_tokens": remaining,
        "over_budget": bool(budget is not None and total_estimated > budget),
        "items": items,
        "item_count": len(items),
        "closed_actions": {
            "explicit_context_files_read": len(items),
            "source_object_bytes_read": False,
            "prompt_or_response_body_stored": False,
            "files_written": False,
            "provider_api_called": False,
            "secrets_read": False,
        },
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }


def ai_usage_receipt_relative_path(receipt_seed: dict[str, Any]) -> str:
    digest = sha256_json_value(receipt_seed).removeprefix("sha256:")
    return f"{AI_USAGE_RECEIPTS_DIR}/{digest[:24]}.ai-usage.json"


def ai_usage_record(
    archive_root: Path | str,
    *,
    task_id: str | None,
    runtime: str | None,
    model: str | None,
    purpose: str | None,
    input_tokens: int | None,
    output_tokens: int | None,
    total_tokens: int | None = None,
    cached_input_tokens: int | None = None,
    reasoning_tokens: int | None = None,
    budget_tokens: int | None = None,
    planned_tokens: int | None = None,
    context_plan_sha256: str | None = None,
    dry_run: bool = False,
    approve: bool = False,
    reviewed_by: str | None = None,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []

    if dry_run is approve:
        blockers.append("Choose exactly one mode: --dry-run or --approve.")
    reviewer = safe_foreign_quarantine_actor_id(reviewed_by)
    if approve and reviewer is None:
        blockers.append("ai-usage-record approve requires a safe --reviewed-by actor id.")
    if reviewed_by and reviewer is None:
        blockers.append("reviewed_by must be a safe non-secret actor id.")

    task_label = ai_usage_safe_label(task_id, blockers, "task_id")
    runtime_label = ai_usage_safe_label(runtime, blockers, "runtime")
    model_label = ai_usage_safe_label(model, blockers, "model")
    purpose_label = ai_usage_safe_label(purpose, blockers, "purpose")
    input_count = ai_usage_non_negative_int(input_tokens, blockers, "input_tokens")
    output_count = ai_usage_non_negative_int(output_tokens, blockers, "output_tokens")
    cached_count = ai_usage_non_negative_int(cached_input_tokens, blockers, "cached_input_tokens", required=False) or 0
    reasoning_count = ai_usage_non_negative_int(reasoning_tokens, blockers, "reasoning_tokens", required=False) or 0
    budget_count = ai_usage_non_negative_int(budget_tokens, blockers, "budget_tokens", required=False)
    planned_count = ai_usage_non_negative_int(planned_tokens, blockers, "planned_tokens", required=False)
    context_plan_hash = ai_usage_safe_label(context_plan_sha256, blockers, "context_plan_sha256", required=False)
    if context_plan_hash and not re.match(r"^sha256:[0-9a-f]{64}$", context_plan_hash):
        blockers.append("context_plan_sha256 must use sha256:<64 lowercase hex> syntax.")

    inferred_total = None
    if input_count is not None and output_count is not None:
        inferred_total = input_count + output_count
    total_count = ai_usage_non_negative_int(total_tokens, blockers, "total_tokens", required=False)
    if total_count is None:
        total_count = inferred_total
    if input_count is not None and cached_count > input_count:
        blockers.append("cached_input_tokens cannot exceed input_tokens.")
    if total_count is not None and inferred_total is not None and total_count < inferred_total:
        blockers.append("total_tokens cannot be smaller than input_tokens + output_tokens.")
    if budget_count is not None and total_count is not None and total_count > budget_count:
        warnings.append("Recorded total_tokens exceed the stated budget_tokens.")
    if planned_count is not None and input_count is not None and input_count > planned_count:
        warnings.append("Recorded input_tokens exceed planned_tokens.")

    recorded_at = datetime.now().astimezone().replace(microsecond=0).isoformat()
    usage = {
        "input_tokens": input_count,
        "output_tokens": output_count,
        "total_tokens": total_count,
        "cached_input_tokens": cached_count,
        "reasoning_tokens": reasoning_count,
    }
    receipt_seed = {
        "schema": AI_USAGE_RECEIPT_SCHEMA,
        "lifecycle_action": "ai_usage_record",
        "archive_id": archive_id,
        "task_id": task_label,
        "runtime": runtime_label,
        "model": model_label,
        "purpose": purpose_label,
        "usage": usage,
        "budget_tokens": budget_count,
        "planned_tokens": planned_count,
        "context_plan_sha256": context_plan_hash,
    }
    proposed_receipt_path = ai_usage_receipt_relative_path(receipt_seed) if not blockers else None
    if proposed_receipt_path and archive_internal_path(root, proposed_receipt_path).exists():
        blockers.append(f"Proposed AI usage receipt already exists: {proposed_receipt_path}.")

    result: dict[str, Any] = {
        "ok": not blockers,
        "dry_run": bool(dry_run),
        "lifecycle_action": "ai_usage_record",
        "archive_id": archive_id,
        "status": "blocked" if blockers else ("would_write" if dry_run else "ready_to_write"),
        "task_id": task_label,
        "runtime": runtime_label,
        "model": model_label,
        "purpose": purpose_label,
        "usage": usage,
        "budget_tokens": budget_count,
        "planned_tokens": planned_count,
        "context_plan_sha256": context_plan_hash,
        "proposed_receipt_path": proposed_receipt_path,
        "closed_actions": {
            "prompt_or_response_body_stored": False,
            "provider_api_called": False,
            "secrets_read": False,
            "files_written": False,
        },
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }
    if dry_run or blockers:
        return result

    assert approve
    assert reviewer is not None
    assert proposed_receipt_path is not None
    receipt = {
        **receipt_seed,
        "receipt_path": proposed_receipt_path,
        "reviewed_by": reviewer,
        "recorded_at": recorded_at,
        "closed_actions": {
            "prompt_or_response_body_stored": False,
            "provider_api_called": False,
            "secrets_read": False,
        },
        "files_written": [proposed_receipt_path],
    }
    receipt_path = archive_internal_path(root, proposed_receipt_path)
    receipt_path.parent.mkdir(parents=True, exist_ok=True)
    write_json_new_file(receipt_path, receipt)
    result.update(
        {
            "ok": True,
            "dry_run": False,
            "status": "written",
            "receipt_path": proposed_receipt_path,
            "reviewed_by": reviewer,
            "recorded_at": recorded_at,
            "closed_actions": {
                "prompt_or_response_body_stored": False,
                "provider_api_called": False,
                "secrets_read": False,
                "files_written": True,
            },
            "blockers": [],
        }
    )
    return result


def ai_usage_report(
    archive_root: Path | str,
    *,
    task_id: str | None = None,
    runtime: str | None = None,
    model: str | None = None,
    dry_run: bool = False,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []
    if not dry_run:
        blockers.append("ai-usage-report is read-only and requires --dry-run.")
    task_filter = ai_usage_safe_label(task_id, blockers, "task_id", required=False)
    runtime_filter = ai_usage_safe_label(runtime, blockers, "runtime", required=False)
    model_filter = ai_usage_safe_label(model, blockers, "model", required=False)
    receipts_root = archive_internal_path(root, AI_USAGE_RECEIPTS_DIR)
    receipts: list[dict[str, Any]] = []
    skipped_receipts: list[str] = []

    def usage_counter(value: Any) -> int:
        try:
            number = int(value)
        except (TypeError, ValueError):
            return 0
        return max(0, number)

    if receipts_root.is_dir():
        for path in sorted(receipts_root.glob("*.ai-usage.json")):
            relative = archive_relative_path(path, root)
            try:
                data = json.loads(path.read_text(encoding="utf-8"))
            except (OSError, json.JSONDecodeError):
                skipped_receipts.append(relative)
                continue
            if data.get("schema") != AI_USAGE_RECEIPT_SCHEMA or data.get("lifecycle_action") != "ai_usage_record":
                skipped_receipts.append(relative)
                continue
            if task_filter and data.get("task_id") != task_filter:
                continue
            if runtime_filter and data.get("runtime") != runtime_filter:
                continue
            if model_filter and data.get("model") != model_filter:
                continue
            usage = data.get("usage") if isinstance(data.get("usage"), dict) else {}
            receipts.append(
                {
                    "receipt_path": relative,
                    "task_id": data.get("task_id"),
                    "runtime": data.get("runtime"),
                    "model": data.get("model"),
                    "purpose": data.get("purpose"),
                    "recorded_at": data.get("recorded_at"),
                    "usage": {
                        "input_tokens": usage_counter(usage.get("input_tokens")),
                        "output_tokens": usage_counter(usage.get("output_tokens")),
                        "total_tokens": usage_counter(usage.get("total_tokens")),
                        "cached_input_tokens": usage_counter(usage.get("cached_input_tokens")),
                        "reasoning_tokens": usage_counter(usage.get("reasoning_tokens")),
                    },
                    "budget_tokens": data.get("budget_tokens"),
                    "planned_tokens": data.get("planned_tokens"),
                }
            )
    if skipped_receipts:
        warnings.append(f"Skipped {len(skipped_receipts)} unreadable or invalid AI usage receipt(s).")

    totals = {
        "records": len(receipts),
        "input_tokens": sum(item["usage"]["input_tokens"] for item in receipts),
        "output_tokens": sum(item["usage"]["output_tokens"] for item in receipts),
        "total_tokens": sum(item["usage"]["total_tokens"] for item in receipts),
        "cached_input_tokens": sum(item["usage"]["cached_input_tokens"] for item in receipts),
        "reasoning_tokens": sum(item["usage"]["reasoning_tokens"] for item in receipts),
    }

    def aggregate_by(field: str) -> list[dict[str, Any]]:
        buckets: dict[str, dict[str, Any]] = {}
        for item in receipts:
            key = str(item.get(field) or "unknown")
            bucket = buckets.setdefault(
                key,
                {"key": key, "records": 0, "input_tokens": 0, "output_tokens": 0, "total_tokens": 0},
            )
            bucket["records"] += 1
            bucket["input_tokens"] += item["usage"]["input_tokens"]
            bucket["output_tokens"] += item["usage"]["output_tokens"]
            bucket["total_tokens"] += item["usage"]["total_tokens"]
        return sorted(buckets.values(), key=lambda item: (-int(item["total_tokens"]), str(item["key"])))

    return {
        "ok": not blockers,
        "dry_run": bool(dry_run),
        "lifecycle_action": "ai_usage_report",
        "archive_id": archive_id,
        "filters": {
            "task_id": task_filter,
            "runtime": runtime_filter,
            "model": model_filter,
        },
        "totals": totals,
        "by_runtime": aggregate_by("runtime"),
        "by_model": aggregate_by("model"),
        "by_purpose": aggregate_by("purpose"),
        "receipts": receipts,
        "closed_actions": {
            "receipt_files_read": len(receipts) + len(skipped_receipts),
            "prompt_or_response_body_read": False,
            "files_written": False,
            "provider_api_called": False,
            "secrets_read": False,
        },
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }


def runtime_context(
    archive_root: Path | str,
    *,
    expected_archive_id: str | None = None,
    expected_type: str | None = None,
    strict: bool = False,
    redact_local_paths: bool = True,
    diagnostics: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    blockers: list[str] = []
    warnings: list[str] = []

    if expected_type is not None and expected_type not in RUNTIME_CONTEXT_ARCHIVE_TYPES:
        raise ArchiveServiceError("expected archive type must be one of: " + ", ".join(sorted(RUNTIME_CONTEXT_ARCHIVE_TYPES)))

    archive_config = load_runtime_context_yaml(root, "archive.yml", blockers, required=True)
    identity_doc = load_runtime_context_yaml(root, "archive-identity.yml", warnings, required=False)

    archive_id = archive_config.get("archive_id") if isinstance(archive_config.get("archive_id"), str) else None
    archive_type = archive_config.get("type") if isinstance(archive_config.get("type"), str) else None
    identity = identity_doc.get("identity") if isinstance(identity_doc.get("identity"), dict) else {}
    scope = identity.get("scope") if isinstance(identity.get("scope"), str) else None

    if archive_id is None:
        blockers.append("archive.yml does not contain a readable archive_id.")
    elif expected_archive_id and archive_id != expected_archive_id:
        blockers.append(f"Expected archive id {expected_archive_id}, found {archive_id}.")

    if expected_type:
        found_types = {item for item in [archive_type, scope] if item}
        if expected_type not in found_types:
            message = runtime_type_mismatch_message(expected_type, archive_type, scope)
            if strict:
                blockers.append(message)
            else:
                warnings.append(message)

    doctor_summary = runtime_context_doctor_summary(diagnostics, strict=strict, blockers=blockers, warnings=warnings)
    paths = runtime_context_paths(root, archive_config, warnings)
    operational_context_summary = runtime_context_operational_context(root)
    if not operational_context_summary["ok"]:
        warnings.append("ops/operational-context.yml is present but not safe/readable; run operational-context dry-run.")
    if strict and warnings:
        blockers.extend(warnings)
        warnings = []

    result: dict[str, Any] = {
        "ok": not blockers,
        "lifecycle_action": "runtime_context",
        "archive_id": archive_id,
        "archive_type": archive_type,
        "scope": scope,
        "principal": runtime_context_principal_summary(archive_config, identity_doc),
        "owner": runtime_context_owner_summary(identity_doc),
        "ai_write_policy": runtime_context_ai_write_policy_summary(archive_config),
        "paths": paths,
        "wom_kit_version": wom_kit_version_info(root, redact_local_paths=redact_local_paths),
        "operational_context": operational_context_summary,
        "canonical_entrypoints": runtime_context_canonical_entrypoints(root, archive_config, paths),
        "available_safe_actions": list(RUNTIME_CONTEXT_SAFE_ACTIONS),
        "doctor_summary": doctor_summary,
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
        "redaction": {
            "local_paths_redacted": bool(redact_local_paths),
        },
    }
    if not redact_local_paths:
        result["local_archive_root"] = str(root)
        result["local_paths"] = runtime_context_local_paths(root, paths)
    return result


def load_runtime_context_yaml(root: Path, relative_path: str, messages: list[str], *, required: bool) -> dict[str, Any]:
    try:
        data = load_yaml(read_archive_text(root, relative_path))
    except ArchiveServiceError as exc:
        if required:
            messages.append(f"{relative_path} could not be read: {exc}")
        return {}
    except Exception as exc:
        if required:
            messages.append(f"{relative_path} could not be parsed as YAML: {exc}")
        else:
            messages.append(f"{relative_path} could not be parsed as YAML.")
        return {}
    if not isinstance(data, dict):
        messages.append(f"{relative_path} must be a YAML object.")
        return {}
    return json_safe(data)


def runtime_type_mismatch_message(expected_type: str, archive_type: str | None, scope: str | None) -> str:
    found_values = unique_preserve_order([item for item in [archive_type, scope] if item])
    found = ", ".join(found_values) or "unknown"
    return f"Expected archive type {expected_type}, found {found}."


def runtime_context_doctor_summary(
    diagnostics: list[dict[str, Any]] | None,
    *,
    strict: bool,
    blockers: list[str],
    warnings: list[str],
) -> dict[str, Any]:
    if diagnostics is None:
        return {"checked": False, "errors": 0, "warnings": 0, "infos": 0}
    errors = sum(1 for item in diagnostics if item.get("severity") == "ERROR")
    warning_count = sum(1 for item in diagnostics if item.get("severity") == "WARN")
    infos = sum(1 for item in diagnostics if item.get("severity") == "INFO")
    if errors:
        blockers.append(f"archive doctor reported {errors} error(s).")
    if warning_count:
        message = f"archive doctor reported {warning_count} warning(s)."
        if strict:
            blockers.append(message)
        else:
            warnings.append(message)
    return {"checked": True, "errors": errors, "warnings": warning_count, "infos": infos}


def runtime_context_paths(root: Path, archive_config: dict[str, Any], warnings: list[str]) -> dict[str, str | None]:
    root_policy = archive_config.get("root_policy") if isinstance(archive_config.get("root_policy"), dict) else {}
    return {
        "inbox": runtime_context_relative_path(root, root_policy.get("ai_inbox"), "inbox/", warnings, "inbox", directory=True),
        "zettels": runtime_context_relative_path(root, root_policy.get("canonical_zettels"), "zettels/", warnings, "zettels", directory=True),
        "receipts": runtime_context_relative_path(root, None, "receipts/", warnings, "receipts", directory=True),
        "operational_context": runtime_context_relative_path(
            root,
            None,
            OPERATIONAL_CONTEXT_RELATIVE_PATH,
            warnings,
            "operational context",
            directory=False,
        ),
        "object_manifest": runtime_context_relative_path(
            root,
            root_policy.get("object_manifest"),
            "objects/manifests/files.jsonl",
            warnings,
            "object manifest",
            directory=False,
            only_if_exists=True,
        ),
    }


def runtime_context_canonical_entrypoints(
    root: Path,
    archive_config: dict[str, Any],
    paths: dict[str, str | None],
) -> dict[str, Any]:
    root_policy = archive_config.get("root_policy") if isinstance(archive_config.get("root_policy"), dict) else {}
    configured_entrypoints = [
        {
            "path": paths.get("zettels"),
            "role": "canonical_zets",
            "kind": "directory",
            "required": True,
            "source": "archive.yml root_policy.canonical_zettels",
        },
        {
            "path": paths.get("inbox"),
            "role": "draft_inbox",
            "kind": "directory",
            "required": True,
            "source": "archive.yml root_policy.ai_inbox",
        },
        {
            "path": paths.get("object_manifest"),
            "role": "objet_manifest",
            "kind": "file",
            "required": False,
            "source": "archive.yml root_policy.object_manifest",
        },
        {
            "path": paths.get("operational_context"),
            "role": "operational_context",
            "kind": "file",
            "required": False,
            "source": "WOM operational context record",
        },
        {
            "path": root_policy.get("derived_text_manifest") if isinstance(root_policy.get("derived_text_manifest"), str) else None,
            "role": "derived_text_manifest",
            "kind": "file",
            "required": False,
            "source": "archive.yml root_policy.derived_text_manifest",
        },
        {
            "path": root_policy.get("views") if isinstance(root_policy.get("views"), str) else "views/",
            "role": "saved_views",
            "kind": "directory",
            "required": False,
            "source": "archive.yml root_policy.views",
        },
        {
            "path": root_policy.get("sqlite_schema") if isinstance(root_policy.get("sqlite_schema"), str) else "db/schema.sql",
            "role": "sqlite_schema",
            "kind": "file",
            "required": False,
            "source": "archive.yml root_policy.sqlite_schema",
        },
    ]
    read_order = [
        runtime_context_entrypoint_status(root, entry)
        for entry in [*RUNTIME_CONTEXT_FIXED_ENTRYPOINTS, *configured_entrypoints]
    ]
    return {
        "lifecycle_action": "runtime_canonical_entrypoints",
        "start_here": "archive.yml",
        "read_order": read_order,
        "ai_runtime_order": runtime_context_ai_runtime_order(),
        "recommended_first_commands": runtime_context_recommended_first_commands(),
        "material_link_routes": runtime_context_material_link_routes(),
        "source_truths": {
            "archive_identity_and_policy": "archive.yml",
            "local_agent_instructions": "AGENTS.md",
            "owner_and_principal_identity": "archive-identity.yml",
            "source_catalog": "source-bindings.yml",
            "provider_setup_metadata": "provider-bindings.yml",
            "canonical_zets": paths.get("zettels"),
            "draft_inbox": paths.get("inbox"),
            "objet_manifest": paths.get("object_manifest"),
            "operational_context": paths.get("operational_context"),
            "derived_text_manifest": (
                root_policy.get("derived_text_manifest")
                if isinstance(root_policy.get("derived_text_manifest"), str)
                else None
            ),
        },
        "closed_actions": {
            "file_bodies_read": False,
            "files_written": False,
            "provider_api_called": False,
            "secrets_read": False,
        },
    }


def runtime_context_recommended_first_commands() -> list[dict[str, str]]:
    return [
        {
            "command": "archive runtime-context <archive-root> --format json",
            "purpose": "confirm archive identity, local policy, canonical entrypoints, and redaction before any work",
        },
        {
            "command": "archive operational-context <archive-root> --dry-run --format json",
            "purpose": "load the AI-facing mission, scope, state, gotchas, and decisions record before choosing next actions",
        },
        {
            "command": "archive ai-response-concept-guide <archive-root> --topic all --dry-run --format json",
            "purpose": "load beginner-facing WOM concepts, safe routing hints, and overclaim guardrails",
        },
    ]


def runtime_context_ai_runtime_order() -> list[dict[str, Any]]:
    return [
        {
            "step": 1,
            "action": "run_runtime_context",
            "command": "archive runtime-context <archive-root> --format json",
            "reason": "establish the archive root, identity, write policy, and safe entrypoint map",
        },
        {
            "step": 2,
            "action": "read_operational_context",
            "fields": ["operational_context.record", "operational_context.session_start_injection"],
            "reason": "rehydrate the current mission, scope, state, gotchas, decisions, and next actions before local exploration",
        },
        {
            "step": 3,
            "action": "read_canonical_entrypoints",
            "fields": ["canonical_entrypoints.read_order", "canonical_entrypoints.source_truths"],
            "reason": "prefer archive-relative source-of-truth paths before inspecting zets or provider artifacts",
        },
        {
            "step": 4,
            "action": "read_local_agent_instructions",
            "path": "AGENTS.md",
            "when": "canonical_entrypoints.read_order reports AGENTS.md as present",
            "reason": "load archive-local human/AI rules before choosing tools",
        },
        {
            "step": 5,
            "action": "run_ai_response_concept_guide",
            "command": "archive ai-response-concept-guide <archive-root> --topic all --dry-run --format json",
            "reason": "load WOM concept wording, safe routing, material-link routes, and overclaim guardrails",
        },
        {
            "step": 6,
            "action": "choose_material_link_route",
            "field": "canonical_entrypoints.material_link_routes",
            "reason": "use omitted-locator, source-map, or body-locator routes without inventing provider calls",
        },
    ]


def runtime_context_material_link_routes() -> list[dict[str, Any]]:
    return [
        {
            "when": "imported zettel bodies already omitted provider locators",
            "command": "archive notion-objet-import-clue-audit <archive-root> --source-map source-maps/<source>.jsonl --ledger receipts/import/<ledger>.jsonl --dry-run --format json",
            "writes": False,
            "provider_api_called": False,
        },
        {
            "when": "source maps or download ledgers can recover page-to-object material candidates",
            "command": "archive notion-objet-source-map-link-plan <archive-root> --source-map source-maps/<source>.jsonl --ledger receipts/import/<ledger>.jsonl --dry-run --format json",
            "writes": False,
            "provider_api_called": False,
        },
        {
            "when": "imported zettel bodies still contain provider locator text that can be fingerprinted",
            "command": "archive notion-objet-link-index <archive-root> --dry-run --format json",
            "writes": False,
            "provider_api_called": False,
        },
        {
            "when": "one zettel with body locator text needs a candidate material preview",
            "command": "archive notion-objet-link-plan <archive-root> --path <zet.md> --dry-run --format json",
            "writes": False,
            "provider_api_called": False,
        },
    ]


def runtime_context_entrypoint_status(root: Path, entry: dict[str, Any]) -> dict[str, Any]:
    relative = entry.get("path") if isinstance(entry.get("path"), str) else None
    kind = entry.get("kind") if entry.get("kind") in {"file", "directory"} else "file"
    required = bool(entry.get("required"))
    status = "not_configured"
    exists = False
    if relative:
        try:
            path = resolve_archive_relative_path(root, relative.rstrip("/"))
        except ArchivePathError:
            status = "unsafe_path"
        else:
            exists = path.is_dir() if kind == "directory" else path.is_file()
            if exists:
                status = "present"
            else:
                status = "missing_required" if required else "missing_optional"
    return {
        "path": relative,
        "role": entry.get("role"),
        "kind": kind,
        "required": required,
        "status": status,
        "exists": exists,
        "source": entry.get("source"),
    }


def runtime_context_relative_path(
    root: Path,
    raw_path: Any,
    fallback: str,
    warnings: list[str],
    label: str,
    *,
    directory: bool,
    only_if_exists: bool = False,
) -> str | None:
    relative = str(raw_path or fallback)
    try:
        path = resolve_archive_relative_path(root, relative)
    except ArchivePathError:
        warnings.append(f"{label} path is unsafe in archive.yml; using {fallback}.")
        path = resolve_archive_relative_path(root, fallback)
    if only_if_exists and not path.exists():
        return None
    display = archive_relative_path(path, root)
    if directory and not display.endswith("/"):
        display += "/"
    return display


def runtime_context_local_paths(root: Path, paths: dict[str, str | None]) -> dict[str, str | None]:
    local_paths: dict[str, str | None] = {}
    for key, relative in paths.items():
        if relative is None:
            local_paths[key] = None
            continue
        normalized = relative.rstrip("/")
        local_paths[key] = str(resolve_archive_relative_path(root, normalized))
    return local_paths


def runtime_context_principal_summary(archive_config: dict[str, Any], identity_doc: dict[str, Any]) -> dict[str, Any]:
    principal = archive_config.get("principal") if isinstance(archive_config.get("principal"), dict) else {}
    identity = identity_doc.get("identity") if isinstance(identity_doc.get("identity"), dict) else {}
    return {
        "principal_id": identity.get("principal_id") or principal.get("principal_id"),
        "display_name": identity.get("display_name") or principal.get("display_name"),
        "kind": principal.get("kind"),
        "identity_id": identity.get("identity_id"),
    }


def runtime_context_owner_summary(identity_doc: dict[str, Any]) -> dict[str, Any]:
    ownership = identity_doc.get("ownership") if isinstance(identity_doc.get("ownership"), dict) else {}
    operators = ownership.get("operators") if isinstance(ownership.get("operators"), list) else []
    subjects = ownership.get("subjects") if isinstance(ownership.get("subjects"), list) else []
    return {
        "owner_id": ownership.get("owner_id"),
        "owner_kind": ownership.get("owner_kind"),
        "owner_display_name": ownership.get("owner_display_name"),
        "owner_archive_id": ownership.get("owner_archive_id"),
        "operator_count": len(operators),
        "subject_count": len(subjects),
    }


def runtime_context_ai_write_policy_summary(archive_config: dict[str, Any]) -> dict[str, Any]:
    policy = archive_config.get("ai_write_policy") if isinstance(archive_config.get("ai_write_policy"), dict) else {}
    default = policy.get("default")
    canonical_requires = policy.get("canonical_requires")
    summary = "unavailable"
    if default or canonical_requires:
        summary = f"default={default or 'unknown'}; canonical_requires={canonical_requires or 'unknown'}"
    return {
        "default": default,
        "canonical_requires": canonical_requires,
        "summary": summary,
    }


def source_mount_step(binding: dict[str, Any], *, local_profile_present: bool) -> dict[str, Any]:
    source_id = str(binding.get("source_id") or "")
    source_type = str(binding.get("source_type") or "")
    root_ref = str(binding.get("root_ref") or "")
    container_root = f"/sources/{safe_slug(source_id)}"
    if source_type == IMAP_MAILBOX_SOURCE_TYPE:
        return {
            "source_id": source_id,
            "source_type": source_type,
            "root_ref": root_ref,
            "enabled": binding.get("enabled") is not False,
            "needs_host_mount": False,
            "local_profile_present": False,
            "container_source_root": None,
            "compose_volume_hint": None,
            "host_native_scan_command": f"archive imap-mailbox-plan <archive> --source-id {source_id} --dry-run",
            "docker_scan_command": None,
            "manual_required": True,
            "note": "IMAP mailbox sources use credential refs and future provider access, not host folder mounts.",
        }
    archive_relative = root_ref.startswith("archive:") or source_type == "object_manifest"
    if archive_relative:
        container_root = root_ref.removeprefix("archive:") if root_ref.startswith("archive:") else "objects/manifests/files.jsonl"
    docker_command = f"docker compose run --rm archive-cli scan-source /archives/<archive-folder> --source {source_id} --dry-run"
    if not archive_relative:
        docker_command = f"docker compose run --rm archive-cli scan-source /archives/<archive-folder> --source {source_id} --source-root {container_root} --dry-run"
    return {
        "source_id": source_id,
        "source_type": source_type,
        "root_ref": root_ref,
        "enabled": binding.get("enabled") is not False,
        "needs_host_mount": not archive_relative,
        "local_profile_present": local_profile_present,
        "container_source_root": container_root,
        "compose_volume_hint": None
        if archive_relative
        else f"${{{root_ref}}}:{container_root}:ro",
        "host_native_scan_command": f"archive scan-source <archive> --source {source_id} --dry-run",
        "docker_scan_command": docker_command,
        "manual_required": not archive_relative,
    }


def load_source_map_entries(archive_root: Path, relative_path: str) -> list[dict[str, Any]]:
    path = archive_internal_path(archive_root, relative_path)
    if not path.is_file():
        return []
    entries: list[dict[str, Any]] = []
    for raw_line in path.read_text(encoding="utf-8").splitlines():
        line = raw_line.strip()
        if not line:
            continue
        try:
            record = json.loads(line)
        except json.JSONDecodeError:
            continue
        if isinstance(record, dict):
            entries.append(record)
    return entries


def source_intake_plan(
    archive_root: Path | str,
    *,
    local_path: Path | str | None = None,
    source_id: str | None = None,
    item_id: str | None = None,
    relative_path: str | None = None,
    objet_ref: str | None = None,
    object_id: str | None = None,
    provider: str | None = None,
    provider_object_id: str | None = None,
    provider_kind: str | None = None,
    ai_artifact_ref: str | None = None,
    runtime: str | None = None,
    artifact_kind: str | None = None,
    expected_archive_id: str | None = None,
    expected_type: str | None = None,
    profile_id: str | None = None,
    source_role: str = SOURCE_INTAKE_DEFAULT_ROLE,
    title: str | None = None,
    mime: str | None = None,
    redact_local_paths: bool = True,
    project_intake_receipt: str | None = None,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_config = read_archive_config(root)
    archive_id = str(archive_config.get("archive_id") or "")
    archive_type = archive_config.get("type") if isinstance(archive_config.get("type"), str) else None
    blockers: list[str] = []
    warnings: list[str] = []

    if expected_archive_id and expected_archive_id != archive_id:
        blockers.append(f"Expected archive id mismatch: expected {expected_archive_id}, found {archive_id or 'unknown'}.")
    if expected_type and expected_type != archive_type:
        blockers.append(f"Expected archive type mismatch: expected {expected_type}, found {archive_type or 'unknown'}.")

    role = (source_role or SOURCE_INTAKE_DEFAULT_ROLE).strip()
    if role not in SOURCE_INTAKE_ROLES:
        blockers.append("source_role must be one of: " + ", ".join(sorted(SOURCE_INTAKE_ROLES)) + ".")
        role = SOURCE_INTAKE_DEFAULT_ROLE

    for field_name, field_value in {
        "profile_id": profile_id,
        "title": title,
        "mime": mime,
    }.items():
        if field_value and not safe_source_intake_text(str(field_value)):
            blockers.append(f"{field_name} must not contain local paths, provider URLs, tokens, or secrets.")

    locator_kinds = source_intake_locator_kinds(
        local_path=local_path,
        source_id=source_id,
        item_id=item_id,
        relative_path=relative_path,
        objet_ref=objet_ref,
        object_id=object_id,
        provider=provider,
        provider_object_id=provider_object_id,
        provider_kind=provider_kind,
        ai_artifact_ref=ai_artifact_ref,
        runtime=runtime,
        artifact_kind=artifact_kind,
        blockers=blockers,
    )
    input_kind = locator_kinds[0] if len(locator_kinds) == 1 else None
    if len(locator_kinds) != 1:
        blockers.append("Exactly one source locator mode is required.")

    result_body = source_intake_empty_body(
        archive_id=archive_id,
        profile_id=profile_id,
        input_kind=input_kind,
        source_role=role,
        object_storage_context=object_storage_context(root),
    )
    result_body["project_intake_context"] = source_intake_project_intake_context(
        root,
        project_intake_receipt,
        blockers,
        warnings,
    )

    if input_kind == "local_path":
        apply_local_path_source_intake(
            root,
            result_body,
            Path(str(local_path)),
            title=title,
            mime=mime,
            source_role=role,
            redact_local_paths=redact_local_paths,
            blockers=blockers,
            warnings=warnings,
        )
    elif input_kind == "source_map_item":
        apply_source_map_item_source_intake(
            root,
            result_body,
            source_id=str(source_id or ""),
            item_id=str(item_id or ""),
            relative_path=None,
            title=title,
            mime=mime,
            source_role=role,
            blockers=blockers,
            warnings=warnings,
        )
    elif input_kind == "source_map_relative_path":
        apply_source_map_item_source_intake(
            root,
            result_body,
            source_id=str(source_id or ""),
            item_id=None,
            relative_path=str(relative_path or ""),
            title=title,
            mime=mime,
            source_role=role,
            blockers=blockers,
            warnings=warnings,
        )
    elif input_kind == "objet_ref":
        resolved_object_id = object_id_from_objet_ref(str(objet_ref or ""), blockers)
        apply_manifest_object_source_intake(
            root,
            result_body,
            resolved_object_id,
            title=title,
            mime=mime,
            source_role=role,
            direct_lookup=True,
            blockers=blockers,
            warnings=warnings,
        )
    elif input_kind == "object_id":
        normalized_object_id = normalize_object_id(str(object_id or ""), blockers)
        apply_manifest_object_source_intake(
            root,
            result_body,
            normalized_object_id,
            title=title,
            mime=mime,
            source_role=role,
            direct_lookup=True,
            blockers=blockers,
            warnings=warnings,
        )
    elif input_kind == "provider_object":
        apply_provider_object_source_intake(
            result_body,
            provider=str(provider or ""),
            provider_object_id=str(provider_object_id or ""),
            provider_kind=str(provider_kind or ""),
            title=title,
            mime=mime,
            source_role=role,
            blockers=blockers,
        )
    elif input_kind == "ai_artifact":
        apply_ai_artifact_source_intake(
            result_body,
            ai_artifact_ref=str(ai_artifact_ref or ""),
            runtime=str(runtime or ""),
            artifact_kind=str(artifact_kind or ""),
            title=title,
            mime=mime,
            source_role=role,
            blockers=blockers,
        )

    if not result_body["object_storage_context"]["object_storage_configured"]:
        warnings.append("Run the object storage / objet setup planner before real objet capture.")

    if blockers:
        result_body["objet_status"] = "blocked"
    result_body["ok"] = not blockers
    result_body["blockers"] = unique_preserve_order(blockers)
    result_body["warnings"] = unique_preserve_order(warnings)
    result_body["next_safe_actions"] = source_intake_next_safe_actions(result_body)
    return json_safe(result_body)


def source_intake_empty_body(
    *,
    archive_id: str,
    profile_id: str | None,
    input_kind: str | None,
    source_role: str,
    object_storage_context: dict[str, Any],
) -> dict[str, Any]:
    return {
        "ok": True,
        "dry_run": True,
        "lifecycle_action": "source_intake_plan",
        "archive_id": archive_id,
        "profile_id": profile_id,
        "input_kind": input_kind,
        "source_kind": None,
        "source_role": source_role,
        "objet_status": None,
        "source_refs_for_draft": [],
        "objet_ref": {},
        "provider_object_ref": {},
        "project_intake_context": {
            "provided": False,
            "decision_values_included": False,
            "automatic_execution_authorized": False,
        },
        "object_storage_context": object_storage_context,
        "content_access": {
            "metadata_only": True,
            "content_read": False,
            "copied": False,
            "uploaded": False,
            "imported": False,
            "ocr_performed": False,
            "transcription_performed": False,
            "external_api_called": False,
            "full_hash_calculated": False,
        },
        "draft_provenance_suggestions": {},
        "source_metadata": {},
        "blockers": [],
        "warnings": [],
        "next_safe_actions": [],
        "would_change": [],
    }


def source_intake_project_intake_context(
    archive_root: Path,
    receipt: str | None,
    blockers: list[str],
    warnings: list[str],
) -> dict[str, Any]:
    if not receipt:
        return {
            "provided": False,
            "decision_values_included": False,
            "automatic_execution_authorized": False,
        }
    try:
        status = project_intake_status(archive_root, receipt, dry_run=True)
    except (ArchiveServiceError, OSError):
        blockers.append("project_intake_receipt could not be reviewed safely.")
        return {
            "provided": True,
            "ok": False,
            "decision_values_included": False,
            "automatic_execution_authorized": False,
        }
    if not status.get("ok"):
        blockers.append("project_intake_receipt must pass project-intake-status --dry-run before source-intake uses it.")
    warnings.extend(str(item) for item in status.get("warnings", []) if isinstance(item, str))
    return {
        "provided": True,
        "ok": bool(status.get("ok")),
        "receipt_path": status.get("receipt_path"),
        "session_id": status.get("session_id"),
        "reviewed_by": status.get("reviewed_by"),
        "reviewed_at": status.get("reviewed_at"),
        "decision_sha256": status.get("decision_sha256"),
        "checklist_coverage": status.get("checklist_coverage"),
        "readiness": status.get("readiness"),
        "decision_values_included": False,
        "automatic_execution_authorized": False,
    }


def source_intake_locator_kinds(
    *,
    local_path: Path | str | None,
    source_id: str | None,
    item_id: str | None,
    relative_path: str | None,
    objet_ref: str | None,
    object_id: str | None,
    provider: str | None,
    provider_object_id: str | None,
    provider_kind: str | None,
    ai_artifact_ref: str | None,
    runtime: str | None,
    artifact_kind: str | None,
    blockers: list[str],
) -> list[str]:
    kinds: list[str] = []
    if local_path is not None:
        kinds.append("local_path")
    if source_id and item_id:
        kinds.append("source_map_item")
    if source_id and relative_path:
        kinds.append("source_map_relative_path")
    if objet_ref:
        kinds.append("objet_ref")
    if object_id:
        kinds.append("object_id")
    if provider or provider_object_id or provider_kind:
        kinds.append("provider_object")
        if not (provider and provider_object_id and provider_kind):
            blockers.append("Provider locator requires --provider, --provider-object-id, and --provider-kind.")
    if ai_artifact_ref or runtime or artifact_kind:
        kinds.append("ai_artifact")
        if not (ai_artifact_ref and runtime and artifact_kind):
            blockers.append("AI artifact locator requires --ai-artifact-ref, --runtime, and --artifact-kind.")
    if source_id and not (item_id or relative_path):
        blockers.append("Source locator requires --item-id or --relative-path.")
    if (item_id or relative_path) and not source_id:
        blockers.append("Source locator requires --source.")
    return kinds


def apply_local_path_source_intake(
    root: Path,
    result: dict[str, Any],
    local_path: Path,
    *,
    title: str | None,
    mime: str | None,
    source_role: str,
    redact_local_paths: bool,
    blockers: list[str],
    warnings: list[str],
) -> None:
    raw_path = str(local_path)
    if "\x00" in raw_path or source_intake_has_provider_url(raw_path) or source_intake_secret_like(raw_path):
        blockers.append("local_path must be a local file path, not a provider URL, token, or secret.")
        result["objet_status"] = "blocked"
        return
    candidate = local_path.expanduser().resolve()
    if not candidate.exists():
        blockers.append("local_path does not exist.")
        result["objet_status"] = "blocked"
        return
    if not candidate.is_file():
        blockers.append("local_path must point to a file for source intake planning.")
        result["objet_status"] = "blocked"
        return

    stat = candidate.stat()
    guessed_mime = safe_mime(mime or mimetypes.guess_type(candidate.name)[0])
    label = safe_source_label(title, candidate.name, redact_local_paths)
    result["source_kind"] = classify_source_kind(guessed_mime, candidate.suffix)
    result["source_metadata"] = {
        "label": label,
        "extension": candidate.suffix.lower(),
        "mime": guessed_mime,
        "size_bytes": stat.st_size,
        "modified_at": datetime.fromtimestamp(stat.st_mtime).astimezone().replace(microsecond=0).isoformat(),
        "local_path": "<redacted-local-path>" if redact_local_paths else str(candidate),
        "body_read": False,
        "full_hash_calculated": False,
    }

    manifest_record = manifest_record_for_local_path(root, candidate)
    if manifest_record:
        set_manifest_object_intake_result(result, manifest_record, source_role=source_role, title=title, mime=mime)
    else:
        result["objet_status"] = "candidate_unmanifested"
        result["source_refs_for_draft"] = [
            {"type": "source_intake_candidate", "value": f"candidate:{safe_slug(label)}", "role": source_role}
        ]
        result["draft_provenance_suggestions"] = {
            "source": "source_intake_candidate",
            "derived_from": [f"candidate:{safe_slug(label)}"],
        }

    if not local_path_inside_registered_source_root(root, candidate):
        warnings.append("Local file is outside registered source roots; register or scan the source before real objet capture.")
    if candidate.suffix.lower() in {".md", ".markdown", ".txt"}:
        warnings.append(".md/.txt files may already be zets or text notes; confirm whether this is an objet before capture.")


def apply_source_map_item_source_intake(
    root: Path,
    result: dict[str, Any],
    *,
    source_id: str,
    item_id: str | None,
    relative_path: str | None,
    title: str | None,
    mime: str | None,
    source_role: str,
    blockers: list[str],
    warnings: list[str],
) -> None:
    if source_intake_secret_like(source_id) or contains_forbidden_location_reference(source_id):
        blockers.append("source must not contain local paths, provider URLs, tokens, or secrets.")
        return
    if relative_path:
        try:
            normalized_relative = normalize_source_intake_relative_path(relative_path)
        except ArchivePathError as exc:
            blockers.append(f"relative_path is unsafe: {exc}.")
            return
    else:
        normalized_relative = None
    try:
        binding = source_binding_by_id(root, source_id)
    except ArchiveServiceError as exc:
        blockers.append(str(exc))
        return
    map_relative = source_map_relative_path(source_id)
    entries = load_source_map_entries(root, map_relative)
    match: dict[str, Any] | None = None
    for entry in entries:
        if item_id and str(entry.get("item_id") or "") == item_id:
            match = entry
            break
        if normalized_relative and str(entry.get("relative_path") or "").replace("\\", "/") == normalized_relative:
            match = entry
            break
    if match is None:
        blockers.append("Source map item was not found.")
        return

    source_mime = safe_mime(mime or str(match.get("mime") or ""))
    label = safe_source_map_label(title, match)
    result["source_kind"] = classify_source_kind(source_mime, str(match.get("relative_path") or ""))
    result["source_metadata"] = {
        "label": label,
        "source_id": source_id,
        "source_type": binding.get("source_type"),
        "source_map_path": map_relative,
        "item_id": match.get("item_id"),
        "item_kind": match.get("item_kind"),
        "relative_path": match.get("relative_path"),
        "mime": source_mime,
        "size_bytes": match.get("size_bytes"),
        "modified_at": match.get("modified_at"),
        "scan_status": match.get("scan_status"),
    }
    object_id_value = str(match.get("object_id") or "").strip()
    if object_id_value:
        normalized = normalize_object_id(object_id_value, blockers)
        record = find_manifest_record(root, normalized)
        if record:
            set_manifest_object_intake_result(result, record, source_role=source_role, title=title, mime=mime)
        else:
            result["objet_status"] = "candidate_unmanifested"
            warnings.append("Source map item has an object_id, but the object manifest record was not found.")
            result["objet_ref"] = {"ref": f"objet:{normalized}", "object_id": normalized, "manifested": False}
            result["source_refs_for_draft"] = [{"type": "object_id", "value": normalized, "role": source_role}]
        result["source_refs_for_draft"].append(
            {"type": "source_map_item", "value": str(match.get("item_id") or item_id or normalized_relative), "role": "supporting_context"}
        )
    else:
        result["objet_status"] = "candidate_unmanifested"
        source_item_value = str(match.get("item_id") or normalized_relative or "")
        result["source_refs_for_draft"] = [{"type": "source_map_item", "value": source_item_value, "role": source_role}]
        result["draft_provenance_suggestions"] = {
            "source": "source_map_item",
            "derived_from": [source_item_value],
        }

    if str(match.get("relative_path") or "").lower().endswith((".md", ".markdown", ".txt")):
        warnings.append(".md/.txt files may already be zets or text notes; confirm whether this is an objet before capture.")


def apply_manifest_object_source_intake(
    root: Path,
    result: dict[str, Any],
    object_id_value: str,
    *,
    title: str | None,
    mime: str | None,
    source_role: str,
    direct_lookup: bool,
    blockers: list[str],
    warnings: list[str],
) -> None:
    if not object_id_value:
        return
    record = find_manifest_record(root, object_id_value)
    if record is None:
        if direct_lookup:
            blockers.append("object_id or objet_ref does not resolve to objects/manifests/files.jsonl.")
        result["objet_status"] = "blocked"
        return
    set_manifest_object_intake_result(result, record, source_role=source_role, title=title, mime=mime)
    if str(record.get("logical_key") or "").lower().endswith((".md", ".markdown", ".txt")):
        warnings.append(".md/.txt manifest records may already be zets or text notes; confirm whether this is an objet.")


def apply_provider_object_source_intake(
    result: dict[str, Any],
    *,
    provider: str,
    provider_object_id: str,
    provider_kind: str,
    title: str | None,
    mime: str | None,
    source_role: str,
    blockers: list[str],
) -> None:
    if not safe_source_intake_ref(provider) or not safe_source_intake_ref(provider_object_id) or not safe_source_intake_artifact_kind(provider_kind):
        blockers.append("provider, provider_object_id, and provider_kind must be safe refs, not URLs, paths, tokens, or secrets.")
        return
    source_mime = safe_mime(mime)
    label = title.strip() if isinstance(title, str) and title.strip() else provider_object_id
    value = f"{provider}:{provider_kind}:{provider_object_id}"
    result["source_kind"] = "provider_item"
    result["objet_status"] = "provider_reference"
    result["provider_object_ref"] = {
        "provider": provider,
        "provider_kind": provider_kind,
        "provider_object_id": provider_object_id,
        "manifested": False,
    }
    result["source_metadata"] = {
        "label": label,
        "mime": source_mime,
        "provider": provider,
        "provider_kind": provider_kind,
    }
    result["source_refs_for_draft"] = [{"type": "provider_object_ref", "value": value, "role": source_role}]
    result["draft_provenance_suggestions"] = {
        "source": "provider_object_ref",
        "derived_from": [value],
    }


def apply_ai_artifact_source_intake(
    result: dict[str, Any],
    *,
    ai_artifact_ref: str,
    runtime: str,
    artifact_kind: str,
    title: str | None,
    mime: str | None,
    source_role: str,
    blockers: list[str],
) -> None:
    normalized_runtime = runtime.strip()
    if normalized_runtime not in SOURCE_INTAKE_RUNTIMES:
        blockers.append("runtime must be one of: " + ", ".join(sorted(SOURCE_INTAKE_RUNTIMES)) + ".")
    if not safe_source_intake_ref(ai_artifact_ref):
        blockers.append("ai_artifact_ref must be a safe ref, not a URL, path, token, or secret.")
    if not safe_source_intake_artifact_kind(artifact_kind):
        blockers.append("artifact_kind must be a safe label.")
    if blockers:
        return
    source_mime = safe_mime(mime)
    label = title.strip() if isinstance(title, str) and title.strip() else ai_artifact_ref
    result["source_kind"] = "ai_artifact"
    result["objet_status"] = "ai_artifact"
    result["source_metadata"] = {
        "label": label,
        "runtime": normalized_runtime,
        "artifact_kind": artifact_kind,
        "mime": source_mime,
    }
    result["source_refs_for_draft"] = [{"type": "ai_artifact", "value": ai_artifact_ref, "role": source_role}]
    result["draft_provenance_suggestions"] = {
        "source": "ai_artifact",
        "assisted_by": [f"ai_runtime:{normalized_runtime}"],
        "derived_from": [ai_artifact_ref],
    }


def set_manifest_object_intake_result(
    result: dict[str, Any],
    record: dict[str, Any],
    *,
    source_role: str,
    title: str | None,
    mime: str | None,
) -> None:
    object_id_value = str(record.get("object_id") or "")
    source_mime = safe_mime(mime or str(record.get("mime") or ""))
    logical_key = str(record.get("logical_key") or "")
    result["source_kind"] = classify_source_kind(source_mime, logical_key)
    result["objet_status"] = "manifested"
    result["objet_ref"] = {
        "ref": f"objet:{object_id_value}",
        "object_id": object_id_value,
        "manifested": True,
        "manifest_path": "objects/manifests/files.jsonl",
        "logical_key": logical_key or None,
        "mime": source_mime,
        "size_bytes": record.get("size_bytes") if isinstance(record.get("size_bytes"), int) else None,
    }
    existing_metadata = result["source_metadata"] if isinstance(result.get("source_metadata"), dict) else {}
    existing_label = existing_metadata.get("label") if isinstance(existing_metadata.get("label"), str) else None
    label = title.strip() if isinstance(title, str) and title.strip() else existing_label or logical_key or object_id_value
    result["source_metadata"] = {
        **existing_metadata,
        "label": label,
        "logical_key": logical_key or None,
        "mime": source_mime,
        "size_bytes": record.get("size_bytes") if isinstance(record.get("size_bytes"), int) else None,
    }
    result["source_refs_for_draft"] = [{"type": "object_id", "value": object_id_value, "role": source_role}]
    result["draft_provenance_suggestions"] = {
        "source": "object_manifest",
        "derived_from": [object_id_value],
    }


def source_intake_next_safe_actions(result: dict[str, Any]) -> list[str]:
    status = result.get("objet_status")
    actions = ["create-draft --dry-run with source_refs_for_draft", "mint only through separate human approval"]
    project_context = result.get("project_intake_context") if isinstance(result.get("project_intake_context"), dict) else {}
    if project_context.get("provided"):
        actions.insert(0, "treat project_intake_context as session evidence only, not automatic execution approval")
    if status == "manifested":
        return actions
    if status == "candidate_unmanifested":
        return [
            "register or scan the source in metadata-only mode if needed",
            "run the object storage / objet setup planner before real objet capture",
            "wait for a future explicit objet capture/import flow before canonical object_id citation",
            *actions,
        ]
    if status == "provider_reference":
        return [
            "export or register provider metadata without storing raw provider URLs",
            "wait for a future provider capture/import flow before canonical object_id citation",
            *actions,
        ]
    if status == "ai_artifact":
        return [
            "keep the AI artifact ref as provenance context",
            *actions,
        ]
    return []


def object_storage_context(root: Path) -> dict[str, Any]:
    provider_doc = load_provider_bindings(root)
    candidates: list[dict[str, Any]] = []
    for binding in provider_bindings_list(provider_doc):
        provider = str(binding.get("provider") or "")
        provider_kind = str(binding.get("provider_kind") or "")
        resource = binding.get("resource") if isinstance(binding.get("resource"), dict) else {}
        if provider.lower() not in SOURCE_INTAKE_OBJECT_STORAGE_PROVIDERS and provider_kind.lower() not in SOURCE_INTAKE_OBJECT_STORAGE_PROVIDERS:
            continue
        candidates.append(
            drop_none_values(
                {
                    "binding_id": binding.get("binding_id"),
                    "provider": provider,
                    "provider_kind": provider_kind or None,
                    "bucket": resource.get("bucket"),
                    "prefix": resource.get("prefix"),
                    "visibility": resource.get("visibility"),
                    "enabled": binding.get("enabled") is not False,
                }
            )
        )
    configured = any(item.get("enabled") for item in candidates)
    return {
        "object_storage_configured": configured,
        "candidate_storage_providers": candidates,
        "manual_setup_required": not configured,
        "upload_performed": False,
        "provider_api_called": False,
    }


def normalize_object_id(value: str, blockers: list[str]) -> str:
    text = value.strip().lower()
    if SHA256_RE.match(text):
        text = f"sha256:{text}"
    if not OBJECT_ID_RE.match(text):
        blockers.append("object_id must be formatted as sha256:<64 lowercase hex characters>.")
        return ""
    return text


def object_id_from_objet_ref(value: str, blockers: list[str]) -> str:
    text = value.strip().lower()
    if not text.startswith("objet:"):
        blockers.append("objet_ref must be formatted as objet:sha256:<64 lowercase hex characters>.")
        return ""
    return normalize_object_id(text.removeprefix("objet:"), blockers)


def find_manifest_record(root: Path, object_id_value: str) -> dict[str, Any] | None:
    if not object_id_value:
        return None
    for record in load_manifest_records(root):
        if str(record.get("object_id") or "").lower() == object_id_value.lower():
            return record
    return None


def resolve_objet_ref(
    archive_root: Path | str,
    *,
    object_id: str,
    dry_run: bool = True,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []
    if not dry_run:
        blockers.append("resolve-objet-ref is read-only; pass --dry-run.")
    normalized_object_id = normalize_object_id(str(object_id or ""), blockers)
    records = [
        record
        for record in load_manifest_records(root)
        if normalized_object_id and str(record.get("object_id") or "").lower() == normalized_object_id
    ]
    if normalized_object_id and not records:
        blockers.append("object_id_not_found_in_manifest")
    if len(records) > 1:
        warnings.append("duplicate_manifest_records_for_object_id")

    digest = normalized_object_id.removeprefix("sha256:") if normalized_object_id else ""
    local_candidates: list[dict[str, Any]] = []
    external_candidates: list[dict[str, Any]] = []
    record_summaries: list[dict[str, Any]] = []
    seen_local: set[str] = set()
    unsafe_location_refs_redacted = 0

    def safe_label(value: Any, *, field: str) -> str | None:
        nonlocal unsafe_location_refs_redacted
        if value is None:
            return None
        text = str(value).strip()
        if not text:
            return None
        if contains_forbidden_location_reference(text) or source_intake_has_provider_url(text) or source_intake_secret_like(text):
            unsafe_location_refs_redacted += 1
            return f"redacted_unsafe_{field}"
        return text

    def add_local_candidate(relative_path: str, *, provider: str = "local", availability: str | None = None) -> None:
        try:
            normalized = normalize_archive_relative_path(relative_path)
            candidate = archive_internal_path(root, normalized)
        except (ArchiveServiceError, ArchivePathError):
            return
        if normalized in seen_local:
            return
        seen_local.add(normalized)
        exists = candidate.is_file()
        local_candidates.append(
            {
                "provider": provider,
                "archive_relative_path": normalized,
                "exists": exists,
                "availability": availability or ("available" if exists else "missing"),
                "path_kind": "archive_relative",
                "sha256_verified_now": False,
                "file_bytes_read": False,
                "open_hint": "open this path relative to the archive root" if exists else "local bytes not present at this path",
            }
        )

    if records and digest:
        add_local_candidate(f"objects/sha256/{digest[:2]}/{digest}", availability="canonical_candidate")

    for record in records:
        logical_key = safe_label(record.get("logical_key"), field="logical_key")
        provenance = record.get("provenance") if isinstance(record.get("provenance"), dict) else {}
        record_summaries.append(
            {
                "object_id": normalized_object_id,
                "logical_key": logical_key,
                "mime": safe_label(record.get("mime"), field="mime"),
                "size_bytes": record.get("size_bytes") if isinstance(record.get("size_bytes"), int) else None,
                "location_count": len(record.get("locations")) if isinstance(record.get("locations"), list) else 0,
                "provenance_source": safe_label(provenance.get("source"), field="provenance_source"),
            }
        )
        if logical_key and logical_key.startswith("objects/sha256/"):
            add_local_candidate(logical_key, availability="manifest_logical_key")
        locations = record.get("locations")
        if not isinstance(locations, list):
            continue
        for location in locations:
            if not isinstance(location, dict):
                continue
            provider = safe_label(location.get("provider"), field="provider") or "unknown"
            availability = safe_label(location.get("availability"), field="availability")
            path_value = location.get("path")
            if provider == "local" and isinstance(path_value, str):
                add_local_candidate(path_value, provider=provider, availability=availability)
                continue
            external_candidates.append(
                {
                    "provider": provider,
                    "store_kind": safe_label(location.get("store_kind"), field="store_kind"),
                    "store_ref": safe_label(location.get("store_ref"), field="store_ref"),
                    "availability": availability,
                    "content_addressed": bool(location.get("content_addressed")),
                    "byte_verification_by_wom_kit": bool(location.get("byte_verification_by_wom_kit")),
                    "presigned_url_created": False,
                    "provider_api_called": False,
                    "download_performed": False,
                }
            )

    local_available = any(candidate.get("exists") for candidate in local_candidates)
    external_declared = bool(external_candidates)
    if blockers:
        resolution_state = "blocked"
    elif local_available:
        resolution_state = "local_available"
    elif external_declared:
        resolution_state = "external_declared"
    elif records:
        resolution_state = "manifest_only"
    else:
        resolution_state = "not_found"

    next_safe_actions: list[str] = []
    if local_available:
        next_safe_actions.append("Open the existing archive-relative local candidate from the archive root.")
    if external_declared:
        next_safe_actions.append("Use the external store label for manual lookup; this command does not call providers or create presigned URLs.")
    if not local_available and not external_declared and records:
        next_safe_actions.append("Review the manifest record; it has no available local or external location candidate.")
    if blockers:
        next_safe_actions.append("Fix blockers before using this object_id as an openable objet reference.")

    return {
        "ok": not blockers,
        "dry_run": True,
        "lifecycle_action": "resolve_objet_ref",
        "archive_id": archive_id,
        "object_id": normalized_object_id or str(object_id or ""),
        "resolution_state": resolution_state,
        "manifest_path": "objects/manifests/files.jsonl",
        "manifest_record_count": len(records),
        "record_summaries": record_summaries,
        "local_candidates": local_candidates,
        "external_candidates": external_candidates,
        "local_openable": local_available,
        "external_declared": external_declared,
        "privacy_guards": {
            "absolute_local_paths_echoed": False,
            "provider_urls_echoed": False,
            "unsafe_location_refs_redacted": unsafe_location_refs_redacted,
            "provider_api_called": False,
            "presigned_url_created": False,
            "download_performed": False,
            "file_bytes_read": False,
            "file_hash_verified_now": False,
            "writes": False,
        },
        "would_change": [],
        "next_safe_actions": next_safe_actions,
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }


def presigned_url_plan(
    archive_root: Path | str,
    *,
    object_id: str,
    store_ref: str | None = None,
    operation: str = "download",
    ttl_seconds: int = PRESIGNED_URL_DEFAULT_TTL_SECONDS,
    dry_run: bool = True,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []
    if not dry_run:
        blockers.append("presigned-url-plan is read-only; pass --dry-run.")

    normalized_object_id = normalize_object_id(str(object_id or ""), blockers)
    normalized_operation = str(operation or "").strip().lower().replace("-", "_")
    if normalized_operation in {"get", "read"}:
        normalized_operation = "download"
    if normalized_operation not in PRESIGNED_URL_OPERATIONS:
        blockers.append("operation must be one of: " + ", ".join(sorted(PRESIGNED_URL_OPERATIONS)) + ".")
        normalized_operation = "download"

    try:
        normalized_ttl_seconds = int(ttl_seconds)
    except (TypeError, ValueError):
        blockers.append("ttl_seconds must be an integer.")
        normalized_ttl_seconds = PRESIGNED_URL_DEFAULT_TTL_SECONDS
    if normalized_ttl_seconds < PRESIGNED_URL_MIN_TTL_SECONDS or normalized_ttl_seconds > PRESIGNED_URL_MAX_TTL_SECONDS:
        blockers.append(
            "ttl_seconds must be between "
            f"{PRESIGNED_URL_MIN_TTL_SECONDS} and {PRESIGNED_URL_MAX_TTL_SECONDS}."
        )
        normalized_ttl_seconds = max(
            PRESIGNED_URL_MIN_TTL_SECONDS,
            min(normalized_ttl_seconds, PRESIGNED_URL_MAX_TTL_SECONDS),
        )

    normalized_store_ref = str(store_ref or "").strip()
    if normalized_store_ref and not safe_source_intake_ref(normalized_store_ref):
        blockers.append("store_ref must be a safe label/ref, not a URL, email, token, secret, or path.")
        normalized_store_ref = ""

    resolution: dict[str, Any] | None = None
    if normalized_object_id:
        resolution = resolve_objet_ref(root, object_id=normalized_object_id, dry_run=True)
        for blocker in resolution.get("blockers", []):
            blockers.append(str(blocker))
        for warning in resolution.get("warnings", []):
            warnings.append(str(warning))

    external_candidates = []
    if isinstance(resolution, dict) and isinstance(resolution.get("external_candidates"), list):
        external_candidates = [candidate for candidate in resolution["external_candidates"] if isinstance(candidate, dict)]

    selected_external_candidates: list[dict[str, Any]] = []
    if normalized_store_ref:
        selected_external_candidates = [
            candidate
            for candidate in external_candidates
            if str(candidate.get("store_ref") or "") == normalized_store_ref
        ]
        if external_candidates and not selected_external_candidates:
            blockers.append("store_ref_not_found_for_object_id")
    elif len(external_candidates) == 1:
        selected_external_candidates = external_candidates
        candidate_ref = selected_external_candidates[0].get("store_ref")
        if isinstance(candidate_ref, str) and candidate_ref:
            normalized_store_ref = candidate_ref
    elif len(external_candidates) > 1:
        blockers.append("store_ref_required_when_multiple_external_candidates")

    if normalized_object_id and not external_candidates and resolution and not resolution.get("blockers"):
        blockers.append("no_external_store_candidate_for_object_id")

    object_storage_status = object_storage_context(root)
    object_storage_configured = bool(object_storage_status.get("object_storage_configured"))
    if not object_storage_configured:
        warnings.append("No local object-storage provider binding is configured; future presigned URL adapters will need one.")

    selected_external_candidate = selected_external_candidates[0] if selected_external_candidates else None
    plan_state = "blocked" if blockers else "ready_for_future_adapter"
    next_safe_actions = [
        f"archive resolve-objet-ref <archive-root> --object-id {normalized_object_id or 'sha256:<hex>'} --dry-run",
        "Verify provider setup with archive provider-status --dry-run before any future adapter work.",
        "Require a credential policy check and human approval receipt before any future live provider call.",
    ]
    if blockers:
        next_safe_actions.insert(0, "Fix blockers before treating this as a presigned URL request.")
    else:
        next_safe_actions.append("A future adapter may create a URL only if it keeps URL output private and receipt-scoped.")

    return {
        "ok": not blockers,
        "dry_run": True,
        "lifecycle_action": "presigned_url_plan",
        "archive_id": archive_id,
        "object_id": normalized_object_id or str(object_id or ""),
        "plan_state": plan_state,
        "presigned_url_request": {
            "operation": normalized_operation,
            "ttl_seconds": normalized_ttl_seconds,
            "store_ref": normalized_store_ref or None,
            "object_storage_provider_binding_present": object_storage_configured,
        },
        "resolution_summary": {
            "resolution_state": resolution.get("resolution_state") if isinstance(resolution, dict) else "not_checked",
            "manifest_record_count": resolution.get("manifest_record_count") if isinstance(resolution, dict) else 0,
            "local_openable": bool(resolution.get("local_openable")) if isinstance(resolution, dict) else False,
            "external_candidate_count": len(external_candidates),
            "selected_external_candidate": selected_external_candidate,
        },
        "current_capability": {
            "presigned_url_creation_implemented": False,
            "provider_api_call_implemented": False,
            "credential_broker_live_adapter_implemented": False,
            "download_implemented": False,
            "upload_implemented": False,
        },
        "future_adapter_requirements": [
            "explicit provider adapter implementation",
            "safe object store binding that does not echo bucket URLs or secrets",
            "credential access policy check",
            "human approval receipt for the live provider call",
            "private URL handling policy that keeps generated URLs out of public records",
            "short TTL and operation-specific scope",
            "non-secret audit receipt after adapter execution",
        ],
        "privacy_guards": {
            "absolute_local_paths_echoed": False,
            "provider_urls_echoed": False,
            "secret_values_echoed": False,
            "exact_credential_refs_echoed": False,
            "object_file_bytes_read": False,
            "file_hash_verified_now": False,
            "provider_api_called": False,
            "presigned_url_created": False,
            "download_performed": False,
            "upload_performed": False,
            "writes": False,
        },
        "closed_actions": {
            "provider_api_called": False,
            "presigned_url_created": False,
            "credential_value_read": False,
            "provider_url_echoed": False,
            "object_file_bytes_read": False,
            "download_performed": False,
            "upload_performed": False,
            "receipt_written": False,
        },
        "would_change": [],
        "next_safe_actions": next_safe_actions,
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }


def manifest_record_for_local_path(root: Path, candidate: Path) -> dict[str, Any] | None:
    relative: str | None = None
    try:
        if candidate.resolve().is_relative_to(root.resolve()):
            relative = archive_relative_path(candidate, root)
    except (OSError, RuntimeError, ValueError, ArchivePathError):
        relative = None
    if not relative:
        return None
    for record in load_manifest_records(root):
        if record.get("logical_key") == relative:
            return record
        locations = record.get("locations")
        if isinstance(locations, list):
            for location in locations:
                if isinstance(location, dict) and location.get("path") == relative:
                    return record
    return None


def local_path_inside_registered_source_root(root: Path, candidate: Path) -> bool:
    for binding in source_bindings_list(load_source_bindings(root)):
        source_id = str(binding.get("source_id") or "")
        root_ref = str(binding.get("root_ref") or "")
        roots: list[Path] = []
        if root_ref.startswith("archive:"):
            try:
                roots.append(archive_internal_path(root, root_ref.removeprefix("archive:")))
            except ArchiveServiceError:
                pass
        elif root_ref and os.environ.get(root_ref):
            roots.append(Path(os.environ[root_ref]).expanduser().resolve())
        local_profile_root = local_source_root_path(root, source_id)
        if local_profile_root is not None:
            roots.append(local_profile_root)
        for source_root in roots:
            try:
                if candidate.resolve().is_relative_to(source_root.resolve()):
                    return True
            except (OSError, RuntimeError, ValueError):
                continue
    return False


def normalize_source_intake_relative_path(value: str) -> str:
    normalized = normalize_archive_relative_path(value)
    if contains_forbidden_location_reference(normalized) or source_intake_secret_like(normalized):
        raise ArchivePathError("relative path must not contain provider URLs, local paths, tokens, or secrets")
    return normalized


def safe_source_label(title: str | None, filename: str, redact_local_paths: bool) -> str:
    if isinstance(title, str) and title.strip():
        return title.strip()
    suffix = Path(filename).suffix.lower()
    if redact_local_paths:
        return f"local-file{suffix}" if suffix else "local-file"
    return filename


def safe_source_map_label(title: str | None, item: dict[str, Any]) -> str:
    if isinstance(title, str) and title.strip():
        return title.strip()
    item_title = item.get("title")
    if isinstance(item_title, str) and item_title.strip():
        return item_title.strip()
    relative = item.get("relative_path")
    if isinstance(relative, str) and relative.strip():
        return Path(relative.replace("\\", "/")).name
    item_id = item.get("item_id")
    return str(item_id or "source-map-item")


def safe_mime(value: str | None) -> str | None:
    text = (value or "").strip()
    if not text:
        return None
    if not re.match(r"^[A-Za-z0-9][A-Za-z0-9.+-]{0,99}/[A-Za-z0-9][A-Za-z0-9.+-]{0,99}$", text):
        return None
    if source_intake_secret_like(text) or contains_forbidden_location_reference(text):
        return None
    return text


def classify_source_kind(mime: str | None, path_or_ext: str | None = None) -> str:
    suffix = Path(path_or_ext or "").suffix.lower()
    if mime:
        if mime.startswith("image/"):
            return "image"
        if mime.startswith("audio/"):
            return "audio"
        if mime.startswith("video/"):
            return "video"
        if mime in {"application/pdf"}:
            return "document"
        if mime.startswith("text/"):
            return "text"
    if suffix in {".ppt", ".pptx"}:
        return "presentation"
    if suffix in {".xls", ".xlsx", ".csv"}:
        return "spreadsheet"
    if suffix in {".pdf", ".doc", ".docx", ".hwp", ".hwpx", ".odt", ".rtf"}:
        return "document"
    if suffix in {".png", ".jpg", ".jpeg", ".gif", ".webp", ".heic"}:
        return "image"
    if suffix in {".mp3", ".wav", ".m4a", ".flac", ".ogg"}:
        return "audio"
    if suffix in {".mp4", ".mov", ".mkv", ".webm"}:
        return "video"
    if suffix in {".md", ".markdown", ".txt"}:
        return "text"
    return "file"


def safe_source_intake_text(value: str) -> bool:
    return not (contains_forbidden_location_reference(value) or DRAFT_SECRET_VALUE_RE.search(value) or source_intake_secret_like(value))


def safe_source_intake_ref(value: str) -> bool:
    text = value.strip()
    if not text or not text.isascii():
        return False
    if "@" in text or "://" in text or "\\" in text or "/" in text or "#" in text or "?" in text or "\x00" in text:
        return False
    if contains_forbidden_location_reference(text) or source_intake_secret_like(text):
        return False
    return bool(SOURCE_INTAKE_SAFE_REF_RE.match(text))


def safe_source_intake_artifact_kind(value: str) -> bool:
    text = value.strip()
    if not text or not text.isascii():
        return False
    if contains_forbidden_location_reference(text) or source_intake_secret_like(text):
        return False
    return bool(SOURCE_INTAKE_ARTIFACT_KIND_RE.match(text))


def source_intake_has_provider_url(value: str) -> bool:
    return bool(re.search(r"(?i)\b(?:s3|b2|r2|gs)://|://", value))


def zettel_body_has_private_provider_locator(value: str) -> bool:
    return bool(ZETTEL_PRIVATE_PROVIDER_LOCATOR_RE.search(value))


def zettel_body_has_forbidden_location_reference(value: str) -> bool:
    return contains_forbidden_location_reference(value) or zettel_body_has_private_provider_locator(value)


def source_intake_secret_like(value: str) -> bool:
    return bool(DRAFT_SECRET_VALUE_RE.search(value) or GITHUB_SECRET_LIKE_RE.search(value))


def source_scan_dry_run(
    archive_root: Path | str,
    *,
    source_id: str,
    source_root: Path | str | None = None,
    limit: int = 2000,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    binding = source_binding_by_id(root, source_id)
    source_type = str(binding.get("source_type") or "")
    if source_type not in SOURCE_TYPES:
        raise ArchiveServiceError("source_type must be one of: " + ", ".join(sorted(SOURCE_TYPES)))
    limit = max(1, min(int(limit), 10000))
    scope_policy = binding.get("scope_policy") if isinstance(binding.get("scope_policy"), dict) else {}
    policy_max = scope_policy.get("max_items")
    if isinstance(policy_max, int):
        limit = min(limit, max(1, min(policy_max, 10000)))

    blockers: list[str] = []
    warnings: list[str] = []
    if binding.get("enabled") is False:
        blockers.append(f"Source is disabled in source-bindings.yml: {source_id}.")

    resolved_root, root_resolution = resolve_source_scan_root(root, binding, source_root, blockers, warnings)
    scan_now = datetime.now().astimezone().replace(microsecond=0).isoformat()
    items: list[dict[str, Any]] = []
    if not blockers:
        items = discover_source_map_items(
            archive_root=root,
            binding=binding,
            resolved_root=resolved_root,
            scanned_at=scan_now,
            limit=limit,
            warnings=warnings,
        )
        items = [drop_none_values(item) for item in items]
        if not items:
            warnings.append(f"Source scan found no metadata items: {source_id}.")

    source_map_path = source_map_relative_path(source_id)
    fingerprint = source_scan_fingerprint(source_id, source_type, items)
    proposed_receipt_path = source_scan_receipt_relative_path(source_id, fingerprint)
    if archive_internal_path(root, proposed_receipt_path).exists():
        blockers.append(f"Proposed source scan receipt already exists: {proposed_receipt_path}.")

    scope_gate = {
        "unit": "source",
        "source_id": source_id,
        "source_type": source_type,
        "scan_mode": SOURCE_SCAN_MODE,
        "metadata_only": True,
        "content_read": False,
        "full_hash_calculated": False,
        "root_ref": binding.get("root_ref"),
        "item_count": len(items),
        "limit": limit,
    }
    trust_gate = {
        "required": False,
        "ok": True,
        "status": "local_or_export_metadata_only",
        "external_api_called": False,
        "secret_values_required": False,
    }
    lineage = {
        "event": "source_scan",
        "source_archive": archive_id,
        "source_id": source_id,
        "source_type": source_type,
        "scan_mode": SOURCE_SCAN_MODE,
    }
    receipt_preview = {
        "receipt_id": f"receipt:source-scan:{safe_slug(archive_id)}:{safe_slug(source_id)}:{fingerprint}",
        "receipt_path": proposed_receipt_path,
        "action": "scan_archive_source",
        "dry_run": True,
        "timestamp": "<execution-time>",
        "source_archive": archive_id,
        "source_id": source_id,
        "source_type": source_type,
        "scan_mode": SOURCE_SCAN_MODE,
        "source_root_resolution": root_resolution,
        "item_count": len(items),
        "source_map_path": source_map_path,
        "scope_gate": scope_gate,
        "trust_gate": trust_gate,
        "lineage": lineage,
        "blockers": blockers,
        "warnings": warnings,
    }
    return {
        "ok": not blockers,
        "dry_run": True,
        "action": "scan_archive_source",
        "source_archive": archive_id,
        "source_id": source_id,
        "source_type": source_type,
        "scan_mode": SOURCE_SCAN_MODE,
        "source_root_resolution": root_resolution,
        "source_map_path": source_map_path,
        "proposed_source_map_path": source_map_path,
        "proposed_receipt_path": proposed_receipt_path,
        "item_count": len(items),
        "items": items,
        "scope_gate": scope_gate,
        "trust_gate": trust_gate,
        "lineage": lineage,
        "receipt_preview": receipt_preview,
        "would_change": [source_map_path, proposed_receipt_path],
        "blockers": blockers,
        "warnings": warnings,
    }


def scan_source(
    archive_root: Path | str,
    *,
    source_id: str,
    reviewed_by: str,
    source_root: Path | str | None = None,
    limit: int = 2000,
) -> dict[str, Any]:
    reviewer = reviewed_by.strip()
    if not reviewer:
        raise ArchiveServiceError("Source scan requires --reviewed-by.")
    root = require_existing_archive_root(archive_root)
    dry_run = source_scan_dry_run(root, source_id=source_id, source_root=source_root, limit=limit)
    if dry_run["blockers"]:
        raise ArchiveServiceError("Source scan blocked by dry-run: " + "; ".join(dry_run["blockers"]))

    now = datetime.now().astimezone().replace(microsecond=0).isoformat()
    source_map_relative = dry_run["source_map_path"]
    source_map_path = archive_internal_path(root, source_map_relative)
    receipt_relative = dry_run["proposed_receipt_path"]
    receipt_path = archive_internal_path(root, receipt_relative)
    if receipt_path.exists():
        raise ArchiveServiceError(f"Proposed source scan receipt already exists: {receipt_relative}.")

    old_source_map_text = source_map_path.read_text(encoding="utf-8") if source_map_path.is_file() else None
    receipt = dict(dry_run["receipt_preview"])
    receipt["dry_run"] = False
    receipt["timestamp"] = now
    receipt["reviewed_by"] = reviewer
    receipt["reviewed_at"] = now
    receipt["result"] = {
        "changed_paths": [source_map_relative, receipt_relative],
        "source_map_written": True,
        "external_api_called": False,
    }
    try:
        source_map_path.parent.mkdir(parents=True, exist_ok=True)
        source_map_text = "".join(
            json.dumps(json_safe(item), ensure_ascii=False, sort_keys=True, default=str) + "\n"
            for item in dry_run["items"]
        )
        source_map_path.write_text(source_map_text, encoding="utf-8")
        receipt_path.parent.mkdir(parents=True, exist_ok=True)
        with receipt_path.open("x", encoding="utf-8") as handle:
            handle.write(json.dumps(json_safe(receipt), indent=2, ensure_ascii=False, default=str) + "\n")
    except Exception:
        if old_source_map_text is None:
            try:
                if source_map_path.exists():
                    source_map_path.unlink()
            except OSError:
                pass
        else:
            try:
                source_map_path.write_text(old_source_map_text, encoding="utf-8")
            except OSError:
                pass
        try:
            if receipt_path.exists():
                receipt_path.unlink()
        except OSError:
            pass
        raise

    return {
        "ok": True,
        "dry_run": False,
        "action": "scan_archive_source",
        "source_archive": dry_run["source_archive"],
        "source_id": dry_run["source_id"],
        "source_type": dry_run["source_type"],
        "scan_mode": dry_run["scan_mode"],
        "item_count": dry_run["item_count"],
        "source_map_path": source_map_relative,
        "receipt_path": receipt_relative,
        "reviewed_by": reviewer,
        "changed_paths": [source_map_relative, receipt_relative],
        "receipt": json_safe(receipt),
    }


def resolve_source_scan_root(
    archive_root: Path,
    binding: dict[str, Any],
    source_root: Path | str | None,
    blockers: list[str],
    warnings: list[str],
) -> tuple[Path | None, dict[str, Any]]:
    source_type = str(binding.get("source_type") or "")
    source_id = str(binding.get("source_id") or "")
    root_ref = str(binding.get("root_ref") or "")
    resolution: dict[str, Any] = {
        "method": None,
        "root_ref": root_ref,
        "path_recorded": False,
        "exists": False,
    }
    if source_type == "object_manifest":
        manifest_path = archive_internal_path(archive_root, "objects/manifests/files.jsonl")
        resolution.update({"method": "archive_object_manifest", "exists": manifest_path.is_file()})
        if not manifest_path.is_file():
            blockers.append("Object manifest source requires objects/manifests/files.jsonl.")
        return manifest_path, resolution
    if source_type == IMAP_MAILBOX_SOURCE_TYPE:
        resolution.update(
            {
                "method": "imap_mailbox_planned",
                "exists": False,
                "path_recorded": False,
                "credential_refs_required": True,
            }
        )
        blockers.append("IMAP mailbox live scans are not implemented in this release; run imap-mailbox-plan to review safe refs first.")
        return None, resolution

    candidate: Path | None = None
    if source_root is not None:
        candidate = Path(source_root).expanduser().resolve()
        resolution["method"] = "cli_argument"
    elif root_ref.startswith("archive:"):
        try:
            candidate = archive_internal_path(archive_root, root_ref.removeprefix("archive:"))
            resolution["method"] = "archive_relative_root_ref"
        except ArchiveServiceError as exc:
            blockers.append(str(exc))
    elif root_ref and os.environ.get(root_ref):
        candidate = Path(os.environ[root_ref]).expanduser().resolve()
        resolution["method"] = f"env:{root_ref}"
    elif source_id and local_source_root_path(archive_root, source_id) is not None:
        candidate = local_source_root_path(archive_root, source_id)
        resolution["method"] = "ignored_local_profile"
    else:
        blockers.append(f"Source requires --source-root or an environment variable named by root_ref: {root_ref}.")
        resolution["method"] = "unresolved"

    if candidate is None:
        return None, resolution
    resolution["exists"] = candidate.exists()
    if not candidate.exists():
        blockers.append("Resolved source root does not exist.")
        return candidate, resolution
    if source_type in {"local_folder", "external_ssd", "notion_export"} and not candidate.is_dir():
        blockers.append(f"Source type {source_type} requires a directory root.")
    if source_type == "google_drive_export" and not (candidate.is_dir() or candidate.is_file()):
        blockers.append("Google Drive export source requires a directory or manifest file.")
    if candidate == archive_root:
        warnings.append("Source root is the archive root; this is allowed for examples but should be explicit for real archives.")
    return candidate, resolution


def discover_source_map_items(
    *,
    archive_root: Path,
    binding: dict[str, Any],
    resolved_root: Path | None,
    scanned_at: str,
    limit: int,
    warnings: list[str],
) -> list[dict[str, Any]]:
    source_type = str(binding.get("source_type") or "")
    if source_type == "object_manifest":
        return object_manifest_source_map_items(archive_root, binding, scanned_at, limit, warnings)
    if resolved_root is None:
        return []
    if source_type == "google_drive_export" and resolved_root.is_file():
        return google_drive_manifest_source_map_items(resolved_root, binding, scanned_at, limit, warnings)
    return filesystem_source_map_items(resolved_root, binding, scanned_at, limit, warnings)


def object_manifest_source_map_items(
    archive_root: Path,
    binding: dict[str, Any],
    scanned_at: str,
    limit: int,
    warnings: list[str],
) -> list[dict[str, Any]]:
    source_id = str(binding.get("source_id") or "")
    visibility = source_visibility(binding)
    entries: list[dict[str, Any]] = []
    for record in load_manifest_records(archive_root)[:limit]:
        object_id = str(record.get("object_id") or "")
        logical_key = record.get("logical_key") if isinstance(record.get("logical_key"), str) else None
        entries.append(
            {
                "source_id": source_id,
                "item_id": object_id or stable_source_item_id(source_id, logical_key or "object"),
                "item_kind": "object",
                "relative_path": logical_key,
                "object_id": object_id or None,
                "size_bytes": record.get("size_bytes") if isinstance(record.get("size_bytes"), int) else None,
                "mime": record.get("mime"),
                "visibility": visibility,
                "scan_status": "seen",
                "provenance": {
                    "source_type": "object_manifest",
                    "scan_mode": SOURCE_SCAN_MODE,
                    "scanned_at": scanned_at,
                    "content_read": False,
                    "full_hash_calculated": False,
                    "external_api_called": False,
                },
            }
        )
    if len(load_manifest_records(archive_root)) > limit:
        warnings.append(f"Object manifest source scan was limited to {limit} item(s).")
    return entries


def google_drive_manifest_source_map_items(
    manifest_path: Path,
    binding: dict[str, Any],
    scanned_at: str,
    limit: int,
    warnings: list[str],
) -> list[dict[str, Any]]:
    data = load_external_import_manifest_data(manifest_path)
    raw_items = data.get("items") if isinstance(data, dict) else []
    if not isinstance(raw_items, list):
        warnings.append("Google Drive source manifest has no items list.")
        return []
    source_id = str(binding.get("source_id") or "")
    visibility = source_visibility(binding)
    entries: list[dict[str, Any]] = []
    for raw_item in raw_items[:limit]:
        if not isinstance(raw_item, dict):
            continue
        external_id = str(raw_item.get("external_id") or raw_item.get("id") or raw_item.get("url") or raw_item.get("path") or "")
        relative_path = str(raw_item.get("path") or "") or None
        entries.append(
            {
                "source_id": source_id,
                "item_id": stable_source_item_id(source_id, external_id or relative_path or str(len(entries))),
                "item_kind": str(raw_item.get("kind") or "file"),
                "relative_path": relative_path,
                "external_url": raw_item.get("url") or raw_item.get("source_url"),
                "provider_id": external_id or None,
                "size_bytes": raw_item.get("size_bytes") if isinstance(raw_item.get("size_bytes"), int) else None,
                "modified_at": raw_item.get("modified_at") or raw_item.get("updated_at"),
                "mime": raw_item.get("mime"),
                "title": raw_item.get("title") or raw_item.get("name"),
                "visibility": visibility,
                "scan_status": "seen",
                "provenance": {
                    "source_type": "google_drive_export",
                    "scan_mode": SOURCE_SCAN_MODE,
                    "scanned_at": scanned_at,
                    "content_read": False,
                    "full_hash_calculated": False,
                    "external_api_called": False,
                },
            }
        )
    if len(raw_items) > limit:
        warnings.append(f"Google Drive source scan was limited to {limit} item(s).")
    return entries


def filesystem_source_map_items(
    root: Path,
    binding: dict[str, Any],
    scanned_at: str,
    limit: int,
    warnings: list[str],
) -> list[dict[str, Any]]:
    source_id = str(binding.get("source_id") or "")
    source_type = str(binding.get("source_type") or "")
    visibility = source_visibility(binding)
    scope_policy = binding.get("scope_policy") if isinstance(binding.get("scope_policy"), dict) else {}
    include_patterns = scope_patterns(scope_policy.get("include"), ["**/*"])
    exclude_patterns = scope_patterns(scope_policy.get("exclude"), [".git/**", "__pycache__/**"])
    entries: list[dict[str, Any]] = []
    skipped = 0
    for path in sorted(root.rglob("*")):
        if len(entries) >= limit:
            skipped += 1
            continue
        if not path.is_file():
            continue
        if not is_path_within_root(path, root):
            skipped += 1
            continue
        relative = path.relative_to(root).as_posix()
        if not matches_any_pattern(relative, include_patterns):
            skipped += 1
            continue
        if matches_any_pattern(relative, exclude_patterns):
            skipped += 1
            continue
        try:
            stat = path.stat()
        except OSError:
            skipped += 1
            continue
        entries.append(
            {
                "source_id": source_id,
                "item_id": stable_source_item_id(source_id, relative),
                "item_kind": "file",
                "relative_path": relative,
                "size_bytes": int(stat.st_size),
                "modified_at": datetime.fromtimestamp(stat.st_mtime).astimezone().replace(microsecond=0).isoformat(),
                "mime": mimetypes.guess_type(path.name)[0],
                "title": path.stem,
                "visibility": visibility,
                "scan_status": "seen",
                "provenance": {
                    "source_type": source_type,
                    "scan_mode": SOURCE_SCAN_MODE,
                    "scanned_at": scanned_at,
                    "content_read": False,
                    "full_hash_calculated": False,
                    "external_api_called": False,
                },
            }
        )
    if skipped:
        warnings.append(f"Source scan skipped or deferred {skipped} item(s) because of limits, filters, or path safety.")
    return entries


def source_visibility(binding: dict[str, Any]) -> dict[str, Any]:
    visibility = binding.get("visibility")
    if isinstance(visibility, dict):
        return json_safe(visibility)
    return default_private_visibility()


def scope_patterns(value: Any, default: list[str]) -> list[str]:
    if isinstance(value, list):
        return [str(item) for item in value if isinstance(item, str) and item]
    if isinstance(value, str) and value:
        return [value]
    return default


def matches_any_pattern(relative_path: str, patterns: list[str]) -> bool:
    normalized = relative_path.replace("\\", "/")
    for pattern in patterns:
        normalized_pattern = pattern.replace("\\", "/")
        if normalized_pattern in {"*", "**", "**/*"}:
            return True
        if fnmatch.fnmatch(normalized, normalized_pattern):
            return True
        if normalized_pattern.endswith("/**") and normalized.startswith(normalized_pattern[:-3]):
            return True
    return False


def stable_source_item_id(source_id: str, key: str) -> str:
    digest = hashlib.sha256(f"{source_id}\n{key}".encode("utf-8")).hexdigest()[:16]
    return f"sourceitem:{safe_slug(source_id)}:{digest}"


def source_scan_fingerprint(source_id: str, source_type: str, items: list[dict[str, Any]]) -> str:
    payload = {
        "source_id": source_id,
        "source_type": source_type,
        "items": [
            {
                "item_id": item.get("item_id"),
                "relative_path": item.get("relative_path"),
                "external_url": item.get("external_url"),
                "object_id": item.get("object_id"),
                "size_bytes": item.get("size_bytes"),
                "modified_at": item.get("modified_at"),
            }
            for item in items
        ],
    }
    return hashlib.sha256(json.dumps(payload, sort_keys=True, default=str).encode("utf-8")).hexdigest()[:16]


def unique_workpack_id(archive_root: Path, view_id: str, iso_now: str) -> str:
    base = f"workpack_{iso_now[:10].replace('-', '')}_{safe_slug(view_id)}"
    candidate = base
    suffix = 2
    while (archive_root / "workpacks" / candidate).exists():
        candidate = f"{base}_{suffix}"
        suffix += 1
    return candidate


def safe_slug(value: str) -> str:
    return re.sub(r"[^a-z0-9]+", "_", value.lower()).strip("_")[:64] or "item"


def resolve_workpack_package_path(workpack_path: Path | str) -> tuple[Path, Path]:
    candidate = Path(workpack_path).resolve()
    package_file = candidate / "package.yml" if candidate.is_dir() else candidate
    if package_file.name != "package.yml":
        raise ArchiveServiceError("Workpack path must be a workpack directory or package.yml file.")
    if not package_file.is_file():
        raise ArchiveServiceError(f"Workpack package.yml not found: {package_file}")
    return package_file.parent, package_file


def inspect_workpack_zettels(
    target_root: Path,
    package_root: Path,
    package: dict[str, Any],
    blockers: list[str],
    warnings: list[str],
) -> list[dict[str, Any]]:
    entries = extract_workpack_zettel_entries(package, package_root, blockers)
    target_ids = collect_target_zettel_ids(target_root)
    previews: list[dict[str, Any]] = []
    for entry in entries:
        package_path = entry["package_path"]
        try:
            zettel_path = resolve_archive_relative_path(package_root, package_path)
        except ArchivePathError as exc:
            blockers.append(f"Workpack zettel path is unsafe: {package_path} ({exc}).")
            continue
        if not zettel_path.is_file():
            blockers.append(f"Workpack zettel file is missing: {package_path}.")
            continue
        frontmatter, _body = split_zettel_text(zettel_path.read_text(encoding="utf-8"))
        frontmatter = json_safe(frontmatter)
        zettel_id = frontmatter.get("id")
        filename = zettel_path.name
        target_path = f"inbox/{filename}"
        preview = {
            "id": zettel_id,
            "title": frontmatter.get("title"),
            "package_path": archive_relative_path(zettel_path, package_root),
            "target_path": target_path,
            "action": "create_inbox_draft",
            "conflicts": [],
        }
        if zettel_id in target_ids:
            preview["conflicts"].append("zettel_id_exists")
            blockers.append(f"Target archive already has zettel id: {zettel_id}.")
        if (target_root / target_path).exists():
            preview["conflicts"].append("target_path_exists")
            blockers.append(f"Target inbox path already exists: {target_path}.")
        if contains_forbidden_location_reference(zettel_path.read_text(encoding="utf-8")):
            warnings.append(f"Workpack zettel may contain a provider URL or local absolute path: {package_path}.")
        previews.append(preview)
    return previews


def extract_workpack_zettel_entries(
    package: dict[str, Any],
    package_root: Path,
    blockers: list[str],
) -> list[dict[str, str]]:
    contents = package.get("contents") if isinstance(package.get("contents"), dict) else {}
    raw_entries = contents.get("zettels") if isinstance(contents, dict) else None
    entries: list[dict[str, str]] = []
    if isinstance(raw_entries, list):
        for item in raw_entries:
            if isinstance(item, dict) and isinstance(item.get("package_path"), str):
                entries.append({"package_path": item["package_path"]})
            elif isinstance(item, str):
                entries.append({"package_path": item})
            else:
                blockers.append("Workpack contents.zettels contains an unsupported entry.")
    if entries:
        return entries

    zettels_root = package_root / "zettels"
    if zettels_root.is_dir():
        for path in safe_archive_glob(zettels_root, "*.md", package_root):
            entries.append({"package_path": archive_relative_path(path, package_root)})
    return entries


def collect_target_zettel_ids(target_root: Path) -> set[Any]:
    zettel_ids: set[Any] = set()
    for path in iter_zettel_paths(target_root):
        frontmatter, _body = split_zettel_text(path.read_text(encoding="utf-8"))
        if frontmatter.get("id"):
            zettel_ids.add(frontmatter.get("id"))
    return zettel_ids


def inspect_workpack_manifest(
    target_root: Path,
    package_root: Path,
    package: dict[str, Any],
    blockers: list[str],
    warnings: list[str],
) -> list[dict[str, Any]]:
    contents = package.get("contents") if isinstance(package.get("contents"), dict) else {}
    objects = contents.get("objects") if isinstance(contents.get("objects"), dict) else {}
    manifest_relative = objects.get("manifest_path") if isinstance(objects.get("manifest_path"), str) else "manifests/files.jsonl"
    try:
        manifest_path = resolve_archive_relative_path(package_root, manifest_relative)
    except ArchivePathError as exc:
        blockers.append(f"Workpack manifest path is unsafe: {manifest_relative} ({exc}).")
        return []
    if not manifest_path.is_file():
        if objects.get("object_ids"):
            blockers.append(f"Workpack object manifest is missing: {manifest_relative}.")
        return []

    target_objects = {record.get("object_id"): record for record in load_manifest_records(target_root)}
    previews: list[dict[str, Any]] = []
    for line_number, raw_line in enumerate(manifest_path.read_text(encoding="utf-8").splitlines(), start=1):
        line = raw_line.strip()
        if not line:
            continue
        try:
            record = json.loads(line)
        except json.JSONDecodeError as exc:
            blockers.append(f"Workpack manifest invalid JSON on line {line_number}: {exc}.")
            continue
        object_id = record.get("object_id") if isinstance(record, dict) else None
        if not object_id:
            blockers.append(f"Workpack manifest entry missing object_id on line {line_number}.")
            continue
        action = "already_present" if object_id in target_objects else "append_manifest_record"
        preview = {
            "object_id": object_id,
            "logical_key": record.get("logical_key") if isinstance(record, dict) else None,
            "action": action,
            "include_original": False,
        }
        if action == "already_present":
            warnings.append(f"Target manifest already has object_id: {object_id}.")
        previews.append(preview)
    return previews


def build_import_scope_gate(
    package: dict[str, Any],
    zettel_previews: list[dict[str, Any]],
    object_previews: list[dict[str, Any]],
) -> dict[str, Any]:
    package_scope = package.get("scope_gate") if isinstance(package.get("scope_gate"), dict) else {}
    included_paths = [item["package_path"] for item in zettel_previews if item.get("action") == "create_inbox_draft"]
    return {
        "unit": package_scope.get("unit") or "workpack",
        "view_id": package_scope.get("view_id") or nested_value(package, ["contents", "view_id"]),
        "included_zettels": included_paths,
        "included_objects": [item["object_id"] for item in object_previews if item.get("action") == "append_manifest_record"],
        "excluded": package_scope.get("excluded") or [],
        "sensitive_categories_blocked_by_default": package_scope.get("sensitive_categories_blocked_by_default")
        or sorted(SENSITIVE_SHARE_CATEGORIES),
    }


def build_import_trust_gate(
    target_root: Path,
    package: dict[str, Any],
    *,
    counterparty_id: str | None,
    counterparty_fingerprint: str | None,
    blockers: list[str],
) -> dict[str, Any]:
    trust_policy = package.get("trust_gate") if isinstance(package.get("trust_gate"), dict) else {}
    if not trust_policy.get("counterparty_identity_required"):
        return {"required": False, "ok": True, "status": "not_required"}
    return validate_counterparty_trust(
        target_root,
        counterparty_id=counterparty_id or str(package.get("source_archive") or ""),
        counterparty_fingerprint=counterparty_fingerprint,
        blockers=blockers,
    )


def load_archive_identity(archive_root: Path) -> dict[str, Any]:
    data = load_yaml(read_archive_text(archive_root, "archive-identity.yml"))
    if not isinstance(data, dict):
        raise ArchiveServiceError("archive-identity.yml must be a YAML object.")
    return json_safe(data)


def load_json_file(path: Path) -> dict[str, Any]:
    try:
        data = json.loads(path.read_text(encoding="utf-8"))
    except json.JSONDecodeError as exc:
        raise ArchiveServiceError(f"JSON file is invalid: {path}") from exc
    if not isinstance(data, dict):
        raise ArchiveServiceError(f"JSON file must contain an object: {path}")
    return json_safe(data)


def resolve_receipt_input_path(archive_root: Path, raw_path: str) -> Path:
    value = (raw_path or "").strip()
    if not value:
        raise ArchiveServiceError("Receipt path is required.")
    candidate = Path(value).expanduser()
    if candidate.is_absolute():
        path = candidate.resolve()
    else:
        path = archive_internal_path(archive_root, value)
    if not path.is_file():
        raise ArchiveServiceError(f"Receipt file is missing: {value}")
    return path


def display_receipt_input_path(archive_root: Path, path: Path) -> str:
    if is_path_within_root(path, archive_root):
        return archive_relative_path(path, archive_root)
    return str(path)


def string_or_empty(value: Any) -> str:
    return value if isinstance(value, str) else ""


def normalized_delegated_zets(raw_items: Any, blockers: list[str]) -> list[dict[str, Any]]:
    if not isinstance(raw_items, list):
        blockers.append("Delegated zets must be a list.")
        return []
    normalized: list[dict[str, Any]] = []
    for index, item in enumerate(raw_items):
        if not isinstance(item, dict):
            blockers.append(f"Delegated zets entry must be an object: index {index}.")
            continue
        path = item.get("path")
        zettel_id = item.get("zettel_id")
        sha256 = item.get("sha256")
        if not isinstance(path, str) or not path:
            blockers.append(f"Delegated zets entry missing path: index {index}.")
        if not isinstance(zettel_id, str) or not zettel_id:
            blockers.append(f"Delegated zets entry missing zettel_id: index {index}.")
        if not isinstance(sha256, str) or not SHA256_RE.match(sha256):
            blockers.append(f"Delegated zets entry has invalid sha256: index {index}.")
        normalized.append(
            {
                "path": path,
                "zettel_id": zettel_id,
                "title": item.get("title"),
                "sha256": sha256,
                "sensitive_categories": item.get("sensitive_categories") if isinstance(item.get("sensitive_categories"), list) else [],
            }
        )
    if not normalized:
        blockers.append("Delegated zets list is empty.")
    return normalized


def validate_counterparty_trust(
    archive_root: Path,
    *,
    counterparty_id: str | None,
    counterparty_fingerprint: str | None,
    blockers: list[str],
) -> dict[str, Any]:
    identity_doc = load_archive_identity(archive_root)
    counterparty = (counterparty_id or "").strip()
    fingerprint = (counterparty_fingerprint or "").strip()
    result = {
        "required": True,
        "ok": False,
        "counterparty_id": counterparty or None,
        "provided_fingerprint": fingerprint or None,
        "matched": None,
        "status": "blocked",
    }
    if not counterparty:
        blockers.append("Counterparty identity is required for archive sharing.")
        return result
    if not fingerprint:
        blockers.append("Counterparty fingerprint is required for trust gate verification.")
        return result

    trusted = identity_doc.get("trusted_counterparties") or []
    if not isinstance(trusted, list):
        blockers.append("archive-identity.yml trusted_counterparties must be a list.")
        return result
    for item in trusted:
        if not isinstance(item, dict):
            continue
        identifiers = {
            str(value)
            for value in [item.get("identity_id"), item.get("archive_id"), item.get("principal_id")]
            if value
        }
        if counterparty not in identifiers:
            continue
        expected = str(item.get("expected_fingerprint") or "")
        result["matched"] = {
            "identity_id": item.get("identity_id"),
            "archive_id": item.get("archive_id"),
            "principal_id": item.get("principal_id"),
            "trust_level": item.get("trust_level"),
            "expected_fingerprint": expected or None,
        }
        if expected != fingerprint:
            blockers.append("Counterparty fingerprint does not match trusted identity.")
            return result
        result["ok"] = True
        result["status"] = "verified"
        return result

    blockers.append(f"Counterparty identity is not trusted by this archive: {counterparty}.")
    return result


def sensitive_categories_for_frontmatter(frontmatter: dict[str, Any]) -> list[str]:
    raw_values: list[Any] = [frontmatter.get("kind")]
    facets = frontmatter.get("facets")
    if isinstance(facets, dict):
        for key in ["domain", "record_type", "category", "sensitivity", "privacy", "tags"]:
            raw_values.append(facets.get(key))
    visibility = frontmatter.get("visibility")
    if isinstance(visibility, dict):
        raw_values.append(visibility.get("scope"))

    found: set[str] = set()
    for value in raw_values:
        values = value if isinstance(value, list) else [value]
        for item in values:
            if not isinstance(item, str):
                continue
            normalized = re.sub(r"[^a-z0-9]+", "-", item.lower()).strip("-")
            normalized = SENSITIVE_CATEGORY_ALIASES.get(normalized, normalized)
            if normalized in SENSITIVE_SHARE_CATEGORIES:
                found.add(normalized)
    return sorted(found)


def index_archive(archive_root: Path | str) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    db_path = archive_internal_path(root, INDEX_RELATIVE_PATH)
    db_path.parent.mkdir(parents=True, exist_ok=True)

    zettel_count = 0
    object_count = 0
    derived_text_count = 0
    view_count = 0
    source_map_count = 0
    edge_count = 0
    facet_count = 0
    conn = connect_archive_index(db_path, write=True)
    try:
        conn.executescript(
            """
            CREATE TABLE IF NOT EXISTS zettels (
              path TEXT PRIMARY KEY,
              zettel_id TEXT,
              title TEXT,
              status TEXT,
              kind TEXT,
              body TEXT,
              frontmatter_json TEXT,
              file_size INTEGER,
              file_mtime_ns INTEGER,
              body_sha256 TEXT,
              approved_body_sha256 TEXT,
              forbidden_location_reference_found INTEGER
            );
            CREATE TABLE IF NOT EXISTS objects (
              object_id TEXT PRIMARY KEY,
              logical_key TEXT,
              mime TEXT,
              manifest_json TEXT
            );
            CREATE TABLE IF NOT EXISTS derived_texts (
              derived_text_id TEXT PRIMARY KEY,
              source_object_id TEXT,
              derivation_kind TEXT,
              review_status TEXT,
              language TEXT,
              text_logical_key TEXT,
              text_body TEXT,
              manifest_json TEXT
            );
            CREATE TABLE IF NOT EXISTS views (
              path TEXT PRIMARY KEY,
              view_id TEXT,
              name TEXT,
              view_for TEXT,
              view_json TEXT
            );
            CREATE TABLE IF NOT EXISTS source_map_entries (
              item_id TEXT PRIMARY KEY,
              source_id TEXT,
              item_kind TEXT,
              relative_path TEXT,
              external_url TEXT,
              scan_status TEXT,
              source_json TEXT
            );
            CREATE TABLE IF NOT EXISTS edges (
              from_id TEXT,
              to_id TEXT,
              edge_type TEXT
            );
            CREATE INDEX IF NOT EXISTS edges_from ON edges(from_id);
            CREATE INDEX IF NOT EXISTS edges_to ON edges(to_id);
            CREATE TABLE IF NOT EXISTS zettel_facets (
              zettel_id TEXT,
              facet_key TEXT,
              facet_value TEXT
            );
            CREATE INDEX IF NOT EXISTS facets_key_value ON zettel_facets(facet_key, facet_value);
            CREATE TABLE IF NOT EXISTS index_metadata (
              key TEXT PRIMARY KEY,
              value TEXT
            );
            DELETE FROM zettels;
            DELETE FROM objects;
            DELETE FROM derived_texts;
            DELETE FROM views;
            DELETE FROM source_map_entries;
            DELETE FROM edges;
            DELETE FROM zettel_facets;
            DELETE FROM index_metadata;
            """
        )
        ensure_archive_index_zettel_columns(conn)

        warnings: list[str] = []
        canonical_metadata_count = 0
        canonical_metadata_max_mtime_ns = 0

        def insert_facet_row(zettel_id: str, facet_key: str, facet_value: Any) -> bool:
            if not isinstance(facet_value, (str, int, float, bool)):
                return False
            conn.execute(
                "INSERT INTO zettel_facets(zettel_id, facet_key, facet_value) VALUES (?, ?, ?)",
                (zettel_id, str(facet_key), str(facet_value)),
            )
            return True

        for path in iter_zettel_paths(root):
            relative_path = archive_relative_path(path, root)
            try:
                zettel_stat = path.stat()
                zettel_mtime_ns = zettel_stat.st_mtime_ns
                zettel_size = zettel_stat.st_size
            except OSError:
                zettel_mtime_ns = 0
                zettel_size = 0
            text = path.read_text(encoding="utf-8")
            frontmatter, body = split_zettel_text(text)
            frontmatter = json_safe(frontmatter)
            zettel_status = frontmatter.get("status")
            draft_creation = frontmatter.get("draft_creation") if isinstance(frontmatter.get("draft_creation"), dict) else {}
            approved_body_sha256 = draft_creation.get("approved_body_sha256")
            if not isinstance(approved_body_sha256, str) or not SHA256_RE.match(approved_body_sha256):
                approved_body_sha256 = None
            if relative_path.startswith("zettels/") and zettel_status == "canonical":
                canonical_metadata_count += 1
                canonical_metadata_max_mtime_ns = max(canonical_metadata_max_mtime_ns, zettel_mtime_ns)
            # Privacy/defense-in-depth: a 'redacted' zettel's plaintext (title/body/frontmatter) must
            # never be written into the disposable on-disk index. path/id/status/kind are kept so the row
            # stays countable + filterable; search additionally excludes redacted rows entirely.
            redacted = zettel_status == "redacted"
            conn.execute(
                """
                INSERT OR REPLACE INTO zettels(
                  path, zettel_id, title, status, kind, body, frontmatter_json,
                  file_size, file_mtime_ns, body_sha256, approved_body_sha256,
                  forbidden_location_reference_found
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    relative_path,
                    frontmatter.get("id"),
                    "" if redacted else frontmatter.get("title"),
                    zettel_status,
                    frontmatter.get("kind"),
                    "" if redacted else body,
                    "" if redacted else json.dumps(frontmatter, ensure_ascii=False, default=str),
                    zettel_size,
                    zettel_mtime_ns,
                    "" if redacted else sha256_text(body),
                    "" if redacted else approved_body_sha256,
                    1 if (not redacted and contains_forbidden_location_reference(text)) else 0,
                ),
            )
            zettel_count += 1
            # Edges and facets are content: a redacted zettel's outgoing references and
            # facet values are suppressed like its body. (Inbound edges TO a redacted
            # zettel are filtered at query time.)
            if not redacted:
                from_id = str(frontmatter.get("id") or "")
                if from_id:
                    for ref in collect_referenced_zets(frontmatter):
                        conn.execute(
                            "INSERT INTO edges(from_id, to_id, edge_type) VALUES (?, ?, ?)",
                            (from_id, ref["id"], ref.get("edge_type")),
                        )
                        edge_count += 1
                    facets = frontmatter.get("facets")
                    if isinstance(facets, dict):
                        for facet_key, facet_value in facets.items():
                            if insert_facet_row(from_id, str(facet_key), facet_value):
                                facet_count += 1
                            elif isinstance(facet_value, list):
                                for index, item in enumerate(facet_value):
                                    if insert_facet_row(from_id, str(facet_key), item):
                                        facet_count += 1
                                    else:
                                        warnings.append(
                                            f"facet list member not indexed: {from_id} facets.{facet_key}[{index}]"
                                        )

        manifest_path = root / "objects" / "manifests" / "files.jsonl"
        if manifest_path.is_file():
            for raw_line in manifest_path.read_text(encoding="utf-8").splitlines():
                line = raw_line.strip()
                if not line:
                    continue
                try:
                    record = json.loads(line)
                except json.JSONDecodeError:
                    continue
                conn.execute(
                    """
                    INSERT OR REPLACE INTO objects(object_id, logical_key, mime, manifest_json)
                    VALUES (?, ?, ?, ?)
                    """,
                    (
                        record.get("object_id"),
                        record.get("logical_key"),
                        record.get("mime"),
                        json.dumps(record, ensure_ascii=False, default=str),
                    ),
                )
                object_count += 1

        for record in load_derived_text_records(root):
            text_body = ""
            text_logical_key = record.get("text_logical_key")
            if isinstance(text_logical_key, str) and text_logical_key:
                try:
                    text_path = archive_internal_path(root, text_logical_key)
                    if text_path.is_file():
                        text_body = text_path.read_text(encoding="utf-8")
                    else:
                        warnings.append(f"derived text body missing: {text_logical_key}")
                except (OSError, UnicodeError, ArchiveServiceError) as exc:
                    warnings.append(f"derived text body not indexed: {text_logical_key} ({exc})")
            conn.execute(
                """
                INSERT OR REPLACE INTO derived_texts(
                  derived_text_id, source_object_id, derivation_kind, review_status,
                  language, text_logical_key, text_body, manifest_json
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    record.get("derived_text_id"),
                    record.get("source_object_id"),
                    record.get("derivation_kind"),
                    record.get("review_status"),
                    record.get("language"),
                    text_logical_key,
                    text_body,
                    json.dumps(record, ensure_ascii=False, default=str),
                ),
            )
            derived_text_count += 1

        views_root = root / "views"
        if views_root.is_dir():
            for path in safe_archive_glob(views_root, "*.yml", root):
                data = load_yaml(path.read_text(encoding="utf-8"))
                safe_data = json_safe(data)
                conn.execute(
                    """
                    INSERT OR REPLACE INTO views(path, view_id, name, view_for, view_json)
                    VALUES (?, ?, ?, ?, ?)
                    """,
                    (
                        archive_relative_path(path, root),
                        safe_data.get("id") if isinstance(safe_data, dict) else None,
                        safe_data.get("name") if isinstance(safe_data, dict) else None,
                        safe_data.get("for") if isinstance(safe_data, dict) else None,
                        json.dumps(safe_data, ensure_ascii=False, default=str),
                    ),
                )
                view_count += 1

        source_maps_root = root / SOURCE_MAPS_DIR
        if source_maps_root.is_dir():
            for path in safe_archive_glob(source_maps_root, "*.jsonl", root):
                for raw_line in path.read_text(encoding="utf-8").splitlines():
                    line = raw_line.strip()
                    if not line:
                        continue
                    try:
                        record = json.loads(line)
                    except json.JSONDecodeError:
                        continue
                    if not isinstance(record, dict):
                        continue
                    conn.execute(
                        """
                        INSERT OR REPLACE INTO source_map_entries(
                          item_id, source_id, item_kind, relative_path, external_url, scan_status, source_json
                        )
                        VALUES (?, ?, ?, ?, ?, ?, ?)
                        """,
                        (
                            record.get("item_id"),
                            record.get("source_id"),
                            record.get("item_kind"),
                            record.get("relative_path"),
                            record.get("external_url"),
                            record.get("scan_status"),
                            json.dumps(record, ensure_ascii=False, default=str),
                        ),
                    )
                    source_map_count += 1

        replace_archive_index_metadata(
            conn,
            canonical_zettel_count=canonical_metadata_count,
            canonical_max_mtime_ns=canonical_metadata_max_mtime_ns,
        )
        conn.commit()
    finally:
        conn.close()

    return {
        "ok": True,
        "index_path": archive_relative_path(db_path, root),
        "zettels": zettel_count,
        "objects": object_count,
        "derived_texts": derived_text_count,
        "views": view_count,
        "source_map_entries": source_map_count,
        "edges": edge_count,
        "facets": facet_count,
        "warnings": warnings,
    }


def replace_archive_index_metadata(
    conn: sqlite3.Connection,
    *,
    canonical_zettel_count: int,
    canonical_max_mtime_ns: int,
) -> None:
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS index_metadata (
          key TEXT PRIMARY KEY,
          value TEXT
        )
        """
    )
    payload = {
        "schema": INDEX_METADATA_SCHEMA,
        "canonical_zettel_count": str(max(0, canonical_zettel_count)),
        "canonical_max_mtime_ns": str(max(0, canonical_max_mtime_ns)),
        "updated_at": datetime.now().astimezone().replace(microsecond=0).isoformat(),
        "updated_by": f"wom-kit/{WOM_KIT_VERSION}",
    }
    for key, value in payload.items():
        conn.execute("INSERT OR REPLACE INTO index_metadata(key, value) VALUES (?, ?)", (key, value))


def ensure_archive_index_zettel_columns(conn: sqlite3.Connection) -> None:
    existing = {str(row[1]) for row in conn.execute("PRAGMA table_info(zettels)").fetchall()}
    columns = {
        "file_size": "INTEGER",
        "file_mtime_ns": "INTEGER",
        "body_sha256": "TEXT",
        "approved_body_sha256": "TEXT",
        "forbidden_location_reference_found": "INTEGER",
    }
    for name, ddl_type in columns.items():
        if name not in existing:
            conn.execute(f"ALTER TABLE zettels ADD COLUMN {name} {ddl_type}")


def upsert_zettel_index_entry(root: Path, zettel_path: Path, frontmatter: dict[str, Any], body: str) -> bool:
    db_path = root / INDEX_RELATIVE_PATH
    if not db_path.is_file():
        return False

    relative = archive_relative_path(zettel_path, root)
    zettel_status = frontmatter.get("status")
    zettel_id = str(frontmatter.get("id") or "")
    redacted = zettel_status == "redacted"

    conn = connect_archive_index(db_path, write=True)
    try:
        ensure_archive_index_zettel_columns(conn)
        old_row = conn.execute("SELECT status FROM zettels WHERE path = ?", (relative,)).fetchone()
        old_is_canonical = (
            old_row is not None
            and relative.startswith("zettels/")
            and str(old_row[0] if not isinstance(old_row, sqlite3.Row) else old_row["status"]) == "canonical"
        )
        try:
            zettel_stat = zettel_path.stat()
            zettel_size = zettel_stat.st_size
            zettel_mtime_ns = zettel_stat.st_mtime_ns
        except OSError:
            zettel_size = 0
            zettel_mtime_ns = 0
        draft_creation = frontmatter.get("draft_creation") if isinstance(frontmatter.get("draft_creation"), dict) else {}
        approved_body_sha256 = draft_creation.get("approved_body_sha256")
        if not isinstance(approved_body_sha256, str) or not SHA256_RE.match(approved_body_sha256):
            approved_body_sha256 = None
        full_text = "---\n" + dump_yaml(frontmatter) + "---\n" + body
        conn.execute(
            """
            INSERT OR REPLACE INTO zettels(
              path, zettel_id, title, status, kind, body, frontmatter_json,
              file_size, file_mtime_ns, body_sha256, approved_body_sha256,
              forbidden_location_reference_found
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                relative,
                zettel_id or None,
                "" if redacted else frontmatter.get("title"),
                zettel_status,
                frontmatter.get("kind"),
                "" if redacted else body,
                "" if redacted else json.dumps(json_safe(frontmatter), ensure_ascii=False, default=str),
                zettel_size,
                zettel_mtime_ns,
                "" if redacted else sha256_text(body),
                "" if redacted else approved_body_sha256,
                1 if (not redacted and contains_forbidden_location_reference(full_text)) else 0,
            ),
        )

        if zettel_id:
            conn.execute("DELETE FROM edges WHERE from_id = ?", (zettel_id,))
            conn.execute("DELETE FROM zettel_facets WHERE zettel_id = ?", (zettel_id,))
            if not redacted:
                for ref in collect_referenced_zets(frontmatter):
                    conn.execute(
                        "INSERT INTO edges(from_id, to_id, edge_type) VALUES (?, ?, ?)",
                        (zettel_id, ref["id"], ref.get("edge_type")),
                    )
                facets = frontmatter.get("facets")
                if isinstance(facets, dict):
                    for facet_key, facet_value in facets.items():
                        values = facet_value if isinstance(facet_value, list) else [facet_value]
                        for item in values:
                            if isinstance(item, (str, int, float, bool)):
                                conn.execute(
                                    "INSERT INTO zettel_facets(zettel_id, facet_key, facet_value) VALUES (?, ?, ?)",
                                    (zettel_id, str(facet_key), str(item)),
                                )
        update_archive_index_metadata_for_zettel_upsert(
            conn,
            zettel_path=zettel_path,
            old_is_canonical=old_is_canonical,
            new_is_canonical=relative.startswith("zettels/") and zettel_status == "canonical",
        )
        conn.commit()
    finally:
        conn.close()
    return True


def update_archive_index_metadata_for_zettel_upsert(
    conn: sqlite3.Connection,
    *,
    zettel_path: Path,
    old_is_canonical: bool,
    new_is_canonical: bool,
) -> None:
    metadata = read_archive_index_metadata(conn)
    if not metadata or metadata.get("schema") != INDEX_METADATA_SCHEMA:
        return
    try:
        canonical_count = int(metadata.get("canonical_zettel_count", "0"))
        canonical_max_mtime_ns = int(metadata.get("canonical_max_mtime_ns", "0"))
    except ValueError:
        return
    if old_is_canonical and not new_is_canonical:
        canonical_count = max(0, canonical_count - 1)
    elif new_is_canonical and not old_is_canonical:
        canonical_count += 1
    if new_is_canonical:
        try:
            canonical_max_mtime_ns = max(canonical_max_mtime_ns, zettel_path.stat().st_mtime_ns)
        except OSError:
            pass
    replace_archive_index_metadata(
        conn,
        canonical_zettel_count=canonical_count,
        canonical_max_mtime_ns=canonical_max_mtime_ns,
    )


def view_zets(
    archive_root: Path | str,
    *,
    view_id: str | None = None,
    facets: dict[str, str] | None = None,
    limit: int = 50,
) -> dict[str, Any]:
    """Execute a saved view's facet filters (or ad-hoc facet filters) against the index.

    This makes the filters already written in views/*.yml actually run. Filters are
    ANDed; only `facets.<key>` filters are supported — any other filter key is a
    blocker rather than being silently ignored (a silently-ignored filter would return
    a BROADER set than the view declared). Redacted zettels are never returned.
    """
    root = require_existing_archive_root(archive_root)
    if bool(view_id) == bool(facets):
        raise ArchiveServiceError("Provide exactly one of view_id or facets.")
    db_path = root / INDEX_RELATIVE_PATH
    if not db_path.is_file():
        raise ArchiveServiceError("Archive index is missing. Run archive index first.")
    limit = max(1, min(int(limit), 500))
    blockers: list[str] = []
    resolved_name: str | None = None

    wanted: dict[str, str] = {}
    if facets:
        for raw_key, raw_value in facets.items():
            key = str(raw_key)
            if isinstance(raw_value, list):
                blockers.append(f"view filter value list not supported: facets.{key}")
                continue
            wanted[key] = str(raw_value)
    else:
        view_filters: dict[str, Any] | None = None
        views_root = root / "views"
        if views_root.is_dir():
            for view_path in safe_archive_glob(views_root, "*.yml", root):
                try:
                    doc = load_yaml(view_path.read_text(encoding="utf-8"))
                except Exception:
                    continue
                if not isinstance(doc, dict):
                    continue
                candidates = [doc] + [item for item in doc.get("saved_views") or [] if isinstance(item, dict)]
                for candidate in candidates:
                    if str(candidate.get("id") or "") == view_id:
                        raw_filters = candidate.get("filters")
                        view_filters = raw_filters if isinstance(raw_filters, dict) else {}
                        resolved_name = str(candidate.get("name") or "") or None
                        break
                if view_filters is not None:
                    break
        if view_filters is None:
            raise ArchiveServiceError(f"View not found: {view_id}")
        for raw_key, raw_value in view_filters.items():
            key = str(raw_key)
            if not key.startswith("facets."):
                blockers.append(f"view filter key not supported: {key}")
                continue
            if isinstance(raw_value, list):
                blockers.append(f"view filter value list not supported: {key}")
                continue
            wanted[key.split(".", 1)[1]] = str(raw_value)

    if blockers:
        return {
            "ok": False,
            "view_id": view_id,
            "view_name": resolved_name,
            "filters": wanted,
            "count": 0,
            "zettels": [],
            "blockers": blockers,
            "warnings": [],
        }

    sql = [
        "SELECT zettel_id, title, status, kind, path FROM zettels",
        "WHERE zettel_id IS NOT NULL AND coalesce(status, '') != 'redacted'",
    ]
    params: list[Any] = []
    for key, value in wanted.items():
        sql.append(
            "AND EXISTS (SELECT 1 FROM zettel_facets f WHERE f.zettel_id = zettels.zettel_id"
            " AND f.facet_key = ? AND f.facet_value = ?)"
        )
        params.extend([key, value])
    sql.append("ORDER BY path LIMIT ?")
    params.append(limit)

    conn = connect_archive_index(db_path, row_factory=True)
    try:
        rows = conn.execute(" ".join(sql), params).fetchall()
    finally:
        conn.close()
    zettels = [
        {
            "id": row["zettel_id"],
            "title": row["title"],
            "status": row["status"],
            "kind": row["kind"],
            "path": row["path"],
        }
        for row in rows
    ]
    return {
        "ok": True,
        "view_id": view_id,
        "view_name": resolved_name,
        "filters": wanted,
        "count": len(zettels),
        "zettels": zettels,
        "blockers": [],
        "warnings": [],
    }


def iter_saved_view_definitions(root: Path) -> list[dict[str, Any]]:
    views_root = root / "views"
    if not views_root.is_dir():
        return []
    views: list[dict[str, Any]] = []
    for view_path in safe_archive_glob(views_root, "*.yml", root):
        try:
            doc = load_yaml(view_path.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(doc, dict):
            continue
        candidates = [doc] + [item for item in doc.get("saved_views") or [] if isinstance(item, dict)]
        for candidate in candidates:
            view_id = str(candidate.get("id") or "").strip()
            if not view_id:
                continue
            views.append(
                {
                    "id": view_id,
                    "name": safe_manifest_label(candidate.get("name"), fallback=None),
                    "filters": candidate.get("filters") if isinstance(candidate.get("filters"), dict) else {},
                    "source_path": archive_relative_path(view_path, root),
                    "nested": candidate is not doc,
                }
            )
    return views


def normalize_view_facet_filters(raw_filters: dict[str, Any]) -> tuple[dict[str, str], list[str]]:
    wanted: dict[str, str] = {}
    blockers: list[str] = []
    for raw_key, raw_value in raw_filters.items():
        key = str(raw_key)
        if not key.startswith("facets."):
            blockers.append(f"view filter key not supported: {key}")
            continue
        if isinstance(raw_value, list):
            blockers.append(f"view filter value list not supported: {key}")
            continue
        wanted[key.split(".", 1)[1]] = str(raw_value)
    return wanted, blockers


def count_indexed_zets_for_facets(conn: sqlite3.Connection, facets: dict[str, str]) -> int:
    sql = [
        "SELECT COUNT(*) AS count FROM zettels",
        "WHERE zettel_id IS NOT NULL AND coalesce(status, '') != 'redacted'",
    ]
    params: list[Any] = []
    for key, value in facets.items():
        sql.append(
            "AND EXISTS (SELECT 1 FROM zettel_facets f WHERE f.zettel_id = zettels.zettel_id"
            " AND f.facet_key = ? AND f.facet_value = ?)"
        )
        params.extend([key, value])
    row = conn.execute(" ".join(sql), params).fetchone()
    return int(row["count"] if isinstance(row, sqlite3.Row) else row[0])


def indexed_facet_value_count(conn: sqlite3.Connection, key: str, value: str) -> int:
    row = conn.execute(
        """
        SELECT COUNT(DISTINCT f.zettel_id) AS count
        FROM zettel_facets f
        JOIN zettels z ON z.zettel_id = f.zettel_id
        WHERE coalesce(z.status, '') != 'redacted'
          AND f.facet_key = ?
          AND f.facet_value = ?
        """,
        (key, value),
    ).fetchone()
    return int(row["count"] if isinstance(row, sqlite3.Row) else row[0])


def indexed_facet_distribution(conn: sqlite3.Connection, key: str, *, limit: int) -> dict[str, Any]:
    total_row = conn.execute(
        """
        SELECT COUNT(DISTINCT facet_value) AS count
        FROM zettel_facets f
        JOIN zettels z ON z.zettel_id = f.zettel_id
        WHERE coalesce(z.status, '') != 'redacted'
          AND f.facet_key = ?
        """,
        (key,),
    ).fetchone()
    rows = conn.execute(
        """
        SELECT f.facet_value, COUNT(DISTINCT f.zettel_id) AS count
        FROM zettel_facets f
        JOIN zettels z ON z.zettel_id = f.zettel_id
        WHERE coalesce(z.status, '') != 'redacted'
          AND f.facet_key = ?
        GROUP BY f.facet_value
        ORDER BY count DESC, f.facet_value ASC
        LIMIT ?
        """,
        (key, limit),
    ).fetchall()
    values: list[dict[str, Any]] = []
    for row in rows:
        safe_value = safe_manifest_label(row["facet_value"], fallback="redacted_facet_value")
        values.append({"value": safe_value, "count": int(row["count"])})
    distinct_count = int(total_row["count"] if isinstance(total_row, sqlite3.Row) else total_row[0])
    return {"key": key, "distinct_value_count": distinct_count, "top_values": values}


NAVIGATION_FACET_KEYS = {
    "area",
    "client",
    "collection",
    "course",
    "domain",
    "event",
    "institution",
    "organization",
    "period",
    "person",
    "place",
    "project",
    "record_type",
    "source_category",
    "subject",
    "tag",
    "tags",
    "theme",
    "topic",
    "workstream",
}

INTERNAL_FACET_KEYS = {
    "block_count",
    "contents",
    "database_id",
    "file_count",
    "migration_batch",
    "notion_status",
    "object_count",
    "page_id",
    "raw_export",
}

INTERNAL_FACET_PREFIXES = (
    "_",
    "adapter_",
    "asr_",
    "crawl_",
    "export_",
    "import_",
    "migration_",
    "notion_",
    "ocr_",
    "pipeline_",
    "provider_",
    "raw_",
    "schema_",
    "sync_",
    "tool_",
)


def facet_role_for_key(key: str) -> tuple[str, str]:
    normalized = str(key or "").strip().lower().replace("-", "_")
    if normalized in NAVIGATION_FACET_KEYS:
        return "navigation", "known_navigation_axis"
    if normalized in INTERNAL_FACET_KEYS:
        return "internal", "known_import_or_system_metadata"
    if any(normalized.startswith(prefix) for prefix in INTERNAL_FACET_PREFIXES):
        return "internal", "internal_prefix"
    if normalized.endswith(("_id", "_ids", "_hash", "_sha256", "_path", "_url", "_ref", "_refs")):
        return "internal", "locator_or_machine_reference_suffix"
    return "unknown", "needs_human_axis_review"


def indexed_facet_role_report(conn: sqlite3.Connection, *, used_facet_keys: set[str], limit: int) -> tuple[dict[str, Any], list[dict[str, Any]]]:
    rows = conn.execute(
        """
        SELECT f.facet_key,
               COUNT(DISTINCT f.zettel_id) AS zettel_count,
               COUNT(DISTINCT f.facet_value) AS distinct_value_count
        FROM zettel_facets f
        JOIN zettels z ON z.zettel_id = f.zettel_id
        WHERE coalesce(z.status, '') != 'redacted'
        GROUP BY f.facet_key
        ORDER BY f.facet_key ASC
        """
    ).fetchall()
    roles: list[dict[str, Any]] = []
    counts = {"navigation": 0, "internal": 0, "unknown": 0}
    saved_view_internal_keys: list[str] = []
    saved_view_unknown_keys: list[str] = []
    for row in rows:
        key = str(row["facet_key"])
        role, reason = facet_role_for_key(key)
        counts[role] = counts.get(role, 0) + 1
        used_by_saved_view = key in used_facet_keys
        if used_by_saved_view and role == "internal":
            saved_view_internal_keys.append(key)
        if used_by_saved_view and role == "unknown":
            saved_view_unknown_keys.append(key)
        distribution = indexed_facet_distribution(conn, key, limit=limit)
        roles.append(
            {
                "key": key,
                "role": role,
                "role_reason": reason,
                "used_by_saved_view": used_by_saved_view,
                "indexed_zettel_count": int(row["zettel_count"]),
                "distinct_value_count": int(row["distinct_value_count"]),
                "top_values": distribution["top_values"],
            }
        )
    summary = {
        "indexed_facet_key_count": len(roles),
        "navigation_key_count": counts.get("navigation", 0),
        "internal_key_count": counts.get("internal", 0),
        "unknown_key_count": counts.get("unknown", 0),
        "saved_view_filter_key_count": len(used_facet_keys),
        "saved_view_internal_filter_keys": sorted(saved_view_internal_keys),
        "saved_view_unknown_filter_keys": sorted(saved_view_unknown_keys),
        "classification_basis": "static_key_heuristics_no_body_read",
    }
    return summary, roles


def view_health(
    archive_root: Path | str,
    *,
    dry_run: bool = True,
    max_values: int = 10,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []
    if not dry_run:
        blockers.append("view-health is read-only; pass --dry-run.")
    db_path = root / INDEX_RELATIVE_PATH
    if not db_path.is_file():
        blockers.append("archive_index_missing")
    views = iter_saved_view_definitions(root)
    if not views:
        warnings.append("no_saved_views_found")

    max_values = max(1, min(int(max_values), 50))
    view_results: list[dict[str, Any]] = []
    used_facet_keys: set[str] = set()
    summary = {
        "saved_view_count": len(views),
        "active_view_count": 0,
        "empty_view_count": 0,
        "blocked_view_count": 0,
    }
    facet_distribution: list[dict[str, Any]] = []
    facet_role_summary: dict[str, Any] = {
        "indexed_facet_key_count": 0,
        "navigation_key_count": 0,
        "internal_key_count": 0,
        "unknown_key_count": 0,
        "saved_view_filter_key_count": 0,
        "saved_view_internal_filter_keys": [],
        "saved_view_unknown_filter_keys": [],
        "classification_basis": "static_key_heuristics_no_body_read",
    }
    facet_roles: list[dict[str, Any]] = []

    if blockers:
        for view in views:
            normalized_filters, view_blockers = normalize_view_facet_filters(view.get("filters") if isinstance(view.get("filters"), dict) else {})
            used_facet_keys.update(normalized_filters)
            view_results.append(
                {
                    "id": view.get("id"),
                    "name": view.get("name"),
                    "source_path": view.get("source_path"),
                    "filters": normalized_filters,
                    "state": "blocked",
                    "count": 0,
                    "filter_diagnostics": [],
                    "blockers": unique_preserve_order(view_blockers + blockers),
                    "warnings": [],
                }
            )
        summary["blocked_view_count"] = len(view_results)
    else:
        conn = connect_archive_index(db_path, row_factory=True)
        try:
            for view in views:
                normalized_filters, view_blockers = normalize_view_facet_filters(
                    view.get("filters") if isinstance(view.get("filters"), dict) else {}
                )
                used_facet_keys.update(normalized_filters)
                filter_diagnostics: list[dict[str, Any]] = []
                for key, value in normalized_filters.items():
                    filter_diagnostics.append(
                        {
                            "facet_key": key,
                            "filter_value": safe_manifest_label(value, fallback="redacted_facet_value"),
                            "matching_zettel_count": indexed_facet_value_count(conn, key, value),
                            "observed_values": indexed_facet_distribution(conn, key, limit=max_values)["top_values"],
                        }
                    )
                count = count_indexed_zets_for_facets(conn, normalized_filters) if not view_blockers else 0
                if view_blockers:
                    state = "blocked"
                    summary["blocked_view_count"] += 1
                elif count == 0:
                    state = "empty_result"
                    summary["empty_view_count"] += 1
                else:
                    state = "active"
                    summary["active_view_count"] += 1
                view_warnings: list[str] = []
                if state == "empty_result":
                    view_warnings.append("saved_view_has_zero_matches")
                view_results.append(
                    {
                        "id": view.get("id"),
                        "name": view.get("name"),
                        "source_path": view.get("source_path"),
                        "filters": normalized_filters,
                        "state": state,
                        "count": count,
                        "filter_diagnostics": filter_diagnostics,
                        "blockers": unique_preserve_order(view_blockers),
                        "warnings": view_warnings,
                    }
                )
            for key in sorted(used_facet_keys):
                facet_distribution.append(indexed_facet_distribution(conn, key, limit=max_values))
            facet_role_summary, facet_roles = indexed_facet_role_report(
                conn,
                used_facet_keys=used_facet_keys,
                limit=max_values,
            )
        finally:
            conn.close()

    if blockers and used_facet_keys:
        saved_view_internal_keys: list[str] = []
        saved_view_unknown_keys: list[str] = []
        for key in sorted(used_facet_keys):
            role, _reason = facet_role_for_key(key)
            if role == "internal":
                saved_view_internal_keys.append(key)
            if role == "unknown":
                saved_view_unknown_keys.append(key)
        facet_role_summary["saved_view_filter_key_count"] = len(used_facet_keys)
        facet_role_summary["saved_view_internal_filter_keys"] = saved_view_internal_keys
        facet_role_summary["saved_view_unknown_filter_keys"] = saved_view_unknown_keys

    next_safe_actions: list[str] = []
    if "archive_index_missing" in blockers:
        next_safe_actions.append("Run archive index before checking saved view health.")
    else:
        if summary["blocked_view_count"]:
            next_safe_actions.append("Fix unsupported saved view filters before relying on those views.")
        if summary["empty_view_count"]:
            next_safe_actions.append("Review empty saved views against observed facet distributions before changing view filters.")
        if facet_role_summary.get("saved_view_internal_filter_keys") or facet_role_summary.get("saved_view_unknown_filter_keys"):
            next_safe_actions.append("Review saved views that filter on internal or unknown facet keys before relying on them for AI navigation.")
        elif facet_role_summary.get("internal_key_count") or facet_role_summary.get("unknown_key_count"):
            next_safe_actions.append("Prefer navigation facet keys when creating AI navigation views; review internal and unknown keys before adding filters.")
        if not next_safe_actions:
            next_safe_actions.append("Saved views have matching indexed zets.")

    return {
        "ok": not blockers and summary["blocked_view_count"] == 0,
        "dry_run": True,
        "lifecycle_action": "view_health",
        "archive_id": archive_id,
        "index_path": INDEX_RELATIVE_PATH,
        "summary": summary,
        "views": view_results,
        "facet_distribution": facet_distribution,
        "facet_role_summary": facet_role_summary,
        "facet_roles": facet_roles,
        "privacy_guards": {
            "zettel_body_text_echoed": False,
            "zettel_titles_echoed": False,
            "absolute_local_paths_echoed": False,
            "provider_urls_echoed": False,
            "provider_api_called": False,
            "object_file_bytes_read": False,
            "writes": False,
        },
        "would_change": [],
        "next_safe_actions": unique_preserve_order(next_safe_actions),
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }


def safe_view_id_segment(value: Any, *, max_chars: int = 48) -> str:
    text = str(value or "").strip().lower()
    slug = re.sub(r"[^a-z0-9]+", "_", text).strip("_")
    if slug:
        return slug[:max_chars].strip("_") or slug[:max_chars]
    digest = hashlib.sha256(text.encode("utf-8")).hexdigest()[:8]
    return f"value_{digest}"


def view_recommendation_plan(
    archive_root: Path | str,
    *,
    dry_run: bool = True,
    max_values: int = 5,
    max_recommendations: int = 12,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []
    if not dry_run:
        blockers.append("view-recommendation-plan is read-only; pass --dry-run.")

    max_values = max(1, min(int(max_values), 20))
    max_recommendations = max(1, min(int(max_recommendations), 100))
    health = view_health(root, dry_run=True, max_values=max_values)
    blockers.extend(health.get("blockers") if isinstance(health.get("blockers"), list) else [])
    warnings.extend(health.get("warnings") if isinstance(health.get("warnings"), list) else [])

    existing_pairs: set[tuple[str, str]] = set()
    views = health.get("views") if isinstance(health.get("views"), list) else []
    for view in views:
        if not isinstance(view, dict):
            continue
        filters = view.get("filters") if isinstance(view.get("filters"), dict) else {}
        for key, value in filters.items():
            existing_pairs.add((str(key), str(value)))

    recommendations: list[dict[str, Any]] = []
    facet_roles = health.get("facet_roles") if isinstance(health.get("facet_roles"), list) else []
    if not blockers:
        for role_entry in facet_roles:
            if not isinstance(role_entry, dict) or role_entry.get("role") != "navigation":
                continue
            key = str(role_entry.get("key") or "").strip()
            if not key:
                continue
            top_values = role_entry.get("top_values") if isinstance(role_entry.get("top_values"), list) else []
            for value_entry in top_values[:max_values]:
                if not isinstance(value_entry, dict):
                    continue
                value = str(value_entry.get("value") or "").strip()
                if not value or value == "redacted_facet_value":
                    continue
                match_count = int(value_entry.get("count") or 0)
                if match_count <= 0:
                    continue
                already_used = (key, value) in existing_pairs
                recommendations.append(
                    {
                        "recommendation_kind": "single_navigation_facet_view",
                        "facet_key": key,
                        "facet_value": value,
                        "match_count": match_count,
                        "already_used_by_saved_view_filter": already_used,
                        "view_id_suggestion": (
                            f"view.ai.{safe_view_id_segment(key, max_chars=24)}."
                            f"{safe_view_id_segment(value, max_chars=40)}"
                        ),
                        "name_suggestion": f"AI navigation: {key} = {value}",
                        "filters": {f"facets.{key}": value},
                        "role_reason": role_entry.get("role_reason"),
                    }
                )

    recommendations.sort(
        key=lambda item: (
            -int(item.get("match_count") or 0),
            str(item.get("facet_key") or ""),
            str(item.get("facet_value") or ""),
        )
    )
    recommendations_truncated = len(recommendations) > max_recommendations
    recommendations = recommendations[:max_recommendations]
    if recommendations_truncated:
        warnings.append("view_recommendation_plan_truncated")

    health_summary = health.get("summary") if isinstance(health.get("summary"), dict) else {}
    facet_role_summary = health.get("facet_role_summary") if isinstance(health.get("facet_role_summary"), dict) else {}
    next_safe_actions: list[str] = []
    if "archive_index_missing" in blockers:
        next_safe_actions.append("Run archive index before planning saved view recommendations.")
    elif recommendations:
        next_safe_actions.append("Review suggested filters against the human archive purpose before editing views/*.yml.")
        next_safe_actions.append("After a reviewed view edit, run archive index and view-health again.")
    elif facet_role_summary.get("navigation_key_count", 0):
        next_safe_actions.append("No non-empty navigation facet values were available for saved view recommendations.")
    else:
        next_safe_actions.append("Add or review navigation facets before creating AI navigation saved views.")

    return {
        "ok": not blockers,
        "dry_run": True,
        "lifecycle_action": "view_recommendation_plan",
        "archive_id": archive_id,
        "index_path": INDEX_RELATIVE_PATH,
        "summary": {
            "saved_view_count": health_summary.get("saved_view_count", 0),
            "active_view_count": health_summary.get("active_view_count", 0),
            "empty_view_count": health_summary.get("empty_view_count", 0),
            "blocked_view_count": health_summary.get("blocked_view_count", 0),
            "navigation_key_count": facet_role_summary.get("navigation_key_count", 0),
            "internal_key_count": facet_role_summary.get("internal_key_count", 0),
            "unknown_key_count": facet_role_summary.get("unknown_key_count", 0),
            "recommendation_count": len(recommendations),
            "recommendations_truncated": recommendations_truncated,
            "classification_basis": facet_role_summary.get("classification_basis", "static_key_heuristics_no_body_read"),
        },
        "recommendations": recommendations,
        "privacy_guards": {
            "zettel_body_text_echoed": False,
            "zettel_titles_echoed": False,
            "absolute_local_paths_echoed": False,
            "provider_urls_echoed": False,
            "provider_api_called": False,
            "object_file_bytes_read": False,
            "view_files_written": False,
            "index_rebuilt": False,
            "writes": False,
        },
        "would_change": [],
        "next_safe_actions": unique_preserve_order(next_safe_actions),
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }


def live_zettel_index_entries(root: Path, *, db_mtime: float | None = None) -> list[dict[str, Any]]:
    entries: list[dict[str, Any]] = []
    for path in iter_zettel_paths(root):
        try:
            text = path.read_text(encoding="utf-8")
            frontmatter, _body = split_zettel_text(text)
            stat = path.stat()
        except (OSError, UnicodeError, ArchiveServiceError):
            continue
        relative = archive_relative_path(path, root)
        entries.append(
            {
                "path": relative,
                "zettel_id": str(frontmatter.get("id") or ""),
                "status": str(frontmatter.get("status") or ""),
                "kind": str(frontmatter.get("kind") or ""),
                "modified_after_index": bool(db_mtime is not None and stat.st_mtime > db_mtime),
            }
        )
    return entries


def index_health(
    archive_root: Path | str,
    *,
    dry_run: bool = True,
    max_items: int = 50,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []
    if not dry_run:
        blockers.append("index-health is read-only; pass --dry-run.")
    db_path = root / INDEX_RELATIVE_PATH
    if not db_path.is_file():
        blockers.append("archive_index_missing")

    max_items = max(1, min(int(max_items), 500))
    db_mtime = db_path.stat().st_mtime if db_path.is_file() else None
    live_entries = live_zettel_index_entries(root, db_mtime=db_mtime)
    live_by_path = {entry["path"]: entry for entry in live_entries}
    indexed_entries: list[dict[str, Any]] = []

    if db_path.is_file():
        conn = connect_archive_index(db_path, row_factory=True)
        try:
            indexed_entries = [
                {
                    "path": row["path"],
                    "zettel_id": row["zettel_id"],
                    "status": row["status"],
                    "kind": row["kind"],
                }
                for row in conn.execute("SELECT path, zettel_id, status, kind FROM zettels ORDER BY path").fetchall()
            ]
        finally:
            conn.close()
    indexed_by_path = {str(entry.get("path") or ""): entry for entry in indexed_entries}

    live_paths = set(live_by_path)
    indexed_paths = set(indexed_by_path)
    missing_from_index = sorted(live_paths - indexed_paths)
    extra_in_index = sorted(indexed_paths - live_paths)
    changed_metadata: list[dict[str, Any]] = []
    for path in sorted(live_paths & indexed_paths):
        live = live_by_path[path]
        indexed = indexed_by_path[path]
        changed_fields = [
            field
            for field in ("zettel_id", "status", "kind")
            if str(live.get(field) or "") != str(indexed.get(field) or "")
        ]
        if changed_fields:
            changed_metadata.append({"path": path, "changed_fields": changed_fields})
    modified_after_index = sorted(entry["path"] for entry in live_entries if entry.get("modified_after_index"))

    stale_reasons: list[str] = []
    if missing_from_index:
        stale_reasons.append("live_zettels_missing_from_index")
    if extra_in_index:
        stale_reasons.append("index_has_paths_missing_from_live_zettels")
    if changed_metadata:
        stale_reasons.append("indexed_zettel_metadata_differs_from_live_frontmatter")
    if modified_after_index:
        stale_reasons.append("live_zettel_modified_after_index")
    if blockers:
        stale_reasons.append("index_health_blocked")

    index_state = "blocked" if blockers else ("stale_or_incomplete" if stale_reasons else "current")
    next_safe_actions: list[str] = []
    if "archive_index_missing" in blockers:
        next_safe_actions.append("Run archive index before view-zets, related-zets, search, or view-health.")
    elif stale_reasons:
        next_safe_actions.append("Run archive index to rebuild the generated local SQLite index from current archive files.")
    else:
        next_safe_actions.append("Generated index matches the live zettel path/id/status/kind snapshot checked here.")

    return {
        "ok": not blockers and not stale_reasons,
        "dry_run": True,
        "lifecycle_action": "index_health",
        "archive_id": archive_id,
        "index_path": INDEX_RELATIVE_PATH,
        "index_state": index_state,
        "summary": {
            "live_zettel_count": len(live_entries),
            "indexed_zettel_count": len(indexed_entries),
            "missing_from_index_count": len(missing_from_index),
            "extra_in_index_count": len(extra_in_index),
            "changed_metadata_count": len(changed_metadata),
            "modified_after_index_count": len(modified_after_index),
        },
        "samples": {
            "missing_from_index": missing_from_index[:max_items],
            "extra_in_index": extra_in_index[:max_items],
            "changed_metadata": changed_metadata[:max_items],
            "modified_after_index": modified_after_index[:max_items],
            "truncated": any(
                len(items) > max_items
                for items in (missing_from_index, extra_in_index, changed_metadata, modified_after_index)
            ),
        },
        "stale_reasons": unique_preserve_order(stale_reasons),
        "privacy_guards": {
            "zettel_body_text_echoed": False,
            "zettel_titles_echoed": False,
            "absolute_local_paths_echoed": False,
            "provider_urls_echoed": False,
            "provider_api_called": False,
            "object_file_bytes_read": False,
            "writes": False,
        },
        "would_change": [],
        "next_safe_actions": unique_preserve_order(next_safe_actions),
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings),
    }


def get_related_zets(
    archive_root: Path | str,
    zettel_id: str,
    *,
    depth: int = 1,
    edge_types: list[str] | None = None,
    limit: int = 100,
) -> dict[str, Any]:
    """Bidirectional related-zet retrieval over the indexed typed edges.

    Backlinks are the point: "what supersedes / derives-from / references THIS zet" is
    answered by the reverse direction, which raw frontmatter (forward refs only) cannot do.
    Redaction floor: a redacted zettel is never returned as a neighbor, and its outgoing
    edges were never indexed.
    """
    root = require_existing_archive_root(archive_root)
    zettel_id = str(zettel_id or "").strip()
    if not zettel_id.startswith("zet_"):
        raise ArchiveServiceError("zettel_id must be a zet_ id.")
    db_path = root / INDEX_RELATIVE_PATH
    if not db_path.is_file():
        raise ArchiveServiceError("Archive index is missing. Run archive index first.")
    depth = max(1, min(int(depth), 3))
    limit = max(1, min(int(limit), 500))
    wanted_types = {str(value) for value in edge_types} if edge_types else None

    related: list[dict[str, Any]] = []
    visited: set[str] = {zettel_id}
    frontier: set[str] = {zettel_id}
    conn = connect_archive_index(db_path, row_factory=True)
    try:
        # Parity with read_zettel/block_header_preview: a redacted zettel is not a valid
        # query subject; return an empty related set rather than exposing its neighborhood.
        subject = conn.execute(
            "SELECT status FROM zettels WHERE zettel_id = ?", (zettel_id,)
        ).fetchone()
        if subject is not None and (subject["status"] or "") == "redacted":
            return {"zettel_id": zettel_id, "depth": depth, "count": 0, "related": [], "truncated": False}
        for hop in range(1, depth + 1):
            next_frontier: set[str] = set()
            for current in sorted(frontier):
                rows = conn.execute(
                    """
                    SELECT to_id AS other, edge_type, 'out' AS direction FROM edges WHERE from_id = ?
                    UNION ALL
                    SELECT from_id AS other, edge_type, 'in' AS direction FROM edges WHERE to_id = ?
                    ORDER BY other, direction
                    """,
                    (current, current),
                ).fetchall()
                for row in rows:
                    other = str(row["other"] or "")
                    if not other or other in visited:
                        continue
                    if wanted_types is not None and (row["edge_type"] or "") not in wanted_types:
                        continue
                    zettel_row = conn.execute(
                        "SELECT title, status, kind, path FROM zettels WHERE zettel_id = ?",
                        (other,),
                    ).fetchone()
                    if zettel_row is not None and (zettel_row["status"] or "") == "redacted":
                        # Privacy floor: traversal must never walk into a redacted zettel.
                        visited.add(other)
                        continue
                    visited.add(other)
                    next_frontier.add(other)
                    related.append(
                        {
                            "id": other,
                            "edge_type": row["edge_type"],
                            "direction": row["direction"],
                            "hop": hop,
                            "via": current if hop > 1 else None,
                            "exists": zettel_row is not None,
                            "title": zettel_row["title"] if zettel_row is not None else None,
                            "status": zettel_row["status"] if zettel_row is not None else None,
                            "kind": zettel_row["kind"] if zettel_row is not None else None,
                            "path": zettel_row["path"] if zettel_row is not None else None,
                        }
                    )
                    if len(related) > limit:
                        # Collected one past the limit only to KNOW more exists; drop it and
                        # report truncated. Hitting exactly `limit` with nothing left is NOT
                        # truncation (off-by-one fix).
                        related.pop()
                        return {"zettel_id": zettel_id, "depth": depth, "count": len(related), "related": related, "truncated": True}
            frontier = next_frontier
            if not frontier:
                break
    finally:
        conn.close()
    return {"zettel_id": zettel_id, "depth": depth, "count": len(related), "related": related, "truncated": False}


def search_archive(archive_root: Path | str, query: str, limit: int = 20) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    if not query.strip():
        raise ArchiveServiceError("query is required.")
    db_path = root / INDEX_RELATIVE_PATH
    if not db_path.is_file():
        raise ArchiveServiceError("Archive index is missing. Run archive index first.")

    like = f"%{query.lower()}%"
    limit = max(1, min(int(limit), 100))
    results: list[dict[str, Any]] = []
    conn = connect_archive_index(db_path, row_factory=True)
    try:
        for row in conn.execute(
            """
            SELECT path, zettel_id, title, status, kind, body, frontmatter_json
            FROM zettels
            -- Privacy: a 'redacted' zettel's content is deliberately suppressed; it must never be
            -- matched on or surfaced (body/frontmatter) by search. draft/canonical/archived stay searchable.
            WHERE coalesce(status, '') != 'redacted'
              AND lower(coalesce(zettel_id, '') || ' ' || coalesce(title, '') || ' ' || coalesce(status, '') || ' ' ||
                        coalesce(kind, '') || ' ' || coalesce(body, '') || ' ' || coalesce(frontmatter_json, '')) LIKE ?
            ORDER BY path
            LIMIT ?
            """,
            (like, limit),
        ):
            if (row["status"] or "") == "redacted":
                # Defense in depth: redacted zettels are already excluded in SQL above; this guard
                # guarantees their body can never be emitted even if the query is later modified.
                continue
            results.append(
                {
                    "type": "zettel",
                    "path": row["path"],
                    "id": row["zettel_id"],
                    "title": row["title"],
                    "status": row["status"],
                    "kind": row["kind"],
                    "snippet": make_snippet(row["body"] or row["frontmatter_json"] or "", query),
                }
            )

        remaining = limit - len(results)
        if remaining > 0:
            for row in conn.execute(
                """
                SELECT object_id, logical_key, mime, manifest_json
                FROM objects
                WHERE lower(coalesce(object_id, '') || ' ' || coalesce(logical_key, '') || ' ' ||
                            coalesce(mime, '') || ' ' || coalesce(manifest_json, '')) LIKE ?
                ORDER BY logical_key
                LIMIT ?
                """,
                (like, remaining),
            ):
                results.append(
                    {
                        "type": "object",
                        "path": row["logical_key"],
                        "id": row["object_id"],
                        "title": row["logical_key"],
                        "mime": row["mime"],
                        "snippet": make_snippet(row["manifest_json"] or "", query),
                    }
                )

        remaining = limit - len(results)
        if remaining > 0:
            for row in conn.execute(
                """
                SELECT derived_text_id, source_object_id, derivation_kind, review_status,
                       language, text_logical_key, text_body, manifest_json
                FROM derived_texts
                WHERE lower(coalesce(derived_text_id, '') || ' ' || coalesce(source_object_id, '') || ' ' ||
                            coalesce(derivation_kind, '') || ' ' || coalesce(review_status, '') || ' ' ||
                            coalesce(language, '') || ' ' || coalesce(text_logical_key, '') || ' ' ||
                            coalesce(text_body, '') || ' ' || coalesce(manifest_json, '')) LIKE ?
                ORDER BY text_logical_key
                LIMIT ?
                """,
                (like, remaining),
            ):
                results.append(
                    {
                        "type": "derived_text",
                        "path": row["text_logical_key"],
                        "id": row["derived_text_id"],
                        "title": row["source_object_id"],
                        "source_object_id": row["source_object_id"],
                        "derivation_kind": row["derivation_kind"],
                        "review_status": row["review_status"],
                        "language": row["language"],
                        "snippet": make_snippet(row["text_body"] or row["manifest_json"] or "", query),
                    }
                )

        remaining = limit - len(results)
        if remaining > 0:
            for row in conn.execute(
                """
                SELECT path, view_id, name, view_for, view_json
                FROM views
                WHERE lower(coalesce(view_id, '') || ' ' || coalesce(name, '') || ' ' ||
                            coalesce(view_for, '') || ' ' || coalesce(view_json, '')) LIKE ?
                ORDER BY path
                LIMIT ?
                """,
                (like, remaining),
            ):
                results.append(
                    {
                        "type": "view",
                        "path": row["path"],
                        "id": row["view_id"],
                        "title": row["name"],
                        "for": row["view_for"],
                        "snippet": make_snippet(row["view_json"] or "", query),
                    }
                )

        remaining = limit - len(results)
        if remaining > 0:
            for row in conn.execute(
                """
                SELECT item_id, source_id, item_kind, relative_path, external_url, scan_status, source_json
                FROM source_map_entries
                WHERE lower(coalesce(item_id, '') || ' ' || coalesce(source_id, '') || ' ' ||
                            coalesce(item_kind, '') || ' ' || coalesce(relative_path, '') || ' ' ||
                            coalesce(external_url, '') || ' ' || coalesce(scan_status, '') || ' ' ||
                            coalesce(source_json, '')) LIKE ?
                ORDER BY source_id, relative_path, external_url
                LIMIT ?
                """,
                (like, remaining),
            ):
                title = row["relative_path"] or row["external_url"] or row["item_id"]
                results.append(
                    {
                        "type": "source_map",
                        "path": row["relative_path"] or row["external_url"],
                        "id": row["item_id"],
                        "title": title,
                        "source_id": row["source_id"],
                        "item_kind": row["item_kind"],
                        "scan_status": row["scan_status"],
                        "snippet": make_snippet(row["source_json"] or "", query),
                    }
                )
    finally:
        conn.close()

    return {"query": query, "count": len(results), "results": results}


def iter_zettel_paths(archive_root: Path) -> list[Path]:
    archive_root = archive_root.resolve()
    paths: list[Path] = []
    for folder in ["zettels", "inbox"]:
        root = archive_root / folder
        if root.is_dir():
            paths.extend(safe_archive_glob(root, "*.md", archive_root, recursive=True))
    return paths


def safe_archive_glob(root: Path, pattern: str, archive_root: Path, *, recursive: bool = False) -> list[Path]:
    """Return matching files whose resolved target stays inside the archive root."""

    iterator = root.rglob(pattern) if recursive else root.glob(pattern)
    return sorted(path for path in iterator if path.is_file() and is_path_within_root(path, archive_root))


def make_snippet(text: str, query: str, size: int = 160) -> str:
    compact = " ".join(text.split())
    index = compact.lower().find(query.lower())
    if index < 0:
        return compact[:size]
    start = max(0, index - size // 3)
    end = min(len(compact), start + size)
    return compact[start:end]


def read_archive_id(archive_root: Path) -> str:
    data = read_archive_config(archive_root)
    if not isinstance(data.get("archive_id"), str):
        raise ArchiveServiceError("archive.yml does not contain archive_id and archive_id was not provided.")
    return data["archive_id"]


def read_archive_config(archive_root: Path) -> dict[str, Any]:
    data = load_yaml(read_archive_text(archive_root, "archive.yml"))
    if not isinstance(data, dict):
        raise ArchiveServiceError("archive.yml is not a readable object.")
    return data


def migrate_archive(
    archive_root: Path | str,
    *,
    target: str,
    dry_run: bool,
    approve: bool,
    revert: bool = False,
) -> dict[str, Any]:
    if target == FRONTMATTER_V03_TARGET:
        if revert:
            return migrate_frontmatter_v03_revert(archive_root, target=target, dry_run=dry_run, approve=approve)
        return migrate_frontmatter_v03(archive_root, target=target, dry_run=dry_run, approve=approve)
    if target == LINK_TYPES_V03_TARGET:
        if revert:
            return migrate_link_types_v03_revert(archive_root, target=target, dry_run=dry_run, approve=approve)
        return migrate_link_types_v03(archive_root, target=target, dry_run=dry_run, approve=approve)
    raise ArchiveServiceError(f"Unsupported migration target: {target}")


def migration_receipt_relative_path(target: str, seed: dict[str, Any]) -> str:
    digest = sha256_json_hex(seed)
    target_segment = zettel_edge_filename_segment(target)
    return f"{MIGRATION_RECEIPTS_DIR}/{target_segment}.{digest[:24]}.migration.json"


def migration_revert_receipt_relative_path(target: str, source_receipt_relative: str) -> str:
    digest = sha256_json_hex({"target": target, "source_receipt_path": source_receipt_relative})
    target_segment = zettel_edge_filename_segment(target)
    return f"{MIGRATION_REVERT_RECEIPTS_DIR}/{target_segment}.{digest[:24]}.migration-revert.json"


def latest_migration_receipt(root: Path, target: str, blockers: list[dict[str, Any]]) -> tuple[dict[str, Any] | None, str | None]:
    receipts_root = archive_internal_path(root, MIGRATION_RECEIPTS_DIR)
    if not receipts_root.is_dir():
        blockers.append(
            {
                "path": MIGRATION_RECEIPTS_DIR,
                "field": "receipt",
                "code": "migration_receipt_required",
                "message": f"{target} revert requires a prior migration receipt.",
            }
        )
        return None, None
    target_segment = zettel_edge_filename_segment(target)
    candidates = sorted(receipts_root.glob(f"{target_segment}.*.migration.json"))
    if not candidates:
        blockers.append(
            {
                "path": MIGRATION_RECEIPTS_DIR,
                "field": "receipt",
                "code": "migration_receipt_required",
                "message": f"{target} revert requires a prior migration receipt.",
            }
        )
        return None, None
    for path in reversed(candidates):
        receipt_doc = load_json_object_for_review(path, "migration receipt", [])
        if receipt_doc is not None and receipt_doc.get("target") == target and receipt_doc.get("receipt_kind") == "migration_write":
            return receipt_doc, archive_relative_path(path, root)
    blockers.append(
        {
            "path": MIGRATION_RECEIPTS_DIR,
            "field": "receipt",
            "code": "migration_receipt_required",
            "message": f"{target} revert requires a valid prior migration receipt.",
        }
    )
    return None, None


def migrate_link_types_v03(
    archive_root: Path | str,
    *,
    target: str,
    dry_run: bool,
    approve: bool,
) -> dict[str, Any]:
    if target != LINK_TYPES_V03_TARGET:
        raise ArchiveServiceError(f"Unsupported migration target: {target}")
    if dry_run == approve:
        raise ArchiveServiceError("archive migrate requires exactly one of --dry-run or --approve.")

    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    types_relative = "zettel-kasten/types.yml"
    types_path = archive_internal_path(root, types_relative)
    if not types_path.is_file():
        raise ArchiveServiceError("zettel-kasten/types.yml is missing; initialize or restore archive type metadata first.")

    archive_types = load_yaml(types_path.read_text(encoding="utf-8"))
    base_types = load_yaml((KIT_ROOT / "zettel-kasten" / "types.yml").read_text(encoding="utf-8"))
    if not isinstance(archive_types, dict) or not isinstance(archive_types.get("link_types"), list):
        raise ArchiveServiceError("zettel-kasten/types.yml must be a YAML object with link_types.")
    if not isinstance(base_types, dict) or not isinstance(base_types.get("link_types"), list):
        raise ArchiveServiceError("Base zettel-kasten/types.yml must be a YAML object with link_types.")

    archive_link_types = archive_types["link_types"]
    present_ids = {
        item.get("id")
        for item in archive_link_types
        if isinstance(item, dict) and isinstance(item.get("id"), str) and item.get("id")
    }
    base_by_id = {
        item.get("id"): item
        for item in base_types["link_types"]
        if isinstance(item, dict) and isinstance(item.get("id"), str) and item.get("id")
    }
    recommended = sorted(CONNECTION_IMPORT_RECOMMENDED_EDGE_TYPES)
    missing = [edge_type for edge_type in recommended if edge_type not in present_ids]
    missing_records = [copy.deepcopy(base_by_id[edge_type]) for edge_type in missing if edge_type in base_by_id]
    missing_without_base = [edge_type for edge_type in missing if edge_type not in base_by_id]
    blockers = [
        {
            "path": types_relative,
            "field": "link_types",
            "code": "missing_base_link_type",
            "message": f"Base template does not define recommended edge type: {edge_type}",
        }
        for edge_type in missing_without_base
    ]

    files_written: list[str] = []
    original_text = types_path.read_text(encoding="utf-8")
    new_text = original_text
    receipt_relative: str | None = None
    if missing_records and not blockers:
        new_types = copy.deepcopy(archive_types)
        new_link_types = copy.deepcopy(archive_link_types)
        new_link_types.extend(missing_records)
        new_types["link_types"] = new_link_types
        new_types.setdefault("schema_version", archive_types.get("schema_version") or "wom-kit/zettel-kasten-types/v0.2-draft")
        new_text = dump_yaml(new_types)
        receipt_relative = migration_receipt_relative_path(
            target,
            {
                "archive_id": archive_id,
                "target": target,
                "appended_link_type_ids": missing,
                "before_sha256": sha256_text(original_text),
                "after_sha256": sha256_text(new_text),
            },
        )
        receipt_path = archive_internal_path(root, receipt_relative)
        if receipt_path.exists():
            blockers.append(
                {
                    "path": receipt_relative,
                    "field": "receipt",
                    "code": "migration_receipt_exists",
                    "message": "Link type migration receipt already exists.",
                }
            )
        if approve:
            now = datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace("+00:00", "Z")
            receipt = {
                "schema_version": "wom-kit/migration-receipt/v0.1",
                "lifecycle_action": "link_types_v03_migration",
                "receipt_kind": "migration_write",
                "created_at": now,
                "archive_id": archive_id,
                "target": LINK_TYPES_V03_TARGET,
                "migration_direction": "forward",
                "files_changed": [types_relative],
                "appended_link_type_ids": missing,
                "before_sha256": sha256_text(original_text),
                "after_sha256": sha256_text(new_text),
                "result": {
                    "types_file_written": True,
                    "receipt_written": True,
                },
                "closed_actions": {
                    "provider_api_called": False,
                    "real_source_export_files_read": False,
                    "zettel_files_written": False,
                    "edge_receipts_deleted": False,
                },
            }
            try:
                write_text_atomic(types_path, new_text)
                files_written.append(types_relative)
                receipt_path.parent.mkdir(parents=True, exist_ok=True)
                write_json_new_file(receipt_path, receipt)
                files_written.append(receipt_relative)
            except OSError:
                write_text_atomic(types_path, original_text)
                if receipt_path.exists():
                    try:
                        receipt_path.unlink()
                    except OSError:
                        pass
                raise

    changes = [
        {
            "action": "append_link_type",
            "field": "link_types",
            "id": item.get("id"),
            "source": "wom-kit/zettel-kasten/types.yml",
        }
        for item in missing_records
    ]
    return {
        "ok": not blockers,
        "lifecycle_action": "link_types_v03_migration",
        "target": LINK_TYPES_V03_TARGET,
        "dry_run": bool(dry_run),
        "approved": bool(approve),
        "archive_id": archive_id,
        "files_scanned": 1,
        "files_with_changes": 1 if changes else 0,
        "files_written": files_written,
        "blocked": bool(blockers),
        "blockers": blockers,
        "warnings": [],
        "archive_link_type_status": {
            "source": types_relative,
            "recommended_edge_types": recommended,
            "present_recommended_edge_types": sorted(edge_type for edge_type in recommended if edge_type in present_ids),
            "missing_recommended_edge_types": missing,
        },
        "receipt_path": receipt_relative,
        "would_change": [
            {
                "path": types_relative,
                "changes": changes
                + (
                    [
                        {
                            "action": "write_receipt",
                            "field": "receipt",
                            "path": receipt_relative,
                        }
                    ]
                    if receipt_relative
                    else []
                ),
                "manual_review_required": bool(blockers),
                "blockers": blockers,
            }
        ]
        if changes or blockers
        else [],
        "new_text": new_text if dry_run and changes and not blockers else None,
    }


def used_zettel_edge_types(root: Path, candidate_types: set[str]) -> dict[str, list[str]]:
    usage: dict[str, list[str]] = {edge_type: [] for edge_type in candidate_types}
    for path in iter_zettel_paths(root):
        try:
            frontmatter, _body = split_zettel_text(path.read_text(encoding="utf-8"))
        except (OSError, ArchiveServiceError, ValueError):
            continue
        edges = frontmatter.get("edges")
        if not isinstance(edges, list):
            continue
        relative = archive_relative_path(path, root)
        for edge in edges:
            if not isinstance(edge, dict):
                continue
            edge_type = str(edge.get("type") or "").strip()
            if edge_type in candidate_types:
                usage.setdefault(edge_type, []).append(relative)
    return {edge_type: unique_preserve_order(paths) for edge_type, paths in usage.items() if paths}


def migrate_link_types_v03_revert(
    archive_root: Path | str,
    *,
    target: str,
    dry_run: bool,
    approve: bool,
) -> dict[str, Any]:
    if target != LINK_TYPES_V03_TARGET:
        raise ArchiveServiceError(f"Unsupported migration target: {target}")
    if dry_run == approve:
        raise ArchiveServiceError("archive migrate --revert requires exactly one of --dry-run or --approve.")

    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    types_relative = "zettel-kasten/types.yml"
    types_path = archive_internal_path(root, types_relative)
    if not types_path.is_file():
        raise ArchiveServiceError("zettel-kasten/types.yml is missing; initialize or restore archive type metadata first.")

    archive_types = load_yaml(types_path.read_text(encoding="utf-8"))
    base_types = load_yaml((KIT_ROOT / "zettel-kasten" / "types.yml").read_text(encoding="utf-8"))
    if not isinstance(archive_types, dict) or not isinstance(archive_types.get("link_types"), list):
        raise ArchiveServiceError("zettel-kasten/types.yml must be a YAML object with link_types.")
    if not isinstance(base_types, dict) or not isinstance(base_types.get("link_types"), list):
        raise ArchiveServiceError("Base zettel-kasten/types.yml must be a YAML object with link_types.")

    archive_link_types = archive_types["link_types"]
    base_by_id = {
        item.get("id"): item
        for item in base_types["link_types"]
        if isinstance(item, dict) and isinstance(item.get("id"), str) and item.get("id")
    }
    recommended = sorted(CONNECTION_IMPORT_RECOMMENDED_EDGE_TYPES)
    recommended_set = set(recommended)
    blockers: list[dict[str, Any]] = []
    source_receipt, source_receipt_relative = latest_migration_receipt(root, LINK_TYPES_V03_TARGET, blockers)
    appended_ids = []
    if source_receipt is not None:
        if source_receipt.get("schema_version") != "wom-kit/migration-receipt/v0.1":
            blockers.append(
                {
                    "path": source_receipt_relative or MIGRATION_RECEIPTS_DIR,
                    "field": "schema_version",
                    "code": "migration_receipt_invalid",
                    "message": "Migration receipt schema_version must be wom-kit/migration-receipt/v0.1.",
                }
            )
        if source_receipt.get("archive_id") != archive_id:
            blockers.append(
                {
                    "path": source_receipt_relative or MIGRATION_RECEIPTS_DIR,
                    "field": "archive_id",
                    "code": "migration_receipt_archive_mismatch",
                    "message": "Migration receipt archive_id must match this archive.",
                }
            )
        raw_appended_ids = source_receipt.get("appended_link_type_ids")
        if not isinstance(raw_appended_ids, list) or not raw_appended_ids:
            blockers.append(
                {
                    "path": source_receipt_relative or MIGRATION_RECEIPTS_DIR,
                    "field": "appended_link_type_ids",
                    "code": "migration_receipt_invalid",
                    "message": "Migration receipt must list appended link type ids.",
                }
            )
        else:
            appended_ids = [str(item) for item in raw_appended_ids if isinstance(item, str) and item in recommended_set]
    revert_candidate_set = set(appended_ids)
    used_types = used_zettel_edge_types(root, revert_candidate_set)

    removable_ids: list[str] = []
    kept_records: list[dict[str, Any]] = []
    changed_records: list[str] = []
    for item in archive_link_types:
        if not isinstance(item, dict):
            kept_records.append(item)
            continue
        edge_type = item.get("id")
        if not isinstance(edge_type, str) or edge_type not in revert_candidate_set:
            kept_records.append(item)
            continue
        if edge_type in used_types:
            kept_records.append(item)
            blockers.append(
                {
                    "path": types_relative,
                    "field": "link_types",
                    "code": "link_type_in_use",
                    "id": edge_type,
                    "message": f"Cannot revert link type while existing zettel edges use it: {edge_type}",
                    "used_in": used_types[edge_type],
                }
            )
            continue
        if json_safe(item) != json_safe(base_by_id.get(edge_type)):
            kept_records.append(item)
            changed_records.append(edge_type)
            blockers.append(
                {
                    "path": types_relative,
                    "field": "link_types",
                    "code": "link_type_record_changed",
                    "id": edge_type,
                    "message": f"Cannot safely revert modified link type record: {edge_type}",
                }
            )
            continue
        removable_ids.append(edge_type)

    changes = [
        {
            "action": "remove_link_type",
            "field": "link_types",
            "id": edge_type,
            "source": types_relative,
        }
        for edge_type in removable_ids
    ]
    files_written: list[str] = []
    original_text = types_path.read_text(encoding="utf-8")
    new_text = original_text
    revert_receipt_relative = (
        migration_revert_receipt_relative_path(LINK_TYPES_V03_TARGET, source_receipt_relative)
        if source_receipt_relative
        else None
    )
    if revert_receipt_relative and archive_internal_path(root, revert_receipt_relative).exists():
        blockers.append(
            {
                "path": revert_receipt_relative,
                "field": "receipt",
                "code": "migration_revert_receipt_exists",
                "message": "Migration revert receipt already exists.",
            }
        )
    if changes and not blockers:
        new_types = copy.deepcopy(archive_types)
        new_types["link_types"] = kept_records
        new_text = dump_yaml(new_types)
        if approve:
            assert revert_receipt_relative is not None
            now = datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace("+00:00", "Z")
            revert_receipt = {
                "schema_version": "wom-kit/migration-revert-receipt/v0.1",
                "lifecycle_action": "link_types_v03_revert",
                "receipt_kind": "migration_revert",
                "created_at": now,
                "archive_id": archive_id,
                "target": LINK_TYPES_V03_TARGET,
                "migration_direction": "revert",
                "source_migration_receipt_path": source_receipt_relative,
                "files_changed": [types_relative],
                "removed_link_type_ids": removable_ids,
                "before_sha256": sha256_text(original_text),
                "after_sha256": sha256_text(new_text),
                "result": {
                    "types_file_written": True,
                    "receipt_written": True,
                },
                "closed_actions": {
                    "provider_api_called": False,
                    "real_source_export_files_read": False,
                    "zettel_files_written": False,
                    "edge_receipts_deleted": False,
                },
            }
            revert_receipt_path = archive_internal_path(root, revert_receipt_relative)
            try:
                write_text_atomic(types_path, new_text)
                files_written.append(types_relative)
                revert_receipt_path.parent.mkdir(parents=True, exist_ok=True)
                write_json_new_file(revert_receipt_path, revert_receipt)
                files_written.append(revert_receipt_relative)
            except OSError:
                write_text_atomic(types_path, original_text)
                if revert_receipt_path.exists():
                    try:
                        revert_receipt_path.unlink()
                    except OSError:
                        pass
                raise

    return {
        "ok": not blockers,
        "lifecycle_action": "link_types_v03_revert",
        "target": LINK_TYPES_V03_TARGET,
        "revert": True,
        "dry_run": bool(dry_run),
        "approved": bool(approve),
        "archive_id": archive_id,
        "files_scanned": 1 + len(iter_zettel_paths(root)),
        "files_with_changes": 1 if changes and not blockers else 0,
        "files_written": files_written,
        "receipt_path": source_receipt_relative,
        "revert_receipt_path": revert_receipt_relative,
        "blocked": bool(blockers),
        "blockers": blockers,
        "warnings": [],
        "archive_link_type_status": {
            "source": types_relative,
            "recommended_edge_types": recommended,
            "revert_candidate_edge_types": removable_ids,
            "source_receipt_appended_edge_types": appended_ids,
            "used_recommended_edge_types": sorted(used_types),
            "changed_recommended_edge_types": sorted(changed_records),
        },
        "would_change": [
            {
                "path": types_relative,
                "changes": changes
                + (
                    [
                        {
                            "action": "write_receipt",
                            "field": "receipt",
                            "path": revert_receipt_relative,
                        }
                    ]
                    if revert_receipt_relative and changes
                    else []
                ),
                "manual_review_required": bool(blockers),
                "blockers": blockers,
            }
        ]
        if changes or blockers
        else [],
        "new_text": new_text if dry_run and changes and not blockers else None,
        "next_safe_actions": [
            "Run revert-batch or revert-edge for edges using these link types before reverting the type vocabulary."
            if blockers
            else "Run archive doctor after approving the link type revert."
        ],
    }


def migrate_frontmatter_v03_revert(
    archive_root: Path | str,
    *,
    target: str,
    dry_run: bool,
    approve: bool,
) -> dict[str, Any]:
    if target != FRONTMATTER_V03_TARGET:
        raise ArchiveServiceError(f"Unsupported migration target: {target}")
    if dry_run == approve:
        raise ArchiveServiceError("archive migrate --revert requires exactly one of --dry-run or --approve.")

    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers = [
        {
            "path": "zettels/",
            "field": "frontmatter",
            "code": "snapshot_receipt_required",
            "message": "frontmatter-v0.3 revert requires a prior migration snapshot receipt before WOM-kit can restore old frontmatter safely.",
        }
    ]
    return {
        "ok": False,
        "lifecycle_action": "frontmatter_v03_revert",
        "target": FRONTMATTER_V03_TARGET,
        "revert": True,
        "dry_run": bool(dry_run),
        "approved": bool(approve),
        "archive_id": archive_id,
        "files_scanned": len(iter_zettel_paths(root)),
        "files_with_changes": 0,
        "files_written": [],
        "blocked": True,
        "blockers": blockers,
        "warnings": [],
        "would_change": [
            {
                "path": "zettels/",
                "changes": [],
                "manual_review_required": True,
                "blockers": blockers,
            }
        ],
        "next_safe_actions": [
            "Use receipt-based edge or link-type rollback where available; add migration snapshot receipts before attempting lossless frontmatter rollback.",
        ],
    }


def migrate_frontmatter_v03(
    archive_root: Path | str,
    *,
    target: str,
    dry_run: bool,
    approve: bool,
) -> dict[str, Any]:
    if target != FRONTMATTER_V03_TARGET:
        raise ArchiveServiceError(f"Unsupported migration target: {target}")
    if dry_run == approve:
        raise ArchiveServiceError("archive migrate requires exactly one of --dry-run or --approve.")

    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    plans: list[dict[str, Any]] = []
    blockers: list[dict[str, Any]] = []
    files_scanned = 0

    for path in iter_zettel_paths(root):
        files_scanned += 1
        plan = frontmatter_v03_migration_plan_for_path(path, root, archive_id)
        if plan["blockers"]:
            blockers.extend(plan["blockers"])
        if plan["changes"] or plan["blockers"]:
            plans.append(plan)

    ok = not blockers
    files_written: list[str] = []
    if approve and ok:
        for plan in plans:
            if not plan["changes"]:
                continue
            path = root / plan["path"]
            if not is_path_within_root(path, root):
                raise ArchiveServiceError(f"Migration target escaped archive root: {plan['path']}")
            write_text_atomic(path, str(plan["new_text"]))
            files_written.append(str(plan["path"]))

    return {
        "ok": ok,
        "lifecycle_action": "frontmatter_v03_migration",
        "target": FRONTMATTER_V03_TARGET,
        "dry_run": bool(dry_run),
        "approved": bool(approve),
        "archive_id": archive_id,
        "files_scanned": files_scanned,
        "files_with_changes": sum(1 for plan in plans if plan["changes"]),
        "files_written": files_written,
        "blocked": bool(blockers),
        "blockers": blockers,
        "warnings": [],
        "would_change": [
            {
                "path": plan["path"],
                "changes": plan["changes"],
                "manual_review_required": bool(plan["blockers"]),
                "blockers": plan["blockers"],
            }
            for plan in plans
        ],
    }


def frontmatter_v03_migration_plan_for_path(path: Path, archive_root: Path, archive_id: str) -> dict[str, Any]:
    relative_path = archive_relative_path(path, archive_root)
    text = path.read_text(encoding="utf-8")
    match = FRONTMATTER_RE.match(text)
    changes: list[dict[str, Any]] = []
    blockers: list[dict[str, Any]] = []

    if not match:
        return {
            "path": relative_path,
            "changes": changes,
            "blockers": [
                frontmatter_v03_blocker(relative_path, "$", "missing_frontmatter", "Zettel has no YAML frontmatter.")
            ],
            "new_text": text,
        }

    frontmatter_text = match.group(1)
    loaded = load_yaml(frontmatter_text)
    if not isinstance(loaded, dict):
        return {
            "path": relative_path,
            "changes": changes,
            "blockers": [
                frontmatter_v03_blocker(relative_path, "$", "invalid_frontmatter", "Zettel frontmatter is not an object.")
            ],
            "new_text": text,
        }

    frontmatter = copy.deepcopy(json_safe(loaded))
    for field in ("id", "title", "created_at", "updated_at", "archive_id", "status"):
        if not str(frontmatter.get(field) or "").strip():
            blockers.append(
                frontmatter_v03_blocker(
                    relative_path,
                    f"$.{field}",
                    "manual_identity_or_time_required",
                    f"Required identity/time/archive field is missing: {field}.",
                )
            )

    if "facets" not in frontmatter:
        frontmatter["facets"] = {}
        changes.append(frontmatter_v03_change("$.facets", "add", None, {}))
    elif not isinstance(frontmatter.get("facets"), dict):
        blockers.append(frontmatter_v03_blocker(relative_path, "$.facets", "manual_review_required", "facets must be an object."))

    if "assets" not in frontmatter:
        frontmatter["assets"] = []
        changes.append(frontmatter_v03_change("$.assets", "add", None, []))
    elif not isinstance(frontmatter.get("assets"), list):
        blockers.append(frontmatter_v03_blocker(relative_path, "$.assets", "manual_review_required", "assets must be an array."))

    if "edges" not in frontmatter:
        frontmatter["edges"] = []
        changes.append(frontmatter_v03_change("$.edges", "add", None, []))
    elif not isinstance(frontmatter.get("edges"), list):
        blockers.append(frontmatter_v03_blocker(relative_path, "$.edges", "manual_review_required", "edges must be an array."))

    provenance = frontmatter.get("provenance")
    if not isinstance(provenance, dict):
        blockers.append(frontmatter_v03_blocker(relative_path, "$.provenance", "manual_review_required", "provenance must be an object."))
    else:
        migrate_frontmatter_v03_provenance(relative_path, frontmatter, provenance, archive_id, changes, blockers)

    visibility = frontmatter.get("visibility")
    if not isinstance(visibility, dict):
        blockers.append(frontmatter_v03_blocker(relative_path, "$.visibility", "manual_review_required", "visibility must be an object."))
    else:
        migrate_frontmatter_v03_visibility(relative_path, visibility, changes, blockers)

    body = text[match.end() :]
    new_text = "---\n" + dump_yaml(frontmatter) + "---\n" + body
    return {"path": relative_path, "changes": changes, "blockers": blockers, "new_text": new_text}


def migrate_frontmatter_v03_provenance(
    relative_path: str,
    frontmatter: dict[str, Any],
    provenance: dict[str, Any],
    archive_id: str,
    changes: list[dict[str, Any]],
    blockers: list[dict[str, Any]],
) -> None:
    if not str(provenance.get("created_by") or "").strip():
        blockers.append(
            frontmatter_v03_blocker(
                relative_path,
                "$.provenance.created_by",
                "manual_identity_or_time_required",
                "provenance.created_by is missing.",
            )
        )
    if "created_in" not in provenance:
        provenance["created_in"] = archive_id
        changes.append(frontmatter_v03_change("$.provenance.created_in", "add", None, archive_id))
    elif not str(provenance.get("created_in") or "").strip():
        blockers.append(
            frontmatter_v03_blocker(
                relative_path,
                "$.provenance.created_in",
                "manual_identity_or_time_required",
                "provenance.created_in is empty.",
            )
        )

    if "derived_from" not in provenance:
        provenance["derived_from"] = []
        changes.append(frontmatter_v03_change("$.provenance.derived_from", "add", None, []))
    elif not isinstance(provenance.get("derived_from"), list):
        blockers.append(
            frontmatter_v03_blocker(
                relative_path,
                "$.provenance.derived_from",
                "manual_review_required",
                "provenance.derived_from must be an array.",
            )
        )

    if "source" not in provenance or provenance.get("source") is None:
        blockers.append(
            frontmatter_v03_blocker(
                relative_path,
                "$.provenance.source",
                "manual_review_required",
                "provenance.source is missing.",
            )
        )
        return
    source = provenance.get("source")
    if isinstance(source, str):
        if not source.strip():
            blockers.append(frontmatter_v03_blocker(relative_path, "$.provenance.source", "manual_review_required", "provenance.source is empty."))
        return

    if not frontmatter_v03_source_object_is_clean(source):
        blockers.append(
            frontmatter_v03_blocker(
                relative_path,
                "$.provenance.source",
                "manual_review_required",
                "Object-shaped provenance.source is ambiguous or contains unsafe values; review before migration.",
            )
        )
        return

    source_refs = frontmatter.get("source_refs")
    if source_refs is None:
        source_refs = []
        frontmatter["source_refs"] = source_refs
        changes.append(frontmatter_v03_change("$.source_refs", "add", None, []))
    if not isinstance(source_refs, list):
        blockers.append(frontmatter_v03_blocker(relative_path, "$.source_refs", "manual_review_required", "source_refs must be an array."))
        return

    canonical_value = json.dumps(json_safe(source), ensure_ascii=False, sort_keys=True, separators=(",", ":"))
    source_ref = {
        "type": FRONTMATTER_V03_LEGACY_REF_TYPE,
        "value": canonical_value,
        "role": FRONTMATTER_V03_LEGACY_REF_ROLE,
    }
    if not any(isinstance(item, dict) and item.get("type") == source_ref["type"] and item.get("value") == canonical_value for item in source_refs):
        source_refs.append(source_ref)
        changes.append(frontmatter_v03_change("$.source_refs[]", "append", None, source_ref))
    provenance["source"] = FRONTMATTER_V03_LEGACY_REF_TYPE
    changes.append(frontmatter_v03_change("$.provenance.source", "replace", source, FRONTMATTER_V03_LEGACY_REF_TYPE))


def migrate_frontmatter_v03_visibility(
    relative_path: str,
    visibility: dict[str, Any],
    changes: list[dict[str, Any]],
    blockers: list[dict[str, Any]],
) -> None:
    scope = visibility.get("scope")
    if not isinstance(scope, str) or not scope.strip():
        blockers.append(
            frontmatter_v03_blocker(
                relative_path,
                "$.visibility.scope",
                "manual_review_required",
                "visibility.scope is missing.",
            )
        )
    if "allowed_archives" not in visibility:
        visibility["allowed_archives"] = []
        changes.append(frontmatter_v03_change("$.visibility.allowed_archives", "add", None, []))
    elif not isinstance(visibility.get("allowed_archives"), list):
        blockers.append(
            frontmatter_v03_blocker(
                relative_path,
                "$.visibility.allowed_archives",
                "manual_review_required",
                "visibility.allowed_archives must be an array.",
            )
        )
    if "source_visibility" not in visibility:
        inferred = scope.strip() if isinstance(scope, str) and scope.strip() else "private"
        visibility["source_visibility"] = inferred
        changes.append(frontmatter_v03_change("$.visibility.source_visibility", "add", None, inferred))
    elif not isinstance(visibility.get("source_visibility"), str) or not visibility.get("source_visibility").strip():
        blockers.append(
            frontmatter_v03_blocker(
                relative_path,
                "$.visibility.source_visibility",
                "manual_review_required",
                "visibility.source_visibility is empty.",
            )
        )


def frontmatter_v03_source_object_is_clean(value: Any) -> bool:
    if not isinstance(value, dict):
        return False
    if not any(key in value for key in ("type", "value", "id", "ref", "source_id", "object_id")):
        return False
    serialized = json.dumps(json_safe(value), ensure_ascii=False, sort_keys=True, default=str)
    if contains_forbidden_location_reference(serialized) or DRAFT_SECRET_VALUE_RE.search(serialized):
        return False
    return all(frontmatter_v03_scalar_tree_is_clean(item) for item in value.values())


def frontmatter_v03_scalar_tree_is_clean(value: Any) -> bool:
    if isinstance(value, dict):
        return all(isinstance(key, str) and frontmatter_v03_scalar_tree_is_clean(item) for key, item in value.items())
    if isinstance(value, list):
        return all(frontmatter_v03_scalar_tree_is_clean(item) for item in value)
    if isinstance(value, (str, int, float, bool)) or value is None:
        text = str(value)
        return not (contains_forbidden_location_reference(text) or DRAFT_SECRET_VALUE_RE.search(text))
    return False


def frontmatter_v03_change(field: str, action: str, before: Any, after: Any) -> dict[str, Any]:
    return {"field": field, "action": action, "before": json_safe(before), "after": json_safe(after)}


def frontmatter_v03_blocker(path: str, field: str, code: str, message: str) -> dict[str, str]:
    return {"path": path, "field": field, "code": code, "message": message}


def sha256_path(path: Path) -> str:
    digest = hashlib.sha256()
    with path.open("rb") as file:
        for chunk in iter(lambda: file.read(1024 * 1024), b""):
            digest.update(chunk)
    return digest.hexdigest()


def newline_normalized_bytes(path: Path) -> bytes:
    return path.read_bytes().replace(b"\r\n", b"\n").replace(b"\r", b"\n")


def files_match_after_newline_normalization(left: Path, right: Path) -> bool:
    try:
        return newline_normalized_bytes(left) == newline_normalized_bytes(right)
    except OSError:
        return False


def default_private_visibility() -> dict[str, Any]:
    return {"scope": "private", "allowed_archives": [], "source_visibility": "private"}


def make_zettel_id(title: str, iso_now: str) -> str:
    day = iso_now[:10].replace("-", "")
    time_part = iso_now[11:19].replace(":", "")
    slug = re.sub(r"[^a-z0-9]+", "_", title.lower()).strip("_")[:32] or "draft"
    return f"zet_{day}_{time_part}_{slug}"


def json_safe(value: Any) -> Any:
    if isinstance(value, dict):
        return {key: json_safe(item) for key, item in value.items()}
    if isinstance(value, list):
        return [json_safe(item) for item in value]
    if isinstance(value, (date, datetime)):
        return value.isoformat()
    return value


def unique_preserve_order(values: list[str]) -> list[str]:
    seen: set[str] = set()
    result: list[str] = []
    for value in values:
        if value in seen:
            continue
        seen.add(value)
        result.append(value)
    return result


def drop_none_values(value: dict[str, Any]) -> dict[str, Any]:
    return {key: item for key, item in value.items() if item is not None}


def _jsonl_needs_leading_newline(path: Path) -> bool:
    if not path.is_file() or path.stat().st_size == 0:
        return False
    with path.open("rb") as handle:
        handle.seek(-1, os.SEEK_END)
        return handle.read(1) != b"\n"


class _DerivedTextManifestLock:
    def __init__(self, root: Path) -> None:
        manifests_dir = archive_internal_path(root, "objects/manifests")
        manifests_dir.mkdir(parents=True, exist_ok=True)
        self._path = manifests_dir / ".derived-text.jsonl.lock"
        self._handle: Any = None

    def __enter__(self) -> "_DerivedTextManifestLock":
        self._handle = open(self._path, "a+b")
        if os.name == "nt":
            import msvcrt

            self._handle.seek(0)
            while True:
                try:
                    msvcrt.locking(self._handle.fileno(), msvcrt.LK_LOCK, 1)
                    break
                except OSError:
                    continue
        else:
            import fcntl

            fcntl.flock(self._handle.fileno(), fcntl.LOCK_EX)
        return self

    def __exit__(self, *exc_info: Any) -> bool:
        try:
            if os.name == "nt":
                import msvcrt

                self._handle.seek(0)
                msvcrt.locking(self._handle.fileno(), msvcrt.LK_UNLCK, 1)
            else:
                import fcntl

                fcntl.flock(self._handle.fileno(), fcntl.LOCK_UN)
        finally:
            self._handle.close()
        return False


def derived_text_canonical_record_ids(records: list[dict[str, Any]]) -> set[str]:
    return {str(record.get("derived_text_id") or "") for record in records if record.get("derived_text_id")}


def derived_text_agent_operating_contract() -> dict[str, Any]:
    return {
        "contract_kind": "derived_text_agent_operating_contract",
        "schema_version": "wom-derived-text-agent-contract/v0.1",
        "default_posture": "maximum_textual_objet_coverage",
        "rules": [
            "Derived text is expected for every textual or plausibly textual objet unless a blocker is recorded.",
            "Maximum coverage is the default; narrowing scope requires an explicit human or policy reason.",
            "Do not stop at PDFs when office documents, HWP/HWPX, spreadsheets, slides, images, audio, or other text-bearing formats remain.",
            "Use coverage facts from objects/manifests/files.jsonl and objects/manifests/derived-text.jsonl instead of subjective confidence.",
            "Classify blocked items honestly as encrypted, password-required, unsupported, or needs human/toolchain review.",
            "Do not fabricate text when OCR/parser output is weak; prefer empty or low-confidence derived text plus review status.",
            "Do not read source bytes, run OCR, call providers, write derived text, draft zets, or mint zets from this contract surface.",
        ],
        "required_preflight_order": [
            "derive-text coverage --dry-run",
            "derive-text toolchain --dry-run for uncovered families",
            "human/toolchain extraction outside this gate",
            "derive-text capture --dry-run",
            "derive-text capture --approve after review",
            "derive-text coverage --dry-run again",
        ],
        "completion_definition": {
            "coverage_gate": "zero missing_derived_text items among textual candidates, or every exception classified with a blocker",
            "human_review_needed": True,
            "coverage_source_of_truth": [
                "objects/manifests/files.jsonl",
                DERIVED_TEXT_MANIFEST_RELATIVE_PATH,
            ],
        },
    }


def derived_text_agent_contract(
    archive_root: Path | str,
    *,
    dry_run: bool = True,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    if not dry_run:
        blockers.append("derive-text agent-contract is read-only; pass --dry-run.")
    return {
        "ok": not blockers,
        "dry_run": True,
        "lifecycle_action": "derived_text_agent_contract",
        "archive_id": archive_id,
        "agent_operating_contract": derived_text_agent_operating_contract(),
        "closed_actions": derived_text_read_only_closed_actions(),
        "privacy_guards": derived_text_read_only_privacy_guards(),
        "would_change": [],
        "blockers": unique_preserve_order(blockers),
        "warnings": [],
    }


def derived_text_read_only_closed_actions() -> dict[str, bool]:
    return {
        "source_file_body_read": False,
        "source_bytes_hashed": False,
        "ocr_run": False,
        "parser_run": False,
        "asr_run": False,
        "llm_vision_called": False,
        "provider_api_called": False,
        "derived_text_written": False,
        "receipt_written": False,
        "draft_created": False,
        "zet_minted": False,
        "files_written": False,
    }


def derived_text_read_only_privacy_guards() -> dict[str, bool]:
    return {
        "source_body_echoed": False,
        "local_absolute_paths_echoed": False,
        "provider_urls_echoed": False,
        "object_filenames_echoed": False,
        "secret_values_echoed": False,
        "writes": False,
    }


def derived_text_toolchain_profile(extension: str | None = None, mime: str | None = None) -> dict[str, Any]:
    ext = normalize_extension_label(extension)
    mime_value = (mime or "").strip().lower()
    if not ext and mime_value:
        ext = extension_from_mime_hint(mime_value)

    def profile(
        *,
        family: str,
        textual_candidate: bool,
        extraction_route: str,
        derivation_kind: str,
        primary_tools: list[str],
        fallback_tools: list[str] | None = None,
        human_review: str = "review derived text before capture",
        blockers: list[str] | None = None,
        notes: list[str] | None = None,
    ) -> dict[str, Any]:
        return {
            "format_family": family,
            "extension": ext or None,
            "mime": mime_value or None,
            "textual_candidate": textual_candidate,
            "extraction_route": extraction_route,
            "recommended_derivation_kind": derivation_kind,
            "primary_tools": primary_tools,
            "fallback_tools": fallback_tools or [],
            "human_review": human_review,
            "blocker_labels": blockers or [],
            "notes": notes or [],
            "source_urls": derived_text_toolchain_source_urls(primary_tools + (fallback_tools or [])),
        }

    if ext in DERIVED_TEXT_PLAIN_TEXT_EXTENSIONS or mime_value.startswith("text/"):
        return profile(
            family="plain_text_or_markup",
            textual_candidate=True,
            extraction_route="utf8_parser",
            derivation_kind="parser",
            primary_tools=["built-in utf-8 text parser"],
            notes=["Verify encoding and preserve original objet separately."],
        )
    if ext == ".docx":
        return profile(
            family="office_open_xml_word",
            textual_candidate=True,
            extraction_route="structured_ooxml_parser",
            derivation_kind="parser",
            primary_tools=["python-docx"],
            fallback_tools=["LibreOffice headless conversion"],
            notes=["Also consider headers, footers, comments, and embedded images as separate future coverage cases."],
        )
    if ext == ".xlsx":
        return profile(
            family="office_open_xml_spreadsheet",
            textual_candidate=True,
            extraction_route="structured_ooxml_parser",
            derivation_kind="parser",
            primary_tools=["openpyxl"],
            fallback_tools=["LibreOffice headless conversion"],
            notes=["Preserve sheet names, cell coordinates, and formulas as review metadata when available."],
        )
    if ext == ".pptx":
        return profile(
            family="office_open_xml_presentation",
            textual_candidate=True,
            extraction_route="structured_ooxml_parser",
            derivation_kind="parser",
            primary_tools=["python-pptx"],
            fallback_tools=["LibreOffice headless conversion"],
            notes=["Slides can contain text in shapes, notes, tables, and embedded images."],
        )
    if ext in DERIVED_TEXT_LEGACY_OFFICE_EXTENSIONS:
        return profile(
            family="legacy_office_binary",
            textual_candidate=True,
            extraction_route="libreoffice_headless_conversion_then_parser",
            derivation_kind="parser",
            primary_tools=["LibreOffice headless conversion"],
            fallback_tools=["format-specific parser after conversion", "OCR if rendered output is image-only"],
            notes=["Treat old OLE Office files as text-bearing by default unless conversion fails."],
        )
    if ext in DERIVED_TEXT_HWP_EXTENSIONS:
        return profile(
            family="hwp_or_hwpx",
            textual_candidate=True,
            extraction_route="hwp_parser_or_conversion_fallback",
            derivation_kind="parser",
            primary_tools=["pyhwp hwp5txt"],
            fallback_tools=["LibreOffice headless conversion", "zip+xml extraction for hwpx", "OCR if rendered output is image-only"],
            notes=["Classify unsupported or damaged files honestly instead of pretending coverage."],
        )
    if ext in DERIVED_TEXT_PDF_EXTENSIONS or mime_value == "application/pdf":
        return profile(
            family="pdf",
            textual_candidate=True,
            extraction_route="pdf_triage_then_parser_or_ocr_or_vision",
            derivation_kind="parser",
            primary_tools=["PyMuPDF text extraction", "PyMuPDF render metadata"],
            fallback_tools=["Tesseract OCR", "LLM vision for complex layout", "human password entry for encrypted PDFs"],
            human_review="review reading order, page coverage, and OCR confidence",
            blockers=["encrypted_pdf_needs_password"],
            notes=["Born-digital PDFs can use parser extraction; scans, two-column layouts, forms, and handwriting need OCR or vision routing."],
        )
    if ext in DERIVED_TEXT_IMAGE_EXTENSIONS or mime_value.startswith("image/"):
        return profile(
            family="image_scan",
            textual_candidate=True,
            extraction_route="ocr_then_human_review",
            derivation_kind="ocr",
            primary_tools=["Tesseract OCR"],
            fallback_tools=["LLM vision for handwriting, tables, forms, or complex layout"],
            human_review="review OCR confidence and mark uncertain spans",
            notes=["Skip only when the image is confirmed non-textual or intentionally excluded."],
        )
    if ext in DERIVED_TEXT_AUDIO_EXTENSIONS or mime_value.startswith("audio/"):
        return profile(
            family="audio",
            textual_candidate=True,
            extraction_route="asr_then_human_review",
            derivation_kind="asr",
            primary_tools=["reviewed local ASR tool"],
            fallback_tools=["provider ASR only after credential and cost approval"],
            notes=["ASR is a future extraction route; this planner does not call any model or provider."],
        )
    if ext in {".odt", ".ods", ".odp", ".rtf"}:
        return profile(
            family="open_document_or_rtf",
            textual_candidate=True,
            extraction_route="libreoffice_or_structured_parser",
            derivation_kind="parser",
            primary_tools=["LibreOffice headless conversion"],
            fallback_tools=["format-specific parser"],
            notes=["Treat open office documents and RTF as text-bearing by default."],
        )
    return profile(
        family="unknown_or_non_textual",
        textual_candidate=False,
        extraction_route="manual_triage",
        derivation_kind="parser",
        primary_tools=["manual review"],
        notes=["Not counted as textual coverage unless extension, MIME, or human review marks it as text-bearing."],
    )


def normalize_extension_label(extension: str | None) -> str:
    text = (extension or "").strip().lower()
    if not text:
        return ""
    if "/" in text or "\\" in text or contains_forbidden_location_reference(text):
        return ""
    if not text.startswith("."):
        text = "." + text
    if not re.match(r"^\.[a-z0-9][a-z0-9._+-]{0,20}$", text):
        return ""
    return text


def extension_from_mime_hint(mime: str) -> str:
    mapping = {
        "application/pdf": ".pdf",
        "text/plain": ".txt",
        "text/markdown": ".md",
        "text/csv": ".csv",
        "application/json": ".json",
        "application/xml": ".xml",
        "text/html": ".html",
        "application/vnd.openxmlformats-officedocument.wordprocessingml.document": ".docx",
        "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet": ".xlsx",
        "application/vnd.openxmlformats-officedocument.presentationml.presentation": ".pptx",
        "application/msword": ".doc",
        "application/vnd.ms-excel": ".xls",
        "application/vnd.ms-powerpoint": ".ppt",
        "application/haansofthwp": ".hwp",
        "application/x-hwp": ".hwp",
    }
    if mime in mapping:
        return mapping[mime]
    if mime.startswith("image/"):
        return ".png"
    if mime.startswith("audio/"):
        return ".wav"
    return ""


def derived_text_toolchain_source_urls(tool_names: list[str]) -> list[dict[str, str]]:
    urls: list[dict[str, str]] = []
    for name in tool_names:
        key = name.lower()
        if "python-docx" in key:
            urls.append({"tool": "python-docx", "url": DERIVED_TEXT_TOOLCHAIN_SOURCE_URLS["python-docx"]})
        elif "openpyxl" in key:
            urls.append({"tool": "openpyxl", "url": DERIVED_TEXT_TOOLCHAIN_SOURCE_URLS["openpyxl"]})
        elif "python-pptx" in key:
            urls.append({"tool": "python-pptx", "url": DERIVED_TEXT_TOOLCHAIN_SOURCE_URLS["python-pptx"]})
        elif "libreoffice" in key:
            urls.append({"tool": "LibreOffice", "url": DERIVED_TEXT_TOOLCHAIN_SOURCE_URLS["libreoffice"]})
        elif "tesseract" in key:
            urls.append({"tool": "Tesseract OCR", "url": DERIVED_TEXT_TOOLCHAIN_SOURCE_URLS["tesseract"]})
        elif "pymupdf" in key:
            urls.append({"tool": "PyMuPDF", "url": DERIVED_TEXT_TOOLCHAIN_SOURCE_URLS["pymupdf"]})
        elif "pyhwp" in key or "hwp5txt" in key:
            urls.append({"tool": "pyhwp/hwp5txt", "url": DERIVED_TEXT_TOOLCHAIN_SOURCE_URLS["pyhwp"]})
    deduped: list[dict[str, str]] = []
    seen: set[tuple[str, str]] = set()
    for item in urls:
        key = (item["tool"], item["url"])
        if key not in seen:
            seen.add(key)
            deduped.append(item)
    return deduped


def derived_text_python_module_available(module_name: str) -> bool:
    try:
        return importlib.util.find_spec(module_name) is not None
    except (ImportError, AttributeError, ValueError):
        return False


def derived_text_executable_available(executable_name: str) -> bool:
    return shutil.which(executable_name) is not None


def derived_text_tool_hint_probe_key(value: str) -> str:
    return re.sub(r"[^a-z0-9]+", "", value.strip().lower())


def derived_text_load_tool_hints(tool_hints: Path | str | None) -> tuple[dict[str, list[Path]], dict[str, Any], list[str]]:
    if tool_hints is None:
        return {}, {"provided": False, "accepted_probe_count": 0, "ignored_probe_count": 0, "path_echoed": False}, []

    hints_path = Path(tool_hints)
    raw = json.loads(hints_path.read_text(encoding="utf-8"))
    if not isinstance(raw, dict):
        return {}, {"provided": True, "accepted_probe_count": 0, "ignored_probe_count": 1, "path_echoed": False}, [
            "tool_hints_file_must_be_json_object"
        ]
    executables = raw.get("executables", {})
    if not isinstance(executables, dict):
        return {}, {"provided": True, "accepted_probe_count": 0, "ignored_probe_count": 1, "path_echoed": False}, [
            "tool_hints_executables_must_be_object"
        ]

    allowed_probe_keys = {
        derived_text_tool_hint_probe_key(str(check["probe"])): str(check["probe"])
        for check in DERIVED_TEXT_TOOLCHAIN_DOCTOR_CHECKS
        if check.get("kind") == "executable"
    }
    aliases = {
        "tesseractocr": "tesseract",
        "libreoffice": "libreoffice",
        "soffice": "soffice",
        "hwp5txt": "hwp5txt",
        "pyhwphwp5txt": "hwp5txt",
    }
    by_probe: dict[str, list[Path]] = {}
    ignored_count = 0
    warnings: list[str] = []
    for key, paths in executables.items():
        probe_key = aliases.get(derived_text_tool_hint_probe_key(str(key)), derived_text_tool_hint_probe_key(str(key)))
        probe = allowed_probe_keys.get(probe_key)
        if not probe:
            ignored_count += 1
            warnings.append("tool_hints_unknown_executable_probe_ignored")
            continue
        path_values = paths if isinstance(paths, list) else [paths]
        for item in path_values:
            if not isinstance(item, str) or not item.strip():
                ignored_count += 1
                warnings.append("tool_hints_invalid_path_value_ignored")
                continue
            path = Path(item).expanduser()
            if not path.is_absolute():
                path = hints_path.parent / path
            by_probe.setdefault(probe, []).append(path)
    accepted_count = sum(len(paths) for paths in by_probe.values())
    summary = {
        "provided": True,
        "accepted_probe_count": accepted_count,
        "ignored_probe_count": ignored_count,
        "path_echoed": False,
    }
    return by_probe, summary, unique_preserve_order(warnings)


def derived_text_executable_hint_available(executable_name: str, executable_hints: dict[str, list[Path]]) -> bool:
    for hint in executable_hints.get(executable_name, []):
        try:
            if hint.is_file():
                return True
        except OSError:
            continue
    return False


def derived_text_toolchain_doctor(
    archive_root: Path | str,
    *,
    dry_run: bool = True,
    tool_hints: Path | str | None = None,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    if not dry_run:
        blockers.append("derive-text doctor is read-only; pass --dry-run.")
    executable_hints, tool_hint_summary, hint_warnings = derived_text_load_tool_hints(tool_hints)

    checks: list[dict[str, Any]] = [
        {
            "tool": "built-in utf-8 text parser",
            "kind": "built_in",
            "probe": "python_text_io",
            "available": True,
            "purpose": "plain text and markup extraction route",
            "format_families": ["plain_text_or_markup"],
            "path_echoed": False,
            "secret_echoed": False,
            "hint_used": False,
        }
    ]
    tool_available: dict[str, bool] = {"built-in utf-8 text parser": True}

    for check in DERIVED_TEXT_TOOLCHAIN_DOCTOR_CHECKS:
        kind = str(check["kind"])
        probe = str(check["probe"])
        available = False
        if kind == "python_module":
            available = derived_text_python_module_available(probe)
        elif kind == "executable":
            path_available = derived_text_executable_available(probe)
            hint_available = derived_text_executable_hint_available(probe, executable_hints)
            available = path_available or hint_available
        elif kind == "built_in":
            available = True
        elif kind == "not_configured":
            available = False
        else:
            path_available = False
            hint_available = False
        if kind != "executable":
            path_available = False
            hint_available = False
        tool = str(check["tool"])
        tool_available[tool] = tool_available.get(tool, False) or available
        checks.append(
            {
                "tool": tool,
                "kind": kind,
                "probe": probe,
                "available": available,
                "purpose": check["purpose"],
                "format_families": check["format_families"],
                "path_echoed": False,
                "secret_echoed": False,
                "path_probe_available": path_available if kind == "executable" else None,
                "hint_probe_available": hint_available if kind == "executable" else None,
                "hint_used": hint_available,
            }
        )

    family_readiness: list[dict[str, Any]] = []
    for family in DERIVED_TEXT_TOOLCHAIN_DOCTOR_FAMILIES:
        ready_when_any = [str(tool) for tool in family.get("ready_when_any", [])]
        optional_tools = [str(tool) for tool in family.get("optional_tools", [])]
        available_required = [tool for tool in ready_when_any if tool_available.get(tool, False)]
        missing_required = [tool for tool in ready_when_any if not tool_available.get(tool, False)]
        missing_optional = [tool for tool in optional_tools if not tool_available.get(tool, False)]
        family_readiness.append(
            {
                "format_family": family["format_family"],
                "candidate_extensions": family["candidate_extensions"],
                "ready": bool(available_required),
                "available_tools": available_required,
                "missing_tools": missing_required,
                "missing_optional_tools": missing_optional,
                "notes": family.get("notes", []),
            }
        )

    ready_family_count = sum(1 for item in family_readiness if item["ready"])
    available_tool_count = sum(1 for item in checks if item["available"])
    known_tools = unique_preserve_order(str(item["tool"]) for item in checks if item["kind"] != "not_configured")
    missing_tools = [tool for tool in known_tools if not tool_available.get(tool, False)]
    not_ready_families = [str(item["format_family"]) for item in family_readiness if not item["ready"]]
    warnings: list[str] = []
    if not_ready_families:
        warnings.append("some_derived_text_format_families_need_tool_install_or_policy_configuration")
    return {
        "ok": not blockers,
        "dry_run": True,
        "lifecycle_action": "derived_text_toolchain_doctor",
        "archive_id": archive_id,
        "readiness_summary": {
            "checked_tool_count": len(checks),
            "available_tool_count": available_tool_count,
            "ready_family_count": ready_family_count,
            "total_family_count": len(family_readiness),
            "not_ready_families": not_ready_families,
            "missing_tools": missing_tools,
            "tool_hints": tool_hint_summary,
        },
        "tool_checks": checks,
        "family_readiness": family_readiness,
        "agent_operating_contract": derived_text_agent_operating_contract(),
        "closed_actions": derived_text_read_only_closed_actions(),
        "privacy_guards": {
            **derived_text_read_only_privacy_guards(),
            "tool_paths_echoed": False,
            "import_paths_echoed": False,
            "tool_hint_paths_echoed": False,
        },
        "would_change": [],
        "blockers": unique_preserve_order(blockers),
        "warnings": unique_preserve_order(warnings + hint_warnings),
    }


def derived_text_toolchain(
    archive_root: Path | str,
    *,
    extension: str | None = None,
    mime: str | None = None,
    dry_run: bool = True,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    if not dry_run:
        blockers.append("derive-text toolchain is read-only; pass --dry-run.")
    if not extension and not mime:
        blockers.append("Provide --extension or --mime.")
    profile = derived_text_toolchain_profile(extension, mime)
    return {
        "ok": not blockers,
        "dry_run": True,
        "lifecycle_action": "derived_text_toolchain_recommendation",
        "archive_id": archive_id,
        "toolchain": profile,
        "agent_operating_contract": derived_text_agent_operating_contract(),
        "closed_actions": derived_text_read_only_closed_actions(),
        "privacy_guards": derived_text_read_only_privacy_guards(),
        "would_change": [],
        "blockers": unique_preserve_order(blockers),
        "warnings": [],
    }


def derived_text_record_source_object_ids(records: list[dict[str, Any]]) -> dict[str, int]:
    counts: dict[str, int] = {}
    for record in records:
        source_id = str(record.get("source_object_id") or "").strip().lower()
        if OBJECT_ID_RE.match(source_id):
            counts[source_id] = counts.get(source_id, 0) + 1
    return counts


def derived_text_manifest_record_extension(record: dict[str, Any]) -> str:
    logical_key = str(record.get("logical_key") or "").strip()
    if logical_key:
        suffix = PurePosixPath(logical_key.replace("\\", "/")).suffix.lower()
        if suffix:
            return normalize_extension_label(suffix)
    mime = str(record.get("mime") or "").strip().lower()
    return extension_from_mime_hint(mime)


def derived_text_record_has_encryption_hint(value: Any) -> bool:
    encrypted_keys = {"encrypted", "is_encrypted", "password_required", "requires_password", "needs_password"}
    if isinstance(value, dict):
        for key, child in value.items():
            if str(key).lower() in encrypted_keys and child is True:
                return True
            if derived_text_record_has_encryption_hint(child):
                return True
    if isinstance(value, list):
        return any(derived_text_record_has_encryption_hint(child) for child in value)
    return False


def derived_text_size_bucket(size_value: Any) -> str:
    if isinstance(size_value, bool) or not isinstance(size_value, (int, float)) or size_value < 0:
        return "unknown"
    size = int(size_value)
    if size == 0:
        return "zero"
    if size < 10_000:
        return "tiny"
    if size < 1_000_000:
        return "small"
    if size < 25_000_000:
        return "medium"
    return "large"


def derived_text_manifest_quality(records: list[dict[str, Any]], *, max_items: int) -> dict[str, Any]:
    issue_sample: list[dict[str, Any]] = []
    records_with_issues = 0
    missing_tool_version_count = 0
    unknown_tool_version_count = 0
    invalid_tool_version_count = 0
    missing_tool_name_count = 0
    invalid_derivation_kind_count = 0
    invalid_review_status_count = 0
    required_fields = [
        "source_object_id",
        "derivation_kind",
        "tool_name",
        "tool_version",
        "review_status",
    ]

    def safe_manifest_scalar(value: Any) -> bool:
        if not isinstance(value, str) or not value.strip():
            return False
        text = value.strip()
        if "\n" in text or "\r" in text or "\x00" in text:
            return False
        if contains_forbidden_location_reference(text) or source_intake_has_provider_url(text) or source_intake_secret_like(text):
            return False
        return True

    for index, record in enumerate(records, start=1):
        issues: list[str] = []
        source_object_id = str(record.get("source_object_id") or "").strip().lower()
        if not OBJECT_ID_RE.match(source_object_id):
            issues.append("source_object_id_invalid")

        derivation_kind = str(record.get("derivation_kind") or "").strip()
        if derivation_kind not in DERIVED_TEXT_DERIVATION_KINDS:
            issues.append("derivation_kind_invalid")
            invalid_derivation_kind_count += 1

        if not safe_manifest_scalar(record.get("tool_name")):
            issues.append("tool_name_missing_or_invalid")
            missing_tool_name_count += 1

        tool_version = record.get("tool_version")
        tool_version_text = str(tool_version or "").strip()
        if not tool_version_text:
            issues.append("tool_version_missing")
            missing_tool_version_count += 1
        elif not safe_manifest_scalar(tool_version):
            issues.append("tool_version_invalid")
            invalid_tool_version_count += 1
        elif tool_version_text.lower() in DERIVED_TEXT_UNKNOWN_VERSION_LABELS:
            issues.append("tool_version_unknown")
            unknown_tool_version_count += 1

        review_status = str(record.get("review_status") or "").strip()
        if review_status not in DERIVED_TEXT_REVIEW_STATUSES:
            issues.append("review_status_invalid")
            invalid_review_status_count += 1

        if not issues:
            continue
        records_with_issues += 1
        if len(issue_sample) < max_items:
            issue_sample.append(
                {
                    "record_index": index,
                    "source_object_id": source_object_id if OBJECT_ID_RE.match(source_object_id) else None,
                    "issues": unique_preserve_order(issues),
                    "body_text_echoed": False,
                    "local_path_echoed": False,
                    "tool_path_echoed": False,
                }
            )

    return {
        "status": "passed" if records_with_issues == 0 else "needs_review",
        "required_fields": required_fields,
        "derived_text_record_count": len(records),
        "records_with_required_metadata_count": len(records) - records_with_issues,
        "records_with_issues_count": records_with_issues,
        "missing_tool_version_count": missing_tool_version_count,
        "unknown_tool_version_count": unknown_tool_version_count,
        "invalid_tool_version_count": invalid_tool_version_count,
        "missing_tool_name_count": missing_tool_name_count,
        "invalid_derivation_kind_count": invalid_derivation_kind_count,
        "invalid_review_status_count": invalid_review_status_count,
        "issues_truncated": records_with_issues > len(issue_sample),
        "issue_sample": issue_sample,
        "closed_actions": {
            "source_file_body_read": False,
            "derived_text_body_read": False,
            "tool_executed": False,
            "provider_api_called": False,
            "writes": False,
        },
        "privacy_guards": {
            "body_text_echoed": False,
            "local_absolute_paths_echoed": False,
            "tool_paths_echoed": False,
            "provider_urls_echoed": False,
            "secret_values_echoed": False,
        },
    }


def derived_text_coverage(
    archive_root: Path | str,
    *,
    dry_run: bool = True,
    max_items: int = 25,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    blockers: list[str] = []
    warnings: list[str] = []
    if not dry_run:
        blockers.append("derive-text coverage is read-only; pass --dry-run.")
    max_items = max(0, min(int(max_items), 200))

    manifest_records = load_manifest_records(root)
    derived_records = load_derived_text_records(root)
    source_counts = derived_text_record_source_object_ids(derived_records)
    by_status: dict[str, int] = {}
    by_extension: dict[str, int] = {}
    by_toolchain_family: dict[str, int] = {}
    missing_items: list[dict[str, Any]] = []
    blocked_items: list[dict[str, Any]] = []
    covered_items: list[dict[str, Any]] = []
    textual_candidate_count = 0
    covered_textual_count = 0

    for record in manifest_records:
        object_id = str(record.get("object_id") or "").strip().lower()
        if not OBJECT_ID_RE.match(object_id):
            warnings.append("manifest_record_with_invalid_object_id_skipped")
            continue
        extension = derived_text_manifest_record_extension(record)
        mime = str(record.get("mime") or "").strip().lower()
        toolchain = derived_text_toolchain_profile(extension, mime)
        family = str(toolchain.get("format_family") or "unknown_or_non_textual")
        encrypted = derived_text_record_has_encryption_hint(record)
        derived_count = source_counts.get(object_id, 0)
        manifest_textual_signal = bool(toolchain.get("textual_candidate"))
        derived_text_signal = derived_count > 0
        textual_candidate = manifest_textual_signal or derived_text_signal
        textual_signal = "manifest_extension_or_mime" if manifest_textual_signal else None
        if derived_text_signal and not manifest_textual_signal:
            textual_signal = "derived_text_record_present"
            family = "derived_text_present_unknown_source"
            warnings.append("derived_text_records_used_as_textual_signal_for_unknown_manifest_mime")
        if textual_candidate:
            textual_candidate_count += 1
        if not textual_candidate:
            status = "not_textual_or_unknown"
        elif encrypted and derived_count == 0:
            status = "needs_password_or_encrypted"
        elif derived_count > 0:
            status = "covered"
            covered_textual_count += 1
        else:
            status = "missing_derived_text"
        by_status[status] = by_status.get(status, 0) + 1
        by_extension[extension or "<none>"] = by_extension.get(extension or "<none>", 0) + 1
        by_toolchain_family[family] = by_toolchain_family.get(family, 0) + 1
        item = {
            "object_id": object_id,
            "extension": extension or None,
            "mime": mime or None,
            "coverage_status": status,
            "derived_text_record_count": derived_count,
            "textual_signal": textual_signal,
            "toolchain_family": family,
            "recommended_derivation_kind": toolchain.get("recommended_derivation_kind"),
            "suggested_route": toolchain.get("extraction_route"),
            "size_bucket": derived_text_size_bucket(record.get("size_bytes")),
            "source_name_echoed": False,
            "local_path_echoed": False,
        }
        if status == "missing_derived_text":
            if len(missing_items) < max_items:
                missing_items.append(item)
        elif status == "needs_password_or_encrypted":
            if len(blocked_items) < max_items:
                blocked_items.append(item)
        elif status == "covered":
            if len(covered_items) < max_items:
                covered_items.append(item)

    missing_count = by_status.get("missing_derived_text", 0)
    blocked_count = by_status.get("needs_password_or_encrypted", 0)
    manifest_quality = derived_text_manifest_quality(derived_records, max_items=max_items)
    manifest_quality_issue_count = int(manifest_quality.get("records_with_issues_count") or 0)
    coverage_ratio = None
    if textual_candidate_count:
        coverage_ratio = covered_textual_count / textual_candidate_count
    gate_passed = missing_count == 0 and manifest_quality_issue_count == 0
    if blocked_count:
        warnings.append("encrypted_or_password_required_textual_objets_need_human_resolution")
    if manifest_quality_issue_count:
        warnings.append("derived_text_manifest_quality_needs_review")
    return {
        "ok": not blockers and gate_passed,
        "dry_run": True,
        "lifecycle_action": "derived_text_coverage_gate",
        "archive_id": archive_id,
        "coverage_gate": {
            "status": "passed" if gate_passed and not blockers else "blocked",
            "default_posture": "maximum_textual_objet_coverage",
            "textual_candidate_count": textual_candidate_count,
            "covered_textual_count": covered_textual_count,
            "missing_derived_text_count": missing_count,
            "needs_password_or_encrypted_count": blocked_count,
            "manifest_quality_issue_count": manifest_quality_issue_count,
            "coverage_ratio": coverage_ratio,
            "missing_items_truncated": missing_count > len(missing_items),
            "blocked_items_truncated": blocked_count > len(blocked_items),
        },
        "completeness_signal": derived_text_completeness_signal(
            manifest_record_count=len(manifest_records),
            derived_text_record_count=len(derived_records),
            textual_candidate_count=textual_candidate_count,
            covered_textual_count=covered_textual_count,
            missing_derived_text_count=missing_count,
            needs_password_or_encrypted_count=blocked_count,
        ),
        "manifest_counts": {
            "object_manifest_record_count": len(manifest_records),
            "derived_text_record_count": len(derived_records),
            "by_status": by_status,
            "by_extension": by_extension,
            "by_toolchain_family": by_toolchain_family,
        },
        "manifest_quality": manifest_quality,
        "missing_items": missing_items,
        "blocked_items": blocked_items,
        "covered_sample": covered_items,
        "agent_operating_contract": derived_text_agent_operating_contract(),
        "closed_actions": derived_text_read_only_closed_actions(),
        "privacy_guards": derived_text_read_only_privacy_guards(),
        "would_change": [],
        "next_safe_actions": [
            "Run derive-text toolchain for the missing families before extraction.",
            "Produce derived text outside this read-only gate, then capture it with derive-text capture --dry-run and --approve.",
            "Fix derived-text manifest quality issues such as missing tool_version before claiming extraction provenance is complete.",
            "Re-run derive-text coverage until missing_derived_text_count is zero or every exception has a blocker.",
        ],
        "blockers": unique_preserve_order(
            blockers
            + (["missing_derived_text"] if missing_count else [])
            + (["derived_text_manifest_quality_issues"] if manifest_quality_issue_count else [])
        ),
        "warnings": unique_preserve_order(warnings),
    }


def derived_text_completeness_signal(
    *,
    manifest_record_count: int,
    derived_text_record_count: int,
    textual_candidate_count: int,
    covered_textual_count: int,
    missing_derived_text_count: int,
    needs_password_or_encrypted_count: int,
) -> dict[str, Any]:
    if manifest_record_count == 0:
        state = "no_manifested_objets"
    elif missing_derived_text_count:
        state = "manifest_scoped_incomplete"
    elif needs_password_or_encrypted_count:
        state = "manifest_scoped_with_blocked_items"
    else:
        state = "manifest_scoped_text_coverage_passed"
    return {
        "lifecycle_action": "derived_text_completeness_signal",
        "state": state,
        "scope_kind": "manifest_scoped",
        "scope_source_of_truth": [
            "objects/manifests/files.jsonl",
            DERIVED_TEXT_MANIFEST_RELATIVE_PATH,
        ],
        "full_mirror_claimed": False,
        "full_mirror_proof_present": False,
        "operator_reading": (
            "This signal covers manifested objets only. It is not proof that an external "
            "workspace, mailbox, cloud drive, or export has been fully mirrored."
        ),
        "counts": {
            "manifest_record_count": manifest_record_count,
            "derived_text_record_count": derived_text_record_count,
            "textual_candidate_count": textual_candidate_count,
            "covered_textual_count": covered_textual_count,
            "missing_derived_text_count": missing_derived_text_count,
            "needs_password_or_encrypted_count": needs_password_or_encrypted_count,
        },
        "cannot_prove": [
            "external_workspace_fully_exported",
            "external_mailbox_fully_mirrored",
            "cloud_drive_fully_mirrored",
            "notion_or_workspace_full_account_coverage",
            "unmanifested_local_files_absent",
        ],
        "next_safe_actions": [
            "Treat passed coverage as derived-text coverage for manifested objets, not full source mirror completion.",
            "Record a separate source/export mirror receipt before claiming full external account coverage.",
            "Keep partial exports labeled partial until a human-reviewed mirror manifest exists.",
        ],
        "closed_actions": {
            "source_file_body_read": False,
            "external_workspace_scanned": False,
            "provider_api_called": False,
            "files_written": False,
            "secrets_read": False,
        },
    }


def derived_text_identity_digest(
    *,
    source_object_id: str,
    text_sha256: str,
    derivation_kind: str,
    tool_name: str,
    tool_version: str,
    model_name: str | None,
    model_version: str | None,
    review_status: str,
) -> str:
    identity = drop_none_values(
        {
            "source_object_id": source_object_id,
            "text_sha256": text_sha256,
            "derivation_kind": derivation_kind,
            "tool_name": tool_name,
            "tool_version": tool_version,
            "model_name": model_name,
            "model_version": model_version,
            "review_status": review_status,
        }
    )
    encoded = json.dumps(identity, ensure_ascii=False, sort_keys=True, separators=(",", ":"))
    return hashlib.sha256(encoded.encode("utf-8")).hexdigest()


def _derived_text_metadata_blockers(
    *,
    source_object_id: str,
    derivation_kind: str,
    tool_name: str,
    tool_version: str,
    review_status: str,
    confidence: float | int | None,
    language: str | None,
) -> list[str]:
    blockers: list[str] = []
    normalize_object_id(source_object_id, blockers)
    if derivation_kind not in DERIVED_TEXT_DERIVATION_KINDS:
        blockers.append("derivation_kind_invalid")
    if review_status not in DERIVED_TEXT_REVIEW_STATUSES:
        blockers.append("review_status_invalid")
    for label, value in [("tool_name", tool_name), ("tool_version", tool_version)]:
        if not isinstance(value, str) or not value.strip() or "\n" in value or "\r" in value or "\x00" in value:
            blockers.append(f"{label}_invalid")
    if language is not None and ("\n" in language or "\r" in language or "\x00" in language):
        blockers.append("language_invalid")
    if confidence is not None:
        if isinstance(confidence, bool) or not isinstance(confidence, (int, float)):
            blockers.append("confidence_invalid")
        elif confidence < 0 or confidence > 1:
            blockers.append("confidence_invalid")
    return unique_preserve_order(blockers)


def _derived_text_read_source_file(text_file: Path | str) -> tuple[bytes | None, list[str]]:
    path = Path(text_file)
    blockers: list[str] = []
    try:
        entry_stat = os.lstat(path)
    except FileNotFoundError:
        return None, ["text_file_missing"]
    except OSError:
        return None, ["text_file_unreadable"]
    if stat.S_ISLNK(entry_stat.st_mode):
        return None, ["text_file_symlink_not_allowed"]
    if stat.S_ISDIR(entry_stat.st_mode):
        return None, ["text_file_is_directory"]
    if not stat.S_ISREG(entry_stat.st_mode):
        return None, ["text_file_special_not_allowed"]
    try:
        data = path.read_bytes()
    except OSError:
        return None, ["text_file_unreadable"]
    try:
        data.decode("utf-8")
    except UnicodeDecodeError:
        blockers.append("text_file_not_utf8")
    return data, blockers


def _derived_text_build_record(
    *,
    archive_id: str,
    source_object_id: str,
    text_sha256: str,
    text_logical_key: str,
    size_bytes: int,
    text_filename: str,
    derivation_kind: str,
    tool_name: str,
    tool_version: str,
    model_name: str | None,
    model_version: str | None,
    confidence: float | int | None,
    language: str | None,
    review_status: str,
    born_digital: bool,
    captured_at: str,
    reviewed_by: str | None,
) -> dict[str, Any]:
    digest = derived_text_identity_digest(
        source_object_id=source_object_id,
        text_sha256=text_sha256,
        derivation_kind=derivation_kind,
        tool_name=tool_name,
        tool_version=tool_version,
        model_name=model_name,
        model_version=model_version,
        review_status=review_status,
    )
    return drop_none_values(
        {
            "schema": DERIVED_TEXT_RECORD_SCHEMA,
            "derived_text_id": f"derived-text:sha256:{digest}",
            "source_object_id": source_object_id,
            "derivation_kind": derivation_kind,
            "tool_name": tool_name,
            "tool_version": tool_version,
            "model_name": model_name,
            "model_version": model_version,
            "confidence": confidence,
            "language": language,
            "review_status": review_status,
            "born_digital": born_digital,
            "text_sha256": text_sha256,
            "text_logical_key": text_logical_key,
            "mime": "text/plain; charset=utf-8",
            "size_bytes": size_bytes,
            "provenance": {
                "source": "derived_text_capture",
                "created_in": f"archive:{archive_id}",
                "captured_at": captured_at,
                "captured_by": reviewed_by,
                "source_text_filename": text_filename,
            },
        }
    )


def _derived_text_write_receipt(root: Path, receipt: dict[str, Any], captured_at: str) -> str:
    receipts_dir = archive_internal_path(root, DERIVED_TEXT_CAPTURE_RECEIPTS_DIR)
    receipts_dir.mkdir(parents=True, exist_ok=True)
    timestamp_compact = re.sub(r"[^0-9TZ]", "", captured_at)
    while True:
        capture_id = f"{timestamp_compact}-{secrets.token_hex(6)}"
        receipt_path = receipts_dir / f"{capture_id}.json"
        receipt["receipt_id"] = f"receipt:derived-text-capture:{capture_id}"
        try:
            with receipt_path.open("x", encoding="utf-8") as handle:
                handle.write(json.dumps(json_safe(receipt), indent=2, ensure_ascii=False, default=str) + "\n")
        except FileExistsError:
            continue
        except OSError:
            receipt_path.unlink(missing_ok=True)
            raise
        return f"{DERIVED_TEXT_CAPTURE_RECEIPTS_DIR}/{capture_id}.json"


def _derived_text_capture_run(
    archive_root: Path | str,
    *,
    text_file: Path | str,
    source_object_id: str,
    derivation_kind: str,
    tool_name: str,
    tool_version: str,
    review_status: str,
    approve: bool,
    reviewed_by: str | None,
    model_name: str | None = None,
    model_version: str | None = None,
    confidence: float | int | None = None,
    language: str | None = None,
    born_digital: bool = False,
) -> dict[str, Any]:
    root = require_existing_archive_root(archive_root)
    archive_id = read_archive_id(root)
    captured_at = datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace("+00:00", "Z")
    blockers = _derived_text_metadata_blockers(
        source_object_id=source_object_id,
        derivation_kind=derivation_kind,
        tool_name=tool_name,
        tool_version=tool_version,
        review_status=review_status,
        confidence=confidence,
        language=language,
    )
    normalized_source_object_id = normalize_object_id(source_object_id, []) if not blockers else ""
    source_record_present = False
    if normalized_source_object_id:
        source_record_present = find_manifest_record(root, normalized_source_object_id) is not None
        if not source_record_present:
            blockers.append("source_object_missing")

    text_bytes, file_blockers = _derived_text_read_source_file(text_file)
    blockers.extend(file_blockers)
    if blockers or text_bytes is None:
        return {
            "ok": False,
            "dry_run": not approve,
            "lifecycle_action": "derived_text_capture_plan" if not approve else "derived_text_capture",
            "item_status": "blocked",
            "archive_id": archive_id,
            "source_object_id": normalized_source_object_id or source_object_id,
            "source_object_present": source_record_present,
            "derived_text_id": None,
            "text_logical_key": None,
            "planned_action": "blocked",
            "action": "blocked",
            "blockers": unique_preserve_order(blockers),
            "warnings": [],
            "would_change": [],
        }

    warnings: list[str] = []
    if len(text_bytes) == 0:
        warnings.append("zero_byte_text")
    text_sha256 = hashlib.sha256(text_bytes).hexdigest()
    text_logical_key = f"{DERIVED_TEXT_STORE_PREFIX}/{text_sha256[:2]}/{text_sha256}.txt"
    text_filename = Path(text_file).name
    record = _derived_text_build_record(
        archive_id=archive_id,
        source_object_id=normalized_source_object_id,
        text_sha256=text_sha256,
        text_logical_key=text_logical_key,
        size_bytes=len(text_bytes),
        text_filename=text_filename,
        derivation_kind=derivation_kind,
        tool_name=tool_name.strip(),
        tool_version=tool_version.strip(),
        model_name=model_name.strip() if isinstance(model_name, str) and model_name.strip() else None,
        model_version=model_version.strip() if isinstance(model_version, str) and model_version.strip() else None,
        confidence=confidence,
        language=language.strip() if isinstance(language, str) and language.strip() else None,
        review_status=review_status,
        born_digital=born_digital,
        captured_at=captured_at,
        reviewed_by=reviewed_by,
    )
    derived_text_id = str(record["derived_text_id"])
    dest = archive_internal_path(root, text_logical_key)

    def compute_planned_action(existing_ids: set[str]) -> str:
        record_present = derived_text_id in existing_ids
        dest_present = dest.is_file()
        if dest_present and sha256_path(dest) != text_sha256:
            return "dest_collision"
        if record_present and dest_present:
            return "skip_already_present"
        if record_present and not dest_present:
            return "re_materialize"
        if not record_present and dest_present:
            return "repair_append"
        return "capture"

    existing_ids = derived_text_canonical_record_ids(load_derived_text_records(root))
    planned_action = compute_planned_action(existing_ids)
    if planned_action == "dest_collision":
        blockers.append("dest_collision")

    base_output = {
        "dry_run": not approve,
        "lifecycle_action": "derived_text_capture_plan" if not approve else "derived_text_capture",
        "archive_id": archive_id,
        "source_object_id": normalized_source_object_id,
        "source_object_present": source_record_present,
        "derived_text_id": derived_text_id,
        "derivation_kind": derivation_kind,
        "review_status": review_status,
        "text_sha256": text_sha256,
        "text_logical_key": text_logical_key,
        "size_bytes": len(text_bytes),
        "mime": "text/plain; charset=utf-8",
    }
    planned_writes: list[str] = []
    if planned_action in ("capture", "re_materialize"):
        planned_writes.append(text_logical_key)
    if planned_action in ("capture", "repair_append"):
        planned_writes.append(f"{DERIVED_TEXT_MANIFEST_RELATIVE_PATH} (+1 line)")

    if not approve:
        timestamp_compact = re.sub(r"[^0-9TZ]", "", captured_at)
        return {
            "ok": not blockers,
            **base_output,
            "item_status": derived_text_capture_item_status(
                ok=not blockers,
                approve=False,
                planned_action=planned_action if not blockers else "blocked",
            ),
            "planned_action": planned_action if not blockers else "blocked",
            "proposed_receipt_path": f"{DERIVED_TEXT_CAPTURE_RECEIPTS_DIR}/{timestamp_compact}-{secrets.token_hex(6)}.json",
            "planned_writes": [] if blockers else planned_writes,
            "blockers": unique_preserve_order(blockers),
            "warnings": warnings,
            "would_change": [] if blockers else planned_writes,
        }

    if reviewed_by is None or not str(reviewed_by).strip():
        blockers.append("reviewed_by_required")

    manifest_record_appended = False
    stored_sha256_verified = False
    action = planned_action
    receipt_path_value: str | None = None
    if not blockers:
        try:
            archive_internal_path(root, DERIVED_TEXT_CAPTURE_RECEIPTS_DIR).mkdir(parents=True, exist_ok=True)
        except OSError:
            blockers.append("receipts_dir_unavailable")
    if not blockers:
        manifest_path = archive_internal_path(root, DERIVED_TEXT_MANIFEST_RELATIVE_PATH)
        with _DerivedTextManifestLock(root):
            action = compute_planned_action(derived_text_canonical_record_ids(load_derived_text_records(root)))
            if action == "dest_collision":
                blockers.append("dest_collision")
            if not blockers and action in ("capture", "re_materialize"):
                dest.parent.mkdir(parents=True, exist_ok=True)
                tmp = dest.parent / (dest.name + ".part-" + secrets.token_hex(8))
                try:
                    with tmp.open("wb") as handle:
                        handle.write(text_bytes)
                        handle.flush()
                        os.fsync(handle.fileno())
                    if sha256_path(tmp) != text_sha256:
                        tmp.unlink(missing_ok=True)
                        blockers.append("lossless_verification_failed")
                    else:
                        _objet_capture_fsync_dir(dest.parent)
                        os.replace(tmp, dest)
                        _objet_capture_fsync_dir(dest.parent)
                        if sha256_path(dest) != text_sha256:
                            dest.unlink(missing_ok=True)
                            blockers.append("lossless_verification_failed")
                        else:
                            stored_sha256_verified = True
                except OSError:
                    tmp.unlink(missing_ok=True)
                    blockers.append("text_store_write_failed")
            elif action == "skip_already_present":
                stored_sha256_verified = dest.is_file() and sha256_path(dest) == text_sha256
            if not blockers and action in ("capture", "repair_append"):
                try:
                    needs_newline = _jsonl_needs_leading_newline(manifest_path)
                    with manifest_path.open("a", encoding="utf-8", newline="\n") as manifest_handle:
                        if needs_newline:
                            manifest_handle.write("\n")
                        manifest_handle.write(
                            json.dumps(record, ensure_ascii=False, default=str, separators=(",", ":")) + "\n"
                        )
                        manifest_handle.flush()
                        os.fsync(manifest_handle.fileno())
                    manifest_record_appended = True
                except OSError:
                    blockers.append("manifest_append_failed")
    receipt = {
        "receipt_id": None,
        "schema": DERIVED_TEXT_CAPTURE_RECEIPT_SCHEMA,
        "dry_run": False,
        "ok": not blockers,
        "archive_id": archive_id,
        "reviewed_by": reviewed_by,
        "captured_at": captured_at,
        "derived_text_id": derived_text_id,
        "source_object_id": normalized_source_object_id,
        "text_sha256": text_sha256,
        "text_logical_key": text_logical_key,
        "derivation_kind": derivation_kind,
        "review_status": review_status,
        "planned_action": action,
        "action": {
            "capture": "captured",
            "repair_append": "repair_appended",
            "re_materialize": "re_materialized",
            "skip_already_present": "skip_already_present",
        }.get(action, action)
        if not blockers
        else "blocked",
        "manifest_record_appended": manifest_record_appended,
        "stored_sha256_verified": stored_sha256_verified,
        "blockers": unique_preserve_order(blockers),
        "warnings": warnings,
    }
    if not (blockers and "receipts_dir_unavailable" in blockers):
        receipt_path_value = _derived_text_write_receipt(root, receipt, captured_at)
    return {
        "ok": not blockers,
        **base_output,
        "item_status": derived_text_capture_item_status(
            ok=not blockers,
            approve=True,
            action=(
                {
                    "capture": "captured",
                    "repair_append": "repair_appended",
                    "re_materialize": "re_materialized",
                    "skip_already_present": "skip_already_present",
                }.get(action, action)
                if not blockers
                else "blocked"
            ),
        ),
        "reviewed_by": reviewed_by,
        "captured_at": captured_at,
        "planned_action": action,
        "action": {
            "capture": "captured",
            "repair_append": "repair_appended",
            "re_materialize": "re_materialized",
            "skip_already_present": "skip_already_present",
        }.get(action, action)
        if not blockers
        else "blocked",
        "manifest_record_appended": manifest_record_appended,
        "stored_sha256_verified": stored_sha256_verified,
        "receipt_path": receipt_path_value,
        "blockers": unique_preserve_order(blockers),
        "warnings": warnings,
    }


